# ANSI colours (disabled on Windows if not supported)
_USE_COLOR = (sys.stdout.isatty() or bool(os.environ.get("FORCE_COLOR")))

def _c(text: str, code: str) -> str:
    if _USE_COLOR:
        return f"\033[{code}m{text}\033[0m"
    return text

RED    = lambda t: _c(t, "31")
GREEN  = lambda t: _c(t, "32")
YELLOW = lambda t: _c(t, "33")
CYAN   = lambda t: _c(t, "36")
BOLD   = lambda t: _c(t, "1")
DIM    = lambda t: _c(t, "2")


# ── Branch / Tournament state helpers ───────────────────────────────────────

def _state_path(branch: Optional[str] = None) -> Path:
    """Return state file path. branch=None means the main pipeline state.

    IMP-20260621-8A27: branch=None인 경우, 활성 runtime store 경로가 있으면 그것을
    반환하고(쓰기 일관성), 없으면 legacy STATE_FILE을 반환한다(read fallback).
    """
    if branch is None:
        read_path = _resolve_state_path_for_read()
        return read_path if read_path is not None else STATE_FILE
    state = _load_state_for(None)
    pid = state.get("pipeline_id", "UNKNOWN")
    short = pid[-4:] if len(pid) >= 4 else pid
    return BASE_DIR / f"pipeline_state_{short}-{branch}.json"


def _load_state_for(branch: Optional[str] = None) -> dict:
    """브랜치별 state 파일 로드. branch=None 이면 메인 runtime store 로드.

    IMP-20260621-8A27: branch=None(메인) 경우 _resolve_state_path_for_read()로
    runtime store(.pipeline/runs/<id>/state.json) 또는 legacy fallback을 사용한다.
    이렇게 해야 cmd_done/cmd_check 등 branch helper를 쓰는 명령도 runtime store와
    일관되게 동작하며 legacy pipeline_state.json에 split-brain write가 발생하지 않는다.
    """
    if branch is None:
        read_path = _resolve_state_path_for_read()
        if read_path is None or not read_path.exists():
            return {}
        for enc in ("utf-8", "cp949", "latin-1"):
            try:
                return json.loads(read_path.read_text(encoding=enc))
            except (UnicodeDecodeError, json.JSONDecodeError):
                continue
        raise SystemExit(3)
    else:
        # branch 경우: 이미 계산된 경로를 직접 산출 (재귀 없이)
        # 메인 state 에서 pipeline_id 를 읽어 short suffix 계산
        main_state: dict = {}
        if STATE_FILE.exists():
            for enc in ("utf-8", "cp949", "latin-1"):
                try:
                    main_state = json.loads(STATE_FILE.read_text(encoding=enc))
                    break
                except (UnicodeDecodeError, json.JSONDecodeError):
                    continue
        pid = main_state.get("pipeline_id", "UNKNOWN")
        short = pid[-4:] if len(pid) >= 4 else pid
        path = BASE_DIR / f"pipeline_state_{short}-{branch}.json"

    if not path.exists():
        return {}
    for enc in ("utf-8", "cp949", "latin-1"):
        try:
            return json.loads(path.read_text(encoding=enc))
        except (UnicodeDecodeError, json.JSONDecodeError):
            continue
    raise SystemExit(3)


# [Purpose]: Windows에서 OneDrive sync/antivirus가 destination 파일을 잠깐 잠그면
#            os.replace()가 WinError 5(Access is denied) PermissionError를 즉시 던진다.
#            acceptance_request.json/packet 등 원자적 커밋 시 이 일시 잠금으로 oracle
#            테스트(TC-6N)가 타임아웃되는 문제를 재시도로 해소한다.
# [Assumptions]: src/dst는 동일 볼륨의 경로이며, 잠금은 일시적(수 초 이내 해제)이다.
# [Vulnerability & Risks]: 잠금이 max_retries*delay(기본 5초)보다 오래 지속되면 마지막
#            PermissionError를 그대로 raise한다. PermissionError 외 예외는 재시도하지 않는다.
# [Improvement]: 지수 백오프 또는 파일 핸들 점유 프로세스 진단(handle.exe) 연동.
def _safe_replace(src: str, dst: str, max_retries: int = 10, delay: float = 0.5) -> None:
    """os.replace with retry for Windows WinError 5 (OneDrive file lock)."""
    import time
    last_err: Optional[Exception] = None
    for attempt in range(max_retries):
        try:
            os.replace(src, dst)
            return
        except PermissionError as e:
            last_err = e
            if attempt < max_retries - 1:
                time.sleep(delay)
    if last_err is not None:
        raise last_err


def _save_state_for(state: dict, branch: Optional[str] = None) -> None:
    """브랜치별 state 파일 원자적 저장. branch=None 이면 메인 runtime store 저장.

    IMP-20260621-8A27: branch=None(메인) 경우 _resolve_state_path_for_write()로
    runtime store(.pipeline/runs/<id>/state.json)에 저장한다. legacy pipeline_state.json은
    절대 write 대상이 되지 않으며, runtime store 디렉토리는 없으면 생성한다.
    """
    if branch is None:
        pid = state.get("pipeline_id")
        if not pid:
            raise TypeError("state must contain a non-empty 'pipeline_id'")
        path = _resolve_state_path_for_write(pid)
        path.parent.mkdir(parents=True, exist_ok=True)
    else:
        pid = state.get("parent_pipeline_id") or state.get("pipeline_id", "UNKNOWN")
        short = pid[-4:] if len(pid) >= 4 else pid
        path = BASE_DIR / f"pipeline_state_{short}-{branch}.json"

    # updated_at 자동 갱신 (기존 _save() 와 동일한 동작)
    state["updated_at"] = _now()

    tmp_path: Optional[Path] = None
    try:
        with tempfile.NamedTemporaryFile(
            mode="w", encoding="utf-8", dir=path.parent,
            delete=False, suffix=".tmp"
        ) as tmp:
            json.dump(state, tmp, ensure_ascii=False, indent=2)
            tmp_path = Path(tmp.name)
        os.replace(str(tmp_path), str(path))
    except Exception:
        if tmp_path is not None and tmp_path.exists():
            tmp_path.unlink(missing_ok=True)
        raise


def _validate_branch(branch: str) -> None:
    """브랜치 ID 형식 검증 (대문자 알파벳 1글자만 허용)."""
    if branch is None:
        raise SystemExit(2)
    if not isinstance(branch, str):
        raise SystemExit(2)
    if not re.fullmatch(r"[A-Z]", branch):
        print(f"[ERROR] branch는 대문자 알파벳 1글자만 허용합니다: '{branch}'")
        raise SystemExit(2)


# ── State helpers ────────────────────────────────────────────────────────────

def _now() -> str:
    return datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")


def _generate_id(pipeline_type: str) -> str:
    date = datetime.now(timezone.utc).strftime("%Y%m%d")
    suffix = secrets.token_hex(2).upper()
    return f"{pipeline_type}-{date}-{suffix}"


