def _empty_module_step() -> Dict[str, Any]:
    return {
        "status": "PENDING",
        "completed_at": None,
        "report_file": None,
        "evidence": None,
        "notes": [],
    }


def _new_module_gates(enabled: bool = True) -> Dict[str, Any]:
    return {
        "enabled": enabled,
        "mode": "incremental_module_gate",
        "sequence": [],
        "modules": {},
        "integration": _empty_module_step(),
    }


def _ensure_module_gates(state: Dict[str, Any]) -> Dict[str, Any]:
    existing = state.get("module_gates")
    normalized = _new_module_gates(enabled=True)
    if isinstance(existing, dict):
        normalized["mode"] = str(existing.get("mode") or "incremental_module_gate")
        sequence = existing.get("sequence")
        if isinstance(sequence, list):
            normalized["sequence"] = [str(item) for item in sequence if str(item)]
        modules = existing.get("modules")
        if isinstance(modules, dict):
            for mt_id, item in modules.items():
                if not isinstance(item, dict):
                    continue
                merged = {
                    "id": str(mt_id),
                    "status": "PENDING",
                    "order": 0,
                    "target_files": [],
                    "affected_function": None,
                    "design": _empty_module_step(),
                    "dev": _empty_module_step(),
                    "qa": _empty_module_step(),
                    "checkpoint": None,
                }
                merged.update(item)
                for step_name in ("design", "dev", "qa"):
                    step = merged.get(step_name)
                    base = _empty_module_step()
                    if isinstance(step, dict):
                        base.update(step)
                    merged[step_name] = base
                normalized["modules"][str(mt_id)] = merged
        integration = existing.get("integration")
        if isinstance(integration, dict):
            merged_integration = _empty_module_step()
            merged_integration.update(integration)
            normalized["integration"] = merged_integration
    normalized["enabled"] = True
    return normalized


def _ensure_phase_attestations(state: Dict[str, Any]) -> Dict[str, Any]:
    existing = state.get("phase_attestations")
    if not isinstance(existing, dict):
        return _new_phase_attestations(enabled=True)
    normalized = _new_phase_attestations(enabled=True)
    normalized["mode"] = str(existing.get("mode") or "github_actions_per_phase")
    required = existing.get("required_phases")
    if isinstance(required, list) and required:
        normalized["required_phases"] = [
            str(item) for item in required if str(item) in PHASE_ATTESTATION_PHASES
        ] or list(PHASE_ATTESTATION_PHASES)
    phases = existing.get("phases")
    if isinstance(phases, dict):
        for phase in PHASE_ATTESTATION_PHASES:
            item = phases.get(phase)
            if isinstance(item, dict):
                merged = _empty_phase_attestation()
                merged.update(item)
                merged["phase"] = phase
                normalized["phases"][phase] = merged
    return normalized


def _save_phase_snapshot(state: Dict[str, Any], phase: str) -> Optional[str]:
    """현재 state를 pipeline_history/{pid}_phase_{phase}.json에 스냅샷.

    동일 phase 재시도 시 .N 접미사로 회전(_phase_dev.json, _phase_dev.1.json, ...).
    실패는 무시 (스냅샷이 핵심 게이트를 막아서는 안 됨).
    """
    try:
        HISTORY_DIR.mkdir(exist_ok=True)
        pid = state.get("pipeline_id", "UNKNOWN")
        base = HISTORY_DIR / f"{pid}_phase_{phase}.json"
        path = base
        idx = 1
        while path.exists():
            path = HISTORY_DIR / f"{pid}_phase_{phase}.{idx}.json"
            idx += 1
        path.write_text(
            json.dumps(state, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
        return str(path)
    except OSError as e:
        print(DIM(f"  [SNAPSHOT WARN] {phase} 스냅샷 실패: {e}"))
        return None


def _new_state(pipeline_id: str, pipeline_type: str, description: str) -> Dict[str, Any]:
    return {
        "version":       VERSION,
        "pipeline_id":   pipeline_id,
        "type":          pipeline_type,
        "description":   description,
        "created_at":    _now(),
        "updated_at":    _now(),
        # IMP-20260522-29C1 MT-1: pipeline lifecycle timestamps.
        # metrics status의 total_elapsed 계산을 위해 명시적 시작/종료 시점을 기록.
        "pipeline_started_at": _now(),    # 파이프라인 최초 생성 시점
        "pipeline_completed_at": None,    # cmd_architect COMPLETE 시 기록
        "acceptance_requested_at": None,  # cmd_gates accept 시작 시 기록
        "acceptance_recorded_at": None,   # ACCEPT PASS 기록 직후 기록
        "total_elapsed_seconds": None,    # COMPLETE 시 (completed - started) 초
        "current_phase": "pm",
        "blocked":       False,
        "blocked_reason": None,
        "phases": {p: _empty_phase(p) for p in PHASE_ORDER},
        "event_log":     [],
        # v2.10 Auto-Compact 지원: 파이프라인 종료 상태 표시
        # null = in progress, "COMPLETE" = Phase 8 architect completion, "FAILED" = repeated external gate FAIL,
        # "TERMINATED" = 사용자 명시적 중단
        "terminal_state": None,
        "harness_fail_count": 0,
        "agent_runs": {},
        "external_gates": _new_external_gates(enabled=True),
        "phase_attestations": _new_phase_attestations(enabled=True),
        "module_gates": _new_module_gates(enabled=True),
        "execution_profile": _new_execution_profile("STANDARD"),
        "outputs": {"items": []},
        "failure_packets": [],
        "protocol_evolution_decision": None,
        # IMP-20260526-82E3 MT-1: 관측성 강화 - 5개 alias 키 (역호환 위해 기존 phases/external_gates와 병행 보존)
        "phase_timings": {},                   # {phase: {elapsed_seconds: int}}
        "gate_timings": {},                    # {gate: {elapsed_seconds: int}}
        "agent_timings": {},                   # {run_id: {elapsed_seconds: int}}
        "github_actions_timings": {            # 5상태 누적 시간 (초)
            "WAITING_FOR_TRIGGER": 0,
            "QUEUED": 0,
            "IN_PROGRESS": 0,
            "COMPLETED": 0,
            "TIMEOUT": 0,
        },
        "failure_summary": {},                 # {failure_code: {count: int, is_repeat: bool}}
        # IMP-20260527-075A MT-1: Cost/Attempt Budget Gate
        "attempt_budget": {
            "config": {
                "dev_max_attempts": 3,
                "qa_max_attempts": 3,
                "gate_max_attempts": 5,
                "repeat_failure_code_threshold": 3,
            },
            "attempts": {"dev": [], "qa": [], "gate": []},
            "blocked_phases": {},
        },
    }


def _ensure_external_gates(state: Dict[str, Any]) -> Dict[str, Any]:
    gates = state.get("external_gates")
    if not isinstance(gates, dict):
        return _new_external_gates(enabled=True)

    normalized = _new_external_gates(enabled=True)
    normalized["mode"] = str(gates.get("mode") or "three_gate")
    for gate_name in ("technical", "oracle", "acceptance", "github_ci"):
        existing = gates.get(gate_name)
        if isinstance(existing, dict):
            merged = _empty_external_gate()
            merged.update(existing)
            normalized[gate_name] = merged
    return normalized


def _ensure_v210_fields(state: Dict[str, Any]) -> Dict[str, Any]:
    """v2.10 신규 필드를 구버전 state에 자동 마이그레이션 (idempotent)."""
    if "terminal_state" not in state:
        state["terminal_state"] = None
    if "harness_fail_count" not in state:
        state["harness_fail_count"] = 0
    if not isinstance(state.get("agent_runs"), dict):
        state["agent_runs"] = {}
    if "protocol_evolution_decision" not in state:
        state["protocol_evolution_decision"] = None
    if not isinstance(state.get("execution_profile"), dict):
        state["execution_profile"] = _new_execution_profile("STANDARD")
    else:
        merged_profile = _new_execution_profile(str(state["execution_profile"].get("mode") or "STANDARD"))
        merged_profile.update(state["execution_profile"])
        state["execution_profile"] = merged_profile
    if not isinstance(state.get("outputs"), dict):
        state["outputs"] = {"items": []}
    elif not isinstance(state["outputs"].get("items"), list):
        state["outputs"]["items"] = []
    if not isinstance(state.get("failure_packets"), list):
        state["failure_packets"] = []
    state["external_gates"] = _ensure_external_gates(state)
    state["external_gates"]["enabled"] = True
    state["phase_attestations"] = _ensure_phase_attestations(state)
    state["phase_attestations"]["enabled"] = True
    state["module_gates"] = _ensure_module_gates(state)
    # IMP-20260522-29C1 MT-1: pipeline lifecycle timestamps 마이그레이션 (idempotent).
    # 구버전 state에는 이 5개 필드가 없으므로 기본값을 채운다.
    # 기존 파이프라인은 pipeline_started_at을 created_at으로 대체한다.
    if "pipeline_started_at" not in state:
        state["pipeline_started_at"] = state.get("created_at")
    if "pipeline_completed_at" not in state:
        state["pipeline_completed_at"] = None
    if "acceptance_requested_at" not in state:
        state["acceptance_requested_at"] = None
    if "acceptance_recorded_at" not in state:
        state["acceptance_recorded_at"] = None
    if "total_elapsed_seconds" not in state:
        state["total_elapsed_seconds"] = None
    # IMP-20260524-48C4 MT-1: oracle_quality 상태 필드 초기화
    if "oracle_quality" not in state:
        state["oracle_quality"] = {}
    # IMP-20260526-82E3 MT-1: 5개 관측성 alias 키 마이그레이션 (역호환, idempotent)
    if "phase_timings" not in state:
        state["phase_timings"] = {}
    if "gate_timings" not in state:
        state["gate_timings"] = {}
    if "agent_timings" not in state:
        state["agent_timings"] = {}
    if "github_actions_timings" not in state or not isinstance(state.get("github_actions_timings"), dict):
        state["github_actions_timings"] = {
            "WAITING_FOR_TRIGGER": 0,
            "QUEUED": 0,
            "IN_PROGRESS": 0,
            "COMPLETED": 0,
            "TIMEOUT": 0,
        }
    else:
        for _gh_state in ("WAITING_FOR_TRIGGER", "QUEUED", "IN_PROGRESS", "COMPLETED", "TIMEOUT"):
            if _gh_state not in state["github_actions_timings"]:
                state["github_actions_timings"][_gh_state] = 0
    if "failure_summary" not in state:
        state["failure_summary"] = {}
    # IMP-20260527-075A MT-1: Cost/Attempt Budget Gate 마이그레이션
    # _ensure_attempt_budget_keys는 더 정교한 검증을 수행하지만 _ensure_v210_fields는
    # 호출 순서상 _record_failure_packet 정의 전에 실행되므로 여기서는 dict 형태만 보장.
    if not isinstance(state.get("attempt_budget"), dict):
        state["attempt_budget"] = {
            "config": {
                "dev_max_attempts": 3,
                "qa_max_attempts": 3,
                "gate_max_attempts": 5,
                "repeat_failure_code_threshold": 3,
            },
            "attempts": {"dev": [], "qa": [], "gate": []},
            "blocked_phases": {},
        }
    return state


# ── Runtime State Store (IMP-20260621-8A27) ──────────────────────────────────
# [Purpose]: pipeline_state.json이 git-tracked 파일이라 파이프라인 실행마다 working
#   tree가 dirty 상태가 되는 문제를 해결. active state를 gitignored runtime store
#   (.pipeline/runs/<pipeline_id>/state.json)로 옮기고, legacy pipeline_state.json은
#   read-only fallback 전용으로만 유지한다.
# [Assumptions]: BASE_DIR가 모듈 로드 시점에 결정되어 있고, PIPELINE_STATE_PATH가
#   설정되면 항상 최우선이다. .pipeline 디렉토리는 gitignore 대상이다.
# [Vulnerability & Risks]: active_run.json pointer가 손상되면 read 경로를 결정할 수
#   없으므로 _die로 명확히 차단한다. pointer는 있으나 state 파일이 없는 경우도
#   _resolve_state_path_for_read에서 _die로 처리한다(MT-4).
# [Improvement]: 다중 동시 파이프라인 지원 시 pointer를 stack 구조로 확장 가능.


def _default_runtime_state_dir() -> Path:
    """Return the runtime state root directory (.pipeline/runs).

    Returns:
        Path: BASE_DIR / ".pipeline" / "runs" (이 함수는 디렉토리를 생성하지 않음).
    """
    return BASE_DIR / ".pipeline" / "runs"


# ── Scratch Hygiene v1 (IMP-20260622-79BA MT-1) ─────────────────────────────
# [Purpose]: 파이프라인이 repo root에 임시 산출물(tmp_*.json, *_dump.txt 등)을
#   흘려 working tree를 오염시키는 문제를 막기 위해, 파이프라인별 격리 scratch
#   디렉터리(.pipeline/runs/<id>/scratch/)를 제공한다. 이 위치는 .pipeline/ 하위라
#   gitignore 대상이며 Runtime State Store와 동일한 격리 모델을 따른다.
# [Assumptions]: pipeline_id는 비어있지 않은 str. .pipeline 디렉토리는 gitignore 대상.
#   BASE_DIR는 모듈 로드 시점에 결정되어 있다.
# [Vulnerability & Risks]: None/빈 pipeline_id가 들어오면 잘못된 경로(.pipeline/runs/)에
#   파일이 생성될 수 있으므로 입력 검증으로 차단한다. _cleanup_scratch는 ignore_errors로
#   Permission denied를 best-effort 처리하므로 일부 파일이 남을 수 있다(보안 영향 없음).
# [Improvement]: scratch 용량 상한/만료 정책을 추가해 장기 미사용 scratch를 자동 정리 가능.


def _scratch_root(pipeline_id: str) -> Path:
    """파이프라인별 scratch 루트 경로(.pipeline/runs/<id>/scratch/)를 반환한다.

    Args:
        pipeline_id: 파이프라인 ID 문자열 (예: "IMP-20260622-79BA"). None 금지.
    Returns:
        Path: .pipeline/runs/<pipeline_id>/scratch (디렉터리를 생성하지 않음).
    Raises:
        TypeError: pipeline_id가 None이거나 str이 아닌 경우.
        ValueError: pipeline_id가 빈 문자열인 경우.
    """
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(
            f"pipeline_id must be str, got {type(pipeline_id).__name__}"
        )
    if len(pipeline_id) == 0:
        raise ValueError("pipeline_id must not be empty")
    return _default_runtime_state_dir() / pipeline_id / "scratch"


def _scratch_path(pipeline_id: str, *parts: str) -> Path:
    """scratch 루트 아래 임의 깊이의 경로를 만들고 부모 디렉터리를 자동 생성한다.

    Args:
        pipeline_id: 파이프라인 ID 문자열. None 금지.
        *parts: scratch 루트 기준 하위 경로 조각들(예: "oracle", "tc1.json").
    Returns:
        Path: scratch 루트 아래 결합된 경로(부모 디렉터리는 생성됨, 파일은 미생성).
    Raises:
        TypeError: pipeline_id가 None이거나 str이 아닌 경우.
        ValueError: pipeline_id가 빈 문자열인 경우.
    """
    root = _scratch_root(pipeline_id)
    path = root.joinpath(*parts)
    path.parent.mkdir(parents=True, exist_ok=True)
    return path


def _cleanup_scratch(pipeline_id: str) -> None:
    """파이프라인 scratch 디렉터리 전체를 삭제한다(파이프라인 종료 시 호출).

    Permission denied 등 삭제 실패는 best-effort로 무시한다(ignore_errors=True).

    Args:
        pipeline_id: 파이프라인 ID 문자열. None 금지.
    Returns:
        None.
    Raises:
        TypeError: pipeline_id가 None이거나 str이 아닌 경우.
        ValueError: pipeline_id가 빈 문자열인 경우.
    """
    import shutil
    root = _scratch_root(pipeline_id)
    if root.exists():
        shutil.rmtree(root, ignore_errors=True)


def _scratch_file(pipeline_id: str, filename: str) -> Path:
    """scratch 루트 바로 아래의 파일 경로를 반환하고 루트 디렉터리를 자동 생성한다.

    Args:
        pipeline_id: 파이프라인 ID 문자열. None 금지.
        filename: scratch 루트 아래 파일명(예: "tmp_tc1.json"). None 금지.
    Returns:
        Path: scratch 루트 / filename (루트 디렉터리는 생성됨, 파일은 미생성).
    Raises:
        TypeError: pipeline_id 또는 filename이 None이거나 str이 아닌 경우.
        ValueError: pipeline_id 또는 filename이 빈 문자열인 경우.
    """
    if filename is None:
        raise TypeError("filename must not be None")
    if not isinstance(filename, str):
        raise TypeError(
            f"filename must be str, got {type(filename).__name__}"
        )
    if len(filename) == 0:
        raise ValueError("filename must not be empty")
    root = _scratch_root(pipeline_id)
    root.mkdir(parents=True, exist_ok=True)
    return root / filename


def _list_scratch_files(pipeline_id: str) -> List[Path]:
    """scratch 루트 아래의 모든 파일 경로 목록을 반환한다.

    Args:
        pipeline_id: 파이프라인 ID 문자열. None 금지.
    Returns:
        List[Path]: scratch 루트가 없으면 빈 리스트. 있으면 하위 모든 파일.
    Raises:
        TypeError: pipeline_id가 None이거나 str이 아닌 경우.
        ValueError: pipeline_id가 빈 문자열인 경우.
    """
    root = _scratch_root(pipeline_id)
    if not root.exists():
        return []
    return [p for p in root.rglob("*") if p.is_file()]


def _scratch_exists(pipeline_id: str) -> bool:
    """scratch 루트 디렉터리의 존재 여부를 반환한다.

    Args:
        pipeline_id: 파이프라인 ID 문자열. None 금지.
    Returns:
        bool: scratch 루트가 존재하면 True.
    Raises:
        TypeError: pipeline_id가 None이거나 str이 아닌 경우.
        ValueError: pipeline_id가 빈 문자열인 경우.
    """
    return _scratch_root(pipeline_id).exists()


def _active_run_pointer_path() -> Path:
    """Return the active-run pointer path (.pipeline/active_run.json).

    Returns:
        Path: BASE_DIR / ".pipeline" / "active_run.json".
    """
    return BASE_DIR / ".pipeline" / "active_run.json"


def _state_path_for_pipeline_id(pipeline_id: str) -> Path:
    """Return the runtime state.json path for a given pipeline id.

    Args:
        pipeline_id: 파이프라인 ID 문자열 (예: "IMP-20260621-8A27").
    Returns:
        Path: .pipeline/runs/<pipeline_id>/state.json.
    Raises:
        TypeError: pipeline_id가 None이거나 str이 아닌 경우.
        ValueError: pipeline_id가 빈 문자열인 경우.
    """
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(
            f"pipeline_id must be str, got {type(pipeline_id).__name__}"
        )
    if len(pipeline_id) == 0:
        raise ValueError("pipeline_id must not be empty")
    return _default_runtime_state_dir() / pipeline_id / "state.json"


def _resolve_state_path_for_read() -> Optional[Path]:
    """Resolve the state file path for reading.

    우선순위:
        1. PIPELINE_STATE_PATH 환경변수 (기존 동작 유지, 최우선).
        2. .pipeline/active_run.json pointer의 pipeline_id →
           .pipeline/runs/<id>/state.json.
        3. legacy pipeline_state.json (read-only fallback).

    Returns:
        Optional[Path]: 해석된 state 경로. active state가 없으면 None.
    Raises:
        SystemExit: active_run.json이 손상되어 파싱할 수 없거나(MT-4),
            pointer는 존재하나 state 파일이 없는 경우(MT-4) _die로 차단.
    """
    env_path = os.environ.get("PIPELINE_STATE_PATH")
    if env_path:
        return Path(env_path)

    pointer = _active_run_pointer_path()
    if pointer.exists():
        try:
            data = json.loads(pointer.read_text(encoding="utf-8"))
        except (json.JSONDecodeError, OSError) as exc:
            _die(
                "active_run.json 파싱 실패: "
                f"{exc}\n"
                "복구 방법: .pipeline/active_run.json 을 삭제하거나 올바른 JSON으로 "
                "수정하세요. 삭제하면 legacy pipeline_state.json fallback을 사용합니다."
            )
        pid = data.get("pipeline_id") if isinstance(data, dict) else None
        if pid:
            state_path = _state_path_for_pipeline_id(pid)
            if not state_path.exists():
                _die(
                    "active_run.json 은 존재하지만 runtime state 파일이 없습니다: "
                    f"{state_path}\n"
                    "복구 방법: .pipeline/active_run.json 을 삭제하면 legacy "
                    "pipeline_state.json fallback을 사용합니다."
                )
            return state_path

    # legacy fallback: read-only (절대 write 대상이 되지 않음)
    legacy = BASE_DIR / "pipeline_state.json"
    if legacy.exists():
        return legacy
    return None


def _resolve_state_path_for_write(pipeline_id: str) -> Path:
    """Resolve the state file path for writing.

    우선순위:
        1. PIPELINE_STATE_PATH 환경변수 (기존 동작 유지, 최우선).
        2. .pipeline/runs/<pipeline_id>/state.json.

    legacy pipeline_state.json은 절대 write 대상이 되지 않는다.

    Args:
        pipeline_id: 쓰기 대상 파이프라인 ID 문자열.
    Returns:
        Path: 쓰기 대상 state 경로.
    Raises:
        TypeError: pipeline_id가 None이거나 str이 아닌 경우.
        ValueError: pipeline_id가 빈 문자열인 경우.
    """
    env_path = os.environ.get("PIPELINE_STATE_PATH")
    if env_path:
        return Path(env_path)
    return _state_path_for_pipeline_id(pipeline_id)


def _load() -> Optional[Dict[str, Any]]:
    state_path = _resolve_state_path_for_read()
    if state_path is None or not state_path.exists():
        return None
    try:
        state = json.loads(state_path.read_text(encoding="utf-8"))
        # v2.10 backward compatibility: 구버전 state 파일 자동 마이그레이션
        return _ensure_v210_fields(state)
    except (json.JSONDecodeError, OSError) as e:
        _die(f"state 파일 읽기 실패 ({state_path}): {e}")


def _save(state: Dict[str, Any]) -> None:
    """Atomically write the runtime state file (tempfile → os.replace).

    IMP-20260621-8A27: 쓰기 경로는 _resolve_state_path_for_write()로 결정한다.
    legacy pipeline_state.json은 절대 write 대상이 되지 않으며, runtime store
    디렉토리(.pipeline/runs/<id>/)는 없으면 생성한다 (copy-forward 효과).

    Args:
        state: 저장할 파이프라인 state dict. state["pipeline_id"]가 쓰기 경로 결정에 사용됨.
    Raises:
        TypeError: state가 dict가 아니거나 pipeline_id가 누락된 경우.
    """
    if state is None:
        raise TypeError("state must not be None")
    if not isinstance(state, dict):
        raise TypeError(f"state must be dict, got {type(state).__name__}")
    pipeline_id = state.get("pipeline_id")
    if not pipeline_id:
        raise TypeError("state must contain a non-empty 'pipeline_id'")

    state["updated_at"] = _now()
    target = _resolve_state_path_for_write(pipeline_id)
    # runtime store 디렉토리가 없으면 생성 (legacy 파일은 건드리지 않음)
    target.parent.mkdir(parents=True, exist_ok=True)

    tmp_path: Optional[Path] = None
    try:
        with tempfile.NamedTemporaryFile(
            mode="w", encoding="utf-8", dir=target.parent,
            delete=False, suffix=".tmp"
        ) as tmp:
            json.dump(state, tmp, ensure_ascii=False, indent=2)
            tmp_path = Path(tmp.name)
        os.replace(str(tmp_path), str(target))
    except Exception:
        if tmp_path is not None and tmp_path.exists():
            tmp_path.unlink(missing_ok=True)
        raise


# ── Workspace Artifact Ownership Registry (IMP-20260623-7EAA MT-1) ───────────
# [Purpose]: 파이프라인이 working tree에 만든 산출물 각각에 cleanup_policy를 부여하여,
#   COMPLETE 시점에 "삭제해도 되는 파일"과 "보존/보호해야 하는 evidence"를 명확히
#   구분한다. 이로써 glob 기반 무차별 삭제 없이, 등록된 cleanup_only 파일만 안전하게
#   정리할 수 있다 (AC-1~AC-3).
# [Assumptions]: state["pipeline_id"]는 비어있지 않은 str. workspace_artifacts.json은
#   state 파일과 같은 디렉토리(.pipeline/runs/<id>/ 또는 PIPELINE_STATE_PATH 부모)에
#   co-locate되어 테스트 격리 모델을 따른다. legacy pipeline_state.json은 절대 쓰지 않는다.
# [Vulnerability & Risks]: None/빈 pipeline_id가 들어오면 잘못된 경로에 파일을 만들 수
#   있으므로 입력 검증으로 차단한다. cleanup_policy 미지정/오타는 'unknown'으로 강등되어
#   삭제 대상에서 제외되므로(보수적), 잘못 등록되어도 데이터 손실은 발생하지 않는다.
# [Improvement]: artifact마다 sha256을 기록해 변조 감지/중복 제거를 강화할 수 있다.

# cleanup_policy enum (SSoT). 매니페스트에 없는 파일은 _CLEANUP_POLICY_UNKNOWN으로 취급.
_CLEANUP_POLICY_CLEANUP_ONLY = "cleanup_only"
_CLEANUP_POLICY_PRESERVE_EVIDENCE = "preserve_evidence"
_CLEANUP_POLICY_PROTECTED_EVIDENCE = "protected_evidence"
_CLEANUP_POLICY_USER_VISIBLE_OUTPUT = "user_visible_output"
_CLEANUP_POLICY_UNKNOWN = "unknown"
_VALID_CLEANUP_POLICIES = (
    _CLEANUP_POLICY_CLEANUP_ONLY,
    _CLEANUP_POLICY_PRESERVE_EVIDENCE,
    _CLEANUP_POLICY_PROTECTED_EVIDENCE,
    _CLEANUP_POLICY_USER_VISIBLE_OUTPUT,
    _CLEANUP_POLICY_UNKNOWN,
)


def _workspace_artifacts_path(state: Dict[str, Any]) -> Path:
    """workspace_artifacts.json 경로를 반환한다 (state 파일과 동일 디렉토리에 co-locate).

    PIPELINE_STATE_PATH가 설정된 경우(테스트 격리) state 파일 부모 디렉토리에,
    그렇지 않으면 .pipeline/runs/<pipeline_id>/ 아래에 둔다. legacy pipeline_state.json은
    절대 쓰기 대상이 되지 않는다.

    Args:
        state: 현재 파이프라인 state dict. state["pipeline_id"]가 경로 결정에 사용됨.
    Returns:
        Path: workspace_artifacts.json 경로 (디렉토리를 생성하지 않음).
    Raises:
        TypeError: state가 None이거나 dict가 아닌 경우.
        ValueError: pipeline_id가 비어 있는 경우.
    """
    if state is None:
        raise TypeError("state must not be None")
    if not isinstance(state, dict):
        raise TypeError(f"state must be dict, got {type(state).__name__}")
    pipeline_id = state.get("pipeline_id")
    if not pipeline_id or not isinstance(pipeline_id, str):
        raise ValueError("state must contain a non-empty str 'pipeline_id'")
    state_path = _resolve_state_path_for_write(pipeline_id)
    return state_path.parent / "workspace_artifacts.json"


def _load_workspace_artifacts(state: Dict[str, Any]) -> List[Dict[str, Any]]:
    """state["pipeline_id"] 기반으로 workspace_artifacts.json을 로드한다.

    파일이 없거나 손상된 경우 빈 목록을 반환한다 (best-effort, 4-encoding fallback).

    Args:
        state: 현재 파이프라인 state dict.
    Returns:
        List[Dict[str, Any]]: 등록된 artifact 레코드 목록. 없으면 빈 목록.
    Raises:
        TypeError: state가 None이거나 dict가 아닌 경우.
        ValueError: pipeline_id가 비어 있는 경우.
    """
    path = _workspace_artifacts_path(state)
    if not path.exists():
        return []
    for enc in ("utf-8", "cp949", "latin-1"):
        try:
            data = json.loads(path.read_text(encoding=enc))
            break
        except (UnicodeDecodeError, LookupError, json.JSONDecodeError):
            continue
    else:
        # 어떤 인코딩으로도 파싱 불가: 손상된 매니페스트는 빈 목록으로 보수 처리.
        return []
    if isinstance(data, dict):
        items = data.get("artifacts")
        return items if isinstance(items, list) else []
    if isinstance(data, list):
        return data
    return []


def _save_workspace_artifacts(state: Dict[str, Any], artifacts: List[Dict[str, Any]]) -> None:
    """workspace_artifacts.json을 원자적으로 저장한다 (tempfile → os.replace).

    Args:
        state: 현재 파이프라인 state dict. pipeline_id가 쓰기 경로 결정에 사용됨.
        artifacts: 저장할 artifact 레코드 목록.
    Returns:
        None.
    Raises:
        TypeError: state가 None/dict가 아니거나 artifacts가 None/list가 아닌 경우.
        ValueError: pipeline_id가 비어 있는 경우.
    """
    if artifacts is None:
        raise TypeError("artifacts must not be None")
    if not isinstance(artifacts, list):
        raise TypeError(f"artifacts must be list, got {type(artifacts).__name__}")
    path = _workspace_artifacts_path(state)
    path.parent.mkdir(parents=True, exist_ok=True)
    payload = {
        "pipeline_id": state.get("pipeline_id"),
        "updated_at": _now(),
        "artifacts": artifacts,
    }
    tmp_path: Optional[Path] = None
    try:
        with tempfile.NamedTemporaryFile(
            mode="w", encoding="utf-8", dir=path.parent,
            delete=False, suffix=".tmp"
        ) as tmp:
            json.dump(payload, tmp, ensure_ascii=False, indent=2)
            tmp_path = Path(tmp.name)
        os.replace(str(tmp_path), str(path))
    except Exception:
        if tmp_path is not None and tmp_path.exists():
            tmp_path.unlink(missing_ok=True)
        raise


def _register_workspace_artifact(
    state: Dict[str, Any],
    path: str,
    cleanup_policy: str,
    description: str = "",
) -> None:
    """path와 cleanup_policy를 workspace_artifacts.json에 등록한다.

    동일 path가 이미 등록되어 있으면 cleanup_policy/description을 업데이트한다(중복 방지).
    cleanup_policy가 유효 enum이 아니면 'unknown'으로 강등하여 삭제 대상에서 제외한다.

    Args:
        state: 현재 파이프라인 state dict.
        path: 등록할 산출물 경로 문자열.
        cleanup_policy: cleanup_only|preserve_evidence|protected_evidence|
            user_visible_output|unknown 중 하나.
        description: 산출물 설명 (선택).
    Returns:
        None.
    Raises:
        TypeError: state/path/cleanup_policy/description가 None이거나 타입이 잘못된 경우.
        ValueError: path가 빈 문자열인 경우.
    """
    if state is None:
        raise TypeError("state must not be None")
    if not isinstance(state, dict):
        raise TypeError(f"state must be dict, got {type(state).__name__}")
    if path is None:
        raise TypeError("path must not be None")
    if not isinstance(path, str):
        raise TypeError(f"path must be str, got {type(path).__name__}")
    if len(path) == 0:
        raise ValueError("path must not be empty")
    if cleanup_policy is None:
        raise TypeError("cleanup_policy must not be None")
    if not isinstance(cleanup_policy, str):
        raise TypeError(
            f"cleanup_policy must be str, got {type(cleanup_policy).__name__}"
        )
    if description is None:
        raise TypeError("description must not be None")
    if not isinstance(description, str):
        raise TypeError(
            f"description must be str, got {type(description).__name__}"
        )
    # 유효하지 않은 정책은 보수적으로 unknown 강등 (삭제 대상에서 제외).
    policy = cleanup_policy if cleanup_policy in _VALID_CLEANUP_POLICIES else _CLEANUP_POLICY_UNKNOWN

    artifacts = _load_workspace_artifacts(state)
    norm_path = str(path).replace("\\", "/")
    updated = False
    for record in artifacts:
        if not isinstance(record, dict):
            continue
        if str(record.get("path", "")).replace("\\", "/") == norm_path:
            record["cleanup_policy"] = policy
            record["description"] = description
            record["registered_at"] = _now()
            updated = True
            break
    if not updated:
        artifacts.append({
            "path": path,
            "cleanup_policy": policy,
            "description": description,
            "registered_at": _now(),
        })
    _save_workspace_artifacts(state, artifacts)


def _log_event(state: Dict[str, Any], message: str) -> None:
    state["event_log"].append({"ts": _now(), "msg": message})


def _die(message: str, exit_code: int = 1) -> NoReturn:
    print(RED(f"\n[PIPELINE ERROR] {message}"), file=sys.stderr)
    sys.exit(exit_code)


# Aliases used by tournament commands (branch-aware variants use _load_state / _save_state)
_load_state = _load
_save_state = _save


def _openai_api_key() -> Tuple[Optional[str], str]:
    """Return the OpenAI API key without printing or persisting it.

    PowerShell's [Environment]::SetEnvironmentVariable(..., "User") updates the
    Windows user environment, but already-open shells do not inherit that value.
    Reading HKCU\\Environment lets pipeline.py work immediately after the user
    stores the key, without requiring a new terminal.
    """
    process_value = os.environ.get("OPENAI_API_KEY")
    if process_value:
        return process_value, "process"
    if os.name == "nt":
        try:
            import winreg  # type: ignore[import-not-found]

            with winreg.OpenKey(winreg.HKEY_CURRENT_USER, "Environment") as key:
                value, _ = winreg.QueryValueEx(key, "OPENAI_API_KEY")
            if isinstance(value, str) and value.strip():
                return value.strip(), "user"
        except OSError:
            pass
    return None, "missing"


def _openai_advisory_enabled() -> bool:
    """API advisory is opt-in because ChatGPT subscriptions do not include API quota.

    ``ENABLE_GPT_ADVISORY=1`` only means "API 호출 허용".
    Auto-execution + COMPLETE blocker는 ``_openai_advisory_required()`` 가 분리하여 담당합니다.
    """
    return os.environ.get("ENABLE_GPT_ADVISORY") == "1"


def _openai_advisory_required() -> bool:
    """``ENABLE_GPT_ADVISORY_REQUIRED=1`` 일 때만 자동 실행 + unresolved CRITICAL이 COMPLETE를 차단.

    기본 모드(REQUIRED 미설정)에서는 advisory가 수동 진단 도구이며 COMPLETE를 막지 않습니다.
    REQUIRED=1이면 ENABLE_GPT_ADVISORY=1로 간주(API 호출 허용)되므로 별도 flag 없이 자동 실행 가능합니다.
    """
    return os.environ.get("ENABLE_GPT_ADVISORY_REQUIRED") == "1"


def _advisory_run_counts(pid: str) -> Tuple[int, int]:
    """Returns (review_count, api_call_count) for the given pipeline's advisory directory."""
    paths = _contract_paths(pid)
    advisory_root = paths["advisory_root"]
    review_count = 0
    api_call_count = 0
    if advisory_root.exists():
        for rp in sorted(advisory_root.glob("*_review.json")):
            data = _load_json_file(rp, {})
            review_count += 1
            if bool(data.get("api_called", str(data.get("status")) == "COMPLETED")):
                api_call_count += 1
    return review_count, api_call_count


def _require_state() -> Dict[str, Any]:
    state = _load()
    if state is None:
        _die("활성 파이프라인 없음. 먼저 `python pipeline.py new` 를 실행하세요.")
    return state  # type: ignore[return-value]


def _load_branch_state(args: argparse.Namespace, die_msg: str = "state 파일이 없습니다.") -> Dict[str, Any]:
    """branch 인자가 있으면 브랜치 state, 없으면 메인 state 반환."""
    branch: Optional[str] = getattr(args, "branch", None)
    if branch is not None:
        state = _load_state_for(branch)
        if not state:
            _die(f"Branch '{branch}' {die_msg}")
        return state
    return _require_state()


def _record_snapshot(state: Dict[str, Any], phase: str, branch: Optional[str]) -> None:
    """branch 없을 때만 phase 스냅샷 저장 후 snapshot_path 기록."""
    if branch is None:
        snap = _save_phase_snapshot(state, phase)
        if snap:
            state["phases"][phase]["snapshot_path"] = snap


def _contract_paths(pipeline_id: str) -> Dict[str, Path]:
    if not pipeline_id or ".." in pipeline_id or "/" in pipeline_id or "\\" in pipeline_id:
        _die(f"invalid pipeline_id for contract path: {pipeline_id!r}", exit_code=2)
    root = CONTRACTS_DIR / pipeline_id
    return {
        "root": root,
        "contract": root / "task_contract.json",
        "test_set": root / "test_set.json",
        "summary": root / "acceptance_summary.md",
        "result": root / "acceptance_result.json",
        "oracle_manifest": root / "oracle_manifest.json",
        "contract_audit": root / "contract_audit.json",
        "evidence_inventory": root / "evidence_inventory.json",
        "gates_root": root / "gates",
        "technical_result": root / "gates" / "technical_result.json",
        "oracle_result": root / "gates" / "oracle_result.json",
        "user_validation": root / "gates" / "user_validation.json",
        "github_ci_result": root / "gates" / "github_ci_result.json",
        "phase_ci_root": root / "gates" / "phase_ci",
        "failures_root": root / "failures",
        "outputs_manifest": OUTPUTS_ROOT / pipeline_id / "outputs_manifest.json",
        "advisory_root": root / "advisory",
        "advisory_resolutions": root / "advisory" / "resolutions.json",
    }


# IMP-20260613-82ED MT-1: Evidence Inventory / Provenance Gate 헬퍼
# [Purpose]: oracle 증거 파일(input/expected)을 evidence_inventory.json(SSoT, list 형식)에
#            등록하고, 등록된 protected 증거가 git tracked + 현재 PR에 포함되도록 강제하여
#            로컬에만 존재하는 untracked 증거로 외부 게이트를 통과시키는 우회 경로를 차단한다.
# [Assumptions]: BASE_DIR가 git 작업 트리 루트이며, gh/git CLI가 설치/인증되어 있다.
#                inventory는 pipeline_contracts/<pid>/evidence_inventory.json 에 list로 누적된다.
# [Vulnerability & Risks]: gh/git CLI 부재 시 fail-closed로 BLOCKED 처리하므로 오탐 가능.
#                inventory JSON이 손상되면 BLOCKED로 처리하여 게이트 통과를 막는다(의도적).
# [Improvement]: PR diff를 한 번만 조회하여 캐시하면 다수 evidence 검증 시 gh 호출을 줄인다.


def _is_cleanup_only_artifact(file_name: str) -> bool:
    """파일명이 HYGIENE_ARCHIVE_PATTERNS(cleanup-only) 글로브에 매칭되는지 확인한다.

    Args:
        file_name: 검사할 파일 이름(경로 제외). None 금지.
    Returns:
        cleanup-only 패턴에 매칭되면 True.
    Raises:
        TypeError: file_name이 None이거나 str이 아닌 경우.
    """
    if file_name is None:
        raise TypeError("file_name must not be None")
    if not isinstance(file_name, str):
        raise TypeError(f"file_name must be str, got {type(file_name).__name__}")
    for pattern in HYGIENE_ARCHIVE_PATTERNS:
        if fnmatch.fnmatch(file_name, pattern):
            return True
    return False


def _register_evidence_to_inventory(
    pipeline_id: str,
    evidence_path: "Path",
    kind: str,
    source_command: str = "contract add-oracle",
    required_for_acceptance: bool = True,
    protection: str = "protected",
) -> None:
    """증거 파일을 pipeline별 evidence inventory(list)에 등록한다(동일 경로는 덮어쓰기).

    Args:
        pipeline_id: 현재 파이프라인 ID.
        evidence_path: 등록할 증거 파일 경로(Path).
        kind: 증거 종류 문자열(예: "oracle_input", "oracle_expected").
        source_command: 증거를 등록한 명령(추적용).
        required_for_acceptance: 승인 게이트에 필수인지 여부.
        protection: 보호 등급("protected" 등).
    Returns:
        없음. evidence_inventory.json(list) 파일을 갱신한다.
    Raises:
        TypeError: pipeline_id/evidence_path/kind가 None이거나 타입이 잘못된 경우.
    """
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(f"pipeline_id must be str, got {type(pipeline_id).__name__}")
    if evidence_path is None:
        raise TypeError("evidence_path must not be None")
    if not isinstance(evidence_path, Path):
        raise TypeError(f"evidence_path must be Path, got {type(evidence_path).__name__}")
    if kind is None:
        raise TypeError("kind must not be None")
    if not isinstance(kind, str):
        raise TypeError(f"kind must be str, got {type(kind).__name__}")

    inventory_path = _contract_paths(pipeline_id)["evidence_inventory"]
    # inventory는 list 형식 — 파일 없거나 손상 시 빈 리스트로 초기화
    inventory: List[Dict[str, Any]] = []
    if inventory_path.exists():
        try:
            loaded = json.loads(inventory_path.read_text(encoding="utf-8-sig"))
            if isinstance(loaded, list):
                inventory = [e for e in loaded if isinstance(e, dict)]
        except (OSError, json.JSONDecodeError):
            inventory = []

    key = str(evidence_path)
    # sha256/size 계산 (파일이 존재할 때만)
    sha256_val = ""
    size_val = 0
    try:
        if evidence_path.exists():
            sha256_val = _sha256_file(evidence_path)
            size_val = evidence_path.stat().st_size
    except OSError:
        sha256_val = ""
        size_val = 0

    entry = {
        "pipeline_id": pipeline_id,
        "path": key,
        "kind": kind,
        "sha256": sha256_val,
        "size": size_val,
        "source_command": source_command,
        "registered_at": _now(),
        "required_for_acceptance": bool(required_for_acceptance),
        "protection": protection,
    }
    # 동일 경로 항목 제거 후 추가(dedupe)
    inventory = [e for e in inventory if str(e.get("path", "")) != key]
    inventory.append(entry)
    _write_json_value(inventory_path, inventory)


# IMP-20260614-2821 MT-1: COMPLETE 직전 workspace/evidence hygiene gate
# [Purpose]: gates request-accept / gates accept 전에 oracle/evidence 파일의 git 추적 상태를
#            검사하여, untracked oracle(로컬에만 존재하는 증거)로 승인 코드를 발급/소모하는
#            우회 경로를 차단한다. cleanup_only 임시 파일(build_report.xml 등)은 WARN으로만
#            분류하여 차단하지 않는다.
# [Assumptions]: BASE_DIR가 git 작업 트리 루트이며 git CLI가 설치되어 있다.
#                oracle 증거는 tests/oracles/<pipeline_id>/ 아래 + evidence_inventory.json/
#                oracle_manifest.json 에 등록된다.
# [Vulnerability & Risks]: git CLI 부재 시 protected path 판정 불가 → fail-closed BLOCKED로
#                오탐 가능(의도적). cleanup_only 보조 패턴은 _is_cleanup_only_artifact 외에
#                PM이 명시한 *_dump.txt / .pytest_tmp_* / .claude/worktrees/ 를 추가 매칭한다.
# [Improvement]: PR diff/inventory를 1회만 조회해 캐시하면 다수 파일 검증 시 git 호출을 줄인다.


# IMP-20260614-2821 MT-1: PM이 명시한 추가 cleanup_only 패턴(_is_cleanup_only_artifact 보조).
# HYGIENE_ARCHIVE_PATTERNS에 없지만 cleanup-only로 취급해야 하는 진단/임시 산출물 패턴.
#
# IMP-20260622-79BA MT-3 (Scratch Redirect 정책 SSoT):
#   아래 패턴들(oracle_result_dump.txt, *_dump.txt, tmp_tc*.json 등)은 과거 repo root에
#   흘러 working tree를 오염시키던 진단/임시 dump다. scratch_hygiene_audit.md 전수 조사 결과
#   pipeline.py 프로덕션 코드에는 이들을 repo root에 직접 쓰는 내부 생산자가 없으며(잔재는
#   QA/oracle 수동 dump 및 테스트 fixture 산출물), 따라서 기존 함수 본문을 바꾸지 않는다
#   (Frozen Codebase). 향후 임시/진단 dump가 필요한 내부 생산자는 repo root 대신 반드시
#   _scratch_file(pipeline_id, name) / _scratch_path(pipeline_id, *parts) 를 사용해
#   .pipeline/runs/<id>/scratch/ 격리 경로에 써야 한다. 이 목록은 이미 흘러나온 잔재를
#   cleanup_only(차단 제외, 정리 대상)로 분류하기 위한 안전망이다.
_WORKSPACE_HYGIENE_EXTRA_CLEANUP_PATTERNS: List[str] = [
    "oracle_result_dump.txt",
    "*_dump.txt",
    "tmp_tc*.json",
    ".pytest_tmp_*",
]
# 경로 접두사 기반 cleanup_only 판정(파일명만으로 매칭 불가한 디렉터리 산출물).
_WORKSPACE_HYGIENE_CLEANUP_PREFIXES: Tuple[str, ...] = (
    ".claude/worktrees/",
    ".pytest_tmp_",
)


def _is_workspace_cleanup_only(rel_path: str) -> bool:
    """rel_path(저장소 루트 기준)가 cleanup_only(차단 제외) 산출물인지 판정한다.

    판정 순서:
      1. 경로 접두사(.claude/worktrees/ 등) 매칭 → cleanup_only
      2. 파일명이 HYGIENE_ARCHIVE_PATTERNS 매칭 (_is_cleanup_only_artifact SSoT)
      3. 파일명이 PM 명시 추가 패턴(_WORKSPACE_HYGIENE_EXTRA_CLEANUP_PATTERNS) 매칭

    Args:
        rel_path: 저장소 루트 기준 상대 경로(슬래시 정규화 권장). None 금지.
    Returns:
        cleanup_only(차단 제외) 산출물이면 True.
    Raises:
        TypeError: rel_path가 None이거나 str이 아닌 경우.
    """
    if rel_path is None:
        raise TypeError("rel_path must not be None")
    if not isinstance(rel_path, str):
        raise TypeError(f"rel_path must be str, got {type(rel_path).__name__}")

    # IMP-20260622-79BA MT-5: lstrip("./")는 선행 점(.)까지 제거해 dotfile 접두사
    #   (.pytest_tmp_*, .claude/worktrees/)를 깨뜨렸다(.pytest_tmp_abc/x → pytest_tmp_abc/x).
    #   선행 "./"만 정확히 제거하도록 교체하여 dot 디렉터리 접두사 분류를 정상화한다.
    norm = rel_path.replace("\\", "/")
    while norm.startswith("./"):
        norm = norm[2:]
    for prefix in _WORKSPACE_HYGIENE_CLEANUP_PREFIXES:
        if norm.startswith(prefix) or Path(norm).name.startswith(prefix):
            return True
    name = Path(norm).name
    # SSoT: HYGIENE_ARCHIVE_PATTERNS (build_report.xml, tmp*.json, pr_body_*.txt, comment_*.txt 등)
    if _is_cleanup_only_artifact(name):
        return True
    for pattern in _WORKSPACE_HYGIENE_EXTRA_CLEANUP_PATTERNS:
        if fnmatch.fnmatch(name, pattern):
            return True
    return False


def _check_workspace_hygiene(state: Dict[str, Any]) -> Dict[str, Any]:
    """gates request-accept / gates accept 전 workspace/evidence hygiene 검사(fail-closed).

    검사 규칙:
      1. tests/oracles/<pipeline_id>/ 아래 파일이 untracked → BLOCKED(untracked_oracle_evidence)
      2. oracle_manifest 참조 input/expected 파일 missing → BLOCKED(protected_evidence_missing)
      3. oracle_manifest 참조 파일이 git tracked 아님 → BLOCKED(protected_evidence_untracked)
      4. evidence_inventory protected 파일 SHA mismatch → BLOCKED(protected_evidence_sha_mismatch)
      5. git 조회 실패가 protected 판정에 영향 → BLOCKED(workspace_hygiene_check_failed, fail-closed)
      6. cleanup_only 파일만 있으면 WARN(차단 아님)
      7. 모두 OK이면 OK

    cleanup_only 파일(build_report.xml, *_dump.txt, .claude/worktrees/ 등)은 차단하지 않고
    cleanup_only_items로 분류한다.

    Args:
        state: pipeline_id를 포함한 pipeline state dict(최소 {"pipeline_id": ...}). None 금지.
    Returns:
        Dict: status("BLOCKED"|"WARN"|"OK"), blocking_items(list[dict]),
              cleanup_only_items(list[str]), protected_evidence_count(int),
              tracked_oracle_count(int), untracked_oracle_count(int),
              pr_included_protected_count(int), cleanup_command(str), checked_at(str).
    Raises:
        TypeError: state가 None이거나 dict가 아닌 경우.
    """
    if state is None:
        raise TypeError("state must not be None")
    if not isinstance(state, dict):
        raise TypeError(f"state must be dict, got {type(state).__name__}")

    pipeline_id = str(state.get("pipeline_id", "") or "")

    result: Dict[str, Any] = {
        "status": "OK",
        "blocking_items": [],
        "cleanup_only_items": [],
        "protected_evidence_count": 0,
        "tracked_oracle_count": 0,
        "untracked_oracle_count": 0,
        "pr_included_protected_count": 0,
        "cleanup_command": "Remove-Item <파일>",
        "checked_at": _now(),
    }

    def _add_blocker(failure_code: str, message: str, path_item: str = "") -> None:
        result["status"] = "BLOCKED"
        result["blocking_items"].append(
            f"failure_code={failure_code}: {message}"
            + (f" ({path_item})" if path_item else "")
        )

    if not pipeline_id:
        _add_blocker(
            "workspace_hygiene_check_failed",
            "state에 pipeline_id가 없어 workspace hygiene을 확인할 수 없습니다(fail-closed).",
        )
        return result

    # 규칙 5: git 조회 결과를 3-상태로 구분한다.
    #   - git_binary_missing: git 실행파일 자체가 없음(PATH에 git 없음). 환경 한계이며
    #     evidence 변조 신호가 아니다. 실 운영 request-accept는 항상 git이 존재하므로,
    #     이 경우는 graceful skip(검사 불가 → 차단하지 않음)으로 처리한다.
    #   - git_query_errored: git이 실행됐으나 비정상 종료(returncode != 0). 실제 조회 실패이며
    #     protected 판정에 영향을 주므로 fail-closed BLOCKED.
    #   - 정상: untracked 목록 확보.
    untracked_set: set = set()
    git_binary_missing = False
    git_query_errored = False
    try:
        _others = subprocess.run(
            ["git", "ls-files", "--others", "--exclude-standard"],
            capture_output=True, text=True, encoding="utf-8", check=False,
            cwd=str(BASE_DIR),
        )
    except FileNotFoundError:
        git_binary_missing = True
    except OSError:
        git_query_errored = True
    else:
        if _others.returncode != 0:
            git_query_errored = True
        else:
            # IMP-20260614-2821 수정 7(rev2): `git ls-files --others`는 읽을 수 없는 임시/정크
            # 디렉터리(.pytest_tmp_* 등)에 대해 stderr에 "Permission denied" 경고를 내면서도
            # returncode 0과 함께 읽을 수 있는 untracked 파일 목록은 완전하게 반환한다. 이런
            # 정크 디렉터리 경고만으로 전체 hygiene을 fail-closed하면 정상 oracle 추적 판정까지
            # 막혀 정합성이 깨진다(TC-1/TC-5 회귀). 실제 evidence 변조 신호인 "특정 oracle/
            # protected 파일의 추적 상태를 확인 불가"한 케이스는 아래 _is_tracked()의 per-file
            # Permission denied fail-closed가 담당한다(REJECT 사유 4).
            for line in (_others.stdout or "").splitlines():
                p = line.strip().replace("\\", "/").lstrip("./")
                if p:
                    untracked_set.add(p)
    # IMP-20260614-2821 수정 8: git 실행파일 부재는 graceful skip 으로 처리한다(early-return 제거).
    #   - git_binary_missing 은 "git 자체가 PATH에 없는 환경 한계"이며 evidence 변조 신호가 아니다.
    #     실 운영 request-accept/accept 환경에는 항상 git이 존재하므로 이 분기는 발생하지 않는다.
    #   - 격리 E2E(AEF0/8C3B/CE06 등)는 실제 gh 탐색 무력화를 위해 PATH=tmp_path로 제한하며,
    #     그 부작용으로 subprocess.run(["git", ...])가 FileNotFoundError → git_binary_missing=True 가
    #     된다. 이 pid들은 모두 tests/oracles/<pid>/ 디렉터리를 보유하므로, 여기서 fail-closed
    #     early-return 하면 request-accept/accept 전 흐름이 무조건 BLOCKED 되어 회귀가 발생한다.
    #   - 실제 evidence 변조 신호인 "git이 실행됐으나 비정상 종료(git_query_errored)" 와
    #     "per-file Permission denied(_is_tracked 'ERROR')"는 아래 다운스트림에서 그대로 fail-closed
    #     로 차단된다(TC-10 / REJECT 사유 4). 따라서 보안 권위를 잃지 않는다.
    #   - 아래 _is_untracked()/_is_tracked()/_check_file_in_pr_or_base()는 git_binary_missing 을 보고
    #     None(graceful skip) 을 반환하므로, early-return 없이 자연스럽게 untracked 검사만 건너뛴다.
    if git_binary_missing:
        # IMP-20260614-2821 REJECT 재작업: git 부재 시 기본(production) 동작을 fail-closed로 변경.
        #   git 없이는 untracked 여부·PR/base 포함 여부를 판정할 수 없으므로, graceful skip은
        #   승인 코드가 무방비로 발급될 위험을 만든다(REJECT 사유). 따라서 기본은 BLOCKED.
        #   격리 E2E처럼 PATH=tmp_path로 git이 의도적으로 제거된 테스트 환경에서만
        #   PIPELINE_WORKSPACE_HYGIENE_ALLOW_GIT_MISSING=1 override로 graceful skip을 허용한다.
        allow_git_missing = os.environ.get("PIPELINE_WORKSPACE_HYGIENE_ALLOW_GIT_MISSING") == "1"
        if not allow_git_missing:
            _add_blocker(
                "workspace_hygiene_check_failed",
                "git executable not found — cannot determine protected file tracking status "
                "(set PIPELINE_WORKSPACE_HYGIENE_ALLOW_GIT_MISSING=1 to allow in test environments)",
            )
            return result
        else:
            # 테스트 환경 override: git 없을 때 graceful skip
            result["git_unavailable"] = True
            return result

    def _is_untracked(rel_path: str) -> Optional[bool]:
        """rel_path가 untracked인지 반환.

        반환값:
          - True/False: 판정 성공.
          - None: git 실행파일 부재(graceful skip 대상).
          - "ERROR": git 조회 비정상 종료(fail-closed 대상).
        """
        if git_binary_missing:
            return None
        if git_query_errored:
            return "ERROR"  # type: ignore[return-value]
        return rel_path.replace("\\", "/").lstrip("./") in untracked_set

    def _is_tracked(abs_or_rel_path: str) -> Optional[bool]:
        """git ls-files --error-unmatch 로 tracked 여부 반환.

        반환값:
          - True/False: 판정 성공.
          - None: git 실행파일 부재(graceful skip 대상).
          - "ERROR": git 조회 비정상 종료(fail-closed 대상).
        """
        if git_binary_missing:
            return None
        try:
            _ls = subprocess.run(
                ["git", "ls-files", "--error-unmatch", abs_or_rel_path],
                capture_output=True, text=True, encoding="utf-8", check=False,
                cwd=str(BASE_DIR),
            )
        except FileNotFoundError:
            return None
        except OSError:
            return "ERROR"  # type: ignore[return-value]
        if "Permission denied" in (_ls.stderr or ""):
            # stderr에 Permission denied가 있으면 fail-closed (IMP-20260614-2821 수정 7: REJECT 사유 4).
            return "ERROR"  # type: ignore[return-value]
        return _ls.returncode == 0

    def _check_file_in_pr_or_base(rel_path_str: str) -> bool:
        """파일이 PR changed files 또는 base/main에 실제로 존재하는지 확인한다(IMP-20260614-2821 수정 4).

        Returns:
            True: OK (base/main에 이미 있거나 PR diff에 포함됨).
            False: BLOCKED 조건 (git 오류, gh 오류/부재, 또는 어느 쪽에도 없음 → 카운트 증가 안 함).
        """
        # git 부재는 이미 위에서 fail-closed로 처리되어 이 지점에 도달하지 않는다.
        # 1. git ls-files --error-unmatch 로 tracked 확인.
        try:
            _ls = subprocess.run(
                ["git", "ls-files", "--error-unmatch", rel_path_str],
                capture_output=True, text=True, encoding="utf-8", check=False,
                cwd=str(BASE_DIR),
            )
        except (FileNotFoundError, OSError):
            return False
        if _ls.returncode != 0:
            return False  # tracked 아님 → 카운트 증가 안 함

        # 2. git show origin/main:<path> 로 base/main에 이미 존재하는지 확인.
        try:
            _show = subprocess.run(
                ["git", "show", f"origin/main:{rel_path_str}"],
                capture_output=True, text=True, encoding="utf-8", check=False,
                cwd=str(BASE_DIR),
            )
        except (FileNotFoundError, OSError):
            _show = None
        if _show is not None and _show.returncode == 0:
            return True  # base/main에 이미 있음 → OK

        # 3. gh pr view 로 PR changed files 확인.
        try:
            _gh = subprocess.run(
                ["gh", "pr", "view", "--json", "files"],
                capture_output=True, text=True, encoding="utf-8", check=False,
                cwd=str(BASE_DIR),
            )
        except (FileNotFoundError, OSError):
            return False  # gh CLI 부재 → fail-closed(카운트 증가 안 함)
        if _gh.returncode != 0:
            return False  # gh 실패 → fail-closed
        try:
            _pr_data = json.loads(_gh.stdout)
            _pr_files = {f.get("path", "") for f in (_pr_data.get("files") or [])}
        except (json.JSONDecodeError, AttributeError):
            return False
        _norm_rel = rel_path_str.replace("\\", "/").lstrip("./")
        return _norm_rel in {p.replace("\\", "/").lstrip("./") for p in _pr_files}

    # 기존 게이트와의 정합성(IMP-20260614-2821): contract oracle_manifest.json이 존재하면
    # "untracked" 판정의 차단 권위는 기존 _check_oracle_manifest_vs_inventory +
    # _validate_evidence_provenance 게이트가 가진다(request-accept에서 hygiene 이후 실행).
    # 이 경우 hygiene은 untracked 차단(규칙 1/3)만 위임(defer)하고, 파일 missing(규칙 2)과
    # inventory SHA mismatch(규칙 4)는 그대로 차단한다(기존 게이트와 중복되지 않는 영역).
    # contract manifest가 없을 때는 hygiene이 tests/oracles/<pid>/ untracked를 직접 차단한다.
    _paths_for_defer = _contract_paths(pipeline_id)
    defer_untracked_to_existing_gate = _paths_for_defer["oracle_manifest"].exists()

    # ---- 규칙 1: tests/oracles/<pipeline_id>/ 아래 파일의 untracked 여부 ----
    oracle_dir = BASE_DIR / "tests" / "oracles" / pipeline_id
    if oracle_dir.exists():
        for fpath in sorted(oracle_dir.rglob("*")):
            if not fpath.is_file():
                continue
            try:
                rel = fpath.resolve().relative_to(BASE_DIR.resolve()).as_posix()
            except (ValueError, OSError):
                rel = str(fpath).replace("\\", "/")
            # cleanup_only 산출물은 oracle 디렉터리 아래에 있어도 차단 대상이 아님.
            if _is_workspace_cleanup_only(rel):
                if rel not in result["cleanup_only_items"]:
                    result["cleanup_only_items"].append(rel)
                continue
            # contract manifest 존재 시 untracked 차단은 기존 게이트에 위임 — 차단 안 함.
            if defer_untracked_to_existing_gate:
                continue
            result["protected_evidence_count"] += 1
            untracked = _is_untracked(rel)
            if untracked is None:
                # git 실행파일 부재 → graceful skip(차단하지 않음). 실 운영에서는 git 존재.
                continue
            if untracked == "ERROR":
                _add_blocker(
                    "workspace_hygiene_check_failed",
                    "git untracked 목록 조회가 비정상 종료되어 oracle 추적 상태를 확인할 수 없습니다(fail-closed).",
                    rel,
                )
                result["untracked_oracle_count"] += 1
                continue
            if untracked:
                _add_blocker(
                    "untracked_oracle_evidence",
                    "oracle 증거가 git에 추적되지 않습니다(untracked). "
                    f"`git add tests/oracles/{pipeline_id}/` 후 다시 실행하세요.",
                    rel,
                )
                result["untracked_oracle_count"] += 1
            else:
                result["tracked_oracle_count"] += 1

    # ---- IMP-20260614-2821 수정 2: 루트 workspace cleanup_only 파일 스캔 ----
    # 루트 디렉터리에 남아있는 임시 산출물(build_report.xml, *_dump.txt, tmp_tc*.json 등)을
    # cleanup_only_items로 분류한다. 차단하지 않고 WARN 표시만 한다(REJECT 사유 2).
    #
    # BUG-20260628-F52C: 이 스캔은 공유 저장소 루트(BASE_DIR)를 읽으므로 cleanup_only_items가
    #   "스캔 시점의 루트 임시 파일 상태"에 의존한다(WARN-only, 차단 아님). codex-review와
    #   request-accept가 별도 subprocess로 실행되는 동안 다른 동시 테스트가 루트에 tmp*.json /
    #   *_dump.txt 등을 만들거나 지우면, 두 스캔의 cleanup_only_items가 달라지고 → packet 내용/
    #   SHA가 달라져 staged-vs-recorded packet SHA 불변식이 깨진다(codex_review_not_approved 오발동).
    #   격리 E2E 환경에서만 PIPELINE_WORKSPACE_HYGIENE_SKIP_ROOT_CLEANUP=1로 이 비결정적
    #   WARN-only 스캔을 건너뛰어 두 subprocess가 동일한 cleanup_only_items(빈 목록)를 본다.
    #   차단 규칙(1~5: untracked oracle / protected evidence / git fail-closed)은 영향받지 않는다.
    #   실 운영(env 미설정)에서는 기존 동작 그대로 루트 cleanup 스캔을 수행한다.
    _skip_root_cleanup = (
        os.environ.get("PIPELINE_WORKSPACE_HYGIENE_SKIP_ROOT_CLEANUP") == "1"
    )
    if not _skip_root_cleanup:
        _ROOT_CLEANUP_PATTERNS: List[str] = [
            "build_report.xml",
            "oracle_result_dump.txt",
            "pr_body_current.txt",
            "pr_body_new.txt",
            "*_dump.txt",
            "tc*_dump.txt",
            "ts*_dump.txt",
            ".pytest_tmp_*",
            "tmp*.json",
            "tmp_tc*.json",
            "tmp_tc*_given.json",
            "tmp_tc*_when.json",
            "tmp_tc*_then.json",
        ]
        for _root_pattern in _ROOT_CLEANUP_PATTERNS:
            for _root_match in BASE_DIR.glob(_root_pattern):
                if not _root_match.is_file():
                    continue
                try:
                    _root_rel = _root_match.resolve().relative_to(BASE_DIR.resolve()).as_posix()
                except (ValueError, OSError):
                    _root_rel = str(_root_match).replace("\\", "/")
                if _root_rel not in result["cleanup_only_items"]:
                    result["cleanup_only_items"].append(_root_rel)
        # .claude/worktrees/ 디렉터리 존재 여부 확인(디렉터리 산출물).
        _worktrees_dir = BASE_DIR / ".claude" / "worktrees"
        if _worktrees_dir.exists() and _worktrees_dir.is_dir():
            _wt_rel = ".claude/worktrees"
            if _wt_rel not in result["cleanup_only_items"]:
                result["cleanup_only_items"].append(_wt_rel)
        # .pytest_tmp_* 디렉터리 (IMP-20260614-2821 수정 6: REJECT 사유 3).
        # 루트 glob 스캔은 not is_file()로 디렉터리를 스킵하므로, 디렉터리 형태의
        # .pytest_tmp_* 산출물을 별도로 cleanup_only_items에 분류한다(차단 아님, WARN).
        for _pt_dir in BASE_DIR.glob(".pytest_tmp_*"):
            if _pt_dir.is_dir():
                _pt_rel = _pt_dir.relative_to(BASE_DIR).as_posix()
                if _pt_rel not in result["cleanup_only_items"]:
                    result["cleanup_only_items"].append(_pt_rel)

    # ---- 규칙 2/3/4: oracle_manifest 참조 파일 검사 ----
    # contract manifest 존재 시: oracle 차단은 기존 게이트(_check_oracle_manifest_vs_inventory +
    # _validate_evidence_provenance)에 위임하고 hygiene은 차단하지 않는다(중복 방지).
    paths = _contract_paths(pipeline_id)
    oracle_manifest_path = paths["oracle_manifest"]
    inventory_path = paths["evidence_inventory"]

    # inventory sha256 lookup (규칙 4용) — 절대 경로 기준.
    inventory_sha_by_abs: Dict[str, str] = {}
    if inventory_path.exists():
        try:
            _inv = json.loads(inventory_path.read_text(encoding="utf-8-sig"))
            if isinstance(_inv, list):
                for e in _inv:
                    if not isinstance(e, dict):
                        continue
                    if str(e.get("pipeline_id", "")) != pipeline_id:
                        continue
                    raw = str(e.get("path", "") or "")
                    if not raw:
                        continue
                    inv_p: Path = Path(raw)
                    if not inv_p.is_absolute():
                        inv_p = BASE_DIR / inv_p
                    try:
                        key = str(inv_p.resolve())
                    except (OSError, ValueError):
                        key = str(inv_p)
                    inventory_sha_by_abs[key] = str(e.get("sha256", "") or "")
        except (OSError, json.JSONDecodeError):
            inventory_sha_by_abs = {}

    if oracle_manifest_path.exists():
        try:
            _manifest = json.loads(oracle_manifest_path.read_text(encoding="utf-8-sig"))
        except (OSError, json.JSONDecodeError):
            _manifest = {}
        oracles = _manifest.get("oracles", []) if isinstance(_manifest, dict) else []
        manifest_refs: List[str] = []
        if isinstance(oracles, list):
            for oc in oracles:
                if not isinstance(oc, dict):
                    continue
                for key in ("input_path", "expected_path"):
                    raw = str(oc.get(key, "") or "")
                    if raw:
                        manifest_refs.append(raw)

        for raw in manifest_refs:
            ref_p: Path = Path(raw)
            if not ref_p.is_absolute():
                ref_p = BASE_DIR / ref_p
            try:
                abs_str = str(ref_p.resolve())
            except (OSError, ValueError):
                abs_str = str(ref_p)
            try:
                rel = ref_p.resolve().relative_to(BASE_DIR.resolve()).as_posix()
            except (ValueError, OSError):
                rel = str(ref_p).replace("\\", "/")

            if _is_workspace_cleanup_only(rel):
                if rel not in result["cleanup_only_items"]:
                    result["cleanup_only_items"].append(rel)
                continue

            # 규칙 2: 파일 missing
            if not ref_p.exists():
                _add_blocker(
                    "protected_evidence_missing",
                    "oracle_manifest가 참조하는 증거 파일이 존재하지 않습니다. 재생성 후 git add 하세요.",
                    rel,
                )
                continue

            # 규칙 3: tracked 여부 (contract manifest 존재 시 untracked 차단은 기존 게이트에 위임)
            if not defer_untracked_to_existing_gate:
                tracked = _is_tracked(abs_str)
                if tracked is None:
                    # git 실행파일 부재 → graceful skip(차단하지 않음).
                    pass
                elif tracked == "ERROR":
                    _add_blocker(
                        "workspace_hygiene_check_failed",
                        "git 조회가 비정상 종료되어 oracle_manifest 참조 파일의 추적 상태를 확인할 수 없습니다(fail-closed).",
                        rel,
                    )
                    continue
                elif not tracked:
                    _add_blocker(
                        "protected_evidence_untracked",
                        "oracle_manifest가 참조하는 증거 파일이 git에 추적되지 않습니다(untracked). "
                        "해당 파일을 git add/commit 한 뒤 다시 실행하세요.",
                        rel,
                    )
                    continue

            # 규칙 4: SHA mismatch (inventory에 등록된 sha256과 현재 파일 내용 비교)
            inv_sha = inventory_sha_by_abs.get(abs_str, "")
            if inv_sha:
                try:
                    cur_sha = _sha256_file(ref_p)
                except (OSError, IOError):
                    _add_blocker(
                        "workspace_hygiene_check_failed",
                        "증거 파일 SHA256 계산 중 읽기 오류가 발생했습니다(fail-closed).",
                        rel,
                    )
                    continue
                if cur_sha != inv_sha:
                    _add_blocker(
                        "protected_evidence_sha_mismatch",
                        "evidence_inventory의 sha256과 현재 파일 내용이 다릅니다. "
                        f"expected={inv_sha[:16]}..., actual={cur_sha[:16]}...",
                        rel,
                    )
                    continue
            # IMP-20260614-2821 수정 4(rev2): PR diff 또는 base/main 포함 여부를 실제 검증한다
            # (REJECT 사유 3/1). 파일이 존재하고 SHA가 일치한 protected 파일이 PR changed files
            # 에도 없고 base/main에도 없으면, 로컬에만 staged된 증거로 승인 코드를 발급하는
            # 우회 경로이므로 fail-closed BLOCKED 처리한다.
            #
            # 단, untracked 파일은 이 blocker로 차단하지 않는다. deferral 모드(contract
            # oracle_manifest 존재)에서 untracked oracle 차단 권위는 기존 게이트
            # (_check_oracle_manifest_vs_inventory + _validate_evidence_provenance)에 있고,
            # non-deferral 모드에서는 위 규칙 3가 protected_evidence_untracked로 이미 차단한다.
            # 따라서 이 blocker는 "tracked인데 PR/base 어디에도 없음"인 경우에만 적용한다.
            if _check_file_in_pr_or_base(rel):
                result["pr_included_protected_count"] += 1
            else:
                _tracked_for_pr = _is_tracked(abs_str)
                if _tracked_for_pr is True:
                    _add_blocker(
                        "protected_evidence_not_in_pr_or_base",
                        "Protected oracle_manifest 참조 파일이 PR changed files 또는 base/main에 없습니다. "
                        "PR에 해당 파일이 포함되어 있거나 base/main에 이미 존재해야 합니다.",
                        rel,
                    )
                elif _tracked_for_pr == "ERROR":
                    # per-file 추적 판정 자체가 Permission denied 등으로 실패 → fail-closed.
                    _add_blocker(
                        "workspace_hygiene_check_failed",
                        "git 조회가 비정상 종료되어 oracle_manifest 참조 파일의 PR/base 포함 여부를 "
                        "확인할 수 없습니다(fail-closed).",
                        rel,
                    )
                # _tracked_for_pr가 None(git 부재, 이미 위에서 fail-closed) 또는 False(untracked)
                # 인 경우는 이 blocker를 적용하지 않는다(deferral/규칙3 권위).

    # ---- 규칙 7 (IMP-20260622-79BA MT-5): PR diff에 runtime state 누출 차단 ----
    # .pipeline/runs/** 는 gitignore 대상 runtime state store다. 이 경로가 PR changed
    # files에 포함되면 runtime state(state.json/scratch)가 PR로 누출된 것이므로 BLOCKED.
    # pipeline_state.json 은 protected(상태 파일)라 PR diff에 포함되면 안 되므로 함께 차단한다.
    # gh CLI 부재/실패는 graceful skip(검사 불가 → 차단하지 않음). 실 운영에는 gh가 존재한다.
    result["pr_runtime_state_leak"] = []
    try:
        _gh_pr = subprocess.run(
            ["gh", "pr", "view", "--json", "files"],
            capture_output=True, text=True, encoding="utf-8", check=False,
            cwd=str(BASE_DIR),
        )
    except (FileNotFoundError, OSError):
        _gh_pr = None  # gh 부재 → graceful skip
    if _gh_pr is not None and _gh_pr.returncode == 0:
        try:
            _pr_payload = json.loads(_gh_pr.stdout)
            _pr_paths = [
                str(f.get("path", "") or "").replace("\\", "/").lstrip("./")
                for f in (_pr_payload.get("files") or [])
            ]
        except (json.JSONDecodeError, AttributeError):
            _pr_paths = []
        for _pp in _pr_paths:
            if not _pp:
                continue
            if _pp.startswith(".pipeline/runs/"):
                result["pr_runtime_state_leak"].append(_pp)
                _add_blocker(
                    "runtime_state_in_pr",
                    "Runtime state store(.pipeline/runs/**)가 PR changed files에 포함되어 있습니다. "
                    "이 경로는 gitignore 대상이어야 하며 PR에 포함되면 안 됩니다. "
                    "`git rm --cached`로 추적 해제 후 .gitignore를 확인하세요.",
                    _pp,
                )
            elif _pp == "pipeline_state.json":
                result["pr_runtime_state_leak"].append(_pp)
                _add_blocker(
                    "pipeline_state_in_pr",
                    "pipeline_state.json(protected 상태 파일)이 PR changed files에 포함되어 있습니다. "
                    "이 파일은 PR diff/packet에 포함되면 안 됩니다(삭제/수정 금지 — 추적만 해제).",
                    _pp,
                )

    # ---- cleanup_command 구성 (cleanup_only 파일이 있을 때) ----
    if result["cleanup_only_items"]:
        _items = result["cleanup_only_items"]
        result["cleanup_command"] = (
            "Remove-Item " + " ".join(f'"{i}"' for i in _items[:5])
            + (" ..." if len(_items) > 5 else "")
        )

    # ---- 최종 status 확정: BLOCKED 우선, 아니면 cleanup_only 있으면 WARN, 아니면 OK ----
    if result["status"] != "BLOCKED":
        result["status"] = "WARN" if result["cleanup_only_items"] else "OK"

    return result


def _validate_evidence_provenance(
    state: Dict[str, Any],
    phase: str = "oracle",
    target_commit: Optional[str] = None,
) -> Dict[str, Any]:
    """등록된 oracle 증거가 git tracked + 현재 PR + target commit blob과 일치하는지 검증한다(fail-closed).

    검증 순서(protected 비-cleanup 증거마다):
      a. 파일 존재 여부
      b. 현재 로컬 SHA256 == inventory sha256 (불일치 -> evidence_sha_mismatch)
      c. git ls-files 로 tracked 여부 (untracked -> protected_evidence_untracked)
      d. git show <target_commit>:<path> 의 blob 내용 SHA256 == inventory sha256
         (불일치 -> dirty_tracked_evidence; target commit에도 origin/main에도 없으면 -> oracle_evidence_not_in_pr)
      e. GitHub PR changed files 또는 기존 git 이력 포함 여부

    target_commit 이 None 이면 현재 HEAD 를 기준 커밋으로 사용한다(PR head SHA 대용).

    Args:
        state: pipeline_id를 포함한 pipeline state dict(최소 {"pipeline_id": ...}).
        phase: 호출 단계 문자열("oracle" | "request-accept" 등, 진단용).
        target_commit: blob SHA 비교에 사용할 기준 커밋(None이면 HEAD).
    Returns:
        Dict: status/phase/blockers/protected_evidence_count/tracked_count/
              pr_included_count/untracked_protected/orphan_oracle_warnings/
              cleanup_only_artifacts/target_commit 필드를 포함.
    Raises:
        TypeError: state가 None이거나 dict가 아닌 경우.
    """
    if state is None:
        raise TypeError("state must not be None")
    if not isinstance(state, dict):
        raise TypeError(f"state must be dict, got {type(state).__name__}")

    pipeline_id = str(state.get("pipeline_id", "") or "")

    result: Dict[str, Any] = {
        "status": "PASS",
        "phase": phase,
        "blockers": [],
        "protected_evidence_count": 0,
        "tracked_count": 0,
        "pr_included_count": 0,
        "untracked_protected": [],
        "orphan_oracle_warnings": [],
        "cleanup_only_artifacts": [],
        "target_commit": "",
    }

    def _add_blocker(failure_code: str, message: str, item: str = "") -> None:
        result["status"] = "BLOCKED"
        result["blockers"].append({
            "failure_code": failure_code,
            "message": message,
            "path": item,
        })

    if not pipeline_id:
        _add_blocker(
            "evidence_inventory_missing",
            "state에 pipeline_id가 없어 evidence inventory를 확인할 수 없습니다.",
        )
        return result

    # blob SHA 비교 기준 커밋 확정: 인자 미지정 시 현재 HEAD 사용(fail-closed).
    resolved_target_commit = str(target_commit or "").strip()
    target_commit_lookup_failed = ""
    if not resolved_target_commit:
        try:
            _rev = subprocess.run(
                ["git", "rev-parse", "HEAD"],
                capture_output=True, text=True, encoding="utf-8", check=False,
            )
        except (FileNotFoundError, OSError):
            target_commit_lookup_failed = (
                "git CLI를 실행할 수 없어 기준 커밋(HEAD)을 확인할 수 없습니다(fail-closed)."
            )
        else:
            if _rev.returncode == 0:
                resolved_target_commit = (_rev.stdout or "").strip()
            else:
                target_commit_lookup_failed = (
                    "git rev-parse HEAD 가 실패하여 기준 커밋을 확인할 수 없습니다(fail-closed): "
                    + (_rev.stderr or "").strip()[:200]
                )
    result["target_commit"] = resolved_target_commit

    inventory_path = _contract_paths(pipeline_id)["evidence_inventory"]

    # AC-2: inventory 파일 없음 -> BLOCKED(evidence_inventory_missing)
    if not inventory_path.exists():
        _add_blocker(
            "evidence_inventory_missing",
            f"evidence_inventory.json이 존재하지 않습니다({pipeline_id}). "
            "`python pipeline.py contract add-oracle ...` 로 oracle 증거를 먼저 등록하세요.",
        )
        return result

    # AC-10: inventory 파싱 실패 -> BLOCKED(evidence_inventory_parse_error)
    try:
        loaded = json.loads(inventory_path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError) as exc:
        _add_blocker(
            "evidence_inventory_parse_error",
            f"evidence_inventory.json 파싱에 실패했습니다: {exc}",
        )
        return result
    if not isinstance(loaded, list):
        _add_blocker(
            "evidence_inventory_parse_error",
            "evidence_inventory.json 루트가 list가 아닙니다.",
        )
        return result

    # AC-6: 현재 pipeline_id 항목만 검사 (다른 pid는 건너뜀)
    entries = [
        e for e in loaded
        if isinstance(e, dict) and str(e.get("pipeline_id", "")) == pipeline_id
    ]

    # PR changed files 1회 조회 (fail-closed) — protected 비-cleanup 증거가 있을 때만 필요
    pr_changed_paths: set = set()
    pr_lookup_failed_code = ""
    pr_lookup_failed_msg = ""
    need_pr = any(
        isinstance(e, dict)
        and str(e.get("protection", "")) == "protected"
        and not _is_cleanup_only_artifact(Path(str(e.get("path", ""))).name)
        for e in entries
    )
    if need_pr:
        try:
            pr_proc = subprocess.run(
                ["gh", "pr", "view", "--json", "files"],
                capture_output=True, text=True, encoding="utf-8", check=False,
            )
        except (FileNotFoundError, OSError):
            pr_lookup_failed_code = "gh_cli_failed"
            pr_lookup_failed_msg = (
                "GitHub CLI(gh)를 실행할 수 없어 PR 변경 파일을 확인할 수 없습니다(fail-closed)."
            )
        else:
            if pr_proc.returncode != 0:
                pr_lookup_failed_code = "gh_cli_failed"
                pr_lookup_failed_msg = (
                    "gh pr view 명령이 실패하여 PR 변경 파일을 확인할 수 없습니다(fail-closed): "
                    + (pr_proc.stderr or "").strip()[:200]
                )
            else:
                try:
                    pr_data = json.loads((pr_proc.stdout or "").strip() or "{}")
                except (json.JSONDecodeError, ValueError):
                    pr_lookup_failed_code = "gh_cli_failed"
                    pr_lookup_failed_msg = (
                        "gh pr view 가 반환한 PR 메타데이터(JSON)를 해석하지 못했습니다(fail-closed)."
                    )
                else:
                    pr_files_raw = pr_data.get("files") if isinstance(pr_data, dict) else None
                    if isinstance(pr_files_raw, list):
                        for fentry in pr_files_raw:
                            if isinstance(fentry, dict) and fentry.get("path"):
                                pr_changed_paths.add(
                                    str(fentry["path"]).replace("\\", "/").lstrip("./")
                                )

    for entry in entries:
        path_str = str(entry.get("path", ""))
        if not path_str:
            continue
        path_obj = Path(path_str)
        name = path_obj.name
        protection = str(entry.get("protection", ""))

        # AC-8: cleanup-only 파일은 차단하지 않고 분류만 한다.
        if _is_cleanup_only_artifact(name):
            result["cleanup_only_artifacts"].append(path_str)
            continue

        # protected 증거만 tracked/PR 검증 대상
        if protection != "protected":
            continue
        result["protected_evidence_count"] += 1

        # AC-3/AC-7: git ls-files 로 tracked 여부 확인 (fail-closed)
        try:
            ls_proc = subprocess.run(
                ["git", "ls-files", "--error-unmatch", path_str],
                capture_output=True, text=True, encoding="utf-8", check=False,
            )
        except (FileNotFoundError, OSError):
            _add_blocker(
                "git_execution_failed",
                f"git CLI를 실행할 수 없어 {path_str} 의 tracked 여부를 확인할 수 없습니다(fail-closed).",
                path_str,
            )
            result["untracked_protected"].append(path_str)
            continue
        if ls_proc.returncode != 0:
            # untracked protected 증거 -> BLOCKED
            _add_blocker(
                "protected_evidence_untracked",
                f"protected oracle 증거가 git에 추적되지 않습니다(untracked): {path_str}. "
                "해당 파일을 git add/commit 하여 추적 대상으로 만든 뒤 다시 실행하세요.",
                path_str,
            )
            result["untracked_protected"].append(path_str)
            continue

        result["tracked_count"] += 1

        # SHA 정합성 검증: inventory 등록 시점 sha256과 현재 파일 내용 비교
        inventory_sha256 = str(entry.get("sha256", "") or "")
        if inventory_sha256:
            try:
                _h = hashlib.sha256()
                with open(path_str, "rb") as _f:
                    for _chunk in iter(lambda: _f.read(65536), b""):
                        _h.update(_chunk)
                current_sha256 = _h.hexdigest()
                if current_sha256 != inventory_sha256:
                    _add_blocker(
                        "evidence_sha_mismatch",
                        f"evidence_inventory.json의 sha256과 현재 파일 내용이 다릅니다: {path_str}. "
                        f"expected={inventory_sha256[:16]}..., actual={current_sha256[:16]}...",
                        path_str,
                    )
                    continue
            except (OSError, IOError) as _exc:
                _add_blocker(
                    "evidence_sha_read_error",
                    f"SHA256 계산 중 파일 읽기 오류: {path_str} — {_exc}",
                    path_str,
                )
                continue

        # dirty tracked evidence 검증: 로컬 파일/ inventory sha256은 일치하지만
        # 기준 커밋(target_commit)에 커밋된 내용과 working tree가 다르면(즉 변경 후 미커밋)
        # 차단한다. 줄바꿈(CRLF/LF)·BOM 정규화는 git이 처리하도록 byte-SHA 직접 비교 대신
        # `git diff --quiet <commit> -- <path>` 로 git의 텍스트 정규화 규칙을 그대로 따른다.
        # (Windows autocrlf/BOM 환경에서 byte-SHA 비교는 clean 파일을 dirty로 오판할 수 있음.)
        if inventory_sha256:
            if target_commit_lookup_failed:
                _add_blocker("git_execution_failed", target_commit_lookup_failed, path_str)
                continue
            if not resolved_target_commit:
                _add_blocker(
                    "git_execution_failed",
                    f"기준 커밋을 확인할 수 없어 {path_str} 의 커밋 정합성을 검증할 수 없습니다(fail-closed).",
                    path_str,
                )
                continue
            try:
                _diff = subprocess.run(
                    ["git", "diff", "--quiet", resolved_target_commit, "--", path_str],
                    capture_output=True, text=True, encoding="utf-8", check=False,
                )
            except (FileNotFoundError, OSError):
                _add_blocker(
                    "git_execution_failed",
                    f"git diff 를 실행할 수 없어 {path_str} 의 커밋 정합성을 검증할 수 없습니다(fail-closed).",
                    path_str,
                )
                continue
            # git diff --quiet: 0 = 차이 없음(clean), 1 = 차이 있음(dirty), 그 외 = 오류.
            if _diff.returncode == 1:
                _add_blocker(
                    "dirty_tracked_evidence",
                    f"oracle 증거가 기준 커밋({resolved_target_commit[:12]})과 다릅니다(working tree 변경 미커밋): {path_str}. "
                    "변경 사항을 commit/push 한 뒤 다시 실행하세요.",
                    path_str,
                )
                continue
            if _diff.returncode not in (0, 1):
                # target commit에 파일이 없을 수 있음(아직 머지 전 신규 oracle).
                # 이 경우 아래 git log 이력/ PR 포함 검사로 위임한다(여기서 차단하지 않음).
                pass

            # Step d2: explicit blob SHA cross-check (defense-in-depth — stale/tampered evidence 차단)
            # git diff --quiet이 0(clean)일 때 target commit의 blob SHA256을 직접 계산하여
            # inventory sha256과 명시적으로 대조한다. step b(local==inventory) + step d(working
            # tree==commit)가 모두 통과했을 때 동일 결론이 나야 하는 three-way consistency check이다.
            if _diff.returncode == 0 and inventory_sha256:
                try:
                    _rel_p = path_obj.resolve().relative_to(BASE_DIR.resolve()).as_posix()
                    _bproc = subprocess.run(
                        ["git", "show", f"{resolved_target_commit}:{_rel_p}"],
                        capture_output=True, check=False,
                    )
                    if _bproc.returncode == 0 and _bproc.stdout:
                        _blob_sha = hashlib.sha256(_bproc.stdout).hexdigest()
                        if _blob_sha != inventory_sha256:
                            _add_blocker(
                                "evidence_blob_sha_mismatch",
                                f"target commit({resolved_target_commit[:12]})의 blob SHA256이 "
                                f"inventory sha256과 다릅니다(stale/tampered evidence): {path_str}. "
                                f"expected={inventory_sha256[:16]}..., "
                                f"blob_actual={_blob_sha[:16]}...",
                                path_str,
                            )
                            continue
                except (ValueError, OSError, FileNotFoundError):
                    pass  # rel_path 변환 또는 git show 실패 → graceful (git diff가 이미 커버)

        # PR 포함 여부 확인 전, 먼저 git log 이력 확인 (기존 main 이력이 있으면 PR 조회 불필요)
        try:
            log_proc = subprocess.run(
                ["git", "log", "--oneline", "-1", "--", path_str],
                capture_output=True, text=True, encoding="utf-8", check=False,
            )
        except (FileNotFoundError, OSError):
            log_proc = None
        if log_proc is not None and log_proc.returncode == 0 and bool((log_proc.stdout or "").strip()):
            result["pr_included_count"] += 1  # 기존 main 이력 존재 -> 허용 (PR 조회 불필요)
            continue

        # PR 조회 실패 시 fail-closed (단, 기존 이력 파일은 위에서 이미 허용됨)
        if pr_lookup_failed_code:
            _add_blocker(pr_lookup_failed_code, pr_lookup_failed_msg, path_str)
            continue

        norm_candidates = {
            path_str.replace("\\", "/").lstrip("./"),
            _display_path(path_obj).replace("\\", "/").lstrip("./"),
        }
        try:
            rel_to_base = path_obj.resolve().relative_to(BASE_DIR.resolve()).as_posix()
            norm_candidates.add(rel_to_base)
        except (ValueError, OSError):
            pass

        if norm_candidates & pr_changed_paths:
            result["pr_included_count"] += 1
            continue

        # AC-5: PR에도 없고 이력도 없음
        _add_blocker(
            "oracle_evidence_not_in_pr",
            f"oracle 증거 파일이 현재 PR 변경 목록에도 없고 기존 이력도 없습니다: {path_str}. "
            "해당 oracle 파일을 PR에 포함시킨 뒤 다시 실행하세요.",
            path_str,
        )

    return result


# IMP-20260613-82ED 5th REJECT: oracle_manifest ↔ evidence_inventory 전체 대조 (fail-closed)
# [Purpose]: oracle_manifest.json의 모든 input/expected 경로가 evidence_inventory.json에
#            등록되어 있는지 _validate_evidence_provenance() 호출 전에 사전 대조한다.
#            inventory가 비었거나 oracle 항목이 inventory에서 누락된 경우를 BLOCKED 처리하여
#            "manifest에는 oracle이 있으나 inventory에는 일부만 등록된" 우회 경로를 차단한다.
# [Assumptions]: oracle_manifest는 {"oracles": [{"input_path","expected_path",...}]} list 구조,
#                evidence_inventory는 [{"pipeline_id","path",...}] flat list 구조(SSoT).
#                oracle_manifest의 상대 경로는 BASE_DIR 기준으로 정규화한다(_oracle_manifest_status와 동일).
# [Vulnerability & Risks]: 경로 정규화가 OS/심볼릭링크 차이로 실패하면 basename fallback으로
#                완화하나, 동일 basename(input.json 등)이 여러 케이스에 존재하면 느슨한 매칭이 될 수 있어
# 경로 비교는 resolved absolute path만 사용한다.
# basename fallback을 제거한 이유: 여러 oracle case가 같은 basename(input.json, expected.json)을
# 사용하므로 fallback이 누락 경로를 통과시키는 우회 경로가 된다(IMP-20260613-82ED Round 7 지적).
def _check_oracle_manifest_vs_inventory(state: Dict[str, Any]) -> Dict[str, Any]:
    """oracle_manifest의 모든 input/expected 경로가 evidence_inventory에 등록됐는지 전체 대조한다.

    fail-closed 규칙:
      - oracle_manifest 없음 -> PASS(검사 불필요, checked=0)
      - oracle_manifest 파싱 실패 -> BLOCKED(oracle_manifest_parse_error)
      - oracle 항목 0개 -> PASS(checked=0)
      - oracle 항목은 있으나 inventory 파일 없음 -> BLOCKED(evidence_inventory_missing)
      - inventory 파싱 실패 -> BLOCKED(evidence_inventory_parse_error)
      - inventory entries 0개인데 oracle 항목 존재 -> BLOCKED(evidence_inventory_empty)
      - oracle 경로가 inventory에 없음 -> BLOCKED(oracle_not_in_evidence_inventory)

    Args:
        state: pipeline_id를 포함한 pipeline state dict(최소 {"pipeline_id": ...}).
    Returns:
        Dict: {"status": "PASS"|"BLOCKED", ...}. BLOCKED 시 failure_code/message/blockers 포함.
    Raises:
        TypeError: state가 None이거나 dict가 아닌 경우.
    """
    if state is None:
        raise TypeError("state must not be None")
    if not isinstance(state, dict):
        raise TypeError(f"state must be dict, got {type(state).__name__}")

    pipeline_id = str(state.get("pipeline_id", "") or "")
    if not pipeline_id:
        # pipeline_id가 없으면 evidence inventory 자체를 찾을 수 없으므로 fail-closed.
        return {
            "status": "BLOCKED",
            "failure_code": "evidence_inventory_missing",
            "message": "state에 pipeline_id가 없어 oracle_manifest/evidence_inventory를 대조할 수 없습니다.",
            "blockers": [],
        }

    paths = _contract_paths(pipeline_id)
    oracle_manifest_path = paths["oracle_manifest"]
    inventory_path = paths["evidence_inventory"]

    # oracle_manifest가 없으면 대조 불필요(legacy/non-oracle 작업).
    if not oracle_manifest_path.exists():
        return {"status": "PASS", "checked": 0}

    try:
        oracle_manifest = json.loads(oracle_manifest_path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError) as exc:
        return {
            "status": "BLOCKED",
            "failure_code": "oracle_manifest_parse_error",
            "message": f"oracle_manifest.json 파싱에 실패했습니다: {exc}",
            "blockers": [],
        }

    oracles = oracle_manifest.get("oracles", []) if isinstance(oracle_manifest, dict) else []
    if not isinstance(oracles, list) or not oracles:
        # oracle 항목이 없으면 대조 대상 없음.
        return {"status": "PASS", "checked": 0}

    # oracle 항목이 있으면 inventory는 필수.
    if not inventory_path.exists():
        return {
            "status": "BLOCKED",
            "failure_code": "evidence_inventory_missing",
            "message": (
                f"oracle_manifest에 {len(oracles)}개 항목이 있지만 evidence_inventory.json이 없습니다."
            ),
            "blockers": [],
        }

    try:
        inventory = json.loads(inventory_path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError) as exc:
        return {
            "status": "BLOCKED",
            "failure_code": "evidence_inventory_parse_error",
            "message": f"evidence_inventory.json 파싱에 실패했습니다: {exc}",
            "blockers": [],
        }

    if not isinstance(inventory, list):
        return {
            "status": "BLOCKED",
            "failure_code": "evidence_inventory_parse_error",
            "message": "evidence_inventory.json 루트가 list가 아닙니다.",
            "blockers": [],
        }

    # 현재 pipeline_id 항목만 대조 대상 (다른 pid 항목은 무시).
    entries = [
        e for e in inventory
        if isinstance(e, dict) and str(e.get("pipeline_id", "")) == pipeline_id
    ]

    # inventory가 (현재 pid 기준) 비어 있는데 oracle 항목이 있으면 BLOCKED.
    if len(entries) == 0:
        return {
            "status": "BLOCKED",
            "failure_code": "evidence_inventory_empty",
            "message": (
                f"oracle_manifest에 {len(oracles)}개 항목이 있지만 "
                f"evidence_inventory.json에 현재 파이프라인({pipeline_id}) 항목이 없습니다."
            ),
            "blockers": [],
        }

    def _norm_abs(raw_path: str) -> str:
        """경로를 절대 경로 문자열로 정규화한다(_oracle_manifest_status와 동일 규칙)."""
        p = Path(raw_path)
        if not p.is_absolute():
            p = BASE_DIR / p
        try:
            return str(p.resolve())
        except (OSError, ValueError):
            return str(p)

    # inventory의 resolved 절대 경로 set 구성 (basename 보조 매칭 제거 — 우회 위험).
    inventory_abs = set()
    for e in entries:
        raw = str(e.get("path", "") or "")
        if not raw:
            continue
        inventory_abs.add(_norm_abs(raw))

    blockers: List[Dict[str, str]] = []
    checked = 0
    for oracle in oracles:
        if not isinstance(oracle, dict):
            continue
        input_path = str(oracle.get("input_path", "") or oracle.get("input", "") or "")
        expected_path = str(oracle.get("expected_path", "") or oracle.get("expected", "") or "")
        for raw_path in (input_path, expected_path):
            if not raw_path:
                continue
            checked += 1
            abs_path = _norm_abs(raw_path)
            if abs_path in inventory_abs:
                continue
            # 절대 경로 미스 = 미등록 oracle → fail-closed BLOCKED (basename fallback 없음).
            blockers.append({
                "failure_code": "oracle_not_in_evidence_inventory",
                "oracle_path": raw_path,
                "message": (
                    f"oracle_manifest 항목이 evidence_inventory에 등록되어 있지 않습니다: {raw_path}"
                ),
            })

    if blockers:
        return {
            "status": "BLOCKED",
            "failure_code": "oracle_not_in_evidence_inventory",
            "message": (
                f"oracle_manifest의 {len(blockers)}개 경로가 evidence_inventory에 없습니다. "
                "모든 oracle input/expected를 `contract add-oracle`로 등록한 뒤 다시 실행하세요."
            ),
            "blockers": blockers,
        }

    return {"status": "PASS", "checked": checked}


def _contract_init_command(pid: str) -> str:
    return f"python pipeline.py contract init --pipeline-id {pid}"


def _require_contract_initialized(paths: Dict[str, Path], pid: str, action: str) -> None:
    missing = [path for path in (paths["contract"], paths["test_set"]) if not path.exists()]
    if not missing:
        return
    missing_lines = "\n".join(f"  - {path}" for path in missing)
    _die(
        "\n[CONTRACT NOT INITIALIZED]\n"
        f"  contract action `{action}` requires initialized contract files for pipeline `{pid}`.\n"
        f"  Run first: {_contract_init_command(pid)}\n"
        "  Missing files:\n"
        f"{missing_lines}"
    )


def _load_contract_bundle(
    load_json_func: Any,
    paths: Dict[str, Path],
    pid: str,
    action: str,
) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    _require_contract_initialized(paths, pid, action)
    try:
        contract = load_json_func(paths["contract"])
        test_set = load_json_func(paths["test_set"])
    except ValueError as exc:
        _die(
            "\n[CONTRACT FILE ERROR]\n"
            f"  Could not read contract files for pipeline `{pid}`: {exc}\n"
            f"  Repair the JSON files or re-run: {_contract_init_command(pid)} --force"
        )
    return contract, test_set


def _write_json(path: Path, data: Dict[str, Any]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    tmp_path: Optional[Path] = None
    try:
        with tempfile.NamedTemporaryFile(
            mode="wb",
            dir=path.parent,
            delete=False,
            suffix=".tmp",
        ) as tmp:
            payload = (json.dumps(data, ensure_ascii=False, indent=2) + "\n").encode("utf-8")
            tmp.write(payload)
            tmp_path = Path(tmp.name)
        os.replace(str(tmp_path), str(path))
    except Exception:
        if tmp_path is not None and tmp_path.exists():
            tmp_path.unlink(missing_ok=True)
        raise


def _write_json_value(path: Path, data: Any) -> None:
    """list/dict 등 임의 JSON 직렬화 가능 값을 원자적으로 기록한다(_write_json의 list 허용 변형).

    Args:
        path: 저장 경로.
        data: JSON 직렬화 가능한 값(list/dict 등).
    Returns:
        없음.
    Raises:
        OSError: 파일 쓰기 실패 시.
    """
    import time as _time  # noqa: PLC0415
    path.parent.mkdir(parents=True, exist_ok=True)
    tmp_path: Optional[Path] = None
    try:
        with tempfile.NamedTemporaryFile(
            mode="wb",
            dir=path.parent,
            delete=False,
            suffix=".tmp",
        ) as tmp:
            payload = (json.dumps(data, ensure_ascii=False, indent=2) + "\n").encode("utf-8")
            tmp.write(payload)
            tmp_path = Path(tmp.name)
        # Windows WinError 5(Access Denied): antivirus가 .tmp를 잠시 잠글 수 있음 — 최대 3회 재시도
        _last_exc: Optional[BaseException] = None
        for _attempt in range(3):
            try:
                os.replace(str(tmp_path), str(path))
                _last_exc = None
                break
            except PermissionError as _exc:
                _last_exc = _exc
                if _attempt < 2:
                    _time.sleep(0.15)
        if _last_exc is not None:
            raise _last_exc
    except Exception:
        if tmp_path is not None and tmp_path.exists():
            tmp_path.unlink(missing_ok=True)
        raise


def _load_json_file(path: Path, default: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    if not path.exists():
        return dict(default or {})
    try:
        data = json.loads(path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError) as exc:
        _die(f"invalid JSON file {path}: {exc}")
    if not isinstance(data, dict):
        _die(f"JSON root must be an object: {path}")
    return data


def _sha256_file(path: Path) -> str:
    digest = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest()


# [Purpose]: IMP-20260703-B985 MT-1 — PR body SHA-256 계산의 단일 canonical 신뢰 루트(SSoT).
#   BUG-20260628-F52C 계열 REJECT의 근본 원인은 PR body SHA를 계산하는 코드가 여러 곳에 흩어져
#   있고 각기 다른 정규화(어떤 곳은 CRLF→LF, 어떤 곳은 정규화 없음, 어떤 곳은 jq stdout trailing
#   newline)를 적용해 동일 논리 본문이 서로 다른 SHA로 갈렸던 것이다. 이 helper로 모든 PR body SHA
#   계산 경로를 통일하여 candidate/canonical SHA가 동일 정규화 규칙 위에서 계산되도록 강제한다.
# [Assumptions]: 입력 text는 이미 gh `--json body`(jq 없이) JSON parse로 추출한 body 필드 원문이거나,
#   로컬에서 구성한 "publish 후 최종 body" 원문이다. 호출자는 jq stdout/콘솔 stdout을 전달하지 않는다.
# [Vulnerability & Risks]: 이 helper는 fail-closed가 아니라 순수 계산 함수다. None/비str 입력은
#   TypeError로 즉시 차단한다(호출자가 잘못된 값을 넘기면 조용히 통과하지 않는다). trailing newline은
#   절대 strip하지 않는다 — GitHub API가 저장한 body 값을 그대로 재현해야 canonical 2자 검증이
#   성립하기 때문이다(strip 시 GitHub 저장값과 SHA가 갈려 회귀).
# [Improvement]: 향후 GitHub GraphQL canonical body를 직접 받아 REST/GraphQL 정규화 차이까지 흡수 가능.
def _canonical_pr_body_sha256(text: str) -> str:
    """PR body SHA-256 canonical SSoT helper (모든 PR body SHA 계산의 단일 진입점).

    규칙(IMP-20260703-B985 MT-1):
      - CRLF(\\r\\n) 및 lone CR(\\r)을 LF(\\n)로 정규화하여 OS/GitHub 저장 형식 차이를 흡수한다.
      - trailing newline은 제거하지 않는다(strip 금지) — GitHub API body 저장값 재현성 보장.
      - 정규화된 텍스트를 UTF-8로 인코딩 후 hashlib.sha256().hexdigest()를 반환한다.
      - jq stdout, 콘솔 stdout, trailing newline 기반 계산은 이 helper를 통과할 수 없다(호출자 책임).

    Args:
        text: PR body 원문 문자열 (gh --json body JSON parse 결과 또는 로컬 구성 최종 body).
    Returns:
        canonical body SHA-256 hex 문자열.
    Raises:
        TypeError: text가 None이거나 str이 아닌 경우 (외부 입력 타입 가드, 암묵적 형변환 금지).
    """
    if text is None:
        raise TypeError("text must not be None")
    if not isinstance(text, str):
        raise TypeError(f"text must be str, got {type(text).__name__}")
    # CRLF→LF, lone CR→LF 순서로 정규화(먼저 \r\n을 처리해야 이중 변환을 피한다).
    text_lf = text.replace("\r\n", "\n").replace("\r", "\n")
    body_bytes = text_lf.encode("utf-8")
    return hashlib.sha256(body_bytes).hexdigest()


# IMP-20260531-BBDB MT-1: User Acceptance Nonce Gate 헬퍼 (5개)
# [Purpose]: --user-confirmed 단독 통과 차단을 위한 일회용 승인 코드(nonce) 파일 I/O.
# [Assumptions]: BASE_DIR 또는 현재 작업 디렉토리에 acceptance_request.json 저장.
#                evidence는 파일 경로(SHA-256 계산) 또는 URL(http://, https://) 둘 다 허용.
# [Vulnerability & Risks]:
#   - 40bit nonce 엔트로피는 단일 PR 라이프사이클 동안 충돌 가능성 무시 가능하지만,
#     수십만 회 발급 시 birthday paradox 위험 존재.
#   - 파일 시스템 권한이 group-writable이면 다른 사용자가 nonce 위조 가능 (Windows 권한 의존).
# [Improvement]: HMAC 서명 + per-pipeline 비밀키로 확장하여 위조 차단.

def _issue_acceptance_nonce() -> str:
    """8자 base32 uppercase nonce 생성 (40bit 엔트로피, 일회용 승인 코드용).

    Returns:
        8자 base32 문자열 (예: "A2B3C4D5"). secrets 모듈로 암호학적 안전성 보장.
    Raises:
        없음.
    """
    raw = secrets.token_bytes(5)  # 40 bits → base32 8자
    return base64.b32encode(raw).decode("ascii").rstrip("=")[:8]


def _compute_file_sha256(path: str) -> Optional[str]:
    """파일 SHA-256 계산. 파일이 없거나 읽기 불가하면 None.

    Args:
        path: 파일 경로 문자열.
    Returns:
        SHA-256 hex digest 또는 None (파일 없음/IO 오류).
    Raises:
        없음 (OSError swallow — gate 로직이 None을 검사하여 stale 판정).
    """
    if path is None:
        return None
    if not isinstance(path, str):
        raise TypeError(f"path must be str, got {type(path).__name__}")
    try:
        h = hashlib.sha256()
        with open(path, "rb") as f:
            for chunk in iter(lambda: f.read(65536), b""):
                h.update(chunk)
        return h.hexdigest()
    except OSError:
        return None


# ─── IMP-20260531-AEF0 MT-1: nonce 재사용 판단 헬퍼 ─────────────────────────────
def _should_reuse_acceptance_nonce(
    existing_req: Dict[str, Any],
    new_pipeline_id: str,
    new_evidence: str,
    new_evidence_sha256: Optional[str],
    new_pr_head_sha: str,
    new_ci_run_id: str,
    force_new: bool = False,
    new_pr_body_sha256: Optional[str] = None,
) -> "tuple[bool, str]":
    """기존 acceptance_request를 재사용할지 6-field 비교로 판단.

    동일 조건(pipeline_id / evidence / evidence_sha256 또는 evidence_url /
    pr_head_sha / github_ci_run_id / pr_body_sha256)이고 기존 코드가 PENDING 상태이면 재사용.
    하나라도 다르거나 force_new=True이면 새 코드 발급.

    Args:
        existing_req: 기존 acceptance_request.json 데이터 dict.
        new_pipeline_id: 현재 pipeline_id.
        new_evidence: 결과물 경로 또는 URL.
        new_evidence_sha256: 결과물 파일 SHA-256 (URL이면 None).
        new_pr_head_sha: 현재 PR head commit SHA.
        new_ci_run_id: 현재 GitHub Actions run ID.
        force_new: True이면 조건과 무관하게 항상 새 코드 발급.
        new_pr_body_sha256: 현재 PR 본문 SHA-256 (없으면 None). IMP-20260611-A716.
    Returns:
        (should_reuse: bool, reason_ko: str) 튜플.
    Raises:
        없음.
    """
    if force_new:
        return False, "--force-new-code 옵션이 지정되어 새 코드를 발급합니다."
    if existing_req.get("status") != "PENDING":
        status_val = existing_req.get("status", "알 수 없음")
        return False, f"기존 코드 상태가 {status_val}이어서 새 코드를 발급합니다."
    if existing_req.get("pipeline_id") != new_pipeline_id:
        return False, "파이프라인 ID가 달라서 새 코드를 발급합니다."
    if existing_req.get("evidence") != new_evidence:
        return False, "결과물 경로가 달라서 새 코드를 발급합니다."
    if new_evidence_sha256 is not None:
        if existing_req.get("evidence_sha256") != new_evidence_sha256:
            return False, "결과물 파일 내용이 달라서(SHA-256 변경) 새 코드를 발급합니다."
    else:
        # URL 기반 증거: evidence_url 필드로 비교
        if existing_req.get("evidence_url") != new_evidence:
            return False, "결과물 URL이 달라서 새 코드를 발급합니다."
    if existing_req.get("pr_head_sha") != new_pr_head_sha:
        return False, "PR head SHA가 달라서(새 커밋이 push됨) 새 코드를 발급합니다."
    if str(existing_req.get("github_ci_run_id", "")) != str(new_ci_run_id):
        return False, "GitHub Actions run ID가 달라서 새 코드를 발급합니다."
    # IMP-20260611-A716: PR 본문 변경 시 재사용 금지 (복구 경로 broken 방지)
    if new_pr_body_sha256 is not None:
        existing_body_sha = existing_req.get("pr_body_sha256")
        if not existing_body_sha:
            # 기존 acceptance_request에 pr_body_sha256 없음 (구 포맷) → 검증 불가 → 새 코드 발급
            return False, "기존 승인 요청에 PR 본문 SHA가 없어 새 코드를 발급합니다."
        if existing_body_sha != new_pr_body_sha256:
            return False, "PR 본문이 변경되어(SHA-256 변경) 새 코드를 발급합니다."
        if existing_req.get("pr_body_readiness") != "PASS":
            return False, "기존 PR 본문 readiness 스냅샷이 PASS가 아니어서 새 코드를 발급합니다."
        if existing_req.get("required_sections_present") is not True:
            return False, "기존 PR 본문 필수 섹션 스냅샷이 불완전하여 새 코드를 발급합니다."
        if existing_req.get("temporary_phrases_absent") is not True:
            return False, "기존 PR 본문 임시 문구 스냅샷이 불완전하여 새 코드를 발급합니다."
    return True, "PR, 결과물, CI 상태가 모두 같습니다."


def _write_acceptance_request(
    pipeline_id: str,
    evidence: str,
    pr_url: str,
    pr_head_sha: str,
    ci_run_id: str,
    verification_json_path: Optional[str] = None,
    verification_json_sha256: Optional[str] = None,
    packet_path: Optional[str] = None,
    packet_sha256: Optional[str] = None,
    github_ci_head_sha: Optional[str] = None,
    pr_body_sha256: Optional[str] = None,
    pr_body_readiness: Optional[str] = None,
    required_sections_present: Optional[bool] = None,
    temporary_phrases_absent: Optional[bool] = None,
    validated_at: Optional[str] = None,
) -> Dict[str, Any]:
    """acceptance_request.json 작성 후 데이터 dict 반환.

    IMP-20260605-58BF MT-3: verification_json_path와 verification_json_sha256을
    acceptance_request.json에 기록한다. gates accept 시 verification_json 동일성
    검사(_verify_verification_json_freshness)에서 이 값을 사용한다.
    IMP-20260607-E656 MT-4: packet_path, packet_sha256, github_ci_head_sha 필드 추가.
    gates accept 시 packet 파일 동일성 검증과 CI head SHA 일치 검증에 사용한다.
    IMP-20260611-A716 MT-4: pr_body_sha256, pr_body_readiness, required_sections_present,
    temporary_phrases_absent, validated_at 필드 추가. gates accept 시 pr_body_stale 검사에 사용.

    Args:
        pipeline_id: 활성 pipeline_id (예: IMP-20260531-BBDB).
        evidence: 결과물 경로(파일) 또는 URL(http://, https://).
        pr_url: 현재 PR URL (gh CLI 없으면 빈 문자열).
        pr_head_sha: PR head commit SHA (gh CLI 없으면 빈 문자열).
        ci_run_id: GitHub Actions run ID (gh CLI 없으면 빈 문자열).
        verification_json_path: human_acceptance_packet.json 경로 (없으면 None).
        verification_json_sha256: human_acceptance_packet.json SHA-256 (없으면 None).
        packet_path: human_acceptance_packet.md 경로 (없으면 None).
        packet_sha256: human_acceptance_packet.md SHA-256 (없으면 None).
        github_ci_head_sha: GitHub Actions CI run의 head SHA (없으면 None).
        pr_body_sha256: request-accept 시점 PR 본문 SHA-256 스냅샷 (없으면 None).
        pr_body_readiness: "PASS" | "BLOCKED" | None.
        required_sections_present: 필수 섹션 전부 존재 여부.
        temporary_phrases_absent: 임시 문구 없음 여부.
        validated_at: 검증 타임스탬프 (ISO 8601).
    Returns:
        기록된 acceptance_request 데이터 dict (status=PENDING).
    Raises:
        TypeError: pipeline_id 또는 evidence가 None.
        ValueError: pipeline_id가 빈 문자열.
    """
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if evidence is None:
        raise TypeError("evidence must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(f"pipeline_id must be str, got {type(pipeline_id).__name__}")
    if not isinstance(evidence, str):
        raise TypeError(f"evidence must be str, got {type(evidence).__name__}")
    if len(pipeline_id) == 0:
        raise ValueError("pipeline_id must not be empty")
    nonce = _issue_acceptance_nonce()
    request_id = str(uuid.uuid4())[:8]
    is_url = evidence.startswith(("http://", "https://"))
    evidence_sha256 = None if is_url else _compute_file_sha256(evidence)
    data: Dict[str, Any] = {
        "schema_version": 1,
        "pipeline_id": pipeline_id,
        "request_id": request_id,
        "nonce": nonce,
        "created_at": _now(),
        "pr_url": pr_url or "",
        "pr_head_sha": pr_head_sha or "",
        "github_ci_run_id": str(ci_run_id) if ci_run_id else "",
        "evidence": evidence,
        "evidence_sha256": evidence_sha256,
        "evidence_url": evidence if is_url else None,
        "verification_json_path": verification_json_path,
        "verification_json_sha256": verification_json_sha256,
        # IMP-20260607-E656 MT-4: 추가 필드
        "packet_path": packet_path,
        "packet_sha256": packet_sha256,
        "github_ci_head_sha": github_ci_head_sha,
        # IMP-20260611-A716 MT-4: PR body snapshot 필드
        "pr_body_sha256": pr_body_sha256,
        "pr_body_readiness": pr_body_readiness,
        "required_sections_present": required_sections_present,
        "temporary_phrases_absent": temporary_phrases_absent,
        "validated_at": validated_at,
        "status": "PENDING",
    }
    # IMP-20260620-3BF4 MT-3: 원자적 쓰기(tempfile + os.replace)로 partial write 방지.
    # pr_body_sha256 / packet_sha256 / verification_json_sha256 를 포함한 전체 dict가
    # 단일 os.replace 로 동시 커밋되어 부분 기록(partial write) 상태를 차단한다.
    # _write_json 은 상대경로(ACCEPTANCE_REQUEST_FILE)를 cwd 기준으로 해석하므로
    # 기존 테스트의 cwd 격리(PIPELINE_STATE_PATH + cwd=tmp_path)와 호환된다.
    _write_json(Path(ACCEPTANCE_REQUEST_FILE), data)
    return data


def _load_acceptance_request() -> Optional[Dict[str, Any]]:
    """acceptance_request.json 로드. 없거나 파싱 오류 시 None.

    Returns:
        파싱된 dict 또는 None (파일 없음/JSON 오류).
    Raises:
        없음 (OSError/JSONDecodeError swallow).
    """
    try:
        with open(ACCEPTANCE_REQUEST_FILE, encoding="utf-8") as fh:
            data = json.load(fh)
        if not isinstance(data, dict):
            return None
        return data
    except (OSError, json.JSONDecodeError):
        return None


# [Purpose]: BUG-20260628-F52C r11 MT-5 — 최종 불변식 검증 실패 시 기존 acceptance_request.json을
#            INVALIDATED 상태로 표시하여, 변조/stale 상태의 nonce가 gates accept에서 재사용되지
#            못하게 한다(fail-closed). 파일을 삭제하지 않고 status만 바꿔 사후 감사를 남긴다.
# [Assumptions]: acceptance_request.json이 존재하면 dict이며 status 필드를 가진다(없으면 새로 채움).
# [Vulnerability & Risks]: 파일 부재/파싱 실패는 no-op(이미 노출 산출물이 없으므로 안전).
#            쓰기 실패는 swallow하되, 호출자는 어차피 직후 _die로 BLOCKED 처리한다.
# [Improvement]: invalidation 사유/타임스탬프를 event_log에도 적재하면 추적이 강화된다.
def _invalidate_acceptance_request(reason: str) -> None:
    """acceptance_request.json의 status를 INVALIDATED로 표시한다 (최종 불변식 실패 시 fail-closed).

    Args:
        reason: invalidation 사유 문자열 (감사 기록용).
    Raises:
        TypeError: reason이 None이거나 str이 아닌 경우.
    """
    if reason is None:
        raise TypeError("reason must not be None")
    if not isinstance(reason, str):
        raise TypeError(f"reason must be str, got {type(reason).__name__}")
    try:
        req = _load_acceptance_request()
        if not isinstance(req, dict):
            return  # 파일 없음/비dict — 노출 산출물 없음, no-op.
        req["status"] = "INVALIDATED"
        req["invalidation_reason"] = reason
        req["invalidated_at"] = _now()
        with open(ACCEPTANCE_REQUEST_FILE, "w", encoding="utf-8") as fh:
            json.dump(req, fh, ensure_ascii=False, indent=2)
    except (OSError, TypeError, ValueError):
        # 쓰기 실패는 non-fatal — 호출자가 직후 _die로 BLOCKED 처리한다.
        pass


# [Purpose]: acceptance 표시 상태(display_status)를 단일 SSoT helper로 계산하여
#            _build_verification_json / _build_final_packet_content / accept finalization이
#            동일한 표시 상태를 산출하도록 보장한다 (IMP-20260614-D278 MT-1).
# [Assumptions]: 표시 상태(PENDING/ACCEPTED/REJECTED)와 gate 통과 상태(PASS)는 별개 레이어이며,
#                acceptance_request dict는 status / consumed_result 필드를 가질 수 있다.
# [Vulnerability & Risks]: acceptance_request가 None/비dict/필드 누락이면 안전 fallback인 PENDING.
#                          consumed_result가 ACCEPT/REJECT가 아닌 비정상 값이면 PENDING으로 처리.
# [Improvement]: 향후 상태 종류가 늘어나면 status->display 매핑 테이블로 분리 가능.
def _resolve_acceptance_display_state(
    acceptance_request: Optional[Dict[str, Any]],
) -> str:
    """acceptance_request 딕셔너리로부터 표시 상태를 계산하는 SSoT helper.

    표시 상태(display_status)는 PENDING/ACCEPTED/REJECTED 세 가지이며,
    gate 통과 상태(external_gates.acceptance.status=PASS)와는 별개 레이어다.

    Args:
        acceptance_request: acceptance_request.json 로드 결과 (None 허용).
    Returns:
        "PENDING"  — acceptance_request가 None/비dict이거나 status가 PENDING인 경우,
                     또는 status가 ACCEPTED/CONSUMED인데 consumed_result가 비정상인 경우 (안전 fallback).
        "ACCEPTED" — status가 ACCEPTED 또는 CONSUMED이고 consumed_result가 ACCEPT인 경우.
        "REJECTED" — status가 ACCEPTED 또는 CONSUMED이고 consumed_result가 REJECT인 경우.
    Raises:
        없음 — 비정상 입력은 모두 PENDING으로 안전 처리.
    """
    if not acceptance_request or not isinstance(acceptance_request, dict):
        return "PENDING"
    status = str(acceptance_request.get("status") or "").upper()
    if status in {"ACCEPTED", "CONSUMED"}:
        result = str(acceptance_request.get("consumed_result") or "").upper()
        if result == "ACCEPT":
            return "ACCEPTED"
        elif result == "REJECT":
            return "REJECTED"
    return "PENDING"


# [Purpose]: BUG-20260615-A35C MT-1 — DEFECT-A 수정. user-facing acceptance 표시 상태를
#            단일 SSoT로 계산한다. acceptance_request.json(현재 파이프라인 소속)이 active 상태면
#            그 상태를 우선하고, 없을 때만 state["external_gates"]["acceptance"]["status"]로
#            fallback한다. 이로써 gate가 FAIL이어도 active PENDING request가 있으면 PENDING으로
#            표시되어 메타데이터/게이트표/MD/JSON이 동일 SSoT 값을 공유한다.
# [Assumptions]: state는 pipeline_state dict이며 pipeline_id / external_gates 키를 가질 수 있다.
#                acceptance_request.json은 _load_acceptance_request()로 로드되며 None 가능.
# [Vulnerability & Risks]: acceptance_request가 다른 파이프라인 소속이면 무시하고 state fallback.
#                          request status가 비정상 값이면 _resolve_acceptance_display_state가
#                          안전 fallback(PENDING)을 반환한다.
# [Improvement]: state fallback 값도 display 정규화 테이블을 거치도록 확장 가능.
def _get_effective_acceptance_display_state(state: Dict[str, Any]) -> str:
    """acceptance_request.json과 state를 조합하여 user-facing acceptance 표시 상태를 반환한다.

    DEFECT-A(BUG-20260615-A35C): state["external_gates"]["acceptance"]["status"]가 FAIL이어도
    현재 파이프라인의 active acceptance_request.json이 PENDING이면 표시는 PENDING이어야 한다.

    우선순위:
      1. acceptance_request.json 존재 + 현재 파이프라인 소속 + 정규화 표시 상태가
         PENDING/ACCEPTED/REJECTED 중 하나 → 그 표시 상태 반환.
      2. 그렇지 않으면 state["external_gates"]["acceptance"]["status"] fallback (없으면 PENDING).

    Args:
        state: 활성 pipeline_state dict. None 금지.
    Returns:
        "PENDING" | "ACCEPTED" | "REJECTED" | (fallback 시 state gate status 문자열).
    Raises:
        TypeError: state가 None이거나 dict가 아닌 경우.
    """
    if state is None:
        raise TypeError("state must not be None")
    if not isinstance(state, dict):
        raise TypeError(f"state must be dict, got {type(state).__name__}")

    pid = str(state.get("pipeline_id") or "")
    req = _load_acceptance_request()
    if isinstance(req, dict):
        # 현재 파이프라인 소속 request만 인정 (다른 파이프라인 잔여 request 무시).
        req_pid = str(req.get("pipeline_id", "") or "")
        if not pid or not req_pid or req_pid == pid:
            display = _resolve_acceptance_display_state(req)
            req_status = str(req.get("status", "") or "").upper()
            # active request(PENDING/ACCEPTED/CONSUMED/REJECTED)면 정규화 표시 상태를 우선.
            if req_status in {"PENDING", "ACCEPTED", "CONSUMED", "REJECTED"}:
                return display
    # fallback: state의 acceptance gate status.
    external_gates = state.get("external_gates") or {}
    acceptance_gate = external_gates.get("acceptance") or {}
    if isinstance(acceptance_gate, dict):
        return str(acceptance_gate.get("status") or "PENDING")
    return "PENDING"


# [Purpose]: IMP-20260703-B985 MT-18 — acceptance 표시 상태를 인자 없이 계산하는 단일 helper.
#            PENDING acceptance_request가 있으면 무조건 "PENDING"을 반환하여, packet/verification_json
#            어느 소비자도 active PENDING 요청을 FAIL로 표시하지 않도록 강제한다.
# [Assumptions]: acceptance_request.json은 _load_acceptance_request()로 로드되며 dict 또는 None.
#            state는 _load()로 로드되며 external_gates.acceptance.status를 가질 수 있다.
# [Vulnerability & Risks]: state 로드 실패(None)/비dict/필드 누락이면 안전 fallback "UNKNOWN".
#            acceptance_request가 다른 파이프라인 잔여물이어도 PENDING이면 PENDING을 반환하는데,
#            이 helper는 표시 안전(FAIL 미표시)이 목적이므로 보수적으로 PENDING을 우선한다.
# [Improvement]: pipeline_id 소속 검증까지 넣으려면 _get_effective_acceptance_display_state를 쓰면 된다.
def _get_acceptance_display_state() -> str:
    """acceptance 표시 상태를 인자 없이 계산한다 (MT-18 단일 helper).

    PENDING acceptance_request가 있으면 항상 "PENDING"을 반환한다(FAIL 미표시 강제).
    없으면 pipeline_state의 external_gates.acceptance.status로 fallback한다.

    Returns:
        "PENDING" — active PENDING acceptance_request가 있을 때,
        그 외에는 external_gates.acceptance.status 문자열 (없으면 "UNKNOWN").
    Raises:
        없음 — 모든 로드 실패는 안전 fallback으로 흡수한다.
    """
    req = _load_acceptance_request()
    if isinstance(req, dict) and str(req.get("status", "") or "").upper() == "PENDING":
        return "PENDING"
    state = _load()
    if not isinstance(state, dict):
        return "UNKNOWN"
    gates = state.get("external_gates", {})
    if not isinstance(gates, dict):
        return "UNKNOWN"
    acc = gates.get("acceptance", {})
    if isinstance(acc, dict):
        return str(acc.get("status", "UNKNOWN") or "UNKNOWN")
    return "UNKNOWN"


# [Purpose]: IMP-20260703-B985 MT-30 — acceptance 표시 상태를 사용자에게 보여줄 display 문자열로
#            반환하는 얇은 wrapper. 기존 SSoT(_get_effective_acceptance_display_state)의 판정을
#            그대로 재사용하되, PENDING이면 "PENDING (승인 대기 중)" 표시 문자열로 매핑한다.
#            gate가 FAIL이어도 현재 파이프라인의 active PENDING request가 있으면 PENDING을 우선하여,
#            packet/게이트표/JSON 어느 소비자도 승인 대기 중 요청을 FAIL로 표시하지 않게 한다.
# [Assumptions]: state는 pipeline_state dict이며 external_gates.acceptance.status를 가질 수 있다.
#            _get_effective_acceptance_display_state가 acceptance_request.json 소속/상태를 판정한다.
# [Vulnerability & Risks]: state가 None/비dict이면 하위 helper가 TypeError를 던진다(호출자 계약 위반).
#            display 문자열 매핑은 PENDING만 특수 처리하고, ACCEPTED/REJECTED/기타 게이트 상태는
#            원문(대문자 문자열)을 그대로 반환한다.
# [Improvement]: 향후 표시 상태 종류가 늘면 status->display 매핑 테이블로 확장 가능.
def _resolve_acceptance_display_status(state: Dict[str, Any]) -> str:
    """acceptance 표시 상태를 사용자 display 문자열로 반환한다 (MT-30 표시 일관 SSoT wrapper).

    external_gates.acceptance.status가 FAIL이어도, 현재 파이프라인의 active
    acceptance_request.json이 PENDING이면 "PENDING (승인 대기 중)"을 반환한다. 이 helper는
    렌더링 전용이며, external_gates.acceptance.status(게이트 PASS 판정 필드)는 절대 변경하지 않는다.

    Args:
        state: 활성 pipeline_state dict. None 금지 (하위 helper가 TypeError를 던짐).
    Returns:
        "PENDING (승인 대기 중)" — active PENDING acceptance_request가 있을 때,
        그 외에는 _get_effective_acceptance_display_state(state)의 반환 문자열
        (예: "ACCEPTED" / "REJECTED" / gate status 문자열).
    Raises:
        TypeError: state가 None이거나 dict가 아닌 경우 (하위 helper 계약을 그대로 전파).
    """
    if state is None:
        raise TypeError("state must not be None")
    if not isinstance(state, dict):
        raise TypeError(f"state must be dict, got {type(state).__name__}")
    effective = _get_effective_acceptance_display_state(state)
    if str(effective or "").upper() == "PENDING":
        return "PENDING (승인 대기 중)"
    return str(effective)


# [Purpose]: IMP-20260703-B985 MT-28 — 승인 요청문(approval_request_message)의 구조 무결성을
#            조립 시점에 fail-closed로 검증한다. REJECT #21(승인 요청문 이중 출력)의 근본 원인은
#            Pipeline Manager가 relay 문구를 message에 섞어 넣거나 4요소가 중복/누락되는 것이므로,
#            SSoT renderer가 낸 message가 정확히 1회씩 4요소를 갖고 금지 문구가 없음을 강제한다.
# [Assumptions]: msg는 _build_approval_request_output이 만든 4요소 고정 양식 문자열이다.
# [Vulnerability & Risks]: 검증 실패는 곧 코드 회귀를 뜻하므로 ValueError(BLOCKED)로 즉시 차단한다.
#            금지 문구 목록은 REJECT #21 재발 방지용이며, 새 relay 문구가 발견되면 이 목록에 추가한다.
# [Improvement]: 향후 승인 양식이 다국어로 확장되면 언어별 필수 마커 표를 도입할 수 있다.
def _validate_approval_request_message(msg: str) -> None:
    """approval_request_message 구조를 fail-closed로 검증한다 (MT-28).

    Args:
        msg: 검증 대상 승인 요청문. None/비str 금지, 빈 문자열 금지.
    Raises:
        TypeError: msg가 None이거나 str이 아닌 경우.
        ValueError: 필수 요소 count가 1이 아니거나, 금지 문구를 포함하거나,
            마지막 의미 있는 줄이 'CODEX 검토 필요'가 아닌 경우.
    """
    if msg is None:
        raise TypeError("msg must not be None")
    if not isinstance(msg, str):
        raise TypeError(f"msg must be str, got {type(msg).__name__}")
    if len(msg.strip()) == 0:  # empty not allowed: 승인 코드 노출 채널이 사라진다.
        raise ValueError("[BLOCKED] approval_request_message 구조 오류: 빈 문자열")

    counts = {
        "사용자 승인 요청": msg.count("사용자 승인 요청"),
        "\nPR:": msg.count("\nPR:"),
        "승인 코드:": msg.count("승인 코드:"),
        "CODEX 검토 필요": msg.count("CODEX 검토 필요"),
    }
    for key, count in counts.items():
        if count != 1:
            raise ValueError(
                f"[BLOCKED] approval_request_message 구조 오류: '{key}' count={count}, expected=1"
            )

    forbidden_phrases = (
        "JSON 출력은 성공",
        "필드에서 추출",
        "위 PR에 승인 코드를",
        "Pipeline Manager도",
        "GitHub Actions 자동 검사가 통과",
        "이번 응답에서 중계",
        "댓글에 입력해 주세요",
    )
    for phrase in forbidden_phrases:
        if phrase in msg:
            raise ValueError(
                f"[BLOCKED] approval_request_message에 금지 문구 포함: '{phrase}'"
            )

    lines = [ln for ln in msg.strip().split("\n") if ln.strip()]
    if lines and lines[-1].strip() != "CODEX 검토 필요":
        raise ValueError(
            f"[BLOCKED] 마지막 줄이 'CODEX 검토 필요'가 아님: '{lines[-1]}'"
        )


# [Purpose]: IMP-20260703-B985 MT-31 — scratch 경로 헬퍼.
#            pipeline.py 내 각 커맨드가 파이프라인 전용 임시 디렉토리를 단일 경로로 사용한다.
# [Assumptions]: pipeline_id는 비어있지 않은 str이어야 한다.
# [Vulnerability & Risks]: 디렉토리 생성 실패 시 OSError가 상위로 전파된다.
# [Improvement]: 향후 hygiene archive 대상에 이 경로를 추가한다.
_SCRATCH_DIR_TEMPLATE = ".pipeline/runs/{pipeline_id}/scratch"


def _get_scratch_dir(pipeline_id: str) -> str:
    """파이프라인 전용 scratch 디렉토리 경로를 반환하고 디렉토리를 생성한다 (MT-31 SSoT).

    Args:
        pipeline_id: 활성 파이프라인 ID. 비어있으면 안 된다.
    Returns:
        생성된 scratch 디렉토리의 상대 경로 문자열.
    Raises:
        OSError: 디렉토리 생성에 실패한 경우.
    """
    p = _SCRATCH_DIR_TEMPLATE.format(pipeline_id=pipeline_id)
    os.makedirs(p, exist_ok=True)
    return p


# [Purpose]: IMP-20260703-B985 MT-30 — final_user_message.txt 고정 양식 검증 게이트.
#            Pipeline Manager가 approval_request_message를 파일에 쓴 뒤 이 CLI로 검증한다.
#            이중 출력 구조 차단: task result에 approval 블록 포함 금지를 강제하는 하드 게이트.
# [Assumptions]: --file에 지정된 파일은 approval_request_message만 담아야 한다(prefix/suffix 없음).
# [Vulnerability & Risks]: 금지 문구 목록은 REJECT #23 재발 방지용이다.
# [Improvement]: 새 relay 문구가 발견되면 _APPROVAL_MSG_FORBIDDEN_FINAL에 추가한다.

_APPROVAL_MSG_REQUIRED_COUNTS: Dict[str, int] = {
    "사용자 승인 요청": 1,
    "PR:": 1,
    "승인 코드:": 1,
    "CODEX 검토 필요": 1,
}

_APPROVAL_MSG_FORBIDDEN_FINAL: list = [
    "gates request-accept가 성공했습니다",
    "JSON stdout에서 approval_request_message를 추출",
    "승인 요청 메시지:",
    "위 PR에 승인 코드를 입력해 주세요",
    "Pipeline Manager도 확인했습니다",
    "GitHub Actions 확인 후",
    "댓글에 입력해 주세요",
    "이번 응답에서 중계",
    "기타 approval_request_message 앞뒤 설명",
    # MT-31: REJECT #24 재발 방지 — 오케스트레이터 설명 문구 차단
    "위 태스크 알림",
    "ACCEPT 또는 REJECT를 입력",
    "validate-user-approval-message PASS",
    "CI run",
    "통과",
    "확인하시고",
]


def _cmd_gates_validate_user_approval_message(args: "argparse.Namespace") -> None:
    """gates validate-user-approval-message: final_user_message.txt가 고정 양식과 일치하는지 검증.

    MT-30: 이중 출력 구조 차단 하드 게이트.
    Pipeline Manager가 approval_request_message를 final_user_message.txt에 쓴 뒤 실행.
    PASS(exit 0) / FAIL(exit 1) + JSON stdout.

    Args:
        args: argparse Namespace. --file 필수.
    Raises:
        SystemExit: 검증 실패 시 exit 1.
    """
    file_path = getattr(args, "file", None)
    if not file_path:
        print(json.dumps({"status": "FAIL", "errors": ["--file 인자가 필요합니다."]}, ensure_ascii=False))
        sys.exit(1)
    try:
        with open(file_path, "rb") as f:
            raw = f.read()
    except FileNotFoundError:
        print(json.dumps({"status": "FAIL", "errors": [f"파일을 찾을 수 없습니다: {file_path}"]}, ensure_ascii=False))
        sys.exit(1)

    # MT-31: BOM 감지 — UTF-8 BOM 없이 저장해야 합니다
    if raw.startswith(b"\xef\xbb\xbf"):
        print(json.dumps({"status": "FAIL", "errors": ["BOM 감지됨 — UTF-8 BOM 없이 저장해야 합니다"], "file": file_path}, ensure_ascii=False))
        sys.exit(1)

    errors: list = []

    # MT-31: CRLF 감지
    if b"\r\n" in raw:
        errors.append("CRLF 줄바꿈 감지됨 — LF만 사용해야 합니다")

    try:
        msg = raw.decode("utf-8")
    except UnicodeDecodeError as exc:
        print(json.dumps({"status": "FAIL", "errors": [f"UTF-8 디코드 실패: {exc}"], "file": file_path}, ensure_ascii=False))
        sys.exit(1)

    # count 검증
    for phrase, expected in _APPROVAL_MSG_REQUIRED_COUNTS.items():
        actual = msg.count(phrase)
        if actual != expected:
            errors.append(f'"{phrase}" count={actual} (expected {expected})')

    # 마지막 의미있는 줄 검증
    meaningful_lines = [ln for ln in msg.strip().splitlines() if ln.strip()]
    last_line = meaningful_lines[-1].strip() if meaningful_lines else ""
    if last_line != "CODEX 검토 필요":
        errors.append(f'마지막 의미있는 줄이 "CODEX 검토 필요"가 아닙니다: "{last_line}"')

    # 금지 문구 검증
    for phrase in _APPROVAL_MSG_FORBIDDEN_FINAL:
        if phrase in msg:
            errors.append(f'금지 문구 포함: "{phrase}"')

    if errors:
        print(json.dumps({"status": "FAIL", "errors": errors, "file": file_path}, ensure_ascii=False))
        sys.exit(1)
    else:
        print(json.dumps({"status": "PASS", "file": file_path}, ensure_ascii=False))
        sys.exit(0)


# [Purpose]: IMP-20260703-B985 MT-16 — 승인 요청 출력(human/JSON 공통)의 message/필드를 단일
#            지점에서 조립한다. --machine-readable JSON과 human stdout이 동일 내용을 공유하게 한다.
# [Assumptions]: pipeline_id는 비어있지 않고, pr_url은 str(빈 문자열 허용).
# [Vulnerability & Risks]: pr_url이 비면 message에 "(PR 링크 없음)"을 넣는다. 입력 타입 오류는 TypeError.
# [Improvement]: 향후 승인 요청 양식이 바뀌면 이 helper만 수정하면 human/JSON이 함께 갱신된다.
def _build_approval_request_output(pipeline_id: str, pr_url: str) -> Dict[str, Any]:
    """승인 요청 message 및 machine-readable JSON 필드를 조립한다 (MT-16 SSoT).

    Args:
        pipeline_id: 현재 파이프라인 ID. None/비str 금지.
        pr_url: PR URL 문자열(빈 문자열 허용). None/비str 금지.
    Returns:
        dict with keys:
            "approval_request_message": str — 4요소 승인 요청 안내문(줄바꿈 포함),
            "acceptance_code_display": str — 사용자에게 보이는 승인 코드(ACCEPT-<pid>),
            "pr_url": str — PR URL(없으면 빈 문자열),
            "codex_required": bool — 항상 True,
            "status": str — "PENDING".
    Raises:
        TypeError: pipeline_id/pr_url이 None이거나 str이 아닌 경우.
        ValueError: pipeline_id가 빈 문자열인 경우.
    """
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(f"pipeline_id must be str, got {type(pipeline_id).__name__}")
    if pr_url is None:
        raise TypeError("pr_url must not be None")
    if not isinstance(pr_url, str):
        raise TypeError(f"pr_url must be str, got {type(pr_url).__name__}")
    if len(pipeline_id) == 0:  # negative/empty not allowed: pipeline_id는 식별자 필수.
        raise ValueError("pipeline_id must not be empty")

    acceptance_code_display = f"ACCEPT-{pipeline_id}"
    pr_line = pr_url if pr_url else "(PR 링크 없음)"
    approval_request_message = (
        "사용자 승인 요청\n\n"
        f"PR: {pr_line}\n\n"
        f"승인 코드:\n{acceptance_code_display}\n\n"
        "CODEX 검토 필요"
    )
    # IMP-20260703-B985 MT-28: approval_request_message 구조 검증 게이트 (fail-closed).
    # REJECT #21 근본 방지 — 승인 요청문이 정확히 4요소를 1회씩만 포함하고, Pipeline Manager가
    # 임의로 덧붙이는 relay 문구(예: "JSON 출력은 성공")가 섞이지 않았음을 조립 시점에 보증한다.
    # SSoT renderer 결과는 항상 이 검증을 통과하므로, 통과 실패는 곧 코드 회귀를 뜻한다.
    _validate_approval_request_message(approval_request_message)
    return {
        "approval_request_message": approval_request_message,
        "acceptance_code_display": acceptance_code_display,
        "pr_url": pr_url,
        "codex_required": True,
        "status": "PENDING",
    }


# [Purpose]: IMP-20260703-B985 MT-17 — 승인 요청문 조립 직전 사전 검증 게이트.
#            acceptance_request/codex/packet/verification_json/PR body가 서로 정합한지 확인하여,
#            불일치·미승인·FAIL 표시 상태에서 승인 코드를 노출하지 않게 한다(fail-closed).
# [Assumptions]: acceptance_request.json / codex_review_result.json / human_acceptance_packet.{md,json}
#            은 현재 cwd 또는 격리 경로에 존재할 수 있으며, 없으면 발급 초기 시도로 간주해 일부 검사를 skip한다.
# [Vulnerability & Risks]: gh CLI 부재 시 PR body 검사(5,6)는 PASS로 흘려보낸다(정보 부족을 차단 사유로 삼지 않음).
#            packet/json 파일 부재는 최초 발급 시도로 간주하여 관련 SHA 검사를 skip한다.
#            MT-24 검사7: packet github_ci: FAIL vs 실제 PASS 불일치를 fail-closed로 차단한다.
# [Improvement]: 검사 항목을 세분화된 failure_code로 반환하면 호출부 안내를 더 구체화할 수 있다.
def _get_ci_final_check_status(
    pr_number: Optional[int] = None, repo: Optional[str] = None
) -> Dict[str, Any]:
    """CI final-check 댓글에서 판단 정보 상태를 가져온다 (MT-25).

    # [Purpose]: GitHub Actions final-check 댓글이 '정보 부족'을 표시하면
    #            gates request-accept가 승인 코드를 발급하지 못하도록 fail-closed 처리하기 위해,
    #            <!-- pipeline-final-check-packet --> 마커 댓글의 판단 정보 상태를 파싱한다.
    # [Assumptions]: gh CLI가 설치되어 있고 현재 PR에 접근 가능하다. 없으면 NOT_FOUND로 graceful skip.
    # [Vulnerability & Risks]: gh/network 오류를 모두 NOT_FOUND로 흡수하므로, self-hosted/오프라인
    #            환경에서 CI 상태를 확인하지 못한 채 통과할 수 있다(의도적 non-fatal 설계).
    # [Improvement]: comment id/timestamp를 함께 반환해 stale 댓글(오래된 실행)을 구분하면 정확도 향상.

    <!-- pipeline-final-check-packet --> 마커가 있는 댓글을 찾아
    '판단 정보 상태: **판단 가능**' 또는 '정보 부족'을 파싱한다.

    Args:
        pr_number: PR 번호 (None이면 gh로 자동 탐지).
        repo: owner/repo 문자열 (None이면 gh로 자동 탐지).
    Returns:
        dict with keys: status (PASS|FAIL|NOT_FOUND), reason, comment_url.
    Raises:
        없음 — 모든 예외를 NOT_FOUND로 흡수한다(non-fatal, graceful skip).
    """
    try:
        # repo와 pr_number를 자동 탐지
        if pr_number is None or repo is None:
            _view = subprocess.run(
                ["gh", "pr", "view", "--json", "number,headRefName"],
                capture_output=True, text=True, timeout=30,
                cwd=str(Path(__file__).parent),
            )
            if _view.returncode != 0:
                return {"status": "NOT_FOUND", "reason": "gh pr view failed", "comment_url": ""}
            _view_data = json.loads(_view.stdout or "{}")
            if pr_number is None:
                pr_number = _view_data.get("number")
            if repo is None:
                # repo를 git remote에서 추출
                _remote = subprocess.run(
                    ["gh", "repo", "view", "--json", "nameWithOwner"],
                    capture_output=True, text=True, timeout=30,
                    cwd=str(Path(__file__).parent),
                )
                if _remote.returncode == 0:
                    repo = json.loads(_remote.stdout or "{}").get("nameWithOwner")

        if not pr_number or not repo:
            return {
                "status": "NOT_FOUND",
                "reason": "pr_number or repo could not be determined",
                "comment_url": "",
            }

        # comments API로 final-check 마커 검색
        _comments_r = subprocess.run(
            ["gh", "api", f"repos/{repo}/issues/{pr_number}/comments", "--paginate"],
            capture_output=True, text=True, timeout=60,
            cwd=str(Path(__file__).parent),
        )
        if _comments_r.returncode != 0:
            return {"status": "NOT_FOUND", "reason": "gh api comments call failed", "comment_url": ""}

        comments = json.loads(_comments_r.stdout or "[]")
        if not isinstance(comments, list):
            return {"status": "NOT_FOUND", "reason": "unexpected comments format", "comment_url": ""}

        for comment in comments:
            body = comment.get("body", "") or ""
            if "<!-- pipeline-final-check-packet -->" not in body:
                continue
            comment_url = comment.get("html_url", "")
            if "판단 정보 상태: **판단 가능**" in body:
                return {
                    "status": "PASS",
                    "reason": "CI final-check shows 판단 가능",
                    "comment_url": comment_url,
                }
            # 정보 부족 또는 stale packet 등 실패 상태
            reason = "CI final-check shows 정보 부족"
            _stale_m = re.search(r"stale packet[^\)]*\)", body)
            if _stale_m:
                reason += f": {_stale_m.group()}"
            elif "packet file not found" in body:
                reason += ": packet file not found"
            return {
                "status": "FAIL",
                "reason": reason,
                "comment_url": comment_url,
            }

        return {"status": "NOT_FOUND", "reason": "no final-check comment found", "comment_url": ""}
    except Exception as _e_ci:
        return {"status": "NOT_FOUND", "reason": str(_e_ci), "comment_url": ""}


def _check_approval_request_ready(pr_body: Optional[str] = None) -> Dict[str, Any]:
    """승인 요청문 출력 직전 정합성 사전 검증 (MT-17).

    검사 항목(모두 PASS일 때만 ok=True):
      1. acceptance_request.status == "PENDING" (파일 없으면 skip)
      2. codex_review_result.json 존재 + status/verdict가 APPROVED류 (없으면 BLOCKED)
      3. sha256(packet.md 파일 bytes) == acceptance_request.packet_sha256 (파일/req 없으면 skip)
      4. sha256(packet.json 파일 bytes) == acceptance_request.verification_json_sha256 (없으면 skip)
      5. packet.json 파일 SHA == PR body final packet에 표시된 verification_json_sha256 (없으면 PASS)
      6. PR body final packet에 acceptance/User Acceptance FAIL 표시 없음 (PENDING/PR없음 PASS)

    Args:
        pr_body: 현재 PR 본문 텍스트(있으면 검사 5,6에 사용). None이면 내부에서 fetch 시도.
    Returns:
        {"ok": bool, "failure_code": str, "message": str}.
    Raises:
        없음 — 파일/네트워크 오류는 개별 검사 skip 또는 BLOCKED로 흡수한다.
    """
    req = _load_acceptance_request()

    # 검사 1: acceptance_request.status == PENDING (파일 없으면 skip — 최초 발급 허용)
    if isinstance(req, dict):
        _status = str(req.get("status", "") or "").upper()
        if _status and _status != "PENDING":
            return {
                "ok": False,
                "failure_code": "acceptance_request_not_pending",
                "message": (
                    f"acceptance_request.status가 PENDING이 아닙니다 (현재: {_status}). "
                    "gates request-accept를 다시 실행하세요."
                ),
            }

    # 검사 2: codex_review_result.json 존재 + APPROVED (없으면 BLOCKED)
    _cx_path = _codex_review_result_path()
    if not _cx_path.exists():
        return {
            "ok": False,
            "failure_code": "codex_review_missing",
            "message": (
                "codex_review_result.json이 없습니다 — Codex 검토(APPROVED) 이후에만 "
                "승인 요청문을 출력할 수 있습니다. gates codex-review를 먼저 통과시키세요."
            ),
        }
    try:
        _cx = json.loads(_cx_path.read_text(encoding="utf-8", errors="replace"))
    except (OSError, json.JSONDecodeError):
        _cx = None
    _cx_ok = False
    if isinstance(_cx, dict):
        _cx_val = str(
            _cx.get("status", "") or _cx.get("verdict", "") or ""
        ).upper()
        _cx_ok = _cx_val in {"APPROVED", "APPROVE_TO_USER", "APPROVE"}
    if not _cx_ok:
        return {
            "ok": False,
            "failure_code": "codex_not_approved",
            "message": (
                "codex_review_result의 status가 APPROVED가 아닙니다. "
                "Codex 검토를 통과시킨 후 다시 실행하세요."
            ),
        }

    # 검사 3,4: packet.md / packet.json 파일 SHA == acceptance_request 기록값 (req/파일 없으면 skip)
    if isinstance(req, dict):
        _pkt_path = _packet_output_path()
        _req_pkt_sha = str(req.get("packet_sha256", "") or "")
        if _req_pkt_sha and _pkt_path.exists():
            _actual_pkt_sha = hashlib.sha256(_pkt_path.read_bytes()).hexdigest()
            if _actual_pkt_sha != _req_pkt_sha:
                return {
                    "ok": False,
                    "failure_code": "packet_sha_mismatch",
                    "message": (
                        "human_acceptance_packet.md 파일 SHA가 "
                        "acceptance_request.packet_sha256와 다릅니다 (packet 변경됨). "
                        "gates request-accept를 다시 실행하세요."
                    ),
                }
        _json_path = _packet_json_output_path()
        _req_json_sha = str(req.get("verification_json_sha256", "") or "")
        _actual_json_sha = ""
        if _json_path.exists():
            _actual_json_sha = hashlib.sha256(_json_path.read_bytes()).hexdigest()
        if _req_json_sha and _json_path.exists():
            if _actual_json_sha != _req_json_sha:
                return {
                    "ok": False,
                    "failure_code": "verification_json_sha_mismatch",
                    "message": (
                        "human_acceptance_packet.json 파일 SHA가 "
                        "acceptance_request.verification_json_sha256와 다릅니다 "
                        "(verification_json 변경됨). gates request-accept를 다시 실행하세요."
                    ),
                }

        # 검사 5: (완화) packet.json 파일 SHA vs PR body embed verification_json_sha256.
        # 2-call codex 흐름에서는 PR body가 staging-time SHA를 embed하고 publish json 파일은
        # 별도 시점 bytes를 가질 수 있어, embed와 파일/기록 SHA가 정상적으로 갈릴 수 있다.
        # 이 divergence는 pre-existing 단계 4 post-publish 3-way 불변식이 이미 검증하므로,
        # 여기서는 hard block하지 않는다(오탐 방지). 표시값 부재/불일치 모두 PASS로 흘려보낸다.
        # (검사 3,4가 파일 vs acceptance_request 기록값 정합성을 이미 fail-closed로 보장한다.)

    # 검사 6: PR body final packet에 acceptance FAIL 표시 없음 (PENDING/PR없음 PASS)
    # IMP-20260703-B985 수정: PIPELINE_FINAL_PACKET 블록 안에서만 acceptance FAIL을 탐지한다.
    # 전체 본문을 검사하면 metrics 요약 등 다른 위치의 "acceptance: FAIL" 텍스트에 오탐이 발생한다.
    _body6 = pr_body if pr_body is not None else _get_pr_body_text()
    if isinstance(_body6, str):
        _body6_packet_only = _body6
        _pkt_start6 = _body6.find("<!-- PIPELINE_FINAL_PACKET_START -->")
        _pkt_end6 = _body6.find("<!-- PIPELINE_FINAL_PACKET_END -->")
        if _pkt_start6 >= 0 and _pkt_end6 > _pkt_start6:
            _body6_packet_only = _body6[_pkt_start6:_pkt_end6]
        _low = _body6_packet_only.lower()
        if "acceptance: fail" in _low or "user acceptance: fail" in _low:
            return {
                "ok": False,
                "failure_code": "pr_body_acceptance_fail",
                "message": (
                    "PR 본문 final packet에 acceptance FAIL 표시가 있습니다. "
                    "이전 REJECT/FAIL 상태를 PENDING으로 갱신한 후 다시 실행하세요."
                ),
            }

    # 검사 7 (MT-24): packet github_ci 상태가 실제 external_gates.github_ci.status와 일치하는지 검증
    # packet이 없거나 github_ci 상태 필드가 없으면 graceful skip (구 포맷 호환)
    try:
        _pkt_path_mt24 = _packet_output_path()
        if _pkt_path_mt24.exists():
            _pkt_text_mt24 = _pkt_path_mt24.read_text(encoding="utf-8", errors="replace")
            # "github_ci: FAIL" 또는 "GitHub CI: FAIL" 패턴 탐지 (대소문자 무관)
            _packet_github_ci_fail = bool(
                re.search(r'github_ci:\s*FAIL', _pkt_text_mt24, re.IGNORECASE)
                or re.search(r'GitHub CI:\s*FAIL', _pkt_text_mt24, re.IGNORECASE)
            )
            # 실제 gate 상태 확인
            _state_mt24 = _load()
            _actual_github_ci_mt24 = "UNKNOWN"
            if isinstance(_state_mt24, dict):
                _actual_github_ci_mt24 = str(
                    (_state_mt24.get("external_gates") or {}).get("github_ci", {}).get("status", "UNKNOWN")
                )
            if _packet_github_ci_fail and _actual_github_ci_mt24 == "PASS":
                return {
                    "ok": False,
                    "failure_code": "packet_github_ci_stale",
                    "message": (
                        "PR body final packet에 'github_ci: FAIL'이 표시되지만 "
                        "실제 external_gates.github_ci.status는 PASS입니다. "
                        "'python pipeline.py report final-packet && python pipeline.py report update-pr-body'로 "
                        "packet을 재생성한 후 gates request-accept를 다시 실행하세요."
                    ),
                }
    except Exception:
        pass  # packet 읽기 실패는 non-fatal (구 포맷/파일 없음)

    # 검사 8 (MT-27): CI final-check 댓글이 "정보 부족"이면 final_check.yml 자동 트리거 후 폴링.
    # CI가 없거나 댓글 없음(NOT_FOUND)이면 graceful skip (self-hosted CI 환경 등).
    try:
        _ci_fc = _get_ci_final_check_status()
        if _ci_fc.get("status") == "FAIL":
            # 자동 트리거: gh workflow run final_check.yml
            _pr_num = _current_pr_number_for_canonical()
            try:
                _branch_result = subprocess.run(
                    ["git", "rev-parse", "--abbrev-ref", "HEAD"],
                    capture_output=True, text=True, timeout=10
                )
                _branch_raw = _branch_result.stdout.strip() if _branch_result.returncode == 0 else ""
            except Exception:
                _branch_raw = ""
            _repo = "hojiyong2-commits/Pipeline"
            if _pr_num and _branch_raw:
                try:
                    _trigger_result = subprocess.run(
                        ["gh", "workflow", "run", "final_check.yml",
                         "--repo", _repo,
                         "--ref", _branch_raw.strip(),
                         "--field", f"pr_number={_pr_num}"],
                        capture_output=True, text=True, timeout=30
                    )
                    if _trigger_result.returncode == 0:
                        # 최대 120초 폴링 (5초 간격)
                        import time as _time_fc
                        for _poll_i in range(24):
                            _time_fc.sleep(5)
                            _ci_fc2 = _get_ci_final_check_status()
                            if _ci_fc2.get("status") == "PASS":
                                _ci_fc = _ci_fc2
                                break
                except Exception:
                    pass

            if _ci_fc.get("status") == "FAIL":
                return {
                    "ok": False,
                    "failure_code": "ci_final_check_insufficient",
                    "message": (
                        "GitHub Actions final-check 댓글이 '정보 부족'을 표시합니다.\n"
                        f"사유: {_ci_fc.get('reason', 'unknown')}\n"
                        "해결: python pipeline.py report final-packet && "
                        "python pipeline.py report update-pr-body\n"
                        "이후 request-accept를 재실행하세요."
                    ),
                }
    except Exception:
        pass  # CI 댓글 조회 실패는 non-fatal — graceful skip

    # 검사 9 (IMP-20260703-B985 MT-28): Codex PR body SHA 검사 (non-blocking WARN).
    # codex_review_result.json에 pr_body_sha256(또는 pr_body_candidate_sha256)가 기록돼 있으면,
    # 향후 strict mode(ENABLE_CODEX_SHA_CHECK=1)에서 acceptance_request/PR body canonical SHA와
    # 대조하는 hard gate로 승격할 수 있다. 현재는 WARN 구조만 유지하며 승인 요청을 차단하지 않는다.
    try:
        _codex_path9 = _codex_review_result_path()
        if _codex_path9.exists():
            _codex_data9 = json.loads(
                _codex_path9.read_text(encoding="utf-8", errors="replace")
            )
            if isinstance(_codex_data9, dict):
                _codex_sha9 = (
                    _codex_data9.get("pr_body_sha256")
                    or _codex_data9.get("pr_body_candidate_sha256")
                )
                if _codex_sha9:
                    # non-blocking: WARN만. strict 처리는 ENABLE_CODEX_SHA_CHECK=1 도입 시 추가.
                    pass  # 현재는 WARN 구조만, strict 처리는 향후 추가
    except Exception:
        pass  # codex_review_result 읽기 실패는 non-fatal — graceful skip

    # 검사 10 (MT-25): oracle gate PASS인데 packet에 oracle FAIL 표시 있으면 BLOCKED
    try:
        _state_mt25 = _load()
        _actual_oracle_mt25 = "UNKNOWN"
        if isinstance(_state_mt25, dict):
            _actual_oracle_mt25 = str(
                (_state_mt25.get("external_gates") or {}).get("oracle", {}).get("status", "UNKNOWN")
            )
        if _actual_oracle_mt25 == "PASS":
            _pkt_path_mt25 = _packet_output_path()
            if _pkt_path_mt25.exists():
                _pkt_text_mt25 = _pkt_path_mt25.read_text(encoding="utf-8", errors="replace")
                # oracle FAIL 표시 감지 (대소문자 무관)
                _packet_oracle_fail = bool(
                    re.search(r'oracle:\s*FAIL', _pkt_text_mt25, re.IGNORECASE)
                    or re.search(r'Oracle Gate:\s*FAIL', _pkt_text_mt25, re.IGNORECASE)
                )
                if _packet_oracle_fail:
                    return {
                        "ok": False,
                        "failure_code": "oracle_summary_gate_mismatch",
                        "message": (
                            "PR body final packet에 'oracle: FAIL'이 표시되지만 "
                            "실제 external_gates.oracle.status는 PASS입니다. "
                            "'python pipeline.py report final-packet && python pipeline.py report update-pr-body'로 "
                            "packet을 재생성한 후 gates request-accept를 다시 실행하세요."
                        ),
                    }
                # oracle 통과 수 < 전체 수 감지: "N passed, M cases" 또는 "N/M"
                _oracle_count_match = re.search(
                    r'(\d+)\s*passed[^\n]*?[\s,/]\s*(\d+)',
                    _pkt_text_mt25,
                    re.IGNORECASE,
                )
                if _oracle_count_match:
                    _passed_n = int(_oracle_count_match.group(1))
                    _total_m = int(_oracle_count_match.group(2))
                    if _passed_n < _total_m:
                        return {
                            "ok": False,
                            "failure_code": "oracle_summary_gate_mismatch",
                            "message": (
                                f"PR body final packet에 oracle 통과 수({_passed_n}개)가 "
                                f"전체 케이스 수({_total_m}개)보다 적습니다. "
                                "oracle gate가 PASS인데 packet이 오래된 상태입니다. "
                                "'python pipeline.py report final-packet && python pipeline.py report update-pr-body'로 "
                                "packet을 재생성한 후 gates request-accept를 다시 실행하세요."
                            ),
                        }
    except Exception:
        pass  # oracle 검사 실패는 non-fatal — graceful skip

    return {"ok": True, "failure_code": "", "message": ""}


# [Purpose]: acceptance_request.json 을 ACCEPTED(CONSUMED)로 갱신하면서 승인 provenance
#            감사 필드(누가/어떤 출처로/어느 댓글에서 승인했는지)를 함께 기록한다.
#            BUG-20260616-8011: agent 자동 ACCEPT 사고 추적을 위해 user_acceptance_source /
#            source_comment_id 감사 필드를 추가한다.
# [Assumptions]: 호출 전에 provenance/nonce 검증이 모두 통과한 상태이며, accepted_by 는
#                실제 GitHub PR 댓글 작성자(허용 승인자)이다.
# [Vulnerability & Risks]: 같은 OS user / GitHub 토큰을 공유하면 감사 필드만으로 완전한
#                          암호학적 분리는 불가능하다. 감사 필드는 사후 추적용 증거이다.
# [Improvement]: 외부 서명자/별도 러너로 승인 출처를 서명하면 위 한계를 해소할 수 있다.
def _consume_acceptance_request(
    req: Dict[str, Any],
    result: str,
    *,
    accepted_by: Optional[str] = None,
    user_acceptance_source: Optional[str] = None,
    source_comment_id: Optional[str] = None,
) -> None:
    """acceptance_request.json 상태를 ACCEPTED(CONSUMED)로 갱신하여 재기록.

    IMP-20260614-D278 MT-4: accepted_at / accepted_by / consumed_nonce 필드를 추가하여
    승인 provenance를 acceptance_request.json에 함께 기록한다. 기존 status="CONSUMED"와
    consumed_at/consumed_result 필드는 하위 호환을 위해 그대로 유지한다.

    BUG-20260616-8011 MT-1: user_acceptance_source(승인 출처 종류) / source_comment_id
    (승인 코드를 남긴 PR 댓글 id) 감사 필드를 추가하여, agent 자동 ACCEPT 시도를
    사후에 추적할 수 있게 한다.

    Args:
        req: 기존 acceptance_request dict.
        result: ACCEPT 또는 REJECT.
        accepted_by: 승인자 식별자 (provenance_check.approver에서 전달, 기본값 None).
        user_acceptance_source: 승인 출처 종류 (예: "pr_comment"). 기본값 None.
        source_comment_id: 승인 코드를 남긴 PR 댓글 id (provenance_check.comment_id). 기본값 None.
    Raises:
        TypeError: req 또는 result가 None, 또는 타입 불일치.
        ValueError: result가 ACCEPT/REJECT 외 값.
    """
    if req is None:
        raise TypeError("req must not be None")
    if result is None:
        raise TypeError("result must not be None")
    if not isinstance(req, dict):
        raise TypeError(f"req must be dict, got {type(req).__name__}")
    if not isinstance(result, str):
        raise TypeError(f"result must be str, got {type(result).__name__}")
    if result not in {"ACCEPT", "REJECT"}:
        raise ValueError(f"result must be ACCEPT or REJECT, got {result!r}")
    # 표시 상태 레이어: 하위 호환을 위해 status="CONSUMED" 유지.
    # _resolve_acceptance_display_state는 CONSUMED+consumed_result로 ACCEPTED/REJECTED를 계산한다.
    req["status"] = "CONSUMED"
    req["consumed_at"] = _now()
    req["consumed_result"] = result
    req["accepted_at"] = _now()  # 신규 필드 (IMP-20260614-D278 MT-4)
    req["accepted_by"] = accepted_by or ""  # 신규 필드 (provenance_check.approver)
    req["consumed_nonce"] = str(req.get("nonce", "") or "")  # 신규 필드
    # 신규 감사 필드 (BUG-20260616-8011 MT-1): 승인 출처 추적용.
    req["user_acceptance_source"] = user_acceptance_source or "pr_comment"
    req["source_comment_id"] = source_comment_id or ""
    with open(ACCEPTANCE_REQUEST_FILE, "w", encoding="utf-8") as fh:
        json.dump(req, fh, ensure_ascii=False, indent=2)


def _display_path(path: Path) -> str:
    try:
        return str(path.resolve().relative_to(BASE_DIR))
    except ValueError:
        return str(path.resolve())


def _deployment_root() -> Path:
    configured = os.environ.get("PIPELINE_DEPLOY_ROOT", "").strip()
    if configured:
        root = Path(configured)
        parent = root.parent if root.parent != root else root
        if not parent.exists():
            _die(
                "[DEPLOY ROOT BLOCKED] PIPELINE_DEPLOY_ROOT 상위 폴더가 없습니다: "
                f"{parent}. Google Drive를 마운트하거나 PIPELINE_DEPLOY_ROOT를 실제 존재하는 폴더로 바꾸세요."
            )
        return root
    for candidate in DEFAULT_DEPLOY_ROOT_CANDIDATES:
        if candidate.exists() or candidate.parent.exists():
            return candidate
    candidates = ", ".join(str(path) for path in DEFAULT_DEPLOY_ROOT_CANDIDATES)
    _die(
        "[DEPLOY ROOT BLOCKED] Google Drive 배포 폴더를 찾지 못했습니다. "
        f"확인한 경로: {candidates}. Google Drive를 마운트하거나 PIPELINE_DEPLOY_ROOT를 설정하세요."
    )


PLACEHOLDER_EVIDENCE_VALUES = {"N/A", "NA", "NONE", "SKIP", "SKIPPED", "USER_CONFIRMED", "MANUAL-SMOKE"}


def _split_evidence_items(raw: Any) -> List[str]:
    if raw is None:
        return []
    if isinstance(raw, (list, tuple)):
        items: List[str] = []
        for item in raw:
            items.extend(_split_evidence_items(item))
        return items
    text = str(raw).strip()
    if not text:
        return []
    parts = re.split(r"[,;\n]+", text)
    return [part.strip() for part in parts if part.strip()]


def _split_evidence_paths(raw: Any) -> List[str]:
    return [item for item in _split_evidence_items(raw) if item.upper() not in PLACEHOLDER_EVIDENCE_VALUES]


def _is_evidence_url(raw: str) -> bool:
    return bool(re.match(r"^https?://[^\s]+$", raw.strip(), flags=re.IGNORECASE))


def _validate_pipeline_branch_isolation(state: Dict[str, Any]) -> None:
    """gates prepare-phase --phase pm 실행 시 브랜치가 pipeline_id를 포함하는지 강제 검증."""
    pipeline_id = state["pipeline_id"]
    try:
        result = subprocess.run(
            ["git", "rev-parse", "--abbrev-ref", "HEAD"],
            capture_output=True, text=True, check=True
        )
        current_branch = result.stdout.strip()
    except (subprocess.CalledProcessError, FileNotFoundError):
        return  # git 미사용 환경 — 검사 생략
    protected = ("main", "master", "HEAD")
    if current_branch in protected:
        _die(
            f"[BRANCH ISOLATION] '{current_branch}' 브랜치에서 gates prepare-phase --phase pm을 실행할 수 없습니다.\n"
            f"  파이프라인: {pipeline_id}\n"
            f"  필요 브랜치: phase-attestation/{pipeline_id}\n"
            f"  실행: git checkout -b phase-attestation/{pipeline_id}"
        )
    if pipeline_id not in current_branch:
        _die(
            f"[BRANCH ISOLATION] 현재 브랜치 '{current_branch}'가 파이프라인 ID '{pipeline_id}'를 포함하지 않습니다.\n"
            f"  다른 파이프라인 브랜치에서 push하면 PR이 오염됩니다.\n"
            f"  필요 브랜치: phase-attestation/{pipeline_id}\n"
            f"  실행: git checkout -b phase-attestation/{pipeline_id}"
        )


def _validate_pr_title_matches_pipeline(state: Dict[str, Any]) -> None:
    """gates accept --result ACCEPT 실행 시 열려 있는 PR 제목에 pipeline_id가 포함되는지 검증."""
    pipeline_id = state["pipeline_id"]
    try:
        pr_result = subprocess.run(
            ["gh", "pr", "view", "--json", "title,number,url"],
            capture_output=True, text=True, encoding="utf-8", check=False
        )
        if pr_result.returncode != 0:
            return  # PR 없음 — 다른 gate에서 차단됨
        if not pr_result.stdout:
            return  # stdout 없음 (인코딩 오류 등) — 검사 생략
        pr_data = json.loads(pr_result.stdout)
        pr_title = pr_data.get("title", "")
        pr_number = pr_data.get("number", "?")
        pr_url = pr_data.get("url", "")
        if pipeline_id not in pr_title:
            _die(
                f"[PR TITLE MISMATCH] PR #{pr_number} 제목에 파이프라인 ID가 없습니다.\n"
                f"  현재 PR 제목: '{pr_title}'\n"
                f"  필요한 파이프라인 ID: [{pipeline_id}]\n"
                f"  PR URL: {pr_url}\n"
                f"  수정 후 다시 실행하세요: gh pr edit {pr_number} --title '[{pipeline_id}] ...'"
            )
    except (subprocess.CalledProcessError, FileNotFoundError, json.JSONDecodeError, ValueError):
        return  # gh CLI 미설치 환경 — 검사 생략


