# IMP-20260531-BBDB MT-1: User Acceptance Nonce Gate
# acceptance_request.json 파일명 + ACCEPT/REJECT 코드 정규식.
# nonce는 8자 base32 uppercase (예: A2B3C4D5). pipeline_id 패턴: TYPE-YYYYMMDD-XXXX.
ACCEPTANCE_REQUEST_FILE = "acceptance_request.json"
# BUG-20260628-F52C: request-accept staging이 생성한 frozen packet bytes를 disk에 보존하여
# 별개 subprocess인 gates codex-review --approve-pending이 동일 bytes를 검토하게 한다.
# 이것이 codex_review_result.pr_body_sha256 == acceptance_request.pr_body_sha256
# == sha256(현재 PR body) 3자 불변식을 보장하는 단일 신뢰 루트(frozen bytes)다.
ACCEPTANCE_STAGING_PATH = ".pipeline/acceptance_staging.json"
ACCEPT_CODE_PATTERN = re.compile(r"^ACCEPT-([A-Z]+-\d{8}-[A-Z0-9]{4})-([A-Z2-7]{8})$")
REJECT_CODE_PATTERN = re.compile(r"^REJECT-([A-Z]+-\d{8}-[A-Z0-9]{4})-([A-Z2-7]{8})$")

# PR 본문에 반드시 포함되어야 하는 섹션 헤더 목록 (순서 무관, OR 쌍 지원)
# 형식: str → 단일 필수 / tuple → 안의 항목 중 하나라도 있으면 통과 (OR 조건)
# Blocker 3 수정: 첫 항목에 "최종 판단 요약"을 OR 후보로 추가.
PR_REQUIRED_SECTIONS: List[Any] = [
    ("작업 요약", "최종 판단 요약", "이번 요청과 완료 결과"),  # 셋 중 하나 (OR)
    "사용자가 확인할 결과물",
    "기대 결과와 실제 결과",
    "중요한 선택과 트레이드오프",
    "검증",
]

# Blocker 2: human acceptance packet readiness — GitHub PR 댓글 태그
_ACCEPTANCE_PACKET_COMMENT_TAG = "<!-- pipeline-human-acceptance-packet -->"
# 판단 정보 상태: **정보 부족** 또는 판단 정보 상태: 정보 부족 형태를 매칭.
# 단순 substring "정보 부족"은 false positive를 일으키므로 regex 기반으로 변경.
# "판단 정보 상태: 정보 부족이면 ..." 같은 안내 문구는 PASS.
_ACCEPTANCE_PACKET_INSUFFICIENT_MARKER = "정보 부족"  # 레거시 참조용 (삭제 금지)
_ACCEPTANCE_PACKET_INSUFFICIENT_PATTERN = re.compile(
    r"판단\s*정보\s*상태\s*:\s*\*{0,2}\s*정보\s*부족\s*\*{0,2}"
)
_ACCEPTANCE_PACKET_SUFFICIENT_MARKER = "판단 가능"
# PR URL → owner/repo 추출용 정규식 (모듈 레벨 1회 컴파일 — Rule D2)
_PR_URL_REPO_PATTERN = re.compile(
    r"github\.com/([^/]+/[^/]+)/pull/(\d+)"
)

# BUG-20260614-32D7: acceptance 댓글 marker 분리 상수 (SSoT — Rule D1 중복 방지).
# 공통 marker만 공유하던 3종 댓글(CI 최종 확인 안내 / pending 승인 요청 / accepted 완료)을
# marker 레벨에서 구분한다.
#  - 공통 marker: 모든 acceptance 관련 댓글에 존재 (기존 코드 호환성 유지)
#  - final-check marker: CI가 만드는 "최종 확인 안내" 댓글 전용
#  - pending marker: gates request-accept가 만드는 PENDING 승인 요청 댓글 전용
#  - accepted marker: gates accept 성공 후 만드는 ACCEPTED 완료 댓글 전용
_ACCEPTANCE_PACKET_FINAL_CHECK_MARKER = "pipeline-final-check-packet"
_ACCEPTANCE_PACKET_PENDING_MARKER = "pipeline-human-acceptance-packet-pending"
_ACCEPTANCE_PACKET_ACCEPTED_MARKER = "pipeline-human-acceptance-packet-accepted"


def _is_pending_or_accepted_acceptance_comment(body: str) -> bool:
    """댓글 본문이 pending 승인 요청 또는 accepted 완료 댓글인지 판정한다.

    [Purpose]: BUG-20260614-32D7 — pending/accepted 댓글 교체 시 CI 최종 확인 안내
      (final-check marker만 있는) 댓글을 잘못 삭제하지 않도록 삭제 대상을 한정한다.
    [Assumptions]: body는 GitHub 댓글 본문 문자열. None/비문자열은 False로 안전 처리.
    [Vulnerability & Risks]: marker 문자열이 변경되면 판정이 깨진다 — 상수 SSoT로 관리.
    [Improvement]: 향후 marker가 늘어나면 집합 기반으로 확장 가능.

    Args:
        body: 검사할 댓글 본문 문자열.
    Returns:
        pending 또는 accepted marker가 본문에 있으면 True, 아니면 False.
    """
    if not body or not isinstance(body, str):
        return False  # None/빈 문자열/비문자열은 삭제 대상 아님 (안전 측 default)
    return (
        _ACCEPTANCE_PACKET_PENDING_MARKER in body
        or _ACCEPTANCE_PACKET_ACCEPTED_MARKER in body
    )


def _is_final_check_only_comment(body: str) -> bool:
    """댓글이 CI 최종 확인 안내(final-check marker만)이고 pending/accepted가 아닌지 판정한다.

    [Purpose]: BUG-20260614-32D7 MT-4 — acceptance packet 조회 시 final-check 전용
      댓글을 승인 댓글로 오인하지 않도록 제외한다.
    [Assumptions]: body는 GitHub 댓글 본문 문자열. None/비문자열은 False.
    [Vulnerability & Risks]: marker 문자열 변경 시 판정 깨짐 — 상수 SSoT로 관리.
    [Improvement]: 향후 다른 비승인 댓글 유형도 동일 패턴으로 확장 가능.

    Args:
        body: 검사할 댓글 본문 문자열.
    Returns:
        final-check marker가 있고 pending/accepted marker가 없으면 True, 아니면 False.
    """
    if not body or not isinstance(body, str):
        return False
    if _ACCEPTANCE_PACKET_FINAL_CHECK_MARKER not in body:
        return False
    return not (
        _ACCEPTANCE_PACKET_PENDING_MARKER in body
        or _ACCEPTANCE_PACKET_ACCEPTED_MARKER in body
    )


def _find_temporary_pr_body_pattern(pr_body: str) -> Optional[str]:
    """PR 본문에 임시(placeholder) 문구가 줄 단위로 존재하면 그 패턴을 반환한다.

    매칭 규칙: 본문을 줄 단위로 끊고, 각 줄을 strip한 뒤
    그 줄이 TEMPORARY_PR_BODY_PATTERNS 중 하나로 "시작"하면 임시 문구로 간주한다.
    (정상 PR이 문장 중간에 'Draft PR' 같은 단어를 설명용으로 언급하는 경우는
     거짓 양성으로 차단하지 않기 위해 substring 전체 검색을 쓰지 않는다.)

    Args:
        pr_body: PR 본문 전체 텍스트.
    Returns:
        탐지된 임시 문구 패턴 문자열. 없으면 None.
    """
    if not pr_body:
        return None
    for raw_line in pr_body.splitlines():
        line = raw_line.strip()
        if not line:
            continue
        for pattern in TEMPORARY_PR_BODY_PATTERNS:
            if line.startswith(pattern):
                return pattern
    return None


# [Purpose]: IMP-20260703-B985 MT-34 (REJECT #27) — 사용자 판단 자료(PR body)의 무결성을
#   검증하여 (1) UTF-8 BOM으로 시작, (2) PIPELINE_FINAL_PACKET_END 뒤 stale acceptance 상태,
#   (3) requirements_summary N/A 세 케이스를 request-accept 이전에 차단한다.
# [Assumptions]: pr_body_text는 gh CLI가 반환한 PR 본문 문자열, requirements_summary는
#   packet 계산값 문자열. 둘 다 None이 아니어야 하며 비문자열이면 TypeError를 던진다.
# [Vulnerability & Risks]: stale 패턴이 정상 문장 중간에 등장하면 false positive가 될 수 있으나,
#   PR_BODY_STALE_PATTERNS는 "acceptance: FAIL/REJECTED" 형태의 메타데이터 줄만 매칭한다.
# [Improvement]: 향후 stale 패턴을 줄-접두 매칭으로 좁혀 오탐 가능성을 더 줄일 수 있다.
def _check_pr_body_user_facing(pr_body_text: str, requirements_summary: str) -> Dict[str, str]:
    """사용자 판단 자료(PR body)의 무결성을 검증한다.

    BOM, stale acceptance 상태, requirements_summary N/A를 차단한다. 부수효과 없는 pure 함수.

    Args:
        pr_body_text: 검사할 PR 본문 문자열. None 금지.
        requirements_summary: packet의 requirements_summary 표시값. None 금지 (빈 문자열 허용).
    Returns:
        status=PASS 또는 status=BLOCKED(+failure_code, message)를 담은 dict.
    Raises:
        TypeError: pr_body_text 또는 requirements_summary가 None/비문자열인 경우.
    """
    if pr_body_text is None:
        raise TypeError("pr_body_text must not be None")
    if not isinstance(pr_body_text, str):
        raise TypeError(
            f"pr_body_text must be str, got {type(pr_body_text).__name__}"
        )
    if requirements_summary is None:
        raise TypeError("requirements_summary must not be None")
    if not isinstance(requirements_summary, str):
        raise TypeError(
            f"requirements_summary must be str, got {type(requirements_summary).__name__}"
        )

    # 1. BOM 검사 — 유니코드 BOM 문자(﻿) 또는 UTF-8 BOM bytes(EF BB BF)로 시작 시 차단.
    if pr_body_text.startswith("﻿") or pr_body_text.encode("utf-8").startswith(
        b"\xef\xbb\xbf"
    ):
        return {
            "status": "BLOCKED",
            "failure_code": "pr_body_bom_detected",
            "message": (
                "PR body가 UTF-8 BOM으로 시작합니다. "
                "report update-pr-body를 다시 실행하세요."
            ),
        }

    # 2. PIPELINE_FINAL_PACKET_END 뒤 stale acceptance 상태 검사.
    end_marker = PIPELINE_FINAL_PACKET_END_MARKER
    if end_marker in pr_body_text:
        after_packet = pr_body_text.split(end_marker, 1)[1]
        for pattern in PR_BODY_STALE_PATTERNS:
            if re.search(pattern, after_packet, re.MULTILINE | re.IGNORECASE):
                return {
                    "status": "BLOCKED",
                    "failure_code": "pr_body_stale_metrics_block",
                    "message": (
                        "PIPELINE_FINAL_PACKET_END 뒤에 stale acceptance 상태가 있습니다. "
                        "report update-pr-body를 다시 실행하세요."
                    ),
                }

    # 3. packet 블록 외부(앞)에 stale acceptance 상태 검사.
    start_marker = PIPELINE_FINAL_PACKET_START_MARKER
    if start_marker in pr_body_text:
        before_packet = pr_body_text.split(start_marker, 1)[0]
    else:
        before_packet = pr_body_text
    for pattern in PR_BODY_STALE_PATTERNS:
        if re.search(pattern, before_packet, re.MULTILINE | re.IGNORECASE):
            return {
                "status": "BLOCKED",
                "failure_code": "pr_body_stale_acceptance_fail",
                "message": (
                    "PR body에 stale acceptance: FAIL 상태가 있습니다. "
                    "PR body를 업데이트하세요."
                ),
            }

    # 4. requirements_summary N/A 검사.
    if requirements_summary and requirements_summary.strip() in _REQUIREMENTS_SUMMARY_NA_VALUES:
        return {
            "status": "BLOCKED",
            "failure_code": "pr_body_requirements_summary_na",
            "message": (
                "requirements_summary가 N/A입니다. structured AC를 추가하거나 "
                "legacy_no_ac_reason을 pipeline state에 명시하세요."
            ),
        }

    return {"status": "PASS"}


# [Purpose]: IMP-20260703-B985 MT-34 — PIPELINE_FINAL_PACKET_END 뒤에 남은 stale metrics
#   메타데이터 라인(acceptance:/technical:/oracle:/github_ci:/ci_run_id:/pr_head_sha:)을 제거한다.
# [Assumptions]: text는 PR 본문 문자열. 한국어 섹션(#..######로 시작)이 나오면 이후 내용은 보존.
# [Vulnerability & Risks]: metrics 라인 형식이 바뀌면 매칭이 깨진다 — 패턴 목록으로 관리.
# [Improvement]: 향후 마커 기반으로 stale 블록 범위를 명시적으로 감쌀 수 있다.
def _strip_stale_metrics_block(text: str) -> str:
    """PIPELINE_FINAL_PACKET_END 뒤의 stale metrics 블록만 제거한다.

    END 마커 앞(신선한 FINAL_PACKET 블록 포함)은 절대 건드리지 않는다. END 마커 뒤에서만
    stale metrics 라인(acceptance:/technical:/oracle:/github_ci:/ci_run_id:/pr_head_sha:)을
    제거하며, 한국어/마크다운 섹션 헤더(#로 시작)가 나오면 제거를 멈추고 이후 내용을 보존한다.

    Args:
        text: PR 본문 문자열. None 금지.
    Returns:
        END 마커 뒤 stale metrics 라인이 제거된 문자열. END 마커가 없으면 원본 그대로.
    Raises:
        TypeError: text가 None/비문자열인 경우.
    """
    if text is None:
        raise TypeError("text must not be None")
    if not isinstance(text, str):
        raise TypeError(f"text must be str, got {type(text).__name__}")

    end_marker = PIPELINE_FINAL_PACKET_END_MARKER
    if end_marker not in text:
        return text  # 정리 대상 없음

    _stale_line_patterns = [
        r"^\s*acceptance:\s+",
        r"^\s*technical:\s+",
        r"^\s*oracle:\s+",
        r"^\s*github_ci:\s+",
        r"^\s*ci_run_id:\s+",
        r"^\s*pr_head_sha:\s+",
    ]
    head, tail = text.split(end_marker, 1)
    kept: List[str] = []
    stripping = True  # END 마커 직후 — stale metrics 제거 모드
    for line in tail.split("\n"):
        # 한국어/마크다운 섹션 헤더가 시작되면 제거 모드 종료 후 이후 내용 모두 보존.
        if re.match(r"^#{1,6}\s+", line):
            stripping = False
        if stripping and any(re.match(p, line) for p in _stale_line_patterns):
            continue  # END 마커 뒤 stale metrics 라인 제거
        kept.append(line)
    return head + end_marker + "\n".join(kept)


def _acceptance_blocked(
    failure_code: str,
    blocked_reason: str,
    *,
    return_phase: str = "build",
    missing_sections: Optional[List[str]] = None,
) -> Dict[str, Any]:
    """_check_acceptance_readiness용 BLOCKED 결과 dict 생성 헬퍼.

    Args:
        failure_code: 실패 원인 코드 (failure_packet schema_v2의 failure_code).
        blocked_reason: 사용자에게 보여줄 차단 사유 (한국어).
        return_phase: 재작업 담당 phase (기본 build).
        missing_sections: PR 본문 누락 섹션 목록 (없으면 빈 리스트).
    Returns:
        status=BLOCKED, allow_accept=False인 결과 dict.
    """
    return {
        "status": "BLOCKED",
        "failure_code": failure_code,
        "failure_category": "missing_evidence",
        "blocked_reason": blocked_reason,
        "missing_sections": list(missing_sections) if missing_sections else [],
        "return_phase": return_phase,
        "allow_accept": False,
    }


def _check_acceptance_packet_via_github(pr_url: str) -> Dict[str, Any]:
    """GitHub PR 댓글에서 human acceptance packet readiness를 검증한다.

    Blocker 2: 로컬 파일 대신 GitHub PR 댓글을 기본 검증 대상으로 한다.
    `<!-- pipeline-human-acceptance-packet -->` 태그 댓글을 찾아
    '판단 가능'/'정보 부족' 상태를 판정한다.

    Args:
        pr_url: gh pr view 가 반환한 PR URL (owner/repo/pr_number 추출용).
    Returns:
        status=PASS 또는 status=BLOCKED 결과 dict.
        - 태그 댓글 없음 → acceptance_packet_missing
        - 댓글에 '정보 부족' → acceptance_packet_insufficient
        - 댓글 조회 실패(API/네트워크) → pr_comments_fetch_failed
        - '판단 가능' 확인 → PASS
    """
    pass_result: Dict[str, Any] = {
        "status": "PASS",
        "failure_code": "",
        "failure_category": "",
        "blocked_reason": None,
        "missing_sections": [],
        "allow_accept": True,
    }

    # PR URL에서 owner/repo, PR 번호 추출
    match = _PR_URL_REPO_PATTERN.search(pr_url or "")
    if match is None:
        return _acceptance_blocked(
            "pr_comments_fetch_failed",
            (
                f"PR URL에서 저장소/번호를 추출하지 못해 acceptance packet 댓글을 "
                f"조회할 수 없습니다: '{pr_url}'. PR 상태를 확인한 뒤 다시 실행하세요."
            ),
        )
    repo_slug = match.group(1)
    pr_number = match.group(2)

    # gh api 로 PR 댓글 목록 조회
    try:
        comments_result = subprocess.run(
            ["gh", "api", f"repos/{repo_slug}/issues/{pr_number}/comments",
             "--paginate"],
            capture_output=True, text=True, encoding="utf-8", check=False,
        )
    except (FileNotFoundError, OSError) as exc:
        return _acceptance_blocked(
            "pr_comments_fetch_failed",
            (
                f"GitHub PR 댓글 조회에 실패했습니다(gh CLI 오류: {exc}). "
                "네트워크와 gh 인증 상태를 확인한 뒤 다시 실행하세요."
            ),
        )

    if comments_result.returncode != 0:
        return _acceptance_blocked(
            "pr_comments_fetch_failed",
            (
                "GitHub PR 댓글 조회에 실패했습니다"
                f"(gh api exit code {comments_result.returncode}). "
                + ((comments_result.stderr or "").strip()[:200])
                + " 네트워크와 gh 인증 상태를 확인한 뒤 다시 실행하세요."
            ),
        )

    raw_stdout = (comments_result.stdout or "").strip()
    if not raw_stdout:
        # 댓글이 0개여도 acceptance packet 댓글은 없는 것 — missing 처리
        return _acceptance_blocked(
            "acceptance_packet_missing",
            (
                "GitHub PR에 사용자 판단용 acceptance packet 댓글이 없습니다. "
                "최종 확인 안내 댓글이 게시된 뒤 다시 실행하세요."
            ),
        )

    try:
        comments = json.loads(raw_stdout)
    except (json.JSONDecodeError, ValueError) as exc:
        return _acceptance_blocked(
            "pr_comments_fetch_failed",
            (
                f"GitHub PR 댓글 응답을 해석하지 못했습니다(JSON 오류: {exc}). "
                "잠시 후 다시 실행하세요."
            ),
        )

    if not isinstance(comments, list):
        return _acceptance_blocked(
            "pr_comments_fetch_failed",
            (
                "GitHub PR 댓글 응답 형식이 올바르지 않습니다. "
                "잠시 후 다시 실행하세요."
            ),
        )

    # acceptance packet 태그 댓글 탐색
    packet_comment_body: Optional[str] = None
    # BUG-20260614-32D7 MT-4: 댓글 선택 우선순위를 명확히 한다.
    #  (1) pending marker(pipeline-human-acceptance-packet-pending) 댓글을 최우선 선택
    #  (2) pending이 없으면 공통 marker만 있는 댓글(legacy 호환)을 선택
    #  (3) final-check marker만 있고 pending/accepted가 없는 CI 최종 확인 안내 댓글은
    #      승인 packet으로 오인하지 않도록 항상 제외한다.
    pending_comment_body: Optional[str] = None
    legacy_comment_body: Optional[str] = None
    for comment in comments:
        if not isinstance(comment, dict):
            continue
        body = comment.get("body") or ""
        if _ACCEPTANCE_PACKET_COMMENT_TAG not in body:
            continue
        if _is_final_check_only_comment(body):
            continue  # CI 최종 확인 안내 전용 댓글 — approval packet 아님
        if _ACCEPTANCE_PACKET_PENDING_MARKER in body:
            pending_comment_body = body  # 최신 pending 댓글 우선
        else:
            legacy_comment_body = body  # 공통 marker만 있는 legacy 댓글 (fallback)
    packet_comment_body = pending_comment_body or legacy_comment_body

    if packet_comment_body is None:
        return _acceptance_blocked(
            "acceptance_packet_missing",
            (
                "GitHub PR에 사용자 판단용 acceptance packet 댓글이 없습니다"
                f"('{_ACCEPTANCE_PACKET_COMMENT_TAG}' 태그 미발견). "
                "최종 확인 안내 댓글이 게시된 뒤 다시 실행하세요."
            ),
        )

    # 정보 부족 우선 검사 (정보 부족이 있으면 판단 가능 문구가 있어도 BLOCKED)
    # AB-1: regex 기반 검사 — "판단 정보 상태: 정보 부족" 형식만 매칭
    # 단순 substring은 "판단 정보 상태가 정보 부족이면..." 같은 안내 문구를 false positive 처리함
    if _ACCEPTANCE_PACKET_INSUFFICIENT_PATTERN.search(packet_comment_body):
        return _acceptance_blocked(
            "acceptance_packet_insufficient",
            (
                "GitHub PR의 acceptance packet 댓글 판단 정보 상태가 '정보 부족'입니다. "
                "PR 본문과 acceptance packet 댓글을 보완한 뒤 다시 실행하세요."
            ),
        )

    if _ACCEPTANCE_PACKET_SUFFICIENT_MARKER in packet_comment_body:
        return pass_result

    # 태그 댓글은 있으나 판단 가능/정보 부족 상태 표기가 없음 — 불완전 packet
    return _acceptance_blocked(
        "acceptance_packet_insufficient",
        (
            "GitHub PR의 acceptance packet 댓글에 판단 정보 상태"
            f"('{_ACCEPTANCE_PACKET_SUFFICIENT_MARKER}'/'"
            f"{_ACCEPTANCE_PACKET_INSUFFICIENT_MARKER}') 표기가 없습니다. "
            "acceptance packet 댓글을 보완한 뒤 다시 실행하세요."
        ),
    )


def _check_acceptance_packet_via_local_file(state: Dict[str, Any]) -> Dict[str, Any]:
    """로컬 human_acceptance_packet*.md 파일로 readiness를 검증하는 fallback.

    Blocker 2: 테스트 환경 전용 fallback. 환경변수
    PIPELINE_TEST_ACCEPTANCE_PACKET_PATH 가 설정된 경우 해당 경로를 우선 사용한다.

    Args:
        state: 파이프라인 state dict (pipeline_id 추출용).
    Returns:
        status=PASS 또는 status=BLOCKED 결과 dict.
    """
    pass_result: Dict[str, Any] = {
        "status": "PASS",
        "failure_code": "",
        "failure_category": "",
        "blocked_reason": None,
        "missing_sections": [],
        "allow_accept": True,
    }

    pid = str(state.get("pipeline_id") or "")
    env_override = os.environ.get("PIPELINE_TEST_ACCEPTANCE_PACKET_PATH", "").strip()
    packet_candidates: List[Path] = []
    if env_override:
        packet_candidates.append(Path(env_override))
    packet_candidates.extend([
        BASE_DIR / f"human_acceptance_packet_{pid}.md",
        BASE_DIR / "human_acceptance_packet_v2.md",
        BASE_DIR / "human_acceptance_packet.md",
    ])

    for packet_path in packet_candidates:
        if packet_path.is_file():
            try:
                packet_text = packet_path.read_text(encoding="utf-8")
            except OSError:
                break  # 읽기 실패 시 검사 생략
            # AB-1: regex 기반 검사 — "판단 정보 상태: 정보 부족" 형식만 매칭
            if _ACCEPTANCE_PACKET_INSUFFICIENT_PATTERN.search(packet_text):
                return _acceptance_blocked(
                    "acceptance_packet_insufficient",
                    (
                        "human acceptance packet의 판단 정보 상태가 '정보 부족'입니다. "
                        "PR 본문과 acceptance packet을 보완한 뒤 다시 실행하세요."
                    ),
                )
            break  # 첫 번째 존재 파일만 검사

    return pass_result


# ===================================================================
# IMP-20260520-D0BB: Protocol Consistency Guard
# [Purpose]: gates accept 전 PR body / acceptance packet / 실제 CI run ID /
#   head SHA / changed files 사이의 불일치를 hard gate로 차단한다.
#   IMP-20260519-E979가 "정보 부족"을 막는다면, 이 가드는 "정보 불일치"를 막는다.
# [Assumptions]: 호출자(_run_protocol_consistency_check)가 gh CLI로 수집한
#   PR 메타데이터를 인자로 전달한다. 이 함수 자체는 순수 함수이며 외부 I/O 없음.
# [Vulnerability & Risks]: PR body 자유 형식 텍스트를 정규식으로 파싱하므로,
#   비정형 본문에서 run ID / SHA / 파일명을 놓칠 수 있다. 이를 false PASS로
#   흘리지 않도록, 추출 실패 시 해당 검사는 SKIP하고 다른 검사로 넘어간다.
# [Improvement]: PR body에 기계가 읽는 구조화 블록(예: HTML 주석 JSON)을
#   강제하면 정규식 의존을 제거할 수 있다.
# ===================================================================

# acceptance packet 식별 태그 — _ACCEPTANCE_PACKET_COMMENT_TAG 재사용
# GitHub Actions run ID 추출 정규식 (모듈 레벨 1회 컴파일 — Rule D2)
# "runs/\d+" URL 기반 추출: "dev-abc123", "pm_planner-xxx" 등
# phase attestation receipt run ID는 URL에 "runs/"가 없으므로 자동 제외됨.
_CONSISTENCY_RUN_ID_PATTERN = re.compile(r"runs/(\d+)")
# head SHA 추출 정규식 (7~40자리 16진수, 단어 경계)
_CONSISTENCY_SHA_PATTERN = re.compile(r"\b([0-9a-f]{7,40})\b")
# 테스트 통과 수 추출 정규식 (예: "434 PASS", "408 passed")
_CONSISTENCY_TEST_COUNT_PATTERN = re.compile(
    r"(\d+)\s*(?:PASS|passed|tests?\s*PASS)"
)
# trust-root 파일 / 패턴 (PR body 설명 의무 대상)
CONSISTENCY_TRUST_ROOT_FILES = [
    "pipeline.py", "CLAUDE.md", ".bandit", ".gitattributes",
    "setup.cfg", "pyproject.toml",
]
CONSISTENCY_TRUST_ROOT_PATTERNS = [
    ".claude/", ".github/workflows/", ".github/CODEOWNERS", "tests/", "test_",
]


def _consistency_extract_run_ids(text: str) -> List[str]:
    """텍스트에서 GitHub Actions run ID(숫자)를 모두 추출한다.

    Args:
        text: 검색 대상 텍스트 (PR body 또는 acceptance packet).
    Returns:
        추출된 run ID 문자열 리스트 (중복 제거, 등장 순서 유지).
    """
    if not text:
        return []
    found: List[str] = []
    for match in _CONSISTENCY_RUN_ID_PATTERN.findall(text):
        if match not in found:
            found.append(match)
    return found


def _consistency_extract_shas(text: str) -> List[str]:
    """텍스트에서 16진수 SHA 후보(7~40자리)를 모두 추출한다.

    Args:
        text: 검색 대상 텍스트.
    Returns:
        추출된 SHA 후보 문자열 리스트 (중복 제거, 등장 순서 유지).
    """
    if not text:
        return []
    found: List[str] = []
    for match in _CONSISTENCY_SHA_PATTERN.findall(text):
        if match not in found:
            found.append(match)
    return found


def _consistency_extract_packet_block(pr_body: str) -> str:
    """PR 본문에서 PIPELINE_FINAL_PACKET 블록 안 텍스트만 추출한다.

    IMP-20260605-9EF5: 검사 A(run_id) / 검사 B(head SHA)는 PR 본문 전체가 아닌
    이 블록 안의 텍스트만 보조 검증 대상으로 사용한다. 블록 밖 자유서술의
    run_id/SHA는 검증 대상이 아니다 — pipeline.py가 자동 생성한 verification_json과
    PIPELINE_FINAL_PACKET 블록 안의 값만 SSoT로 신뢰한다.

    마커 상수 (PIPELINE_FINAL_PACKET_START_MARKER / END_MARKER)는 line ~9982에
    정의되며, Python은 함수 호출 시점에 모듈 글로벌을 lookup하므로 forward-reference로
    문제없이 동작한다.

    Args:
        pr_body: PR 본문 전체 텍스트.
    Returns:
        블록 안 텍스트 (시작 마커 이후 ~ 종료 마커 이전). 블록이 없거나
        마커 순서가 잘못되었으면 빈 문자열.
    """
    # [Purpose]: PR 본문에서 SSoT 검증 대상 텍스트(블록 안)만 분리한다.
    # [Assumptions]: PIPELINE_FINAL_PACKET 마커 상수가 모듈 글로벌로 존재한다.
    # [Vulnerability & Risks]: 마커 문자열이 본문 다른 곳에 우연히 같은 형태로
    #   포함되면 오인할 수 있으나, HTML 주석 형태(<!-- ... -->)라 사용자가
    #   문서 본문에 실수로 쓸 확률이 극히 낮다.
    # [Improvement]: 향후 마커 사이에 여러 블록이 있을 경우 첫 번째 블록만 사용하므로,
    #   복수 블록 처리가 필요해지면 모든 블록을 join하도록 확장 가능.
    if pr_body is None:
        return ""
    if not isinstance(pr_body, str):
        return ""
    if not pr_body:
        return ""
    start = pr_body.find(PIPELINE_FINAL_PACKET_START_MARKER)
    end = pr_body.find(PIPELINE_FINAL_PACKET_END_MARKER)
    if start == -1 or end == -1 or end <= start:
        return ""
    return pr_body[start + len(PIPELINE_FINAL_PACKET_START_MARKER):end]


def _consistency_listed_files(text: str) -> "tuple[set, bool]":
    """PR body / packet의 불릿 목록(`- 파일`, `* 파일`)에서 파일명을 추출한다.

    @deprecated IMP-20260605-58BF MT-2: _check_protocol_consistency에 verification_json이
    제공될 때 검사 D/F는 이 함수 대신 JSON의 changed_files 필드를 사용한다.
    이 함수는 verification_json이 없는 하위 호환 경로에서만 계속 사용된다.

    불릿 첫 토큰 중 `.`(확장자/숨김파일) 또는 `/`(경로 구분자)를 포함하는
    토큰만 파일 후보로 인정한다. `- 장점: 빠름`, `- python -m pytest` 같은
    서술/명령 텍스트의 첫 토큰은 파일이 아니므로 제외한다 (비파일 오탐 방지,
    IMP-20260521-90F4 MT-1).

    AB-2 (BUG-20260521-C675): bold 마커(**) 및 em dash(—) 뒤 설명을 정규화한다.
    AB-3 (BUG-20260521-C675): `...`, `... 외 N개 파일`, `and N more files` 같은
    truncation marker를 파일명으로 취급하지 않는다.

    Args:
        text: 검색 대상 텍스트.
    Returns:
        (files, truncated) — 파일명 집합과 truncation 감지 여부.
    """
    # AB-3: truncation marker 패턴 (파일명으로 취급하지 않음)
    _TRUNCATION_PATTERN = re.compile(
        r"^\.\.\.$|^\.{3}\s*외\s*\d+\s*개?\s*파일|^and\s+\d+\s+more\s+files?",
        re.IGNORECASE,
    )
    if not text:
        return set(), False
    files: set = set()
    truncated = False
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if not (line.startswith("- ") or line.startswith("* ")):
            continue
        # 불릿 기호 제거 후 첫 토큰을 파일 후보로 본다.
        body = line[2:].strip()
        if not body:
            continue
        # AB-2: bold 마커(**) 제거
        body = re.sub(r"\*\*", "", body)
        # 백틱 제거
        body = body.replace("`", "")
        # AB-2: 괄호 안 설명 제거 — `tests/foo.py (추가 10줄)` → `tests/foo.py`
        body = re.sub(r"\([^)]*\)", "", body).strip()
        # AB-2: em dash(—) 및 일반 dash(–) 뒤 설명 제거 — `pipeline.py — 전체 파싱 수정`
        body = re.sub(r"\s*[—–]\s*.*$", "", body).strip()
        tokens = body.split()
        token = tokens[0] if tokens else ""
        # AB-2: colon 뒤 설명 제거 — `- 수정됨: **tests/test_x.py**` → `수정됨:` → 다음 토큰
        # `수정됨:` 같은 한국어 라벨은 파일이 아니므로 다음 토큰을 시도한다.
        # `pipeline.py:` 처럼 파일명에 붙은 콜론은 콜론만 제거하고 파일명 보존.
        if token.endswith(":") and len(tokens) > 1:
            base = token.rstrip(":")
            if "." in base or "/" in base or "\\" in base:
                # `pipeline.py:` 또는 `tests/bar.py:` — 파일명에 붙은 콜론, 콜론만 제거
                token = base
            else:
                # `수정됨:` 같은 한국어 라벨 — 다음 토큰에서 파일 후보 찾기
                token = ""  # nosec B105 — 라벨 뒤 파일 후보 초기화, 비밀번호 아님
                for t in tokens[1:]:
                    t_clean = re.sub(r"\*\*", "", t).rstrip(":").strip()
                    if t_clean and ("." in t_clean or "/" in t_clean or "\\" in t_clean):
                        token = t_clean
                        break
        else:
            # 후행 콜론 제거 — `- 변경된 파일:` 같은 라벨성 토큰의 콜론 정리.
            token = token.rstrip(":")
        if not token:
            continue
        # AB-3: truncation marker 감지
        if _TRUNCATION_PATTERN.search(token):
            truncated = True
            continue
        # IMP-20260525-AA88: 점수/타이밍 오탐 필터
        # `120/120` 같은 숫자/숫자 패턴(점수 표기)은 파일 경로가 아니다.
        if re.search(r"^\d+/\d+$", token):
            continue
        # `34.74s`, `0.5s` 같은 숫자.숫자s 패턴(타이밍 표기)은 파일 확장자가 아니다.
        if re.search(r"^\d+(\.\d+)?s$", token):
            continue
        # IMP-20260531-BBDB: URL은 파일 경로가 아니다 — http/https로 시작하면 제외.
        if token.startswith("http://") or token.startswith("https://"):
            continue
        # 파일처럼 보이는 토큰만 인정: 경로(`/`) 포함이거나 올바른 확장자(`.` + 영숫자 접미어) 보유.
        # 한국어 문장 끝의 `.`(예: `됩니다.`)은 파일명으로 취급하지 않는다 (IMP-20260522-29C1 fix-forward v5).
        if "/" not in token and "\\" not in token and not re.search(r"\.[A-Za-z0-9_]{1,15}$", token):
            continue
        files.add(token)
    return files, truncated


def _check_protocol_consistency(
    pr_body: str,
    acceptance_packet_body: str,
    pr_changed_files: List[str],
    pr_head_sha: str,
    latest_ci_run_id: str,
    latest_ci_run_conclusion: str,
    verification_json: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    """PR body / acceptance packet / 실제 CI 상태 사이의 일치성을 검사하는 순수 함수.

    IMP-20260605-58BF MT-2: verification_json 파라미터가 제공되면 검사 D/F에서
    PR 본문 텍스트 파싱(_consistency_listed_files) 대신 JSON의 changed_files를 사용한다.
    검사 A/B/C/E는 기존 텍스트 기반 로직을 유지한다.

    검사 항목 (하나라도 불일치하면 BLOCKED):
        A. CI run ID 일치 (stale_run_id)
        B. head SHA 일치 (stale_head_sha)
        C. 테스트 통과 수 일치 (test_count_mismatch)
        D. changed files 일치 (changed_files_mismatch) — verification_json 우선
        E. trust-root 변경 설명 의무 (trust_root_change_undocumented)
        F. stale 파일 설명 탐지 (stale_file_description) — verification_json 우선

    이 함수는 순수 함수이다 — subprocess, _save, 파일 I/O를 호출하지 않는다.

    Args:
        pr_body: PR 본문 전체 텍스트.
        acceptance_packet_body: acceptance packet 댓글 본문 (없으면 빈 문자열).
        pr_changed_files: 실제 PR diff의 변경 파일 경로 리스트.
        pr_head_sha: 실제 PR head commit SHA.
        latest_ci_run_id: 실제 최신 GitHub Actions run ID.
        latest_ci_run_conclusion: 최신 CI run의 결론 (success 등).
        verification_json: human_acceptance_packet.json 내용 dict (선택). 제공 시
            검사 D/F에서 PR 본문 텍스트 파싱 대신 JSON의 changed_files 필드를 사용.
    Returns:
        {
            "status": "PASS" | "BLOCKED",
            "failure_code": str,
            "failure_category": str,
            "blocked_reason": Optional[str],
            "return_phase": str,
            "allow_accept": bool,
            "details": Dict[str, Any],
        }
    """
    # --- 입력 방어 (AL.type_valid) ---
    if pr_body is None:
        raise TypeError("pr_body must not be None")
    if not isinstance(pr_body, str):
        raise TypeError(
            f"pr_body must be str, got {type(pr_body).__name__}"
        )
    if acceptance_packet_body is None:
        raise TypeError("acceptance_packet_body must not be None")
    if not isinstance(acceptance_packet_body, str):
        raise TypeError(
            f"acceptance_packet_body must be str, "
            f"got {type(acceptance_packet_body).__name__}"
        )
    if pr_changed_files is None:
        raise TypeError("pr_changed_files must not be None")
    if not isinstance(pr_changed_files, list):
        raise TypeError(
            f"pr_changed_files must be list, "
            f"got {type(pr_changed_files).__name__}"
        )
    if pr_head_sha is None:
        raise TypeError("pr_head_sha must not be None")
    if not isinstance(pr_head_sha, str):
        raise TypeError(
            f"pr_head_sha must be str, got {type(pr_head_sha).__name__}"
        )
    if latest_ci_run_id is None:
        raise TypeError("latest_ci_run_id must not be None")
    if not isinstance(latest_ci_run_id, str):
        raise TypeError(
            f"latest_ci_run_id must be str, "
            f"got {type(latest_ci_run_id).__name__}"
        )
    # latest_ci_run_conclusion: 검사에 직접 쓰지 않지만 시그니처 계약 유지.
    if latest_ci_run_conclusion is not None and not isinstance(
        latest_ci_run_conclusion, str
    ):
        raise TypeError(
            f"latest_ci_run_conclusion must be str, "
            f"got {type(latest_ci_run_conclusion).__name__}"
        )

    def _blocked(
        failure_code: str,
        blocked_reason: str,
        details: Dict[str, Any],
    ) -> Dict[str, Any]:
        """BLOCKED 결과 dict 생성 (내부 클로저)."""
        return {
            "status": "BLOCKED",
            "failure_code": failure_code,
            "failure_category": "protocol_violation",
            "blocked_reason": blocked_reason,
            "return_phase": "build",
            "allow_accept": False,
            "details": details,
        }

    has_packet_tag = _ACCEPTANCE_PACKET_COMMENT_TAG in acceptance_packet_body

    # --- 검사 A: CI run ID 일치 ---
    # IMP-20260605-9EF5: verification_json SSoT 기준으로 변경.
    # PR 본문 전체 텍스트 파싱 제거 — PIPELINE_FINAL_PACKET 블록 안 텍스트와
    # verification_json만 보조/주 검증 대상이다. 블록 밖 자유서술은
    # 사용자 안내용이며 검증 대상이 아니다.
    if verification_json is None:
        return _blocked(
            "verification_json_missing",
            (
                "verification_json(human_acceptance_packet.json)이 없습니다. "
                "'python pipeline.py gates request-accept --evidence <결과물-경로>'를 "
                "먼저 실행하여 verification_json을 생성하세요."
            ),
            {"location": "pre_check_a"},
        )

    vj_run_id = str(verification_json.get("ci_run_id", "") or "")
    if latest_ci_run_id and vj_run_id and vj_run_id != latest_ci_run_id:
        return _blocked(
            "stale_run_id",
            (
                f"verification_json의 GitHub CI run ID({vj_run_id})가 실제 "
                f"최신 CI run ID({latest_ci_run_id})와 다릅니다. "
                "'python pipeline.py gates request-accept'를 재실행하여 "
                "verification_json을 갱신하세요."
            ),
            {
                "expected_run_id": latest_ci_run_id,
                "vj_run_id": vj_run_id,
                "location": "verification_json",
            },
        )

    # PIPELINE_FINAL_PACKET 블록 안의 run ID 보조 검증 (블록 밖 자유서술은 무시)
    packet_block_text = _consistency_extract_packet_block(pr_body)
    block_run_ids = (
        _consistency_extract_run_ids(packet_block_text)
        if packet_block_text else []
    )
    if block_run_ids and vj_run_id:
        block_run_id = block_run_ids[0]
        if block_run_id != vj_run_id:
            return _blocked(
                "stale_run_id",
                (
                    f"PIPELINE_FINAL_PACKET 블록 안의 run ID({block_run_id})가 "
                    f"verification_json의 run ID({vj_run_id})와 다릅니다. "
                    "블록 안의 값을 verification_json과 일치시키거나 "
                    "'python pipeline.py report final-packet'을 재실행하세요."
                ),
                {
                    "expected_run_id": vj_run_id,
                    "packet_block_run_id": block_run_id,
                    "location": "packet_block",
                },
            )

    # acceptance_packet_body(human_acceptance_packet.md) 검증 유지 — packet 파일은
    # verification_json의 인간 렌더링이므로 같은 SSoT 안에 속한다.
    packet_run_ids = (
        _consistency_extract_run_ids(acceptance_packet_body)
        if has_packet_tag else []
    )
    if packet_run_ids and vj_run_id:
        packet_run_id = packet_run_ids[0]
        if packet_run_id != vj_run_id:
            return _blocked(
                "stale_run_id",
                (
                    f"acceptance packet의 GitHub CI run ID({packet_run_id})가 "
                    f"verification_json의 run ID({vj_run_id})와 다릅니다. "
                    "'python pipeline.py report final-packet'을 재실행하여 "
                    "packet을 갱신하세요."
                ),
                {
                    "expected_run_id": vj_run_id,
                    "packet_run_id": packet_run_id,
                    "location": "acceptance_packet",
                },
            )

    # --- 검사 B: head SHA 일치 ---
    # IMP-20260605-9EF5: verification_json SSoT 기준. PR 본문 전체 텍스트 파싱 제거.
    # PIPELINE_FINAL_PACKET 블록 안의 SHA만 보조 검증 대상. 블록 밖 자유서술 무시.
    vj_head_sha = str(verification_json.get("pr_head_sha", "") or "")
    if pr_head_sha and vj_head_sha:
        vj_sha_lower = vj_head_sha.lower()
        head_sha_lower = pr_head_sha.lower()
        # prefix 매칭 (7자 이상) — 양쪽 방향 모두 허용
        sha_ok = (
            len(vj_sha_lower) >= 7 and head_sha_lower.startswith(vj_sha_lower)
        ) or (
            len(head_sha_lower) >= 7 and vj_sha_lower.startswith(head_sha_lower)
        )
        if not sha_ok:
            return _blocked(
                "stale_head_sha",
                (
                    f"verification_json의 head SHA({vj_head_sha[:12]}...)가 실제 "
                    f"PR head SHA({pr_head_sha[:12]}...)와 일치하지 않습니다. "
                    "'python pipeline.py gates request-accept'를 재실행하여 "
                    "verification_json을 갱신하세요."
                ),
                {
                    "expected_head_sha": pr_head_sha,
                    "vj_head_sha": vj_head_sha,
                    "location": "verification_json",
                },
            )

    # PIPELINE_FINAL_PACKET 블록 안의 SHA 보조 검증 (블록 밖 자유서술은 무시)
    # packet_block_text는 위 검사 A에서 이미 추출됨.
    if packet_block_text and pr_head_sha:
        block_sha_candidates = list(
            _consistency_extract_shas(packet_block_text)
        )
        if block_sha_candidates:
            head_sha_lower_b = pr_head_sha.lower()
            block_sha_match = any(
                len(s) >= 7 and head_sha_lower_b.startswith(s.lower())
                for s in block_sha_candidates
            )
            if not block_sha_match:
                return _blocked(
                    "stale_head_sha",
                    (
                        f"PIPELINE_FINAL_PACKET 블록 안의 SHA가 실제 PR head SHA"
                        f"({pr_head_sha[:12]}...)와 일치하지 않습니다. "
                        "블록 안의 SHA를 갱신하거나 "
                        "'python pipeline.py report final-packet'을 재실행하세요."
                    ),
                    {
                        "expected_head_sha": pr_head_sha,
                        "packet_block_sha_candidates": block_sha_candidates,
                        "location": "packet_block",
                    },
                )

    # --- 검사 C: 테스트 통과 수 일치 ---
    # findall 전체 결과 중 최대값을 전체 테스트 수로 사용한다.
    # 개별 파일 테스트 수(예: "20 passed")와 전체 테스트 수(예: "456 PASS")가
    # 공존할 때, 첫 번째 값 대신 최대값을 사용해야 전체 수를 올바르게 비교한다.
    body_counts_raw = _CONSISTENCY_TEST_COUNT_PATTERN.findall(pr_body)
    packet_counts_raw = (
        _CONSISTENCY_TEST_COUNT_PATTERN.findall(acceptance_packet_body)
        if has_packet_tag else []
    )
    body_count = max(int(c) for c in body_counts_raw) if body_counts_raw else None
    packet_count = max(int(c) for c in packet_counts_raw) if packet_counts_raw else None
    if body_count is not None and packet_count is not None:
        if body_count != packet_count:
            return _blocked(
                "test_count_mismatch",
                (
                    f"PR 본문의 테스트 통과 수({body_count} PASS)와 "
                    f"acceptance packet의 테스트 통과 수"
                    f"({packet_count} PASS)가 다릅니다. "
                    "두 값을 동일 수치로 맞추세요."
                ),
                {
                    "pr_body_test_count": str(body_count),
                    "packet_test_count": str(packet_count),
                },
            )

    # --- 검사 F + D: stale 파일 설명 탐지 및 changed files 일치 ---
    # IMP-20260605-58BF MT-2: verification_json이 제공되면 JSON의 changed_files를
    # 공식 파일 목록 소스로 사용하고, PR 본문 텍스트 파싱(_consistency_listed_files)은
    # 생략한다. verification_json이 없으면 기존 텍스트 파싱 경로를 유지한다.
    changed_set = {str(f).replace("\\", "/") for f in pr_changed_files}

    # verification_json 기반 경로 (IMP-20260605-58BF MT-2)
    if verification_json is not None and isinstance(verification_json, dict):
        json_changed_files = [
            str(f).replace("\\", "/")
            for f in (verification_json.get("changed_files") or [])
        ]
        json_changed_set = {f for f in json_changed_files if f}

        # 검사 F (JSON 기반): JSON 파일 목록에 실제 diff에 없는 파일이 있으면 BLOCKED
        for listed in sorted(json_changed_set):
            if listed and listed not in changed_set:
                return _blocked(
                    "stale_file_description",
                    (
                        f"verification_json의 변경 파일 목록에 "
                        f"'{listed}'가 있으나 실제 PR diff에는 변경되지 않았습니다. "
                        "verification_json(human_acceptance_packet.json)을 재생성하세요."
                    ),
                    {
                        "stale_file": listed,
                        "actual_changed_files": sorted(changed_set),
                        "source": "verification_json",
                    },
                )

        # 검사 D (JSON 기반): 실제 diff 파일 중 JSON 목록에 없는 파일 탐지 (완전 일치 필요)
        missing_from_json: List[str] = []
        for actual in sorted(changed_set):
            if actual not in json_changed_set:
                missing_from_json.append(actual)
        if missing_from_json:
            return _blocked(
                "changed_files_mismatch_vs_verification_json",
                (
                    "verification_json의 변경 파일 목록이 실제 PR diff와 다릅니다. "
                    f"실제 변경된 파일이 JSON에 없습니다: "
                    f"{', '.join(missing_from_json)}. "
                    "verification_json(human_acceptance_packet.json)을 재생성하세요."
                ),
                {
                    "missing_from_json": missing_from_json,
                    "actual_changed_files": sorted(changed_set),
                    "json_changed_files": sorted(json_changed_set),
                    "source": "verification_json",
                },
            )
    else:
        # verification_json이 없으면 BLOCKED — PR 본문 텍스트 파싱 fallback 제거 (IMP-20260605-58BF)
        return _blocked(
            "verification_json_missing",
            (
                "changed_files 검증에 필요한 verification_json"
                "(human_acceptance_packet.json)이 없습니다. "
                "gates request-accept를 먼저 실행하여 verification_json을 생성하세요."
            ),
            {"source": "verification_json"},
        )

    # --- 검사 E: trust-root 변경 설명 의무 ---
    # trust-root 파일은 PR body 또는 acceptance packet에 언급되어야 한다.
    combined_text = pr_body + "\n" + acceptance_packet_body
    for actual in sorted(changed_set):
        base = actual.rsplit("/", 1)[-1]
        is_trust_root = base in CONSISTENCY_TRUST_ROOT_FILES or any(
            pat in actual for pat in CONSISTENCY_TRUST_ROOT_PATTERNS
        )
        if not is_trust_root:
            continue
        # trust-root 파일은 PR body 또는 acceptance packet에 substring으로 언급되어야 한다.
        if base not in combined_text and actual not in combined_text:
            return _blocked(
                "trust_root_change_undocumented",
                (
                    f"trust-root 파일 '{actual}'이 변경되었으나 PR 본문에 "
                    "변경 내용이 명시되어 있지 않습니다. "
                    "PR 본문에 해당 파일 변경 내용을 기술하세요."
                ),
                {
                    "undocumented_file": actual,
                    "actual_changed_files": sorted(changed_set),
                },
            )

    # --- 모든 검사 통과 ---
    return {
        "status": "PASS",
        "failure_code": "",
        "failure_category": "",
        "blocked_reason": None,
        "return_phase": "build",
        "allow_accept": True,
        "details": {},
    }


def _verify_verification_json_freshness(req: Dict[str, Any]) -> Optional[str]:
    """acceptance_request.json에 기록된 verification_json SHA256이 현재 파일과 일치하는지 검사.

    IMP-20260605-58BF MT-4: gates accept 전에 verification_json이 request-accept 이후
    변경되지 않았는지 확인한다. 변경됐으면 실패 코드 문자열을 반환하고, 정상이면 None.

    Args:
        req: acceptance_request.json 내용 dict.
    Returns:
        None (검증 통과) 또는
        failure_code 문자열 ("verification_json_missing", "verification_json_changed" 또는 "changed_files_mismatch_vs_verification_json").
    """
    if not isinstance(req, dict):
        return None
    stored_vj_sha = req.get("verification_json_sha256")
    stored_vj_path = req.get("verification_json_path")
    if not stored_vj_sha or not stored_vj_path:
        # verification_json 필드가 없으면 BLOCKED (IMP-20260605-58BF)
        return "verification_json_missing"
    # 현재 verification_json 파일 SHA256 계산
    try:
        vj_path = Path(stored_vj_path)
        if not vj_path.exists():
            # 파일이 없으면 변경된 것으로 간주
            return "verification_json_changed"
        current_sha = _sha256_file(vj_path)
        if current_sha.lower() != stored_vj_sha.lower():
            return "verification_json_changed"
    except (OSError, TypeError):
        # 경로 오류 등 예외 시 안전 실패
        return "verification_json_changed"
    # verification_json 내용 로드 후 changed_files 재검사
    try:
        vj_data = json.loads(vj_path.read_text(encoding="utf-8"))
        current_pr_files = _get_git_diff_files(base="origin/main")
        current_set = {str(f).replace("\\", "/") for f in current_pr_files}
        vj_files = [str(f).replace("\\", "/") for f in (vj_data.get("changed_files") or [])]
        vj_set = set(vj_files)
        # vj에 있는 파일이 실제 PR diff에 없으면 불일치
        for listed in sorted(vj_set):
            if listed and listed not in current_set:
                return "changed_files_mismatch_vs_verification_json"
    except (OSError, json.JSONDecodeError, TypeError):
        pass  # 파싱 실패 시 SHA 검증만 수행 (이미 통과)
    return None


def _validate_pr_body_readiness(pr_body: str) -> Dict[str, Any]:
    """PR 본문의 Draft/섹션/임시문구를 검사하는 SSoT validator.

    IMP-20260611-A716 MT-1: gates request-accept와 gates accept 양쪽에서
    공통으로 호출하는 단일 검증 함수. 기존 _check_acceptance_readiness의
    Draft/섹션/임시문구 검사 로직을 추출하여 통합.

    Args:
        pr_body: PR 본문 전체 텍스트 (빈 문자열이면 PASS 반환 — gh CLI 없는 환경 호환).
    Returns:
        {
            "status": "PASS" | "BLOCKED",
            "failure_code": str,
            "blocked_reason": Optional[str],
            "missing_sections": List[str],
            "return_phase": str,
            "allow_accept": bool,
        }
    """
    pass_result: Dict[str, Any] = {
        "status": "PASS",
        "failure_code": "",
        "blocked_reason": None,
        "missing_sections": [],
        "return_phase": "build",
        "allow_accept": True,
    }

    if pr_body is None:
        # gh CLI 없는 환경 — 검사 생략 (기존 동작 유지).
        # IMP-20260611-A716 Round 4 Bug 1: 빈 문자열("")은 검사를 통과해서는 안 되므로
        # None일 때만 skip한다. 빈 문자열은 섹션 검사로 진행되어 pr_body_incomplete FAIL.
        return pass_result

    # --- 1. 필수 섹션 검사 (섹션 누락이 임시 문구보다 우선 탐지) ---
    missing_sections: List[str] = []
    for section_spec in PR_REQUIRED_SECTIONS:
        if isinstance(section_spec, tuple):
            found = any(s in pr_body for s in section_spec)
            if not found:
                missing_sections.append(" 또는 ".join(section_spec))
        else:
            if section_spec not in pr_body:
                missing_sections.append(section_spec)

    if missing_sections:
        return _acceptance_blocked(
            "pr_body_incomplete",
            "PR 본문에 임시 문구가 포함되어 있거나 필수 섹션이 누락되어 있습니다.",
            missing_sections=missing_sections,
        )

    # --- 2. 임시 문구 탐지 (섹션이 갖춰진 경우에만 검사) ---
    temporary_pattern = _find_temporary_pr_body_pattern(pr_body)
    if temporary_pattern is not None:
        return _acceptance_blocked(
            "pr_body_temporary",
            (
                f"PR 본문에 임시 문구가 포함되어 있습니다: '{temporary_pattern}'. "
                "PR 본문을 완성한 뒤 다시 실행하세요."
            ),
        )

    return pass_result


# IMP-20260626-4121: Codex Review Loop gate.
# [Purpose]: gates accept --result ACCEPT 실행 전, .pipeline/codex_review_loop_state.json의
#   Codex 검토 결과가 APPROVED이고 현재 PR head SHA / packet_sha256과 일치하는지 검증한다.
#   Codex hook(.claude/hooks/codex_user_acceptance_review.py)이 기록한 상태를 신뢰 루트로 사용한다.
# [Assumptions]: hook은 APPROVE 시 status=APPROVED, pr_head_sha, packet_sha256을 기록한다.
#   acceptance_request.json의 packet_sha256은 _check_acceptance_readiness/nonce 검증과 동일 SSoT다.
# [Vulnerability & Risks]: 파일 없음/파싱 오류/상태 불일치는 모두 fail-closed BLOCKED로 처리한다.
#   gh CLI 미설치로 현재 PR head SHA를 얻지 못하면 SHA 비교는 건너뛰되, APPROVED 상태 자체는 요구한다.
# [Improvement]: 향후 packet_sha256 산출을 hook과 pipeline.py가 공유하는 SSoT helper로 통합 가능.
def _codex_review_loop_state_path() -> Path:
    """codex_review_loop_state.json 경로를 반환 (PIPELINE_STATE_PATH 격리 지원).

    Returns:
        .pipeline/codex_review_loop_state.json 절대 경로.
    """
    env_state = os.environ.get("PIPELINE_STATE_PATH")
    if env_state:
        return Path(env_state).resolve().parent / ".pipeline" / "codex_review_loop_state.json"
    return PIPELINE_CI_DIR / "codex_review_loop_state.json"


# [Purpose]: BUG-20260628-F52C — codex_review_result.json SSoT 경로를 반환한다.
#   이 파일은 gates codex-review가 staged snapshot을 검토한 결과(APPROVE_TO_USER/REJECT)와
#   검토 대상 SHA(packet_sha256/pr_body_sha256/pr_head_sha)를 기록하는 유일한 신뢰 루트다.
#   request-accept는 codex_review_loop_state.json을 절대 읽지 않고, 이 파일만 SSoT로 사용한다.
# [Assumptions]: PIPELINE_STATE_PATH 격리 시 동일 .pipeline 디렉토리에 위치한다.
# [Vulnerability & Risks]: 파일 없음/파싱 실패는 호출자가 fail-closed BLOCKED로 처리해야 한다.
# [Improvement]: 향후 result에 reviewer identity/서명을 추가하여 위변조 방지를 강화 가능.
def _codex_review_result_path() -> Path:
    """codex_review_result.json (Codex Review SSoT) 경로를 반환 (PIPELINE_STATE_PATH 격리 지원).

    Returns:
        .pipeline/codex_review_result.json 절대 경로.
    """
    env_state = os.environ.get("PIPELINE_STATE_PATH")
    if env_state:
        return Path(env_state).resolve().parent / ".pipeline" / "codex_review_result.json"
    return PIPELINE_CI_DIR / "codex_review_result.json"


def _codex_review_blocked_flag_path() -> Path:
    """BLOCKED 상태를 나타내는 보조 플래그 파일 경로(Fix 5: BLOCKED 영속성).

    _write_codex_review_blocked_invalidation이 메인 JSON 쓰기 전에 먼저 이 파일을 작성한다.
    메인 JSON 쓰기가 실패해도 이 플래그 파일이 남아 request-accept를 차단한다.
    APPROVED 결과가 성공적으로 기록되면 이 파일을 삭제하여 정상 흐름을 복구한다.

    Returns:
        .pipeline/codex_review_blocked.flag 절대 경로.
    """
    env_state = os.environ.get("PIPELINE_STATE_PATH")
    if env_state:
        return Path(env_state).resolve().parent / ".pipeline" / "codex_review_blocked.flag"
    return PIPELINE_CI_DIR / "codex_review_blocked.flag"


# [Purpose]: BUG-20260702-E69E — Codex Review 입력 bundle(codex_review_bundle.json)의 경로를
#            producer(_build_codex_review_bundle)와 consumer(_codex_snapshot_identity)가 동일하게
#            해석하도록 단일 헬퍼로 통일한다. _codex_review_result_path와 동일한 PIPELINE_STATE_PATH
#            격리 규칙을 사용하여 E2E 테스트가 실제 repo의 pipeline_contracts/를 오염시키지 않게 한다.
# [Assumptions]: PIPELINE_STATE_PATH가 설정되면 state 파일 옆 .pipeline/에, 아니면 운영
#            CONTRACTS_DIR/<pid>/ 아래에 위치한다.
# [Vulnerability & Risks]: pipeline_id가 빈 문자열이면 격리되지 않은 CONTRACTS_DIR 하위에 빈
#            세그먼트가 생기나, 호출자가 pipeline_id 존재를 먼저 검증하므로 실무상 도달하지 않는다.
# [Improvement]: result/history/bundle 경로를 하나의 팩토리로 묶으면 drift를 더 강하게 막을 수 있다.
def _codex_review_bundle_path(pipeline_id: str) -> Path:
    """codex_review_bundle.json 경로를 반환 (PIPELINE_STATE_PATH 격리 지원).

    Args:
        pipeline_id: 현재 파이프라인 ID (운영 경로 계산에 사용).
    Returns:
        codex_review_bundle.json 절대 경로.
    Raises:
        TypeError: pipeline_id가 None/비str인 경우.
    """
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(f"pipeline_id must be str, got {type(pipeline_id).__name__}")
    env_state = os.environ.get("PIPELINE_STATE_PATH")
    if env_state:
        return Path(env_state).resolve().parent / ".pipeline" / "codex_review_bundle.json"
    return CONTRACTS_DIR / pipeline_id / "codex_review_bundle.json"


# [Purpose]: IMP-20260710-DB54 MT-1 — Codex CLI에 bundle을 보내기 전 결정적(deterministic)
#            preflight 검사를 수행하여, gate 상태/계약 동결/bundle 내용 안전성(승인코드·nonce·
#            NOT_CONFIGURED·삭제파일 참조 부재)을 코드로 검증한다. 이 검사가 통과해야만 Codex
#            CLI를 호출할 가치가 있으므로, 비싼 리뷰 호출 전에 실패를 조기에 차단하여 비용을 줄인다.
# [Assumptions]: bundle은 _build_codex_review_bundle이 만든 dict(또는 그 파일을 로드한 dict)이며,
#            state는 external_gates/contract/codex_review_loop_state를 포함할 수 있다(누락 허용).
# [Vulnerability & Risks]: 가장 취약한 지점은 개별 검사 중 예외 발생이다. 모든 검사를 try/except로
#            감싸고 예외 시 해당 검사를 실패(fail-closed)로 집계하여, 관측 불가한 상태에서 통과로
#            오판되지 않게 한다.
# [Improvement]: 검사 목록을 (name, code, callable) 테이블 상수로 추출하면 확장/감사 추적이 쉬워진다.
def _run_codex_preflight_checks(
    bundle: Dict[str, Any], state: Dict[str, Any], pipeline_id: str
) -> Dict[str, Any]:
    """Codex CLI 호출 전 10개 결정적 preflight 검사를 수행한다 (fail-closed).

    검사 목록(순서 고정):
      1. technical_gate_pass    2. oracle_gate_pass      3. github_ci_pass
      4. contract_frozen        5. no_raw_accept_code_in_bundle
      6. reject_count_below_limit  7. no_nonce_exposure  8. no_deleted_file_refs
      9. no_not_configured_fallback  10. no_pending_comment_bypass

    Args:
        bundle: 검토 대상 bundle dict (직렬화하여 내용 안전성을 검사).
        state: 활성 pipeline_state (external_gates/contract/reject_count 조회).
        pipeline_id: 현재 파이프라인 ID (인터페이스 일관성; 검사 로직에는 직접 미사용).
    Returns:
        {"result": "PASS"|"BLOCKED", "preflight_checks_passed": int,
         "preflight_checks_failed": int, "blocked": bool, "failure_codes": list[str]}.
    Raises:
        TypeError: bundle/state가 None/비dict이거나 pipeline_id가 None/비str인 경우.
    """
    if bundle is None:
        raise TypeError("bundle must not be None")
    if not isinstance(bundle, dict):
        raise TypeError(f"bundle must be dict, got {type(bundle).__name__}")
    if state is None:
        raise TypeError("state must not be None")
    if not isinstance(state, dict):
        raise TypeError(f"state must be dict, got {type(state).__name__}")
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(f"pipeline_id must be str, got {type(pipeline_id).__name__}")

    try:
        serialized = json.dumps(bundle, ensure_ascii=False, sort_keys=True, default=str)
    except Exception:  # noqa: BLE001 — 직렬화 실패 시 str fallback (검사는 계속)
        serialized = str(bundle)
    try:
        state_serialized = json.dumps(
            state, ensure_ascii=False, sort_keys=True, default=str
        )
    except Exception:  # noqa: BLE001
        state_serialized = str(state)

    _gates = state.get("external_gates")
    gates = _gates if isinstance(_gates, dict) else {}
    _loop = state.get("codex_review_loop_state")
    loop_state = _loop if isinstance(_loop, dict) else {}
    _contract = state.get("contract")
    contract = _contract if isinstance(_contract, dict) else {}

    failure_codes: List[str] = []
    passed = 0
    failed = 0

    def _record(ok: bool, failure_code: str) -> None:
        nonlocal passed, failed
        if ok:
            passed += 1
        else:
            failed += 1
            failure_codes.append(failure_code)

    def _gate_status(name: str) -> str:
        _g = gates.get(name)
        if isinstance(_g, dict):
            return str(_g.get("status", "") or "")
        return ""

    # 1. technical gate PASS
    try:
        _ok = _gate_status("technical") == "PASS"
    except Exception:  # noqa: BLE001
        _ok = False
    _record(_ok, "technical_gate_not_pass")

    # 2. oracle gate PASS
    try:
        _ok = _gate_status("oracle") == "PASS"
    except Exception:  # noqa: BLE001
        _ok = False
    _record(_ok, "oracle_gate_not_pass")

    # 3. github_ci gate PASS
    try:
        _ok = _gate_status("github_ci") == "PASS"
    except Exception:  # noqa: BLE001
        _ok = False
    _record(_ok, "github_ci_not_pass")

    # 4. contract frozen
    try:
        _ok = bool(contract.get("frozen", False))
    except Exception:  # noqa: BLE001
        _ok = False
    _record(_ok, "contract_not_frozen")

    # 5. bundle에 raw ACCEPT 코드 없음 (승인 코드 노출 방지).
    try:
        _ok = "ACCEPT-" not in serialized
    except Exception:  # noqa: BLE001
        _ok = False
    _record(_ok, "bundle_contains_raw_accept_code")

    # 6. reject_count < 3 (rate-limit 하한). reject_count는 0 이상 정수여야 한다.
    #    음수/비정상 값은 방어적으로 통과 불가(fail-closed) 없이 0으로 정규화하여 판정한다.
    try:
        _rc_raw = loop_state.get("reject_count", 0)
        _rc = int(_rc_raw) if _rc_raw is not None else 0
        if _rc < 0:
            _rc = 0  # negative reject_count is not meaningful; clamp to 0
        _ok = _rc < 3
    except Exception:  # noqa: BLE001
        _ok = False
    _record(_ok, "reject_count_below_limit")

    # 7. nonce 노출 없음 — 8자 base32(A-Z2-7) 토큰 중 알파벳을 포함한 것을 nonce 후보로 본다.
    #    pipeline_id 날짜(예: 20260710)는 base32에 없는 0/1/8/9를 포함하므로 오탐되지 않고,
    #    소문자 SHA hex(예: abc123, 64자 git/packet SHA)도 대문자 base32와 매칭되지 않는다.
    try:
        _nonce_hit = False
        for _m in re.findall(r"(?<![A-Za-z0-9])[A-Z2-7]{8}(?![A-Za-z0-9=])", serialized):
            if any(_c.isalpha() for _c in _m):
                _nonce_hit = True
                break
        _ok = not _nonce_hit
    except Exception:  # noqa: BLE001
        _ok = False
    _record(_ok, "bundle_contains_nonce")

    # 8. 제거된 파일(codex_review_loop_state 등) 참조 없음.
    try:
        _ok = "codex_review_loop_state" not in serialized
    except Exception:  # noqa: BLE001
        _ok = False
    _record(_ok, "bundle_references_deleted_file")

    # 9. NOT_CONFIGURED fallback 문자열 없음 (bundle/state 양쪽).
    try:
        _ok = (
            "NOT_CONFIGURED" not in serialized
            and "NOT_CONFIGURED" not in state_serialized
        )
    except Exception:  # noqa: BLE001
        _ok = False
    _record(_ok, "no_not_configured_fallback")

    # 10. pending comment 우회 경로 없음 (state에 우회 허용 플래그가 없어야 함).
    try:
        _ok = not bool(loop_state.get("pending_comment_bypass_allowed", False))
    except Exception:  # noqa: BLE001
        _ok = False
    _record(_ok, "no_pending_comment_bypass")

    blocked = failed > 0
    return {
        "result": "BLOCKED" if blocked else "PASS",
        "preflight_checks_passed": passed,
        "preflight_checks_failed": failed,
        "blocked": blocked,
        "failure_codes": failure_codes,
    }


# IMP-20260710-DB54 rework MT-3/MT-4: Codex 캐시 유효성 판정에 쓰이는 critical file 집합.
#   이 파일들이 변경되면 이전 Codex verdict를 그대로 신뢰할 수 없으므로, bundle에 이들의 SHA를
#   기록하고(critical_file_shas) 캐시 조회 시 재검증한다. 정확 매칭 + prefix 매칭을 함께 지원한다.
_CODEX_CRITICAL_FILE_EXACT = frozenset({
    "pipeline.py",
    "CLAUDE.md",
    "AGENTS.md",
    ".gitignore",
    ".gitattributes",
    ".claude/settings.json",
})
_CODEX_CRITICAL_FILE_PREFIXES = (
    ".github/workflows/",
    ".claude/agents/",
    ".claude/commands/",
    ".claude/hooks/",
    "tests/oracles/",
    "tests/e2e/test_codex",
)


def _is_codex_critical_file(path: str) -> bool:
    """주어진 상대 경로가 Codex 캐시 무효화 대상 critical file인지 판정한다.

    Args:
        path: 저장소 상대 경로 문자열 (슬래시/역슬래시 혼용 허용).
    Returns:
        critical file이면 True, 아니면 False.
    Raises:
        TypeError: path가 None이거나 str이 아닌 경우 (외부 입력 타입 가드).
    """
    if path is None:
        raise TypeError("path must not be None")
    if not isinstance(path, str):
        raise TypeError(f"path must be str, got {type(path).__name__}")
    norm = path.replace("\\", "/").strip()
    # 선행 "./"만 제거한다. lstrip("./")는 ".github"의 선행 "."까지 지우므로 사용 금지.
    while norm.startswith("./"):
        norm = norm[2:]
    if not norm:
        return False
    if norm in _CODEX_CRITICAL_FILE_EXACT:
        return True
    for _pref in _CODEX_CRITICAL_FILE_PREFIXES:
        if norm.startswith(_pref):
            return True
    # 이번 IMP 관련 codex 테스트 파일도 critical set에 포함(tests/test_codex_*.py).
    if norm.startswith("tests/test_codex_") and norm.endswith(".py"):
        return True
    return False


# [Purpose]: BUG-20260702-E69E — gates codex-review 시작 시 Codex에게 전달할 입력 bundle을
#            codex_review_bundle.json으로 명시적으로 materialize하고 그 SHA256을 반환한다.
#            그동안 bundle을 생성하는 코드가 없어 _codex_snapshot_identity의 review_bundle_sha256이
#            항상 빈 값이었고, --retry-cli-error snapshot 비교에서 이 차원이 제외됐다. 이 함수가
#            그 차원을 실제로 관측 가능하게 닫는다.
# [Assumptions]: gh/git 조회 실패는 개별 필드 빈 값으로 대체한다(BLOCK 아님). write에 성공하면
#            non-empty SHA를 반환하고, write/직렬화 실패 시에만 ("", "")를 반환한다.
# [Vulnerability & Risks]: 가장 취약한 지점은 bundle write 자체 실패다. 이 경우 ("", "")를 반환하고
#            호출자가 fail-closed로 BLOCK하여 Codex CLI 호출을 막는다.
# [Improvement]: critical_file_summary에 diff 통계(추가/삭제 라인)를 포함하면 Codex 컨텍스트가 풍부해진다.
# IMP-20260712-DAE1 MT-2: Codex Review risk 분류 (SSoT 상수 기반, 우선순위 CRITICAL>HIGH>MEDIUM>LOW)
# [Purpose]: 파이썬 소스에서 모듈 상수 전체 정의(multi-line 포함)를 추출한다.
# [Assumptions]: 대문자 상수 이름으로 시작하는 할당문이 가장 바깥쪽 범위에 있다고 가정한다.
# [Vulnerability & Risks]: 주석 안에 동일 패턴이 있으면 오탐 가능(실제로는 없음). 깊이 0이 되는
#   시점을 본문 끝으로 보므로 한 줄 정의(`A = 1`)는 depth=0으로 즉시 종료된다.
# [Improvement]: ast 파싱 기반으로 전환하면 정확도가 높아지지만 performance 비용이 있다.
def _extract_python_constant_bodies(
    source: str,
    constants: List[str],
) -> Dict[str, str]:
    """파이썬 소스에서 모듈 상수 정의 전체 텍스트를 추출한다.

    상수 이름으로 시작하는 대입 줄부터 괄호·브래킷·중괄호 깊이가 0이 될 때까지를 정의 범위로 본다.
    한 줄 정의는 그 줄 하나가 범위다. 두 상수 중 첫 번째 정의를 채택한다(중복 이름 방지).

    Args:
        source: 파이썬 소스 전체 텍스트.
        constants: 추출 대상 상수 이름 목록.
    Returns:
        {상수명: 정의 전체 텍스트}. 찾지 못한 상수는 결과에 포함하지 않는다.
    """
    if not source or not constants:
        return {}
    _const_set = set(constants)
    _lines = source.splitlines()
    _result: Dict[str, str] = {}
    # 모듈 상단 대문자 상수 할당: `NAME: Type = value` 또는 `NAME = value`
    # REJECT#34: 밑줄 선행 상수(_CODEX_EFFORT_CANONICAL 등)도 추출하도록 패턴 확장.
    _const_re = re.compile(r'^(_?[A-Z][A-Z0-9_]*)\s*(?::[^=\n]+)?\s*=')
    i = 0
    while i < len(_lines) and len(_result) < len(_const_set):
        _ln = _lines[i]
        _m = _const_re.match(_ln)
        if _m and _m.group(1) in _const_set and _m.group(1) not in _result:
            _name = _m.group(1)
            _start = i
            # 괄호 깊이: 열리는 것과 닫히는 것 차이로 범위 추적.
            _depth = (_ln.count("(") + _ln.count("[") + _ln.count("{")
                      - _ln.count(")") - _ln.count("]") - _ln.count("}"))
            i += 1
            while i < len(_lines) and _depth > 0:
                _cl = _lines[i]
                _depth += (_cl.count("(") + _cl.count("[") + _cl.count("{")
                           - _cl.count(")") - _cl.count("]") - _cl.count("}"))
                i += 1
            _result[_name] = "\n".join(_lines[_start:i])
        else:
            i += 1
    return _result


# [Purpose]: REJECT#33 Fix — origin/main과 HEAD의 CODEX_CRITICAL_CONSTANTS 소속 상수 SHA 비교.
# [Assumptions]: origin/main이 로컬에 fetch돼 있어야 한다. 상수 본문 텍스트가 동일하면 변경 없음.
# [Vulnerability & Risks]: 상수 추출 실패(빈 문자열 반환) 시 before와 after가 모두 빈 값이 되어
#   변경이 없다고 오판할 수 있다. fail-closed 원칙: 추출 자체가 실패하거나 git show가 실패하면
#   전체 CODEX_CRITICAL_CONSTANTS를 변경된 것으로 간주하여 CRITICAL을 강제한다.
# [Improvement]: ast.parse 기반 AST 비교로 공백·주석 차이를 무시하고 의미적 변경만 감지 가능.
def _detect_changed_critical_constants(changed_files: List[str]) -> List[str]:
    """origin/main과 HEAD의 CODEX_CRITICAL_CONSTANTS 소속 상수 SHA를 비교하여 변경된 상수 목록을 반환한다.

    - pipeline.py가 changed_files에 없으면 빈 목록 반환 (변경 없음).
    - git show 실패 / 추출 실패 시 fail-closed: 전체 CODEX_CRITICAL_CONSTANTS를 변경 목록으로 반환.
    - 상수가 main에 없고 HEAD에도 없으면 변경 없음으로 취급(새 파이프라인에서 상수 미존재 정상).
    - 상수가 main에 없고 HEAD에만 있거나(신규 추가), main에 있고 HEAD에 없으면(삭제) 변경으로 취급.
    - 두 텍스트가 일치하면 변경 없음.

    Args:
        changed_files: 변경된 파일 경로 목록.
    Returns:
        변경된 CODEX_CRITICAL_CONSTANTS 소속 상수 이름 목록. 실패 시 전체 목록.
    """
    if "pipeline.py" not in (str(f) for f in (changed_files or [])):
        return []
    # REJECT#34: 가변 목록(CODEX_CRITICAL_CONSTANTS) 우회 방지 — 독립 최소 보호 집합.
    #   CODEX_CRITICAL_CONSTANTS가 비워지거나 자기 자신 항목을 제거해도 항상 감지한다.
    #   _CODEX_MIN_PROTECTED는 함수 내부 리터럴로, 외부 상수에 의존하지 않는다.
    #   이 함수(_detect_changed_critical_constants)가 CODEX_CRITICAL_FUNCTIONS에 보호되므로
    #   공격자는 이 최소 집합을 제거하려면 CRITICAL 함수를 수정해야 한다.
    _CODEX_MIN_PROTECTED: frozenset = frozenset({"CODEX_CRITICAL_CONSTANTS"})
    _critical_consts = list(set(CODEX_CRITICAL_CONSTANTS) | _CODEX_MIN_PROTECTED)
    # fail-closed fallback: 추출/git 실패 시 전체 상수를 변경된 것으로 간주
    try:
        _before_r = subprocess.run(
            ["git", "show", "origin/main:pipeline.py"],
            capture_output=True, text=True, timeout=30,
            cwd=str(BASE_DIR), encoding="utf-8", errors="replace",
        )
        if _before_r.returncode != 0:
            return _critical_consts  # fail-closed: git show 실패 → 전체 변경으로 간주
        _before_src = _before_r.stdout
        try:
            _after_src = (BASE_DIR / "pipeline.py").read_text(encoding="utf-8", errors="replace")
        except Exception:  # noqa: BLE001
            return _critical_consts  # fail-closed: HEAD 소스 읽기 실패
        _before_bodies = _extract_python_constant_bodies(_before_src, _critical_consts)
        _after_bodies = _extract_python_constant_bodies(_after_src, _critical_consts)
        _changed: List[str] = []
        for _name in _critical_consts:
            _b = _before_bodies.get(_name, "")
            _a = _after_bodies.get(_name, "")
            if _b != _a:
                # 본문이 다르거나(수정/삭제/신규 추가) → 변경으로 간주
                _changed.append(_name)
            # _b == _a (둘 다 빈 문자열 포함): 변경 없음 → 목록에 추가 안 함
        return _changed
    except Exception:  # noqa: BLE001 — 예외 발생 시 fail-closed
        return _critical_consts


# [Purpose]: 변경 파일/함수 목록을 trust-chain risk level로 분류한다.
# [Assumptions]: changed_functions는 변경된 함수명 문자열 목록이며 None 허용(빈 목록으로 처리).
# [Vulnerability & Risks]: 함수명만으로 판정하므로 동명이인 함수가 있으면 오분류 가능(현 구조상 없음).
# [Improvement]: 파일::함수 식별자 기반 정밀 매칭으로 고도화 가능.
def _classify_codex_review_risk(
    changed_files: List[str],
    changed_functions: List[str],
    changed_constants: Optional[List[str]] = None,
) -> Dict[str, Any]:
    """변경 파일/함수/상수를 trust-chain risk level로 분류한다.

    Args:
        changed_files: 변경된 파일 경로 목록 (None 허용 → 빈 목록으로 처리).
        changed_functions: 변경된 함수명 목록 (None 허용 → 빈 목록으로 처리).
        changed_constants: 변경된 모듈 상수명 목록 (None 허용 → 빈 목록으로 처리).
            CODEX_CRITICAL_CONSTANTS에 포함된 상수가 있으면 CRITICAL로 분류된다.
    Returns:
        {"risk_level": "LOW"|"MEDIUM"|"HIGH"|"CRITICAL"|"BLOCKED", "matched_rule": str,
         "matched_items": list, "blocked": bool}.
    """
    # IMP-20260712-DAE1 rework(문제5): fail-closed. changed_files가 None/비list/빈 목록이면
    #   변경 대상을 관측할 수 없으므로 LOW로 흘려보내지 않고 BLOCKED로 판정한다(fail-closed).
    #   (functions가 비어 있는 것은 정상 — 많은 PR이 추적 함수 없이 파일만 바꾼다.)
    if not isinstance(changed_files, list) or len(changed_files) == 0:
        return {
            "risk_level": "BLOCKED",
            "matched_rule": "empty_changeset_fail_closed",
            "matched_items": [],
            "blocked": True,
        }
    _files = changed_files
    _funcs = changed_functions if isinstance(changed_functions, list) else []
    _consts = changed_constants if isinstance(changed_constants, list) else []

    # REJECT#32 Fix: CODEX_CRITICAL_CONSTANTS에 있는 모듈 상수가 변경된 경우 CRITICAL.
    #   함수 변경이 없어도 라우터·정책·신뢰 경계 상수 자체를 변조하면 자기 보호가 무력화됨.
    #
    # REJECT#18: 불변 최소 보호 집합(_CLASSIFY_SELF_PROTECT) 추가.
    #   런타임 CODEX_CRITICAL_CONSTANTS가 빈 목록/자기 항목 제거 등으로 변조되어도
    #   이 함수 내부 리터럴 집합이 자기 보호를 유지한다(외부 상수에 의존하지 않음).
    #   _detect_changed_critical_constants의 _CODEX_MIN_PROTECTED와 같은 방어 패턴.
    _CLASSIFY_SELF_PROTECT: frozenset = frozenset({
        "CODEX_CRITICAL_CONSTANTS",
        "CODEX_CRITICAL_FUNCTIONS",
        "CODEX_HIGH_RISK_PATHS",
        "CODEX_MODEL_POLICIES",
        "CODEX_ALLOWED_MODELS",
        "CODEX_MODEL_ROUTER_VERSION",
        "CODEX_VERIFICATION_ACTUAL",
        "CODEX_CHATGPT_LOGIN_MARKER",
        "_CODEX_EFFORT_CANONICAL",
    })
    _crit_const_set = set(CODEX_CRITICAL_CONSTANTS) | _CLASSIFY_SELF_PROTECT
    for const in _consts:
        if str(const) in _crit_const_set:
            return {
                "risk_level": "CRITICAL",
                "matched_rule": "critical_constant",
                "matched_items": [const],
                "blocked": False,
            }

    # CRITICAL: CODEX_CRITICAL_FUNCTIONS에 있는 함수가 변경된 경우 (최우선, test 파일 제외 무관).
    for func in _funcs:
        if str(func) in CODEX_CRITICAL_FUNCTIONS:
            return {
                "risk_level": "CRITICAL",
                "matched_rule": "critical_function",
                "matched_items": [func],
                "blocked": False,
            }

    # IMP-20260712-DAE1 rework(문제5): tests/** 는 risk를 올리지 않는다. 제품 코드 risk를
    #   상속하도록, HIGH/MEDIUM 경로 판정에서 test 파일을 제외한다(tests 자체는 risk 상승 안 함).
    _product_files = [f for f in _files if not _is_codex_test_path(str(f))]

    # HIGH: CODEX_HIGH_RISK_PATHS 패턴에 해당하는 (test 제외) 제품 파일.
    for f in _product_files:
        _fs = str(f)
        for pat in CODEX_HIGH_RISK_PATHS:
            if _fs == pat or _fs.startswith(pat):
                return {
                    "risk_level": "HIGH",
                    "matched_rule": "high_risk_path",
                    "matched_items": [f],
                    "blocked": False,
                }

    # MEDIUM: 코드 파일 확장자 (test 제외 제품 파일).
    _code_exts = {".py", ".ts", ".js", ".yaml", ".yml", ".sh", ".ps1", ".json"}
    for f in _product_files:
        if Path(str(f)).suffix.lower() in _code_exts:
            return {
                "risk_level": "MEDIUM",
                "matched_rule": "code_file",
                "matched_items": [f],
                "blocked": False,
            }

    # LOW: 기타 (문서/보고서, 또는 test 파일만 변경된 경우 — 제품 코드 risk 없음).
    return {"risk_level": "LOW", "matched_rule": "default", "matched_items": [], "blocked": False}


def _is_codex_test_path(path: str) -> bool:
    """주어진 경로가 테스트 파일인지 판정한다 (risk 상속용, tests 자체는 risk 상승 안 함).

    REJECT#6: 파일명 패턴(test_*.py / *_test.py) 기반 제외를 삭제한다.
    .github/workflows/test_release.py 같은 HIGH/CRITICAL 경로의 test-like 파일이
    LOW로 오분류되는 버그를 수정. tests/ 하위 파일만 테스트로 분류한다.

    Args:
        path: 저장소 상대 경로 (슬래시/역슬래시 혼용 허용).
    Returns:
        tests/ 하위이면 True. 파일명 패턴은 경로 판정에 사용하지 않는다.
    Raises:
        TypeError: path가 None이거나 str이 아닌 경우 (외부 입력 타입 가드).
    """
    if path is None:
        raise TypeError("path must not be None")
    if not isinstance(path, str):
        raise TypeError(f"path must be str, got {type(path).__name__}")
    norm = path.replace("\\", "/").strip()
    while norm.startswith("./"):
        norm = norm[2:]
    if not norm:
        return False
    # REJECT#17: tests/oracles/ 는 사용자 답안(oracle) 파일 — tests/ 제외 대상에서 예외 처리한다.
    #   oracle 파일이 LOW·observe 캐시 경로로 내려가면 보호 없이 처리될 수 있으므로 예외 처리.
    #   예외 처리 후 _product_files에 포함되어 CODEX_HIGH_RISK_PATHS("tests/oracles/")로 HIGH 분류.
    if norm.startswith("tests/oracles/"):
        return False
    # REJECT#6: HIGH/CRITICAL 경로(예: .github/workflows/test_release.py)의 test-like 파일을
    #   제품 파일에서 제외하지 않는다. tests/ 하위 파일만 테스트로 분류하여 risk 상속 제외.
    #   파일명 패턴 기반 제외는 tests/ 외부에서 HIGH → LOW 오분류를 유발하므로 삭제한다.
    return norm.startswith("tests/")


# IMP-20260712-DAE1 MT-3: risk level → 모델 정책 매핑 + 다운그레이드 차단.
# [Purpose]: risk level에 맞는 모델 정책을 반환하고, HIGH/CRITICAL 다운그레이드를 BLOCKED 처리한다.
# [Assumptions]: CODEX_MODEL_POLICIES가 4개 risk level을 모두 정의한다.
# [Vulnerability & Risks]: 알 수 없는 risk_level은 LOW로 fallback한다(fail-safe이나 관측 필요).
# [Improvement]: 정책을 외부 config로 분리하여 파이프라인별 override 지원 가능.
def _build_codex_model_policy(
    risk_level: str,
    requested_model_tier: Optional[str] = None,
    downgrade_requested: bool = False,
) -> Dict[str, Any]:
    """risk level에 맞는 Codex 모델 정책을 반환한다 (다운그레이드 요청은 차단 가능).

    Args:
        risk_level: "LOW"|"MEDIUM"|"HIGH"|"CRITICAL" (대소문자 무관).
        requested_model_tier: 요청된 모델 티어(선택). 현재 risk보다 낮으면 다운그레이드 후보.
        downgrade_requested: 명시적 다운그레이드 요청 플래그.
    Returns:
        정책 dict (router_version 포함) 또는 BLOCKED dict
        ({"result": "BLOCKED", "downgrade_blocked": True, "failure_code": "downgrade_blocked"}).
    """
    _RISK_ORDER: Dict[str, int] = {"LOW": 0, "MEDIUM": 1, "HIGH": 2, "CRITICAL": 3}
    _risk = (str(risk_level) or "").upper()
    # IMP-20260712-DAE1 rework(문제5): 알 수 없는 risk_level은 LOW로 fallback하지 않고 BLOCKED로
    #   처리한다(fail-closed). classifier의 "BLOCKED"(빈 changeset)도 여기서 함께 차단된다.
    if _risk not in CODEX_MODEL_POLICIES:
        return {
            "result": "BLOCKED",
            "failure_code": "unknown_risk_level_blocked",
            "risk_level": _risk or "UNKNOWN",
        }
    policy = dict(CODEX_MODEL_POLICIES[_risk])

    # 다운그레이드 차단: downgrade_requested=True이거나 requested_model_tier가 현재보다 낮으면.
    _should_block_downgrade = downgrade_requested
    if not _should_block_downgrade and requested_model_tier:
        req_order = _RISK_ORDER.get(str(requested_model_tier).upper(), -1)
        curr_order = _RISK_ORDER.get(_risk, 0)
        if req_order < curr_order and policy.get("downgrade_blocked"):
            _should_block_downgrade = True

    if _should_block_downgrade and policy.get("downgrade_blocked"):
        return {
            "result": "BLOCKED",
            "downgrade_blocked": True,
            "failure_code": "downgrade_blocked",
        }

    return {**policy, "risk_level": _risk, "router_version": CODEX_MODEL_ROUTER_VERSION}


# IMP-20260712-DAE1 MT-4: Codex CLI capability 감지 + fail-closed capability gate.
# [Purpose]: Codex CLI 가용성과 actual_model을 감지하고, unknown+HIGH/CRITICAL을 차단한다.
# [Assumptions]: `codex --version` 호출이 CLI 존재를 나타낸다. 모델명은 확정 불가 → unknown.
# [Vulnerability & Risks]: subprocess 호출 실패는 모두 unavailable/unknown으로 흡수한다.
# [Improvement]: CLI가 모델명을 노출하면 model_source를 version_check→cli_reported로 승격 가능.
def _detect_codex_cli_capability(
    verified_bin_path: str = "",
    env: Optional[Dict[str, str]] = None,
    node_bin: Optional[str] = None,
    codex_js: Optional[str] = None,
) -> Dict[str, Any]:
    """Codex CLI 가용성을 감지. actual_model은 실제 exec 결과가 없으면 항상 unknown.

    IMP-20260712-DAE1 rework(문제4): `CODEX_CLI_MODEL` 환경변수는 더 이상 actual_model 증거로
    인정하지 않는다(힌트일 뿐). actual_model의 유일한 신뢰 증거는 `codex exec ... --json`이
    실제로 보고한 모델이며(_invoke_codex_exec), version-check 단계에서는 확정할 수 없으므로
    unknown으로 남긴다(허위 기록 금지). 환경변수는 진단용 env_hint 필드로만 노출한다.

    IMP-20260712-DAE1 REJECT#16 결함A(TOCTOU + OPENAI_API_KEY 노출 방어):
      - verified_bin_path가 주어지면 그 신뢰 검증된 절대경로로 `--version`을 실행한다
        (PATH 재해석 차단 → TOCTOU/PATH 주입 공격 벡터 제거). 빈 값이면 "codex" PATH
        fallback(레거시 호환).
      - env가 주어지면(보통 OPENAI_API_KEY가 제거된 환경) subprocess에 그대로 전달한다.
        None이면 현재 프로세스 환경을 상속한다(레거시 경로).

    IMP-20260712-DAE1 REJECT#32(초기 capability probe도 검증된 node+codex.js 직접 실행):
      - node_bin과 codex_js가 모두 제공되면 초기 --version 확인을 [node_bin, codex_js, "--version"]
        형태로 실행한다. 사용자 쓰기 가능한 npm 래퍼(codex.cmd)를 subprocess 실행 파일로 쓰지
        않으므로, 정상 dispatch 뒤에 악성 명령을 덧붙인 래퍼가 초기 probe에서 임의 코드를
        실행하는 벡터를 제거한다(exec/auth 경로와 동일 정책, REJECT#31과 대칭).
      - 둘 중 하나라도 없으면 verified_bin_path(또는 codex fallback)를 직접 실행한다.
        direct_native 설치에서는 verified_bin_path 자체가 검증된 native 절대 경로이므로 안전하다.

    Args:
        verified_bin_path: 신뢰 검증된 codex 절대경로. 빈 문자열이면 "codex" PATH fallback.
            direct_native 설치에서는 검증된 native 절대 경로를 그대로 직접 실행하는 데 사용한다.
        env: subprocess에 전달할 환경 dict(예: OPENAI_API_KEY 제거 env). None이면 현재 환경 상속.
        node_bin: 신뢰 검증된 node 인터프리터 절대 경로(REJECT#32). codex_js와 함께 제공될 때만
            직접 실행 경로가 활성화된다. None/빈 값이면 verified_bin_path를 사용.
        codex_js: 레지스트리 SHA가 검증된 codex.js 진입점 절대 경로(REJECT#32). node_bin과 함께
            제공되면 npm 래퍼(codex.cmd) 대신 [node_bin, codex_js, "--version"]로 직접 실행.
    Returns:
        {"available": bool, "actual_model": str, "model_source": str, "env_hint": str}.
        model_source: "version_check"(가용하나 모델 미확인) | "unknown"(미가용).
    Raises:
        TypeError: node_bin/codex_js가 None이 아니면서 str이 아닌 경우.
    """
    # None 입력 방어: verified_bin_path가 None이면 "" 로 강등하여 codex PATH fallback을 탄다
    #   (레거시 호환 — 호출자가 명시적으로 None을 넘겨도 안전하게 동작).
    if verified_bin_path is None:
        verified_bin_path = ""  # allowed: None → "" fallback (레거시 호환, 빈 경로는 codex PATH fallback)
    # REJECT#32: node_bin/codex_js는 Optional[str] — 제공되면 str이어야 한다(암묵적 형변환 금지).
    for _pn, _pv in (("node_bin", node_bin), ("codex_js", codex_js)):
        if _pv is not None and not isinstance(_pv, str):
            raise TypeError(f"{_pn} must be str or None, got {type(_pv).__name__}")
    # 운영자 명시 모델(선택). actual_model 증거로 인정하지 않고 진단용 힌트로만 보관한다.
    _env_hint = str(os.environ.get("CODEX_CLI_MODEL", "") or "").strip()
    # REJECT#16 결함A: 신뢰 검증된 절대경로가 있으면 우선 사용(PATH 재해석 차단). 없으면 codex fallback.
    _cap_bin = verified_bin_path if verified_bin_path else "codex"
    # REJECT#32 AC#2/3: node_bin + codex_js가 모두 제공되면 검증된 node로 codex.js를 직접 실행한다.
    #   npm 래퍼(codex.cmd)를 실행 파일로 쓰지 않으므로 악성 래퍼가 초기 probe를 가로챌 수 없다.
    _cap_node_bin = str(node_bin) if node_bin else ""
    _cap_codex_js = str(codex_js) if codex_js else ""
    if _cap_node_bin and _cap_codex_js:
        _cap_cmd = [_cap_node_bin, _cap_codex_js, "--version"]
    else:
        _cap_cmd = [_cap_bin, "--version"]
    try:
        result = subprocess.run(
            _cap_cmd,
            capture_output=True, text=True, timeout=5,
            env=env,  # None이면 현재 환경 상속(레거시), 주어지면 OPENAI_API_KEY 제거 env 전달
        )
        if result.returncode == 0:
            # CLI는 있으나 모델명을 결정적으로 확인할 수 없으므로 unknown으로 남긴다(허위 기록 금지).
            return {
                "available": True, "actual_model": "unknown",
                "model_source": "version_check", "env_hint": _env_hint,
            }
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError, PermissionError):
        pass
    return {
        "available": False, "actual_model": "unknown",
        "model_source": "unknown", "env_hint": _env_hint,
    }


# IMP-20260712-DAE1 rework(문제2): 실제 Codex CLI exec 호출 + 모델/effort 인자 전달.
# [Purpose]: 선택된 모델/사고레벨로 `codex exec --model <m> -c model_reasoning_effort=<e> --json`을
#            실제로 실행하고, CLI가 --json으로 보고한 actual model/effort와 sanitized 명령을 반환한다.
# [Assumptions]: fake/real codex 모두 --json 출력의 첫 유효 JSON object에 model/reasoning_effort를
#            담는다(없으면 unknown). prompt는 stdin으로 전달한다.
# [Vulnerability & Risks]: subprocess 실패/timeout은 available=False + exit_code=-1로 흡수한다.
#            actual_model이 확정되지 않으면 unknown으로 남겨 capability gate가 fail-closed 처리한다.
# [Improvement]: 스트리밍 JSON(NDJSON) 파싱을 지원하면 대형 응답에서 마지막 status를 정확히 잡을 수 있다.
def _invoke_codex_exec(
    selected_model: str,
    reasoning_effort: str,
    prompt: str,
    timeout: int = 600,
    codex_bin: Optional[str] = None,
    repo_root: Optional[str] = None,
    codex_js: Optional[str] = None,
    node_bin: Optional[str] = None,
) -> Dict[str, Any]:
    """선택된 모델/effort로 codex exec를 실제 실행하고 결과를 표준 dict로 반환한다.

    IMP-20260712-DAE1 REJECT#3 rework(요구2/3/4):
      - 실행 명령: codex exec --model <m> -c model_reasoning_effort=<e>
        --sandbox read-only --ephemeral --json -C <repo-root> -
      - timeout 기본값 600초.
      - OPENAI_API_KEY를 subprocess 환경에서 제거한다(ChatGPT 인증만 사용, API key 차단).
      - invoked_model/invoked_effort(=selected)를 반환하고, actual_model/effort는
        CLI가 --json으로 명시 보고한 경우만 기록한다(아니면 unknown, 허위 기록 금지).

    Args:
        selected_model: policy가 선택한 모델 ID (예: gpt-5.6-sol).
        reasoning_effort: policy가 선택한 사고레벨 (low|high|max).
        prompt: Codex에 stdin으로 전달할 리뷰 프롬프트.
        timeout: subprocess 타임아웃(초, 기본 600).
        codex_bin: codex 실행 파일 경로(테스트 fake executable 주입용). None이면 PATH 해석.
        repo_root: -C 인자로 전달할 저장소 루트. None이면 BASE_DIR.
        codex_js: 레지스트리 SHA가 검증된 codex.js 진입점 절대 경로(REJECT#31). node_bin과
            함께 제공되면 사용자 쓰기 가능 npm 래퍼(codex.cmd) 대신 [node_bin, codex_js, ...]로
            직접 실행하여 주석 decoy·악성 래퍼 우회를 차단한다. None/빈 값이면 codex_bin 사용.
        node_bin: 신뢰 검증된 node 인터프리터 절대 경로(REJECT#31). codex_js와 함께 제공될 때만
            직접 실행 경로가 활성화된다.
    Returns:
        {"available": bool, "exit_code": int, "stdout": str, "stderr": str,
         "invoked_model": str, "invoked_effort": str,
         "actual_model": str, "actual_effort": str,
         "codex_cli_command": str(sanitized), "invoked": bool}.
    Raises:
        TypeError: selected_model/reasoning_effort/prompt가 None이거나 str이 아닌 경우.
        ValueError: timeout이 양의 정수가 아닌 경우.
    """
    for _n, _v in (("selected_model", selected_model),
                   ("reasoning_effort", reasoning_effort), ("prompt", prompt)):
        if _v is None:
            raise TypeError(f"{_n} must not be None")
        if not isinstance(_v, str):
            raise TypeError(f"{_n} must be str, got {type(_v).__name__}")
    if not isinstance(timeout, int) or isinstance(timeout, bool) or timeout <= 0:
        raise ValueError(f"timeout must be positive int, got {timeout!r}")  # 0/음수 불허: 무한대기/즉시실패 방지
    # REJECT#31: codex_js/node_bin은 Optional[str] — 제공되면 str이어야 한다(암묵적 형변환 금지).
    for _pn, _pv in (("codex_js", codex_js), ("node_bin", node_bin)):
        if _pv is not None and not isinstance(_pv, str):
            raise TypeError(f"{_pn} must be str or None, got {type(_pv).__name__}")

    # Codex 실행 파일 경로를 PATHEXT까지 고려하여 결정적으로 해석한다(.exe/.cmd/.bat 지원).
    _codex_bin = str(codex_bin) if codex_bin else (shutil.which("codex") or "codex")
    _repo_root = str(repo_root) if repo_root else str(BASE_DIR)
    # IMP-20260712-DAE1 CLI 정규화: 내부 정책값 'max'는 CLI 0.130.0이 지원하는 'xhigh'로 변환.
    # invoked_effort는 정책 선택값(reasoning_effort)을 그대로 기록하고, CLI 인자에만 정규화를 적용한다.
    _CLI_EFFORT_ALIAS: Dict[str, str] = {"max": "xhigh"}
    _cli_effort = _CLI_EFFORT_ALIAS.get(reasoning_effort, reasoning_effort)
    _exec_args = [
        "exec",
        "--model", selected_model,
        "-c", f"model_reasoning_effort={_cli_effort}",
        "--sandbox", "read-only",
        "--ephemeral",
        "--json",
        "-C", _repo_root,
        "-",
    ]
    # REJECT#31 AC#2: node_bin + codex_js가 모두 제공되면 검증된 node 인터프리터로 codex.js를
    #   직접 실행한다([node_bin, codex_js, "exec", ...]). 사용자 쓰기 가능 npm 래퍼(codex.cmd)를
    #   실행 파일로 쓰지 않으므로 주석 decoy/악성 래퍼가 auth/exec/version을 가로챌 수 없다.
    #   둘 중 하나라도 없으면 기존 동작(codex_bin 직접 실행)을 유지한다(direct_native/test seam 호환).
    _codex_js = str(codex_js) if codex_js else ""
    _node_bin = str(node_bin) if node_bin else ""
    if _node_bin and _codex_js:
        cmd = [_node_bin, _codex_js] + _exec_args
    else:
        cmd = [_codex_bin] + _exec_args
    # sanitized 명령: nonce/secret이 섞이지 않는 결정적 인자만 기록한다(prompt/경로 제외).
    codex_cli_command = (
        f"codex exec --model {selected_model} "
        f"-c model_reasoning_effort={_cli_effort} "
        "--sandbox read-only --ephemeral --json -C <repo-root> -"
    )
    # 요구3: ChatGPT Plus 인증만 사용하도록 OPENAI_API_KEY를 subprocess 환경에서 제거한다.
    codex_env = os.environ.copy()
    codex_env.pop("OPENAI_API_KEY", None)
    base = {
        "available": False,
        "exit_code": -1,
        "stdout": "",
        "stderr": "",
        "invoked_model": selected_model,
        "invoked_effort": reasoning_effort,
        "actual_model": "unknown",
        "actual_effort": "unknown",
        "codex_cli_command": codex_cli_command,
        "invoked": False,
    }
    try:
        result = subprocess.run(
            cmd,
            input=prompt,
            capture_output=True, text=True, timeout=timeout,
            encoding="utf-8", errors="replace", env=codex_env,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError, PermissionError) as _exc:
        base["stderr"] = f"codex exec 실행 실패: {type(_exc).__name__}: {_exc}"
        return base

    stdout = result.stdout or ""
    stderr = result.stderr or ""
    # actual_model/effort는 CLI가 --json으로 명시 보고한 경우만 신뢰한다(허위 기록 금지).
    #   보고하지 않으면 unknown으로 남기고, 상위에서 invocation_verified로 판정한다(요구4).
    _actual_model, _raw_actual_effort = _parse_codex_exec_capability(stdout)
    # CLI 출력 effort alias를 canonical 값으로 환원한다 (예: xhigh → max).
    _actual_effort = _CODEX_EFFORT_CANONICAL.get(_raw_actual_effort, _raw_actual_effort)
    base.update({
        "available": True,
        "invoked": True,
        "exit_code": int(result.returncode),
        "stdout": stdout,
        "stderr": stderr,
        "actual_model": _actual_model,
        "actual_effort": _actual_effort,
    })
    return base


def _parse_codex_exec_capability(stdout: str) -> Tuple[str, str]:
    """codex exec --json stdout에서 실제 사용된 model/effort를 추출한다(없으면 unknown).

    REJECT#9 AC#4: agent_message 타입 이벤트, verdict 키 포함 JSON, item.completed 내
    agent_message에서 model/effort를 추출하지 않는다. 위조 방지 — Codex 응답 본문(agent_message)이
    임의로 model 필드를 포함해도 actual_verified 판정에 영향을 줄 수 없어야 한다.

    Args:
        stdout: codex exec --json 표준 출력.
    Returns:
        (actual_model, actual_effort). 확인 불가 시 ("unknown", "unknown").
    """
    if not isinstance(stdout, str) or not stdout.strip():
        return ("unknown", "unknown")
    _model = "unknown"
    _effort = "unknown"

    # REJECT#9: model/effort를 추출할 수 없는 이벤트 타입 (agent_message, verdict 이벤트)
    _UNTRUSTED_TYPES: frozenset = frozenset({
        "agent_message", "turn.started", "thread.started",
        "item.completed",  # item 내부의 agent_message를 포함할 수 있어 신뢰 불가
        "item.created", "item.updated",
    })

    def _is_trusted_source(obj: Any) -> bool:
        """이 JSON 객체가 CLI metadata 출처(trusted)인지 확인한다.

        verdict 키 포함: Codex 응답 본문(위조 가능) → 신뢰 불가.
        agent_message/item 타입: Codex 생성 텍스트 → 신뢰 불가.
        """
        if not isinstance(obj, dict):
            return False
        if "verdict" in obj:  # Codex 응답 본문 (위조 가능)
            return False
        _type = str(obj.get("type", ""))
        if _type in _UNTRUSTED_TYPES:
            return False
        _item = obj.get("item")
        if isinstance(_item, dict) and str(_item.get("type", "")) == "agent_message":
            return False  # item.completed 내 agent_message
        return True

    def _extract(obj: Any) -> None:
        nonlocal _model, _effort
        if not isinstance(obj, dict):
            return
        if not _is_trusted_source(obj):  # REJECT#9: 신뢰 불가 출처 필터
            return
        _m = obj.get("model") or obj.get("actual_model")
        _e = (
            obj.get("reasoning_effort")
            or obj.get("model_reasoning_effort")
            or obj.get("effort")
            or obj.get("actual_effort")
        )
        if _m and _model == "unknown":
            _model = str(_m)
        if _e and _effort == "unknown":
            _effort = str(_e)

    # 1) 전체가 단일 JSON object인 경우.
    try:
        _extract(json.loads(stdout))
        if _model != "unknown":
            return (_model, _effort)
    except (json.JSONDecodeError, ValueError):
        pass
    # 2) NDJSON: 각 줄을 개별 JSON으로 파싱.
    for _line in stdout.splitlines():
        _line = _line.strip()
        if not _line:
            continue
        try:
            _extract(json.loads(_line))
        except (json.JSONDecodeError, ValueError):
            continue
        if _model != "unknown" and _effort != "unknown":
            break
    return (_model, _effort)


# IMP-20260712-DAE1 rework(문제4): capability 정합성 검사 — actual==selected 강제.
# [Purpose]: auto-invoke된 Codex CLI가 정책이 선택한 모델/effort를 실제로 사용했는지 검증한다.
# [Assumptions]: selected_model은 CODEX_MODEL_POLICIES가 정한 값, actual_model/effort는
#            _invoke_codex_exec가 CLI --json에서 관측한 값이다.
# [Vulnerability & Risks]: actual이 unknown이면 HIGH/CRITICAL에서 fail-closed BLOCKED. 허용 오차 없음.
# [Improvement]: effort 동의어(예: "maximum"=="max") 정규화 테이블을 두면 CLI 표기 편차를 흡수 가능.
# REJECT#25: CLI는 'max' → 'xhigh' 변환 후 전달하고, CLI가 actual_effort='xhigh'를 보고한다.
#   정책에서 selected_effort='max'이고 CLI actual_effort='xhigh'이면 동등 값으로 취급해야 한다.
#   xhigh→max로 정규화하여 actual_effort == selected_effort 비교에서 actual_verified를 반환한다.
_CODEX_EFFORT_CANONICAL: Dict[str, str] = {"xhigh": "max"}


def _canonicalize_effort(effort: str) -> str:
    """CLI effort 값을 정책 정규형으로 변환한다(max↔xhigh 동의어 처리).

    Args:
        effort: CLI 또는 정책 effort 값 ("max", "xhigh", "high", "low" 등).
    Returns:
        정규화된 effort 값 (canonical policy form).
    """
    return _CODEX_EFFORT_CANONICAL.get(str(effort or ""), str(effort or ""))


def _compute_model_verification_level(
    selected_model: str,
    selected_effort: str,
    invoked_model: str,
    invoked_effort: str,
    actual_model: str,
    actual_effort: str,
    invocation_ok: bool,
) -> str:
    """selected/invoked/actual 증거로 model_verification_level을 계산한다(요구4).

    Args:
        selected_model: 정책이 선택한 모델.
        selected_effort: 정책이 선택한 effort.
        invoked_model: --model에 실제 전달한 모델(=selected_model).
        invoked_effort: model_reasoning_effort로 실제 전달한 effort(=selected_effort).
        actual_model: CLI가 --json으로 명시 보고한 모델(아니면 "unknown").
        actual_effort: CLI가 --json으로 명시 보고한 effort(아니면 "unknown").
        invocation_ok: 명시 인자로 실제 실행 + exit 0 성공 여부.
    Returns:
        "actual_verified" | "invocation_verified" | "unverified".
    """
    _sm, _se = str(selected_model or ""), str(selected_effort or "")
    _im, _ie = str(invoked_model or ""), str(invoked_effort or "")
    _am, _ae = str(actual_model or "unknown"), str(actual_effort or "unknown")
    # REJECT#25: effort 정규화 — CLI는 'max'→'xhigh'를 전달하고 actual_effort='xhigh'를 보고한다.
    #   정규형으로 변환 후 selected_effort와 비교한다(max==xhigh 동의어 처리).
    _se_can = _canonicalize_effort(_se)
    _ie_can = _canonicalize_effort(_ie)
    _ae_can = _canonicalize_effort(_ae) if _ae != "unknown" else "unknown"
    # CLI가 actual을 명시 보고한 경우: selected와 정확히 일치해야 actual_verified(정규형 비교).
    if _am != "unknown" and _ae_can != "unknown":
        if _am == _sm and _ae_can == _se_can:
            return CODEX_VERIFICATION_ACTUAL
        # 보고했는데 selected와 불일치 → 증거 모순 → unverified(요구4 BLOCKED 대상).
        return CODEX_VERIFICATION_UNVERIFIED
    # CLI가 actual을 보고하지 않은 경우: 명시 인자 실행 성공 + invoked==selected이면 invocation_verified.
    if invocation_ok and _im and _im != "unknown" and _im == _sm and _ie_can == _se_can:
        return CODEX_VERIFICATION_INVOCATION
    return CODEX_VERIFICATION_UNVERIFIED


def _check_codex_model_capability_match(
    selected_model: str,
    selected_effort: str,
    invoked_model: str,
    invoked_effort: str,
    actual_model: str,
    actual_effort: str,
    risk_level: str,
    invocation_ok: bool = True,
) -> Dict[str, Any]:
    """invoked/actual 증거로 capability 정합성을 검증하고 verification_level을 반환한다(요구4).

    Args:
        selected_model: policy 선택 모델.
        selected_effort: policy 선택 effort.
        invoked_model: --model에 실제 전달한 모델(=selected_model).
        invoked_effort: model_reasoning_effort로 실제 전달한 effort(=selected_effort).
        actual_model: CLI가 실제 사용한 모델("unknown"이면 미보고).
        actual_effort: CLI가 실제 사용한 effort("unknown"이면 미보고).
        risk_level: 현재 risk level.
        invocation_ok: 명시 인자로 실행 + exit 0 성공 여부.
    Returns:
        {"result": "OK", "model_verification_level": str} 또는
        {"result": "BLOCKED", "failure_code": str}.
    """
    _risk = str(risk_level or "").upper()
    _sm, _se = str(selected_model or ""), str(selected_effort or "")
    _im, _ie = str(invoked_model or ""), str(invoked_effort or "")
    _am, _ae = str(actual_model or "unknown"), str(actual_effort or "unknown")
    # REJECT#25: effort 정규화 — CLI는 'max'→'xhigh'를 전달하고 actual_effort='xhigh'를 보고한다.
    #   정규형(canonical)으로 변환 후 selected_effort와 비교한다(max==xhigh 동의어 처리).
    _se_can = _canonicalize_effort(_se)
    _ie_can = _canonicalize_effort(_ie)
    _ae_can = _canonicalize_effort(_ae) if _ae != "unknown" else "unknown"

    # (요구4) invoked_model은 selected_model과 정확히 일치해야 한다(--model에 selected를 전달).
    if _im != _sm:
        return {"result": "BLOCKED", "failure_code": "model_mismatch"}
    if _ie_can != _se_can:
        return {"result": "BLOCKED", "failure_code": "effort_mismatch"}
    # (요구4) invoked_model이 GPT-5.6 허용 목록에 없으면 차단.
    if _im not in CODEX_ALLOWED_MODELS:
        return {"result": "BLOCKED", "failure_code": "disallowed_model"}
    # (요구4) CLI가 actual을 명시 보고했는데 selected와 불일치하면 차단(정규형 비교).
    if _am != "unknown" and _am != _sm:
        return {"result": "BLOCKED", "failure_code": "actual_model_mismatch"}
    if _ae_can != "unknown" and _ae_can != _se_can:
        return {"result": "BLOCKED", "failure_code": "actual_effort_mismatch"}

    _level = _compute_model_verification_level(
        _sm, _se, _im, _ie, _am, _ae, invocation_ok,
    )
    # (요구4, REJECT#12 fix) _check_codex_capability_gate에 위임.
    #   REJECT#12: CRITICAL도 invocation_verified 허용. unverified만 차단.
    #   HIGH/CRITICAL에서 invocation_verified 이상을 보장하는 단일 진입점.
    #   이전 REJECT#21 블록(unknown_model_critical_blocked)은 삭제됨 — 정책 번복.
    _cap_gate = _check_codex_capability_gate(_am, _risk, _level)
    if _cap_gate.get("result") == "BLOCKED":
        return {
            "result": "BLOCKED",
            "failure_code": _cap_gate.get("failure_code", "model_verification_unverified"),
            "model_verification_level": _level,
        }
    return {"result": "OK", "model_verification_level": _level}


# [Purpose]: REJECT#17 수정 A + REJECT#33 — npm 실행 파일이 공격자가 임의 배치할 수 없는
#            "관리자 보호 시스템 설치 경로"에 있는지 확인한다. _get_npm_global_bin이 npm을
#            subprocess로 실행하기 전 npm 바이너리 자체의 출처를 검증하여 PATH 선두 주입(가짜 npm)
#            자기참조 신뢰 + 임의 코드 실행을 차단한다.
# [Assumptions]: npm 바이너리는 관리자 보호 설치 경로에만 존재한다(Windows: Program Files\nodejs;
#            POSIX: /usr/bin, /usr/local/bin 등 root 소유 시스템 경로). npm 전역 prefix
#            (%APPDATA%\npm)나 사용자 홈(~/.nvm)은 npm "바이너리" 위치가 아니라 전역 패키지 shim
#            위치이며 사용자 쓰기 가능하므로 바이너리 허용목록에서 제외한다. nvm-for-windows는
#            NVM_HOME/NVM_SYMLINK 환경변수로 관리자 설치 위치를 노출한다.
# [Vulnerability & Risks]: 비표준(그러나 합법) npm 설치 경로가 있으면 오탐(False)으로 fail-closed되어
#            trust가 거부될 수 있다. 이는 안전측 오류이며, 필요 시 허용 경로 목록을 확장한다.
#            REJECT#33에서 %APPDATA%\npm·~/.nvm(사용자 쓰기 가능)을 제거하여 악성 npm 실행 벡터를
#            차단했다. nvm 사용자는 root 소유 시스템 npm으로 fail-closed되며 이는 의도된 정책이다.
# [Improvement]: OS 패키지 매니저 메타데이터(예: dpkg -S, MSI product code)나 POSIX stat 기반 root
#            소유권 검사로 소유권을 교차 검증하면 경로 접두사 heuristic보다 강한 provenance를 얻는다.
def _verify_npm_binary_is_system_path(npm_path: str) -> bool:
    """REJECT#17 수정 A + REJECT#33: npm 실행 파일이 관리자 보호 시스템 설치 경로에 있는지 확인한다.

    _get_npm_global_bin이 npm을 subprocess로 실행하려면 npm 바이너리 자체가 공격자가 임의로 배치할
    수 없는 관리자 보호 시스템 설치 경로에 있어야 한다. 임의 디렉토리(cwd·임시 폴더)뿐 아니라 사용자
    쓰기 가능 경로(%APPDATA%\\npm, ~/.nvm)의 npm도 PATH 선두 주입 + 임의 코드 실행 공격 벡터이므로
    신뢰하지 않는다(fail-closed).

    REJECT#33: npm 전역 prefix(%APPDATA%\\npm)와 POSIX 사용자 홈(~/.nvm)은 npm 바이너리가 정상적으로
    설치되는 위치가 아니라 전역 패키지 shim 위치이며 사용자 쓰기 가능하다. 이들을 허용목록에서 제거하여
    악성 npm.cmd/npm이 검증을 통과한 뒤 subprocess로 실행되는 경로를 차단한다.

    허용:
      - Windows: %ProgramFiles%\\nodejs, %ProgramFiles(x86)%\\nodejs, %ProgramW6432%\\nodejs,
                 nvm-for-windows(NVM_HOME/NVM_SYMLINK, 관리자 설치)
      - POSIX: /usr/bin, /usr/local/bin, /bin, /opt/homebrew/bin, /opt/homebrew, /opt,
               /usr/local (root 소유 시스템 경로)

    Args:
        npm_path: 검증할 npm 실행 파일 절대/상대 경로.
    Returns:
        관리자 보호 시스템 설치 경로 내에 있으면 True, 아니면 False.
    Raises:
        TypeError: npm_path가 None이거나 str이 아닌 경우.
    """
    if npm_path is None:
        raise TypeError("npm_path must not be None")
    if not isinstance(npm_path, str):
        raise TypeError(f"npm_path must be str, got {type(npm_path).__name__}")
    if not npm_path.strip():
        # 빈 경로는 신뢰 불가 (경계값: 빈 문자열 → 미신뢰; 예외 대신 False 반환이 호출부 계약)
        return False
    try:
        _p = Path(os.path.abspath(npm_path))
    except Exception:  # noqa: BLE001
        return False

    _allowed_roots: List[Path] = []
    if sys.platform == "win32":
        for _envk in ("ProgramFiles", "ProgramFiles(x86)", "ProgramW6432"):
            _pf = os.environ.get(_envk)
            if _pf:
                _allowed_roots.append(Path(_pf) / "nodejs")
        # REJECT#33: %APPDATA%\npm 제거 — 사용자 쓰기 가능 경로이므로 공격자가 악성 npm.cmd를
        #   배치하면 _get_npm_global_bin이 검증 통과 후 subprocess로 실행할 수 있다. 정상 npm
        #   바이너리는 전역 prefix가 아니라 관리자 보호 설치 경로(Program Files\nodejs)에 존재한다.
        #   NVM_HOME/NVM_SYMLINK는 nvm-for-windows가 관리자 권한으로 설치한 시스템 위치를 가리키므로
        #   유지한다.
        for _nvmk in ("NVM_HOME", "NVM_SYMLINK"):
            _nv = os.environ.get(_nvmk)
            if _nv:
                _allowed_roots.append(Path(_nv))
        # 환경변수 부재 대비 표준 기본 경로.
        _allowed_roots.append(Path(r"C:\Program Files\nodejs"))
    else:
        # REJECT#33: ~/.nvm 제거 — 사용자 홈 하위 경로는 쓰기 가능하여 root 소유가 보장되지 않는다.
        #   npm 바이너리는 root 소유 시스템 경로에서만 subprocess 실행을 허용한다. nvm 사용자는
        #   root 소유 시스템 npm으로 fail-closed되며 이는 의도된 보안 정책이다.
        _allowed_roots.extend([
            Path("/usr/bin"), Path("/usr/local/bin"), Path("/bin"),
            Path("/opt/homebrew/bin"), Path("/opt/homebrew"),
            Path("/opt"), Path("/usr/local"),
        ])

    for _root in _allowed_roots:
        try:
            _root_abs = Path(os.path.abspath(str(_root)))
        except Exception:  # noqa: BLE001
            continue
        try:
            _p.relative_to(_root_abs)
            return True
        except ValueError:
            continue
    return False


# [Purpose]: REJECT#18 문제 2 — npm이 반환한 global bin 디렉토리가 "허용된 설치 루트" 안에 있는지
#            검증한다. PATH 주입/조작된 npm이 임의 경로(공격자 제어 디렉토리)를 global bin으로
#            반환해도, 그 반환값이 표준 Node/npm 설치 루트 밖이면 신뢰하지 않는다(fail-closed).
#            _verify_npm_binary_is_system_path(문제 1: npm 바이너리 위치)와 독립적인 2차 경계로,
#            npm 출력(prefix/bin)을 알려진 설치 루트로 bound하여 자기참조 신뢰를 좁힌다.
# [Assumptions]: 공식 npm global bin은 Windows에서 prefix 자체(%APPDATA%\npm 또는
#            <ProgramFiles>\nodejs)이고, Unix에서는 prefix/bin(/usr/bin, /usr/local/bin,
#            /opt/homebrew/bin, ~/.nvm/versions/node/*/bin)이다.
# [Vulnerability & Risks]: 비표준(그러나 합법) 커스텀 prefix(예: 사용자 지정 npm prefix)를 쓰는
#            환경에서는 오탐(False)으로 fail-closed되어 codex 신뢰가 거부될 수 있다. 안전측 오류이며
#            필요 시 허용 루트를 확장한다. %APPDATA%\npm 자체는 사용자 쓰기 가능하나, 문제 1(npm
#            바이너리 시스템 경로)·binary 내용 검증·JS/native SHA 체인과 결합하여 심층 방어를 형성한다.
# [Improvement]: OS 패키지 매니저 소유권/코드 서명으로 루트 자체의 무결성까지 검증하면 경로 bound
#            heuristic보다 강한 보장을 얻는다.
def _verify_npm_global_bin_allowed(npm_global_bin: str) -> bool:
    """REJECT#18 문제 2: npm이 반환한 global bin이 허용된 설치 루트 내에 있는지 확인한다.

    _get_npm_global_bin()이 반환한 디렉토리(Windows: prefix, Unix: prefix/bin)를 표준 Node/npm
    설치 루트 목록과 대조한다. 목록 밖이면 조작된 npm 출력으로 간주하여 False(미신뢰)를 반환하고,
    상위(_verify_codex_binary_path_trust)에서 npm_global_bin_not_in_allowed_root로 fail-closed한다.

    허용 루트:
      - Windows: %APPDATA%\\npm, <ProgramFiles>\\nodejs, <ProgramFiles(x86)>\\nodejs,
                 <ProgramW6432>\\nodejs, nvm-for-windows(NVM_SYMLINK, NVM_HOME\\*)
      - Unix: /usr/bin, /usr/local/bin, /bin, /opt/homebrew/bin,
              ~/.nvm/versions/node/*/bin

    Args:
        npm_global_bin: _get_npm_global_bin()이 반환한 global bin 디렉토리 경로.
    Returns:
        허용 설치 루트 내(동일 또는 하위)이면 True, 아니면 False.
    Raises:
        TypeError: npm_global_bin이 None이거나 str이 아닌 경우.
    """
    if npm_global_bin is None:
        raise TypeError("npm_global_bin must not be None")
    if not isinstance(npm_global_bin, str):
        raise TypeError(
            f"npm_global_bin must be str, got {type(npm_global_bin).__name__}"
        )
    if not npm_global_bin.strip():
        # 빈 경로는 신뢰 불가(경계값: 빈 문자열 → 미신뢰).
        return False
    try:
        _p = Path(os.path.abspath(npm_global_bin)).resolve()
    except Exception:  # noqa: BLE001
        return False

    _allowed_roots: List[Path] = []
    if sys.platform == "win32":
        _appdata = os.environ.get("APPDATA")
        if _appdata:
            _allowed_roots.append(Path(_appdata) / "npm")
        for _envk in ("ProgramFiles", "ProgramFiles(x86)", "ProgramW6432"):
            _pf = os.environ.get(_envk)
            if _pf:
                _allowed_roots.append(Path(_pf) / "nodejs")
        _allowed_roots.append(Path(r"C:\Program Files\nodejs"))
        # nvm-for-windows: 활성 심볼릭 링크(NVM_SYMLINK) 및 버전별 설치(NVM_HOME\*).
        _nvm_sym = os.environ.get("NVM_SYMLINK")
        if _nvm_sym:
            _allowed_roots.append(Path(_nvm_sym))
        _nvm_home = os.environ.get("NVM_HOME")
        if _nvm_home:
            try:
                for _ver in Path(_nvm_home).glob("*"):
                    if _ver.is_dir():
                        _allowed_roots.append(_ver)
            except Exception:  # noqa: BLE001
                pass
    else:
        _allowed_roots.extend([
            Path("/usr/bin"), Path("/usr/local/bin"), Path("/bin"),
            Path("/opt/homebrew/bin"),
        ])
        _home = os.environ.get("HOME") or ""
        if not _home:
            try:
                _home = str(Path.home())
            except Exception:  # noqa: BLE001
                _home = ""
        if _home:
            # nvm: ~/.nvm/versions/node/<ver>/bin
            _nvm_dir = os.environ.get("NVM_DIR") or str(Path(_home) / ".nvm")
            try:
                _node_root = Path(_nvm_dir) / "versions" / "node"
                if _node_root.exists():
                    for _ver in _node_root.glob("*"):
                        _allowed_roots.append(_ver / "bin")
            except Exception:  # noqa: BLE001
                pass

    for _root in _allowed_roots:
        try:
            _root_abs = Path(os.path.abspath(str(_root))).resolve()
        except Exception:  # noqa: BLE001
            continue
        if _p == _root_abs:
            return True
        try:
            _p.relative_to(_root_abs)
            return True
        except ValueError:
            continue
    return False


def _get_npm_global_bin() -> Optional[str]:
    """REJECT#10: npm global bin 디렉토리를 쿼리한다.

    npm global bin은 공식 npm install로 설치된 CLI 도구가 위치하는 신뢰된 경로다.
    Windows에서는 npm이 npm.cmd 형태로 설치되어 subprocess 직접 호출 시 'npm'만으로
    실패할 수 있으므로 npm.cmd를 우선 시도한다.

    REJECT#17 수정 A: npm 출력을 신뢰하기 전에 npm 실행 파일 자체가 시스템 설치 경로에 있는지
    확인한다(_verify_npm_binary_is_system_path). PATH 선두에 주입된 가짜 npm이 조작된 prefix/bin을
    출력하는 자기참조 신뢰를 차단한다. npm이 신뢰 불가 위치면 None을 반환하여 상위에서 fail-closed.
    또한 신뢰 검증을 통과한 npm의 "절대 경로"로 subprocess를 실행하여 두 번째 PATH 조회를 제거한다.

    Returns:
        npm global bin 디렉토리 경로 문자열, 조회 실패 또는 npm 미신뢰 시 None.
    """
    import subprocess as _subp

    # REJECT#17 수정 A: npm 바이너리를 PATH에서 1회 해석한 뒤 시스템 경로인지 확인한다.
    _resolved_npm: Optional[str] = None
    for _probe in (["npm.cmd", "npm"] if sys.platform == "win32" else ["npm"]):
        _which = shutil.which(_probe)
        if _which:
            _resolved_npm = _which
            break
    if not _resolved_npm:
        return None
    if not _verify_npm_binary_is_system_path(_resolved_npm):
        # npm 바이너리가 신뢰 불가 위치(PATH 주입/사용자 쓰기 가능 경로 의심) → 검증 통과 전이므로
        # subprocess를 절대 실행하지 않고 그 출력도 신뢰하지 않는다 (REJECT#33 AC#1/#2 fail-closed).
        return None

    # REJECT#33 AC#5: npm subprocess는 민감 환경 변수를 제거한 환경에서만 실행한다. 검증된 npm이라도
    #   실행 환경의 시크릿(API 키/토큰)이 하위 프로세스로 유출되지 않도록 방어한다.
    _npm_env = os.environ.copy()
    for _sensitive in (
        "OPENAI_API_KEY", "ANTHROPIC_API_KEY", "GITHUB_TOKEN", "GH_TOKEN",
        "NPM_TOKEN", "AWS_SECRET_ACCESS_KEY", "AWS_ACCESS_KEY_ID",
        "PIPELINE_APPROVAL_SECRET", "PIPELINE_SERVER_IDENTITY_KEY",
    ):
        _npm_env.pop(_sensitive, None)

    # 신뢰된 npm 절대 경로로만 조회한다(두 번째 PATH 조회 제거 = TOCTOU/재주입 차단).
    for _npm_exe in (_resolved_npm,):
        # 1) npm bin -g: npm < 9 에서 직접 bin 경로 반환
        try:
            _res = _subp.run(
                [_npm_exe, "bin", "-g"],
                capture_output=True, text=True, timeout=10,
                encoding="utf-8", errors="replace",
                env=_npm_env,
            )
            if _res.returncode == 0:
                _out = _res.stdout.strip()
                if _out and _out != "undefined":
                    return _out
        except Exception:  # noqa: BLE001
            pass

        # 2) npm config get prefix: npm >= 9 에서 bin -g 지원 종료 대안
        try:
            _res = _subp.run(
                [_npm_exe, "config", "get", "prefix"],
                capture_output=True, text=True, timeout=10,
                encoding="utf-8", errors="replace",
                env=_npm_env,
            )
            if _res.returncode == 0:
                _prefix = _res.stdout.strip()
                if _prefix and _prefix != "undefined":
                    # Windows: prefix 자체에 .cmd 파일 존재 (e.g. %APPDATA%\npm)
                    # Linux/macOS: prefix/bin
                    if sys.platform == "win32":
                        return _prefix
                    return str(Path(_prefix) / "bin")
        except Exception:  # noqa: BLE001
            pass

    return None


def _verify_npm_wrapper_content(bin_path: "Path") -> bool:
    """REJECT#10: 파일 내용이 npm 래퍼인지 확인한다.

    Windows .cmd: node 실행 + node_modules/%~dp0 참조 패턴.
    Linux/macOS: 심볼릭 링크 대상에 node_modules 포함 또는 node shebang 스크립트.
    Returns:
        True이면 합법적 npm 래퍼, False이면 의심스러운 바이너리.
    """
    try:
        if sys.platform == "win32":
            _suf = bin_path.suffix.lower()
            if _suf in (".cmd", ".bat"):
                _raw = bin_path.read_text(encoding="utf-8", errors="replace")
                # REJECT#31: 주석(rem/::)에만 정품 JS 경로를 넣고 실제로는 다른 악성 실행 파일을
                #   호출하는 decoy 래퍼를 차단한다. 문자열이 파일 어딘가에 존재하는지가 아니라,
                #   주석 줄을 제거한 "실제 실행 코드"에서만 node 실행 + @openai/codex 패키지 경로를
                #   확인한다. .cmd/.bat 주석 규칙: 'rem '으로 시작하거나 '::'으로 시작하는 줄은 주석.
                #   REJECT#20 요건(node + @openai/codex 명시)은 실행 코드 기준으로 그대로 유지한다.
                _exec_lines = []
                for _ln in _raw.splitlines():
                    _stripped = _ln.lstrip()
                    _stripped_low = _stripped.lower()
                    # 'rem ' 접두 또는 'rem' 단독 = 배치 주석 → 제거.
                    if _stripped_low == "rem" or _stripped_low.startswith("rem "):
                        continue
                    # '::' 접두 = 배치 주석 → 제거 (GOTO 레이블 예외는 단순화를 위해 미고려).
                    if _stripped.startswith("::"):
                        continue
                    if not _stripped:
                        continue
                    _exec_lines.append(_stripped_low)
                # REJECT#32: 주석 제거 후 남은 "외부 프로그램 실행 줄"은 정확히 node dispatch만
                #   허용한다. 정상 node dispatch 뒤에 악성 실행 줄을 덧붙인 래퍼(정품 검사 통과 후
                #   --version 탐색 중 임의 코드 실행)를 차단하기 위한 단일 dispatch 강제이다.
                #   배치 내부 명령어(echo/set/if/... )·레이블·그룹핑/제어 토큰만 있는 하위 명령은
                #   외부 실행이 아니므로 제외하고, 그 외 외부 실행 하위 명령이 node를 참조하지
                #   않으면 즉시 거부한다(fail-closed).
                _BATCH_INTERNAL_CMDS = frozenset({
                    "echo", "set", "setlocal", "endlocal", "if", "for", "goto",
                    "call", "exit", "pause", "cls", "pushd", "popd", "else",
                    "title", "rem", "shift", "verify", "type", "color", "cd",
                })
                _all_node_dispatch = True
                for _el in _exec_lines:
                    # 배치 명령 구분자(&&, ||, &, |)로 분할하여 각 하위 명령을 개별 검사한다.
                    _sep_norm = (
                        _el.replace("&&", "\n").replace("||", "\n")
                        .replace("&", "\n").replace("|", "\n")
                    )
                    for _sub in _sep_norm.split("\n"):
                        _norm = _sub.strip()
                        if _norm.startswith("@"):
                            _norm = _norm[1:].strip()  # allowed: '@' 접두 제거 후 첫 토큰 판정
                        # 그룹핑 토큰 제거 후 첫 토큰으로 내부 명령/레이블/빈 줄 판정.
                        _norm = _norm.replace("(", " ").replace(")", " ").strip()
                        if not _norm or _norm.startswith(":"):
                            continue  # 그룹핑 토큰만/레이블 → 외부 실행 아님
                        _first_tok = _norm.split()[0]
                        if _first_tok in _BATCH_INTERNAL_CMDS:
                            continue  # 배치 내부 명령 → 외부 실행 아님
                        if _first_tok.startswith(("2>", "1>", ">", "<")):
                            continue  # 리다이렉션 토큰 → 외부 실행 아님
                        # 외부 프로그램 실행 하위 명령 — 반드시 node를 참조해야 한다(경로 정규화 후).
                        if "node" not in _sub.replace("\\", "/"):
                            _all_node_dispatch = False
                            break
                    if not _all_node_dispatch:
                        break
                # 남은 실행 코드만 합쳐 경로 정규화(역슬래시→슬래시) 후 검사한다.
                _exec_txt = "\n".join(_exec_lines).replace("\\", "/")
                return (
                    _all_node_dispatch
                    and "node" in _exec_txt
                    and "@openai/codex" in _exec_txt
                )
            # REJECT#20: .exe 등 non-script on Windows — fail-closed 처리.
            #   npm global bin에 악성 codex.exe를 배치하면 PATHEXT 우선순위로 .cmd보다 먼저 선택된다.
            #   내용·서명·패키지 출처 검증이 불가능한 .exe는 신뢰하지 않는다 (fail-closed).
            return False
        else:
            # Linux/macOS: 심볼릭 링크이면 대상 경로에 node_modules 포함 여부
            if bin_path.is_symlink():
                return "node_modules" in str(bin_path.resolve())
            # 셸 스크립트: node 호출 포함 여부
            _txt = bin_path.read_text(encoding="utf-8", errors="replace")
            return "node" in _txt.lower() and (
                "node_modules" in _txt or "#!/usr/bin/env node" in _txt
            )
    except Exception:  # noqa: BLE001
        return False


def _find_codex_js_entrypoint(wrapper_path: "Path") -> "Optional[Path]":
    """npm 래퍼/심볼릭 링크/셸 스크립트에서 JS 진입점 파일 경로를 추출한다(REJECT#12 AC#3, REJECT#15 문제 A).

    Windows .cmd 래퍼: '%~dp0\\...\\*.js' 패턴을 찾아 실제 파일 경로로 변환한다.
    POSIX 공식 npm 설치: /usr/local/bin/codex(symlink) → .../@openai/codex/bin/codex.js 구조를
        지원한다. 입력이 .js 파일이거나, symlink 대상이 .js이거나, node shebang 스크립트로
        @openai/codex를 참조하면 해당 JS 진입점 경로를 반환한다.
    파싱 실패 또는 JS 파일 미존재 시 None을 반환한다(best-effort).

    Returns:
        Path: JS 진입점 파일 경로. 찾지 못하면 None.
    """
    try:
        if not isinstance(wrapper_path, Path):
            return None
        _suf = wrapper_path.suffix.lower()
        if _suf in (".cmd", ".bat"):
            # Windows npm 래퍼(.cmd/.bat) — 기존 동작 유지(회귀 방지).
            _txt = wrapper_path.read_text(encoding="utf-8", errors="replace")
            # '%~dp0\...\*.js' 패턴 추출 (따옴표 포함)
            import re as _re
            for _m in _re.finditer(r'"(?:%~dp0|%dp0%)\\([^"]+\.js)"', _txt, _re.IGNORECASE):
                _rel = _m.group(1)
                _candidate = wrapper_path.parent / _rel
                if _candidate.exists():
                    return _candidate.resolve()
            # 절대 경로 인용 패턴 fallback
            for _m in _re.finditer(r'"([^"]+\.js)"', _txt):
                _cand_str = _m.group(1)
                if not _cand_str.startswith("%"):
                    _cand = Path(_cand_str)
                    if _cand.exists():
                        return _cand.resolve()
            return None

        # ---- REJECT#15 문제 A: POSIX/비-Windows npm 설치 지원 ----
        # 1) 입력이 .js 파일 자체인 경우.
        if _suf == ".js" and wrapper_path.exists():
            return wrapper_path.resolve()
        # 2) symlink이고 resolve 대상이 .js 파일인 경우(공식 npm global 설치의 표준 구조).
        _resolved: "Optional[Path]" = None
        try:
            _resolved = wrapper_path.resolve()
        except Exception:  # noqa: BLE001
            _resolved = None
        if (
            _resolved is not None
            and _resolved != wrapper_path
            and _resolved.suffix.lower() == ".js"
            and _resolved.exists()
        ):
            return _resolved
        # 3) node shebang 스크립트(#!/usr/bin/env node)이면서 @openai/codex를 참조하는 경우.
        #    확장자에 의존하지 않고 파일 내용(첫 줄 shebang)으로 판정한다.
        if wrapper_path.exists() and wrapper_path.is_file():
            try:
                _content = wrapper_path.read_text(encoding="utf-8", errors="replace")
            except Exception:  # noqa: BLE001
                _content = ""
            if _content:
                _first_line = _content.splitlines()[0] if _content.splitlines() else ""
                if (
                    _first_line.startswith("#!")
                    and "node" in _first_line
                    and "@openai/codex" in _content
                ):
                    if _resolved is not None and _resolved.exists():
                        return _resolved
                    return wrapper_path.resolve()
    except Exception:  # noqa: BLE001
        pass
    return None


# [Purpose]: REJECT#LATEST — codex.js가 실제로 spawn하는 native/vendor 실행 파일을 결정적으로 찾는다.
#            npm 래퍼(.cmd) + JS 진입점 SHA만 검증하면 vendor native binary만 교체해도 신뢰 통과하는
#            공격(래퍼+JS SHA 불변)을 막기 위해, 최종 실행 체인의 native binary까지 경로+SHA로 고정한다.
# [Assumptions]: @openai/codex 패키지 구조가 platform-specific 서브패키지(@openai/codex-<suffix>)의
#            vendor/<triple>/bin/codex[.exe] 를 spawn한다. js_entrypoint = <pkg_root>/bin/codex.js.
# [Vulnerability & Risks]: 패키지 레이아웃이 미래 버전에서 바뀌면 None 반환 → 상위에서 fail-closed 차단.
#            잘못된 triple 매핑 시 native 미발견 → fail-closed(안전측). 실행 경로 오탐은 신뢰 상승 없음.
# [Improvement]: package.json의 optionalDependencies/require.resolve 결과를 직접 파싱하여 triple 추론을
#            제거하고, 서명된 baseline digest 목록과 대조하는 방식으로 강화할 수 있다.
def _find_codex_native_binary(js_entrypoint_path: "Path") -> "Optional[Path]":
    """codex.js가 실제로 spawn하는 native/vendor binary 경로를 결정적으로 추출한다.

    codex.js는 platform-specific package(@openai/codex-{suffix})의 vendor 디렉토리에서
    native binary를 spawn한다. 이 함수는 JS 진입점 위치로부터 package 구조를 파악하여
    native binary 절대 경로를 반환한다.

    Args:
        js_entrypoint_path: codex.js 진입점 파일 경로.
    Returns:
        Path: native binary 절대 경로. 결정할 수 없으면 None.
    """
    try:
        if not isinstance(js_entrypoint_path, Path):
            return None
        import platform as _platform

        _machine = _platform.machine().lower()
        _arch = "x64" if _machine in ("x86_64", "amd64") else (
            "arm64" if _machine in ("arm64", "aarch64") else None
        )
        if not _arch:
            return None

        _plt = sys.platform
        if _plt.startswith("linux"):
            _plt = "linux"

        # (플랫폼, 아키텍처) → (npm suffix, vendor triple)
        _PLT_MAP: Dict[tuple, tuple] = {
            ("win32", "x64"): ("win32-x64", "x86_64-pc-windows-msvc"),
            ("win32", "arm64"): ("win32-arm64", "aarch64-pc-windows-msvc"),
            ("linux", "x64"): ("linux-x64", "x86_64-unknown-linux-musl"),
            ("linux", "arm64"): ("linux-arm64", "aarch64-unknown-linux-musl"),
            ("darwin", "x64"): ("darwin-x64", "x86_64-apple-darwin"),
            ("darwin", "arm64"): ("darwin-arm64", "aarch64-apple-darwin"),
        }
        _info = _PLT_MAP.get((_plt, _arch))
        if not _info:
            return None

        _pkg_suffix, _triple = _info
        _native_name = "codex.exe" if sys.platform == "win32" else "codex"
        _pkg_name = f"codex-{_pkg_suffix}"

        # @openai/codex 패키지 루트: js_entrypoint_path = <pkg_root>/bin/codex.js
        _pkg_root = js_entrypoint_path.parent.parent

        # 탐색 순서:
        # 1) <pkg_root>/node_modules/@openai/<pkg_name>/vendor/<triple>/bin/codex[.exe]
        #    (npm nested: @openai/codex/node_modules/@openai/codex-win32-x64/...)
        # 2) <pkg_root>.parent/<pkg_name>/vendor/<triple>/bin/codex[.exe]
        #    (sibling: @openai/codex-win32-x64/ alongside @openai/codex/)
        _candidates = [
            _pkg_root / "node_modules" / "@openai" / _pkg_name
            / "vendor" / _triple / "bin" / _native_name,
            _pkg_root.parent / _pkg_name / "vendor" / _triple / "bin" / _native_name,
        ]
        for _c in _candidates:
            if _c.exists():
                return _c.resolve()

        return None
    except Exception:  # noqa: BLE001
        return None


# [Purpose]: REJECT#17 수정 B — @openai/codex package.json의 npm 레지스트리 provenance 필드
#            (_integrity/_resolved)를 확인하여, 수동 복사·조작된 패키지를 자기참조 SHA와 독립적으로
#            교차 검증한다.
# [Assumptions]: npm 레지스트리 설치 시 _resolved가 registry.npmjs.org를 가리킨다. 단, npm 7+
#            `npm install -g`는 설치 package.json에 이 필드를 남기지 않을 수 있다(정상 global 설치).
# [Vulnerability & Risks]: 필드 부재를 차단하면 정상 global 설치가 깨지므로 부재는 non-blocking으로
#            처리한다. 반대로 _resolved가 비레지스트리(file:/로컬)를 가리키면 조작 가능성 → 차단.
#            부재 시 이 레이어는 신뢰를 올리지 못하며 수정 A/C가 보완한다(depth-in-defense).
# [Improvement]: npm registry에 실제 질의하여 tarball SHA를 대조하면 오프라인 조작까지 탐지 가능하나,
#            네트워크 의존이 생겨 CI/오프라인 환경에서 fail-closed 오탐을 유발할 수 있다.
def _check_package_json_npm_integrity(pkg_root: "Path") -> Dict[str, Any]:
    """REJECT#17 수정 B: @openai/codex package.json의 npm 레지스트리 provenance를 확인한다.

    npm 레지스트리에서 설치된 패키지는 설치 메타데이터(_integrity/_resolved)를 기록할 수 있다.
    _resolved가 registry.npmjs.org를 가리키면 레지스트리 provenance가 확인된 것으로 본다.

    중요(현재 시스템 호환성): `npm install -g`(npm 7+)로 설치된 global 패키지의 package.json에는
    _integrity/_resolved가 남지 않고 .package-lock.json도 global root에 생성되지 않을 수 있다.
    따라서 필드 부재(available=False)는 정상 global 설치로 간주하여 차단하지 않는다(non-blocking).
    반대로 필드가 존재하나 _resolved가 레지스트리가 아닌 로컬/비신뢰 출처(file:·비레지스트리 http)를
    가리키면 조작 가능성이 있으므로 available=True, ok=False로 반환하여 상위에서 fail-closed 차단한다.

    Args:
        pkg_root: @openai/codex 패키지 루트(package.json이 위치한 디렉토리).
    Returns:
        {"available": bool, "ok": bool, "integrity": str, "resolved": str, "reason": str}.
        - available=False: provenance 필드 부재(정상 global 설치) → 차단하지 않음(ok=True).
        - available=True, ok=True: registry.npmjs.org provenance 확인.
        - available=True, ok=False: _resolved가 비레지스트리 → 상위에서 차단.
    Raises:
        TypeError: pkg_root가 None인 경우.
    """
    if pkg_root is None:
        raise TypeError("pkg_root must not be None")
    _out: Dict[str, Any] = {
        "available": False, "ok": True,
        "integrity": "", "resolved": "", "reason": "",
    }
    try:
        if not isinstance(pkg_root, Path):
            # 잘못된 타입은 non-blocking으로 처리(정상 설치를 깨지 않음) — 상위 수정 A/C가 보완.
            _out["reason"] = f"invalid_pkg_root_type:{type(pkg_root).__name__}"
            return _out
        _pkg_json = pkg_root / "package.json"
        if not _pkg_json.exists():
            _out["reason"] = "package_json_not_found"
            return _out
        # REJECT#26 AC-3: 파일이 존재하지만 읽기/파싱 실패 → 조작 의심 → fail-closed.
        #   "부재"와 "손상"을 구분: 부재는 non-blocking, 손상은 available=True, ok=False.
        try:
            _raw = _read_text_fallback(_pkg_json)  # 4-encoding fallback (utf-8/utf-8-sig/cp949/latin-1)
            _data = json.loads(_raw)
        except (OSError, PermissionError, json.JSONDecodeError, UnicodeDecodeError, ValueError) as _pe:
            _out["available"] = True
            _out["ok"] = False
            _out["reason"] = f"package_json_exists_but_unreadable:{type(_pe).__name__}:{str(_pe)[:60]}"
            return _out
        if not isinstance(_data, dict):
            _out["reason"] = "package_json_not_object"
            return _out
        _integrity = str(_data.get("_integrity", "") or "")
        _resolved = str(_data.get("_resolved", "") or "")
        _out["integrity"] = _integrity
        _out["resolved"] = _resolved
        if not _integrity and not _resolved:
            # 필드 부재 — 정상 global 설치(npm 7+)로 간주, non-blocking.
            _out["available"] = False
            _out["ok"] = True
            _out["reason"] = "no_npm_provenance_fields(global_install_ok)"
            return _out
        _out["available"] = True
        # REJECT#20: "registry.npmjs.org" 포함 여부만 검사하면 "registry.npmjs.org.evil" 같은
        #   유사 호스트를 차단하지 못한다. URL 파싱으로 hostname이 정확히 "registry.npmjs.org"인지
        #   검증하여 서브도메인·유사 도메인을 모두 차단한다(fail-closed).
        if _resolved:
            try:
                from urllib.parse import urlparse as _urlparse
                _parsed_url = _urlparse(_resolved)
                _hostname = (_parsed_url.hostname or "").lower().strip()
                if _hostname == "registry.npmjs.org":
                    _out["ok"] = True
                    _out["reason"] = "registry_provenance_confirmed"
                else:
                    _out["ok"] = False
                    _out["reason"] = f"resolved_hostname_not_registry:{_hostname or _resolved[:80]}"
            except Exception as _url_exc:  # noqa: BLE001
                _out["ok"] = False
                _out["reason"] = f"resolved_url_parse_error:{_resolved[:60]}"
        else:
            # _resolved 없이 _integrity만 있는 경우: provenance 확인 불충분 → fail-closed.
            _out["ok"] = False
            _out["reason"] = "integrity_without_resolved"
        return _out
    except Exception as _exc:  # noqa: BLE001
        # 예상치 못한 예외(경로 구성 오류 등) — file.exists() 전에 발생하므로 non-blocking.
        # 파일 읽기/파싱 오류는 위의 개별 try-except에서 fail-closed로 처리됨(REJECT#26 AC-3).
        _out["available"] = False
        _out["ok"] = True
        _out["reason"] = f"integrity_check_unexpected_error:{type(_exc).__name__}"
        return _out


# [Purpose]: REJECT#18 문제 3 — npm 7+ global 설치가 node_modules 루트에 남기는 .package-lock.json의
#            _integrity(sha512- 서브리소스 해시)를 package.json 자기참조와 독립적으로 교차검증한다.
#            npm이 레지스트리 tarball 다운로드 시 계산·기록한 해시이므로, 수동 복사/조작된 패키지를
#            자기참조 SHA와 무관하게 탐지하는 provenance 소스가 된다.
# [Assumptions]: .package-lock.json은 global node_modules 루트(pkg_root의 두 단계 상위, 스코프
#            패키지는 <node_modules>/.package-lock.json)에 위치할 수 있다. packages 맵의 키는
#            "node_modules/@openai/codex" 형태, 또는 dependencies["@openai/codex"].integrity로 노출된다.
# [Vulnerability & Risks]: 실측 결과 현재 `npm install -g @openai/codex`(npm 7+)는 global
#            node_modules 루트에 .package-lock.json을 생성하지 않고 package.json._integrity도
#            남기지 않으며 `npm list --json`에도 integrity 필드가 없다. 따라서 lockfile "부재"를
#            하드 fail-closed하면 모든 정상 global 설치가 깨진다(현재 Windows 설치 = 필수 PASS 대상).
#            → 부재는 non-blocking(available=False, ok=True). 오직 lockfile이 존재하고 @openai/codex
#            엔트리에 integrity가 명시되어 있으나 sha512- 형식이 아닌 조작 양성 증거일 때만 fail-closed.
#            신뢰의 하한은 문제 1/2(npm 바이너리 시스템 경로 + global bin 허용 루트 bound)와 JS/native
#            SHA 3-layer 재검증이 담당한다(depth-in-defense).
# [Improvement]: 온라인이면 registry.npmjs.org의 @openai/codex tarball SHA를 실제 질의하여 오프라인
#            조작까지 탐지할 수 있으나, 네트워크 의존이 CI/오프라인에서 fail-closed 오탐을 유발한다.
def _get_npm_ls_integrity(pkg_root: "Optional[Path]" = None) -> Dict[str, Any]:
    """REJECT#19: npm ls -g --json @openai/codex로 독립 provenance _integrity를 조회한다.

    npm이 설치 시 npm registry에서 받아 내부에 보존하는 _integrity(sha512- SRI)를 신뢰된 npm
    binary로 조회한다. 이 값은 설치 후 로컬 파일에서 자체 계산한 SHA와 달리 registry provenance에서
    유래한다(lockfile·package.json 모두 absent인 npm 7+ global 설치에서의 provenance 소스 3).

    [신뢰 전제] npm binary가 _verify_npm_binary_is_system_path()를 통과한 경우에만 결과를 신뢰한다.
    시스템 경로 npm이 아니면 "npm_not_system_path" 이유로 available=False 반환.

    Args:
        pkg_root: 참조용(미사용). npm ls -g 전역 조회를 사용한다.
    Returns:
        {"available": bool, "ok": bool, "integrity": str, "source": str, "reason": str}.
        - available=False, ok=True: npm 없음 / 패키지 미발견 / _integrity 필드 없음.
          REJECT#19 컨텍스트에서 상위가 provenance_absent_all_sources로 acceptance_eligible=False.
        - available=True, ok=True: 유효 sha512-/sha384-/sha256- _integrity → 독립 provenance OK.
        - available=True, ok=False: _integrity 형식 오류(조작 양성) → 상위에서 fail-closed.
    """
    _out: Dict[str, Any] = {
        "available": False, "ok": True,
        "integrity": "", "source": "npm_ls_global", "reason": "",
    }
    try:
        # npm binary 위치 확인 (시스템 경로여야 신뢰).
        # REJECT#20 AC-3: _get_npm_global_bin과 동일한 탐색 순서(Windows는 npm.cmd 우선)로
        #   동일한 npm 절대 경로를 사용한다. PATH 재해석 없이 첫 번째 검증된 경로를 재사용.
        _npm_bin: Optional[str] = None
        for _npm_probe in (["npm.cmd", "npm"] if sys.platform == "win32" else ["npm"]):
            _which_npm = shutil.which(_npm_probe)
            if _which_npm and _verify_npm_binary_is_system_path(_which_npm):
                _npm_bin = _which_npm
                break
        if not _npm_bin:
            _out["reason"] = "npm_not_found_or_not_system_path"
            return _out
        # npm ls -g --json @openai/codex 실행 (OPENAI_API_KEY 제거, 타임아웃 30초)
        _env = os.environ.copy()
        _env.pop("OPENAI_API_KEY", None)
        _res = subprocess.run(
            [_npm_bin, "ls", "-g", "--json", "@openai/codex"],
            capture_output=True, text=True, timeout=30, env=_env,
        )
        # npm ls는 패키지 미발견 시에도 exit 1을 반환할 수 있으므로 exit code 무관하게 stdout 파싱.
        _stdout = (_res.stdout or "").strip()
        if not _stdout:
            _out["reason"] = "npm_ls_empty_output"
            return _out
        try:
            _data = json.loads(_stdout)
        except json.JSONDecodeError:
            _out["reason"] = "npm_ls_json_parse_error"
            return _out
        if not isinstance(_data, dict):
            _out["reason"] = "npm_ls_not_object"
            return _out
        # @openai/codex 엔트리 추출: dependencies["@openai/codex"]["_integrity"]
        _deps = _data.get("dependencies")
        if not isinstance(_deps, dict):
            _out["reason"] = "npm_ls_no_dependencies"
            return _out
        _codex_entry = _deps.get("@openai/codex")
        if not isinstance(_codex_entry, dict):
            _out["reason"] = "npm_ls_codex_not_found"
            return _out
        _integrity = str(_codex_entry.get("_integrity", "") or "")
        if not _integrity:
            _out["reason"] = "npm_ls_codex_no_integrity_field"
            return _out
        _out["available"] = True
        _out["integrity"] = _integrity
        # SRI 형식 검증: sha512-<base64> (sha384/sha256도 허용). 형식 위반은 조작 양성.
        if "-" in _integrity and _integrity.split("-", 1)[0].lower() in ("sha512", "sha384", "sha256"):
            _out["ok"] = True
        else:
            _out["ok"] = False
            _out["reason"] = f"npm_ls_integrity_invalid_format:{_integrity[:40]}"
        return _out
    except subprocess.TimeoutExpired:
        _out["reason"] = "npm_ls_timeout"
        return _out
    except Exception as _exc:  # noqa: BLE001
        _out["reason"] = f"npm_ls_error:{type(_exc).__name__}"
        return _out


def _check_npm_lockfile_integrity(pkg_root: "Path") -> Dict[str, Any]:
    """REJECT#18 문제 3: node_modules 루트의 .package-lock.json에서 @openai/codex의 npm
    레지스트리 integrity(sha512- SRI)를 독립적으로 교차검증한다.

    현재 시스템 호환성(중요): npm 7+ `npm install -g`는 global node_modules 루트에 .package-lock.json을
    생성하지 않을 수 있다(실측 확인). 따라서 lockfile 부재나 엔트리 부재는 차단하지 않는다(non-blocking).
    lockfile이 존재하고 @openai/codex 엔트리에 integrity가 기록되어 있으나 sha512- 유효 형식이 아니면
    조작 양성 증거로 보고 available=True, ok=False로 반환하여 상위에서 fail-closed 차단한다.

    Args:
        pkg_root: @openai/codex 패키지 루트(.../node_modules/@openai/codex).
    Returns:
        {"available": bool, "ok": bool, "integrity": str, "source": str, "reason": str}.
        - available=False, ok=True: lockfile/엔트리 부재 또는 파싱 불가(정상 global 설치) → 미차단.
        - available=True, ok=True: 유효 sha512- integrity 확인(강한 provenance).
        - available=True, ok=False: integrity가 존재하나 sha512- 형식이 아님 → 상위에서 차단.
    Raises:
        TypeError: pkg_root가 None인 경우.
    """
    if pkg_root is None:
        raise TypeError("pkg_root must not be None")
    _out: Dict[str, Any] = {
        "available": False, "ok": True,
        "integrity": "", "source": "", "reason": "",
    }
    try:
        if not isinstance(pkg_root, Path):
            _out["reason"] = f"invalid_pkg_root_type:{type(pkg_root).__name__}"
            return _out
        # lockfile 후보: 스코프 패키지(.../node_modules/@openai/codex)는 node_modules 루트가
        #   pkg_root.parent.parent. 비스코프 fallback으로 pkg_root.parent도 확인한다.
        _candidates: List[Path] = []
        try:
            _candidates.append(pkg_root.parent.parent / ".package-lock.json")
        except Exception:  # noqa: BLE001
            pass
        try:
            _candidates.append(pkg_root.parent / ".package-lock.json")
        except Exception:  # noqa: BLE001
            pass
        _lock_path: "Optional[Path]" = None
        for _c in _candidates:
            try:
                if _c.exists():
                    _lock_path = _c
                    break
            except Exception:  # noqa: BLE001
                continue
        if _lock_path is None:
            # lockfile 부재 — 정상 global 설치(npm 7+)로 간주, non-blocking.
            _out["reason"] = "lockfile_absent(global_install_ok)"
            return _out
        _out["source"] = str(_lock_path)
        # REJECT#26 AC-3: lockfile 존재하지만 읽기/파싱 실패 → 조작 의심 → fail-closed.
        #   "부재"와 "손상" 구분: lockfile이 없으면 non-blocking, 있는데 파싱 불가면 차단.
        try:
            _raw = _read_text_fallback(_lock_path)  # 4-encoding fallback
            _data = json.loads(_raw)
        except (OSError, PermissionError, json.JSONDecodeError, UnicodeDecodeError, ValueError) as _pe:
            _out["available"] = True
            _out["ok"] = False
            _out["reason"] = f"lockfile_exists_but_unreadable:{type(_pe).__name__}:{str(_pe)[:60]}"
            return _out
        if not isinstance(_data, dict):
            _out["reason"] = "lockfile_not_object"
            return _out
        # integrity 추출: packages 맵(키가 @openai/codex로 끝남) 또는 dependencies["@openai/codex"].
        _integrity = ""
        _pkgs = _data.get("packages")
        if isinstance(_pkgs, dict):
            for _k, _v in _pkgs.items():
                if isinstance(_k, str) and _k.endswith("@openai/codex") and isinstance(_v, dict):
                    _integrity = str(_v.get("integrity", "") or "")
                    if _integrity:
                        break
        if not _integrity:
            _deps = _data.get("dependencies")
            if isinstance(_deps, dict):
                _cx = _deps.get("@openai/codex")
                if isinstance(_cx, dict):
                    _integrity = str(_cx.get("integrity", "") or "")
        if not _integrity:
            # lockfile은 있으나 codex integrity 엔트리 부재 — 검증 불가, non-blocking(오탐 회피).
            _out["reason"] = "lockfile_present_no_codex_integrity"
            return _out
        _out["available"] = True
        _out["integrity"] = _integrity
        # npm SRI 표준 형식: "sha512-<base64>" (sha256/sha384도 허용). 형식 위반은 조작 양성 증거.
        if _integrity.split("-", 1)[0].lower() in ("sha512", "sha384", "sha256") and "-" in _integrity:
            _out["ok"] = True
            _out["reason"] = "lockfile_integrity_confirmed"
        else:
            _out["ok"] = False
            _out["reason"] = f"lockfile_integrity_malformed:{_integrity[:60]}"
        return _out
    except Exception as _exc:  # noqa: BLE001
        # 예상치 못한 예외(경로 구성 오류 등) — lockfile 존재 확인 전에 발생하므로 non-blocking.
        # lockfile 존재하지만 파싱 실패는 위의 개별 try-except에서 fail-closed로 처리됨(REJECT#26 AC-3).
        _out["available"] = False
        _out["ok"] = True
        _out["reason"] = f"lockfile_check_unexpected_error:{type(_exc).__name__}"
        return _out


# [Purpose]: REJECT#17 수정 C — install_type=direct_native(시스템 경로 직접 native 설치)를 경로
#            접두사만으로 신뢰하지 않고, 파일 위치·소유권으로 추가 검증한다. 시스템 경로에 사용자가
#            직접 쓴 바이너리(공격자 제어 가능)를 차단한다.
# [Assumptions]: 시스템 패키지 매니저 설치 바이너리는 root(또는 관리자) 소유이며, 사용자 홈/cwd에
#            있지 않다. 현재 프로세스 사용자가 소유한 시스템 경로 파일은 사용자가 직접 배치한 것으로 본다.
# [Vulnerability & Risks]: root로 실행되는 환경에서는 getuid==0이 정상 설치 파일과 일치하여 소유권
#            검사가 무력화될 수 있다(홈/cwd 위치 검사로 부분 보완). Windows는 getuid 부재로 위치
#            검사만 수행한다.
# [Improvement]: Windows는 Get-AuthenticodeSignature(코드 서명), Unix는 파일 capability/SELinux
#            label을 확인하면 소유권 heuristic보다 강한 무결성 보장을 얻을 수 있다.
def _verify_direct_native_ownership(native_path: "Path") -> Dict[str, Any]:
    """REJECT#17 수정 C: direct_native 실행 파일의 위치·소유권을 검증한다(fail-closed).

    차단 대상:
      - 사용자 홈 디렉토리 또는 현재 작업 디렉토리 내부의 바이너리(사용자 배치 의심).
      - (Unix) 현재 프로세스 사용자가 소유한 바이너리 — 시스템 설치는 통상 root 소유.

    Args:
        native_path: direct_native 실행 파일 경로.
    Returns:
        {"trusted": bool, "failure_code": str|None}.
    Raises:
        TypeError: native_path가 None인 경우.
    """
    if native_path is None:
        raise TypeError("native_path must not be None")
    try:
        if not isinstance(native_path, Path):
            return {"trusted": False, "failure_code": "direct_native_invalid_path"}
        _p = Path(os.path.abspath(str(native_path)))
        # 1) 홈 디렉토리 / cwd 내부 차단 (cross-platform).
        _blocked_roots: List[Path] = []
        try:
            _blocked_roots.append(Path(os.path.abspath(str(Path.home()))))
        except Exception:  # noqa: BLE001
            pass
        try:
            _blocked_roots.append(Path(os.path.abspath(os.getcwd())))
        except Exception:  # noqa: BLE001
            pass
        for _br in _blocked_roots:
            try:
                _p.relative_to(_br)
                return {"trusted": False, "failure_code": "direct_native_user_path"}
            except ValueError:
                continue
        # 2) Unix 소유권 검사 — 현재 사용자가 소유하면 차단(root 소유 시스템 설치만 허용).
        if hasattr(os, "getuid"):
            try:
                _st = os.stat(str(_p))
            except OSError:
                return {"trusted": False, "failure_code": "direct_native_stat_error"}
            # getuid()는 Unix에서만 존재 — hasattr 가드로 Windows는 위치 검사만 수행.
            if _st.st_uid == os.getuid():  # type: ignore[attr-defined]
                return {"trusted": False, "failure_code": "direct_native_user_owned"}
        return {"trusted": True, "failure_code": None}
    except Exception as _exc:  # noqa: BLE001
        return {
            "trusted": False,
            "failure_code": f"direct_native_ownership_error:{type(_exc).__name__}",
        }


def _verify_codex_js_against_registry(
    js_path: "Path", pkg_version: str, timeout: int = 60
) -> Dict[str, Any]:
    """REJECT#24 AC-1/2/4: npm 레지스트리 JS SHA 비교로 위조 JS 탐지 (의미론적 분석 대체).

    의미론적 JS 내용 분석(dead code / console.log 우회 가능)의 한계를 극복하기 위해
    npm 레지스트리에서 동일 버전을 임시 설치한 뒤 JS SHA256을 직접 비교한다.

    AC-4: wrapper/JS가 존재하면 외부 레지스트리 provenance 필수; 부재 = fail-closed
    AC-1: 위조 JS + 정품 native binary 조합 → acceptance_eligible=False
    AC-2: console.log, dead-code spawn, minimal vendor string 우회 시도 모두 차단
            (JS 내용이 다르면 SHA가 달라지므로 우회 불가)

    Args:
        js_path: 설치된 codex.js 경로.
        pkg_version: 설치된 @openai/codex 버전 문자열 (예: "1.0.0").
        timeout: npm install 타임아웃 (초).

    Returns:
        {
            "ok": bool,          # True = 레지스트리 JS와 SHA 일치 (정품)
            "available": bool,   # True = npm/네트워크 접근 성공 (False이면 fallback)
            "reason": str,
            "installed_sha": str,
            "registry_sha": str,
        }
        available=False: npm/네트워크 불가 또는 비-semver 버전 → JS 무결성 미확인 → acceptance_eligible=False (fail-closed).
        available=True, ok=False: 위조 JS 탐지 → acceptance_eligible=False (fail-closed).
        available=True, ok=True: 정품 JS 확인 → Authenticode + registry 모두 valid 시 acceptance_eligible=True.
    """
    _r: Dict[str, Any] = {
        "ok": False,
        "available": False,
        "reason": "",
        "installed_sha": "",
        "registry_sha": "",
    }
    try:
        if not js_path or not js_path.exists():
            _r["reason"] = "js_not_found"
            return _r
        # 1. 설치된 JS SHA256 계산
        try:
            _installed_sha = hashlib.sha256(js_path.read_bytes()).hexdigest()
            _r["installed_sha"] = _installed_sha
        except (OSError, PermissionError) as _exc:
            _r["reason"] = f"installed_sha_error:{type(_exc).__name__}:{str(_exc)[:60]}"
            return _r
        # 2. pkg_version 없으면 레지스트리 비교 불가 → available=False (fail-closed)
        if not pkg_version or not pkg_version.strip():
            _r["reason"] = "pkg_version_unknown"
            return _r
        # REJECT#25 AC-3: pkg_version semver 검증 — file:, URL, 태그 injection 차단.
        #   file:../local, https://..., latest, next 등 비-semver는 npm install 인자로 거부한다.
        _ver_stripped = pkg_version.strip()
        if not re.match(r"^\d+\.\d+\.\d+(?:[+.\-][a-zA-Z0-9.+\-]*)?$", _ver_stripped):
            _r["reason"] = "pkg_version_not_semver"
            return _r
        # 3. npm 레지스트리에서 해당 버전 임시 설치 후 JS SHA 비교
        import tempfile as _tf_reg
        import sys as _sys_reg
        import shutil as _shutil_reg
        # REJECT#26 AC-1: Windows .CMD 파일은 shell=True 없이 직접 subprocess 실행 불가.
        #   shutil.which로 npm 경로를 먼저 확인하여 진짜 "npm 없음"과 "Windows subprocess 제한"을 구분.
        #   pkg_version은 위에서 semver 검증 완료 → shell=True 사용해도 injection 없음.
        _npm_exe = (
            _shutil_reg.which("npm")
            or _shutil_reg.which("npm.cmd")
            or _shutil_reg.which("npm.CMD")
        )
        if _npm_exe is None:
            _r["reason"] = "npm_not_found"
            return _r
        # REJECT#26 AC-2: 사용자 쓰기 가능 경로(홈 디렉토리, AppData, .nvm 등)의 npm은 신뢰 루트 불가.
        #   PATH 앞에 가짜 npm을 두는 공격을 차단한다. 시스템 경로(/usr/bin, /usr/local/bin,
        #   C:\Program Files\)의 npm만 허용한다.
        _npm_exe_norm = os.path.normcase(os.path.abspath(_npm_exe))
        _home_norm = os.path.normcase(os.path.abspath(os.path.expanduser("~")))
        _appdata_norm = os.path.normcase(os.path.abspath(
            os.environ.get("APPDATA", os.path.join(os.path.expanduser("~"), "AppData", "Roaming"))
        ))
        _localappdata_norm = os.path.normcase(os.path.abspath(
            os.environ.get("LOCALAPPDATA", os.path.join(os.path.expanduser("~"), "AppData", "Local"))
        ))
        _npm_user_writable = (
            _npm_exe_norm.startswith(_home_norm + os.sep)
            or _npm_exe_norm.startswith(_appdata_norm + os.sep)
            or _npm_exe_norm.startswith(_localappdata_norm + os.sep)
            or os.sep + ".nvm" + os.sep in _npm_exe_norm
            or os.sep + ".npm" + os.sep in _npm_exe_norm
        )
        if _npm_user_writable:
            _r["reason"] = f"npm_in_user_writable_path:{_npm_exe_norm[:80]}"
            return _r
        # REJECT#27: shell=True + bare "npm"은 PATH를 재해석하여 가짜 npm 실행 허용.
        #   검증된 _npm_exe 절대 경로를 직접 사용하고 shell=True를 제거한다.
        #   Windows .CMD: System32 절대 cmd.exe /c + 검증된 npm 절대 경로.
        _is_win_cmd = _sys_reg.platform == "win32" and str(_npm_exe).lower().endswith((".cmd", ".bat"))
        if _is_win_cmd:
            # cmd.exe 절대 경로 고정 (PATH 재조회 방지)
            _cmd_exe_path = r"C:\Windows\System32\cmd.exe"
            if not os.path.isfile(_cmd_exe_path):
                _r["reason"] = "cmd_exe_not_found_at_system32"
                return _r
        try:
            with _tf_reg.TemporaryDirectory(prefix="codex_reg_verify_") as _tmpdir:
                # REJECT#26 AC-2/REJECT#27: NPM_CONFIG_* 및 사용자 설정 제거로 레지스트리 리다이렉션 차단.
                #   PATH도 정리하여 자식 프로세스가 가짜 npm을 호출하지 못하도록 한다.
                _npm_env = {k: v for k, v in os.environ.items()
                            if not k.upper().startswith("NPM_CONFIG_")}
                _npm_env.pop("npm_config_registry", None)
                _npm_env.pop("NPM_CONFIG_REGISTRY", None)
                # 검증된 _npm_exe만 사용: PATH의 가짜 npm 우선순위 공격 차단
                _npm_install_args = [
                    "--prefix", _tmpdir,
                    "--no-save", "--ignore-scripts", "--prefer-offline=false",
                    "--registry", "https://registry.npmjs.org",
                    "--no-userconfig",
                    f"@openai/codex@{pkg_version.strip()}",
                ]
                if _is_win_cmd:
                    # Windows .CMD: System32 cmd.exe /c + 검증된 npm 절대 경로 (shell=False)
                    _npm_cmd_list = [_cmd_exe_path, "/c", _npm_exe, "install"] + _npm_install_args
                else:
                    # POSIX: 검증된 npm 절대 경로를 직접 실행 (shell=False)
                    _npm_cmd_list = [_npm_exe, "install"] + _npm_install_args
                _proc = subprocess.run(
                    _npm_cmd_list,
                    shell=False, capture_output=True, text=True, timeout=timeout,
                    env=_npm_env,
                )
                if _proc.returncode != 0:
                    # npm 실패: 네트워크 오류 / 버전 없음 등 → available=False
                    _err_snippet = (_proc.stderr or "")[:80].replace("\n", " ")
                    _r["reason"] = f"npm_install_error:{_proc.returncode}:{_err_snippet}"
                    return _r
                # 4. 임시 설치된 레지스트리 JS 경로 탐색
                _reg_base = Path(_tmpdir) / "node_modules" / "@openai" / "codex"
                _reg_js_candidates = [
                    _reg_base / "bin" / "codex.js",
                    _reg_base / "codex.js",
                    _reg_base / "index.js",
                ]
                _reg_js: Optional["Path"] = None
                for _cand in _reg_js_candidates:
                    if _cand.exists():
                        _reg_js = _cand
                        break
                if _reg_js is None:
                    _r["reason"] = "registry_js_not_found_in_temp"
                    return _r
                # 5. 레지스트리 JS SHA256 계산
                try:
                    _reg_sha = hashlib.sha256(_reg_js.read_bytes()).hexdigest()
                    _r["registry_sha"] = _reg_sha
                except (OSError, PermissionError) as _exc:
                    _r["reason"] = f"registry_sha_error:{type(_exc).__name__}:{str(_exc)[:60]}"
                    return _r
                # 6. SHA 비교: 일치 → 정품, 불일치 → 위조 JS 탐지
                _r["available"] = True
                if _installed_sha == _reg_sha:
                    _r["ok"] = True
                    _r["reason"] = "js_sha_matches_registry"
                else:
                    _r["ok"] = False
                    _r["reason"] = (
                        f"js_sha_mismatch:"
                        f"installed={_installed_sha[:16]},registry={_reg_sha[:16]}"
                    )
        except subprocess.TimeoutExpired:
            _r["reason"] = f"npm_install_timeout:{timeout}s"
        except FileNotFoundError:
            # npm 경로가 shutil.which 이후에도 실행 불가 → available=False
            _r["reason"] = "npm_not_found"
        except Exception as _exc:  # noqa: BLE001
            _r["reason"] = (
                f"registry_verify_exception:{type(_exc).__name__}:{str(_exc)[:80]}"
            )
    except Exception as _exc:  # noqa: BLE001
        _r["reason"] = f"outer_exception:{type(_exc).__name__}:{str(_exc)[:60]}"
    return _r


def _check_authenticode_signature(native_binary_path: str) -> Dict[str, Any]:
    """REJECT#22: Windows Authenticode 서명으로 native binary가 OpenAI 서명인지 검증한다.

    npm 7+ 글로벌 설치는 lockfile·package.json·npm ls provenance가 모두 absent이 정상.
    이 함수는 npm provenance와 독립된 OS 레벨 신뢰 소스를 제공한다.

    Returns:
        {"available": bool, "ok": bool, "subject": str, "reason": str}
        available=True  → Authenticode 검사가 실행됨 (바이너리 존재, Windows 환경)
        ok=True         → 서명 유효 + Subject에 "openai" 포함
    """
    _r: Dict[str, Any] = {"available": False, "ok": False, "subject": "", "reason": ""}
    if sys.platform != "win32":
        _r["reason"] = "non_windows"
        return _r
    if not native_binary_path or not os.path.isfile(native_binary_path):
        _r["reason"] = "binary_not_found"
        return _r
    try:
        _safe_path = native_binary_path.replace("'", "").replace('"', "")
        _ps_script = (
            "$ErrorActionPreference = 'Stop';"
            + f"$sig = Get-AuthenticodeSignature -FilePath '{_safe_path}';"
            + "$subj = if ($sig.SignerCertificate) { $sig.SignerCertificate.Subject } else { '' };"
            + "@{status=$sig.Status.ToString();subject=$subj} | ConvertTo-Json -Compress"
        )
        # REJECT#26 AC-2: bare "powershell" → PATH 주입 공격 가능. 절대 경로 고정.
        _ps_exe = (
            r"C:\Windows\System32\WindowsPowerShell\v1.0\powershell.exe"
        )
        if not os.path.isfile(_ps_exe):
            # fallback: System32 없으면 SysWOW64 확인
            _ps_exe_alt = r"C:\Windows\SysWOW64\WindowsPowerShell\v1.0\powershell.exe"
            if os.path.isfile(_ps_exe_alt):
                _ps_exe = _ps_exe_alt
            else:
                _r["reason"] = "powershell_not_found_at_system32"
                return _r
        _proc = subprocess.run(
            [_ps_exe, "-NonInteractive", "-Command", _ps_script],
            capture_output=True, text=True, timeout=20,
        )
        if _proc.returncode != 0:
            _r["reason"] = f"powershell_error:{_proc.returncode}"
            return _r
        _stdout = (_proc.stdout or "").strip()
        if not _stdout:
            _r["reason"] = "powershell_empty_output"
            return _r
        _data = json.loads(_stdout)
        _r["available"] = True
        _r["subject"] = str(_data.get("subject") or "")
        _status = str(_data.get("status") or "")
        if _status == "Valid" and "openai" in _r["subject"].lower():
            _r["ok"] = True
            _r["reason"] = "authenticode_valid_openai"
        else:
            _r["ok"] = False
            _r["reason"] = f"authenticode_invalid:{_status}:{_r['subject'][:60]}"
    except Exception as _exc:  # noqa: BLE001
        _r["reason"] = f"authenticode_exception:{type(_exc).__name__}:{str(_exc)[:60]}"
    return _r


# [Purpose]: REJECT#28 AC-4 — 저장/전달되는 모든 binary SHA가 정확히 64자리 hex인지 강제한다.
# [Assumptions]: 정상 SHA-256 hexdigest는 소문자 [0-9a-f] 64자리이다.
# [Vulnerability & Risks]: unreadable:/비-hex/길이 불일치를 통과시키면 재검증을 우회할 수 있어
#            fail-closed로 즉시 False를 반환한다.
# [Improvement]: 대문자 hex 허용이 필요하면 str.lower() 후 비교하도록 확장 가능하나, 현재는
#            hexdigest()가 항상 소문자를 생성하므로 소문자만 허용한다.
def _is_valid_sha256_hex(sha: Any) -> bool:
    """정확히 64자리 소문자 hex SHA-256만 유효로 판정한다(REJECT#28 AC-4, fail-closed).

    Args:
        sha: 검증할 SHA 문자열(또는 임의 값).
    Returns:
        True = 정확히 64자리 [0-9a-f]. unreadable:/비-hex/길이 불일치/비-str은 모두 False.
    """
    if not isinstance(sha, str):
        return False
    return re.fullmatch(r"[0-9a-f]{64}", sha) is not None


# [Purpose]: REJECT#28 AC-5 — 모든 Codex subprocess(login/exec/capability/--version)에 전달할
#            환경에서 OPENAI_API_KEY를 제거한다(ChatGPT Plus 인증만 사용, API key 인증 차단).
# [Assumptions]: 환경변수 키는 대소문자를 구분하나, 방어적으로 두 형태 모두 제거한다.
# [Vulnerability & Risks]: env를 전달하지 않는 subprocess는 현재 프로세스의 OPENAI_API_KEY를
#            상속하여 API key 인증으로 우회될 수 있으므로, 모든 Codex 호출에 이 env를 전달해야 한다.
# [Improvement]: 향후 다른 민감 변수(예: CODEX_TOKEN)도 제거 대상에 추가할 수 있다.
def _codex_clean_env() -> Dict[str, str]:
    """OPENAI_API_KEY를 제거한 Codex subprocess용 환경 dict를 반환한다(REJECT#28 AC-5).

    Returns:
        os.environ 복사본에서 OPENAI_API_KEY(대/소문자)를 제거한 dict.
    """
    _e = os.environ.copy()
    _e.pop("OPENAI_API_KEY", None)
    _e.pop("openai_api_key", None)
    return _e


# [Purpose]: REJECT#28 AC-1/2/3 — wrapper(.cmd)/POSIX shebang이 실제로 실행하는 node 인터프리터를
#            결정적으로 해석하고, 위치(사용자 쓰기 가능)·Authenticode 서명·SHA를 검증한다.
#            정품 wrapper/JS/native를 그대로 둔 채 사용자 쓰기 가능 위치의 악성 node로 로그인·모델·
#            APPROVE 출력을 위조하는 공격 벡터를 차단한다.
# [Assumptions]: Windows npm/codex 래퍼는 `%~dp0\node.exe`(래퍼 옆 node.exe)를 우선 실행하며, 없으면
#            PATH의 node로 대체된다. POSIX shebang(env node)은 PATH의 node를 실행한다.
# [Vulnerability & Risks]: PATH 선두에 주입된 사용자 쓰기 가능 node를 시스템 경로로 오인하면 우회
#            가능하므로, 사용자 쓰기 가능 경로/서명 무효는 즉시 fail-closed(node_interpreter_trusted=False).
# [Improvement]: package.json의 engines/실행 로그로 실제 spawn된 인터프리터를 관측하면 정밀도를 높일 수 있다.
def _verify_node_interpreter_trust(
    wrapper_path: "Path", js_entrypoint_path: "Optional[Path]"
) -> Dict[str, Any]:
    """wrapper/shebang이 실행하는 node 인터프리터를 해석하고 신뢰(위치·서명·SHA)를 검증한다.

    차단(fail-closed) 대상:
      - 사용자 쓰기 가능 경로(홈/AppData/.nvm/.npm/nvm/volta)의 node.
      - POSIX PATH 선두에 주입된 비-시스템 경로 node.
      - (Windows) Authenticode 서명이 유효(Valid)하지 않거나 조회 불가한 node.exe.

    Args:
        wrapper_path: 신뢰 위치로 판정된 래퍼/심볼릭/shebang 경로. None 불가.
        js_entrypoint_path: JS 진입점 경로(참고용). None이면 native 직접 실행 → node 불필요.
    Returns:
        {"node_interpreter_path": str, "node_interpreter_sha256": str,
         "node_interpreter_trusted": bool, "node_interpreter_reason": str}.
    Raises:
        TypeError: wrapper_path가 None인 경우.
    """
    if wrapper_path is None:
        raise TypeError("wrapper_path must not be None")
    _r: Dict[str, Any] = {
        "node_interpreter_path": "",
        "node_interpreter_sha256": "",
        "node_interpreter_trusted": False,
        "node_interpreter_reason": "",
    }
    try:
        if not isinstance(wrapper_path, Path):
            _r["node_interpreter_reason"] = "wrapper_path_invalid_type"
            return _r
        # 1) 실제 실행되는 node 경로를 결정적으로 해석한다.
        _node_path = ""
        if sys.platform == "win32":
            # Windows npm/codex .cmd 래퍼는 `%~dp0\node.exe`(래퍼 옆 node.exe)를 우선 사용한다.
            try:
                _sibling = wrapper_path.parent / "node.exe"
            except Exception:  # noqa: BLE001
                _sibling = None
            if _sibling is not None and _sibling.is_file():
                _node_path = str(_sibling)
            else:
                _node_path = shutil.which("node.exe") or shutil.which("node") or ""
        else:
            # POSIX shebang(#!/usr/bin/env node)은 PATH에서 node를 해석한다.
            _node_path = shutil.which("node") or shutil.which("node.exe") or ""
        if not _node_path:
            _r["node_interpreter_reason"] = "node_interpreter_not_found"
            return _r
        _node_abs = os.path.abspath(_node_path)
        _node_norm = os.path.normcase(_node_abs)
        _r["node_interpreter_path"] = _node_abs

        # 2) 사용자 쓰기 가능 경로 차단(PATH 선두 주입/home nvm 방어).
        _home_norm = os.path.normcase(os.path.abspath(os.path.expanduser("~")))
        _appdata_norm = os.path.normcase(os.path.abspath(
            os.environ.get("APPDATA", os.path.join(os.path.expanduser("~"), "AppData", "Roaming"))
        ))
        _localappdata_norm = os.path.normcase(os.path.abspath(
            os.environ.get("LOCALAPPDATA", os.path.join(os.path.expanduser("~"), "AppData", "Local"))
        ))
        _user_writable = (
            _node_norm.startswith(_home_norm + os.sep)
            or _node_norm.startswith(_appdata_norm + os.sep)
            or _node_norm.startswith(_localappdata_norm + os.sep)
            or os.sep + ".nvm" + os.sep in _node_norm
            or os.sep + ".npm" + os.sep in _node_norm
            or os.sep + ".volta" + os.sep in _node_norm
            or os.sep + "nvm" + os.sep in _node_norm
        )
        if _user_writable:
            _r["node_interpreter_reason"] = f"node_in_user_writable_path:{_node_norm[:80]}"
            return _r

        # 3) SHA-256 계산.
        try:
            _node_sha = hashlib.sha256(Path(_node_path).read_bytes()).hexdigest()
        except (OSError, PermissionError) as _exc:
            _r["node_interpreter_reason"] = f"node_sha_read_error:{type(_exc).__name__}"
            return _r
        _r["node_interpreter_sha256"] = _node_sha

        # 4) (Windows) Authenticode 서명 검증 — node.exe는 Node.js/OpenJS Foundation 서명이므로
        #    openai 주체 검사(_check_authenticode_signature.ok)는 부적절하다. 서명 Status가 Valid인지만
        #    확인한다(무효/미서명/조회 불가는 fail-closed). POSIX는 서명 부재가 정상 → 위치 검사만 신뢰.
        if sys.platform == "win32":
            _sig = _check_authenticode_signature(_node_path)
            if not _sig.get("available"):
                _r["node_interpreter_reason"] = (
                    f"node_authenticode_unavailable_fail_closed:{str(_sig.get('reason', ''))[:60]}"
                )
                return _r
            _sig_reason = str(_sig.get("reason", "") or "")
            # ok=True(openai 서명; node엔 드묾) 또는 reason이 'authenticode_invalid:Valid:...'이면 Status=Valid.
            _status_valid = bool(_sig.get("ok"))
            if not _status_valid and _sig_reason.startswith("authenticode_invalid:"):
                _parts = _sig_reason.split(":", 2)
                _status_valid = (len(_parts) >= 2 and _parts[1] == "Valid")
            if not _status_valid:
                _r["node_interpreter_reason"] = f"node_authenticode_invalid:{_sig_reason[:60]}"
                return _r
        _r["node_interpreter_trusted"] = True
        _r["node_interpreter_reason"] = "node_interpreter_trusted"
        return _r
    except Exception as _exc:  # noqa: BLE001
        _r["node_interpreter_reason"] = f"node_interpreter_error:{type(_exc).__name__}"
        return _r


def _verify_codex_binary_path_trust(bin_path: str) -> Dict[str, Any]:
    """REJECT#10: 공식 npm 설치 또는 시스템 경로만 신뢰; 임의 사용자 경로는 fail-closed.

    신뢰 불가 위치:
      - 현재 git repo (개발/테스트 환경 fake binary 주입)
      - OS 임시 디렉토리 (pytest tmp_path PATH injection)
      - npm global bin 외 임의 사용자 경로 (PATH 선두 삽입 공격)

    신뢰 가능 위치:
      - npm global bin 디렉토리 내 node 래퍼 (공식 npm install 경로)
      - 시스템 경로 (Linux/macOS: /usr/local/bin, /usr/bin 등)

    Args:
        bin_path: 검증할 실행 파일 경로.
    Returns:
        {"trusted": bool, "path": str, "sha256": str, "untrusted_reason": str|None,
         "install_source": str}.
    """
    import tempfile as _tf

    _r: Dict[str, Any] = {
        "trusted": False,
        "path": bin_path,
        "sha256": "",
        "untrusted_reason": None,
        "install_source": "unknown",
        # REJECT#15 문제 B: 설치 유형 — npm_wrapper(Windows .cmd) / posix_npm_symlink(POSIX symlink·
        #   shebang) / direct_native(시스템 경로 직접 native 설치). operational trust step(6b)가
        #   direct_native일 때 native 체인 필드 부재를 허용하기 위해 사용한다.
        "install_type": "",
        # REJECT#12 AC#3: JS 진입점 경로/SHA (npm 래퍼용; native .exe는 빈 값)
        "js_entrypoint_path": "",
        "js_entrypoint_sha256": "",
        # REJECT#LATEST AC#3: 최종 실행 native/vendor binary 경로/SHA (npm 래퍼용).
        "native_binary_path": "",
        "native_binary_sha256": "",
        # REJECT#28 AC#1/2/3: 실제 실행되는 node 인터프리터 경로/SHA/신뢰 여부 (wrapper 체인용).
        #   native 직접 실행(direct_native)에는 node가 관여하지 않으므로 빈 값/False로 남는다.
        "node_interpreter_path": "",
        "node_interpreter_sha256": "",
        "node_interpreter_trusted": False,
        # REJECT#19: lockfile·package.json·npm ls 세 provenance 소스가 모두 absent이면 False.
        #   trusted=True(체인 구조 OK)이지만 독립 provenance 없음 → acceptance_eligible 자격 없음.
        "acceptance_eligible": True,
        "provenance_reason": "",
    }
    try:
        # REJECT#15 문제 A: POSIX 공식 npm 설치는 /usr/local/bin/codex(symlink) → lib/.../codex.js
        #   구조이므로, resolve()를 먼저 하면 신뢰 위치(bin) 밖(lib)으로 벗어나 오탐된다.
        #   신뢰-위치 검사(npm bin/system prefix)는 PATH 진입점의 lexical 절대 경로(_bin_p_lexical)로,
        #   보안 escape 검사(repo/temp)는 symlink을 따라간 실제 대상(_bin_p_resolved)으로 수행한다.
        _bin_p_orig = Path(bin_path)
        try:
            _bin_p_lexical = Path(os.path.abspath(str(_bin_p_orig)))
        except Exception:  # noqa: BLE001
            _bin_p_lexical = _bin_p_orig
        try:
            _bin_p_resolved = _bin_p_orig.resolve()
        except Exception:  # noqa: BLE001
            _bin_p_resolved = _bin_p_lexical
        _bin_p = _bin_p_lexical  # 위치 판정 기준(PATH 진입점 자체)

        # 1) git repo 내 binary 차단 (테스트/개발 환경 fake binary 방지)
        #    lexical + resolved 모두 검사하여 신뢰 위치의 symlink이 repo 내부를 가리키는 우회도 차단.
        _repo = Path(BASE_DIR).resolve()
        for _chk in (_bin_p_resolved, _bin_p_lexical):
            try:
                _chk.relative_to(_repo)
                _r["untrusted_reason"] = f"binary_inside_git_repo:{_chk}"
                return _r
            except ValueError:
                pass  # repo 밖 → OK

        # 2) OS 임시 디렉토리 내 binary 차단 (pytest tmp_path 등 PATH injection 방지)
        _tmpdir = Path(_tf.gettempdir()).resolve()
        for _chk in (_bin_p_resolved, _bin_p_lexical):
            try:
                _chk.relative_to(_tmpdir)
                _r["untrusted_reason"] = f"binary_inside_temp_dir:{_chk}"
                return _r
            except ValueError:
                pass  # 임시 디렉토리 밖 → OK

        # 3) 파일 존재 확인 (symlink이면 대상까지 따라가 확인)
        if not _bin_p_lexical.exists():
            _r["untrusted_reason"] = f"binary_not_found:{_bin_p_lexical}"
            return _r

        # 4) npm global bin 검증 (REJECT#10 핵심: 임의 경로 차단)
        _npm_bin = _get_npm_global_bin()
        _trusted_by_npm = False
        if _npm_bin:
            # REJECT#18 문제 2: npm이 반환한 global bin이 허용된 설치 루트 밖이면 거부(fail-closed).
            #   조작된/주입된 npm이 임의 경로를 global bin으로 반환해도 표준 설치 루트 밖이면 신뢰하지
            #   않는다. 문제 1(_verify_npm_binary_is_system_path)과 독립적인 2차 경계이다.
            if not _verify_npm_global_bin_allowed(_npm_bin):
                _r["untrusted_reason"] = f"npm_global_bin_not_in_allowed_root:{_npm_bin}"
                return _r
            _npm_bin_p = Path(_npm_bin).resolve()
            _in_npm_dir = False
            for _cand_bin in (_bin_p_lexical, _bin_p_resolved):
                try:
                    _cand_bin.relative_to(_npm_bin_p)
                    _in_npm_dir = True
                    break
                except ValueError:
                    pass
            if _in_npm_dir:
                # npm global bin 내에 있음 → wrapper 내용 검증(symlink/shebang/.cmd)
                if not _verify_npm_wrapper_content(_bin_p_lexical):
                    _r["untrusted_reason"] = f"binary_in_npm_dir_but_not_npm_wrapper:{_bin_p_lexical}"
                    return _r
                _trusted_by_npm = True
                _r["install_source"] = "npm_global"

        if not _trusted_by_npm:
            # 5) 시스템 경로 검증 (Linux/macOS 시스템 패키지 설치 경로)
            #    Windows에서는 시스템 경로 예외 없음 — npm global bin 필수
            _SYSTEM_PREFIXES = (
                "/usr/local/bin", "/usr/bin", "/bin",
                "/opt/homebrew/bin", "/opt/homebrew/Cellar",
                "/usr/local/Cellar",
            )
            _trusted_by_system = False
            if sys.platform != "win32":
                for _sp_str in _SYSTEM_PREFIXES:
                    try:
                        _bin_p_lexical.relative_to(Path(_sp_str).resolve())
                        _trusted_by_system = True
                        _r["install_source"] = "system_path"
                        break
                    except ValueError:
                        pass

            if not _trusted_by_system:
                # 임의 사용자 경로 — fail-closed 차단
                _r["untrusted_reason"] = f"binary_in_arbitrary_user_path:{_bin_p_lexical}"
                return _r

        # 6) SHA-256 계산 (신뢰 경로 확인 후; symlink이면 대상 내용 해시)
        try:
            _sha = hashlib.sha256(_bin_p_lexical.read_bytes()).hexdigest()
        except (OSError, PermissionError) as _exc:
            _r["untrusted_reason"] = f"sha_read_error:{type(_exc).__name__}"
            return _r

        # path는 재검증 시 동일 신뢰-위치로 재판정되도록 lexical(PATH 진입점)로 기록한다.
        _r.update({"trusted": True, "path": str(_bin_p_lexical), "sha256": _sha})
        # REJECT#LATEST AC#1/#3/#4 + REJECT#15 문제 A: JS 진입점 + native/vendor binary까지 검증.
        #   래퍼 체인(Windows .cmd 또는 POSIX symlink/shebang)에서는 JS 진입점과 native binary가
        #   모두 필수이다. JS 미발견이나 native binary 미발견은 신뢰 실패로 처리한다 (fail-closed).
        _js_ep = _find_codex_js_entrypoint(_bin_p_lexical)
        if _js_ep is not None:
            # 래퍼 유형 표시: .cmd/.bat → npm_wrapper, 그 외(POSIX symlink/shebang) → posix_npm_symlink.
            _r["install_type"] = (
                "npm_wrapper" if _bin_p_lexical.suffix.lower() in (".cmd", ".bat")
                else "posix_npm_symlink"
            )
            # JS 진입점 발견 → SHA 해시 (fail-closed)
            try:
                _js_sha = hashlib.sha256(_js_ep.read_bytes()).hexdigest()
                _r["js_entrypoint_path"] = str(_js_ep)
                _r["js_entrypoint_sha256"] = _js_sha
            except (OSError, PermissionError) as _exc:
                _r["trusted"] = False
                _r["untrusted_reason"] = f"js_entrypoint_sha_error:{type(_exc).__name__}"
                return _r
            # native/vendor binary 탐색 및 해시 (fail-closed, AC#3/#4)
            _native_bin = _find_codex_native_binary(_js_ep)
            if _native_bin is None:
                _r["trusted"] = False
                _r["untrusted_reason"] = f"native_binary_not_found_for:{_js_ep}"
                return _r
            try:
                _native_sha = hashlib.sha256(_native_bin.read_bytes()).hexdigest()
                _r["native_binary_path"] = str(_native_bin)
                _r["native_binary_sha256"] = _native_sha
            except (OSError, PermissionError) as _exc:
                _r["trusted"] = False
                _r["untrusted_reason"] = f"native_binary_sha_error:{type(_exc).__name__}"
                return _r
            # REJECT#25 AC-1/2: npm 레지스트리 JS SHA 교차검증 (fail-closed).
            #   임시 디렉토리에 @openai/codex를 설치하여 JS SHA를 직접 비교한다.
            #   - available=True, ok=False: 위조 JS 탐지 → acceptance_eligible=False
            #   - available=True, ok=True: 정품 JS 확인 → Authenticode로 최종 결정
            #   - available=False: npm/네트워크 불가 → fail-closed (Authenticode로 대체 불가)
            #   Authenticode는 native binary 체인만 증명; JS 무결성 대체 불가.
            _pkg_version = ""
            for _pkg_json_cand in (
                _js_ep.parent.parent / "package.json",
                _js_ep.parent / "package.json",
            ):
                if _pkg_json_cand.exists():
                    try:
                        _pkg_data = json.loads(
                            _pkg_json_cand.read_text(encoding="utf-8", errors="replace")
                        )
                        _pkg_version = str(_pkg_data.get("version", "") or "")
                    except Exception:  # noqa: BLE001
                        pass
                    break
            _js_registry_check = _verify_codex_js_against_registry(_js_ep, _pkg_version)
            _js_registry_ok = bool(_js_registry_check.get("ok"))
            _js_registry_available = bool(_js_registry_check.get("available"))
            if _js_registry_available and not _js_registry_ok:
                # 레지스트리 확인 성공했으나 SHA 불일치 → 위조 JS 탐지 → fail-closed
                _r["acceptance_eligible"] = False
                _r["provenance_reason"] = (
                    f"js_sha_mismatch_vs_registry:{_js_registry_check.get('reason', '')[:80]}"
                )
            elif not _js_registry_available:
                # REJECT#25: JS 레지스트리 검증 불가(npm 미설치/네트워크 오류/버전 누락/timeout/비-semver)
                #   → fail-closed. Authenticode는 native binary만 증명하며 JS 무결성 대체 불가.
                _r["acceptance_eligible"] = False
                _r["provenance_reason"] = (
                    f"js_registry_unavailable_fail_closed:{_js_registry_check.get('reason', '')[:80]}"
                )
            # REJECT#22/#25: Authenticode — native binary 체인 검증 전용.
            #   acceptance_eligible=True는 registry OK + Authenticode valid 모두 확인 시에만 허용.
            _authenticode = _check_authenticode_signature(str(_native_bin))
            if _authenticode.get("available"):
                if _authenticode.get("ok"):
                    if _js_registry_available and _js_registry_ok:
                        # 레지스트리 정품 확인 + Authenticode valid → acceptance_eligible=True
                        _r["acceptance_eligible"] = True
                        _r["provenance_reason"] = (
                            f"authenticode_valid+registry_ok:{_authenticode.get('subject', '')[:40]}"
                        )
                    # else: registry 실패/불가 → acceptance_eligible=False 유지 (위에서 설정됨)
                else:
                    # Authenticode 실행됐으나 실패 → fake/tampered binary → fail-closed
                    _r["acceptance_eligible"] = False
                    _r["provenance_reason"] = (
                        f"authenticode_invalid:{_authenticode.get('reason', '')[:80]}"
                    )
            else:
                # REJECT#23: Authenticode 미사용 환경(비Windows POSIX + Win32 오류) → fail-closed.
                _r["acceptance_eligible"] = False
                _r["provenance_reason"] = (
                    f"authenticode_unavailable_fail_closed:{_authenticode.get('reason', '')[:60]}"
                )
            # REJECT#28 AC#1/2/3: 실제 실행 체인의 node 인터프리터 신뢰 검증(wrapper 체인 전용).
            #   정품 wrapper/JS/native를 그대로 두고 사용자 쓰기 가능 위치의 악성 node로 로그인·모델·
            #   APPROVE 출력을 위조하는 공격을 차단한다. node 미신뢰 시 acceptance_eligible=False(fail-closed).
            #   이 검사는 Authenticode/registry 판정 이후에 수행하여, node 실패가 최종적으로 승인 자격을
            #   무효화하도록 한다(정품 native여도 악성 node면 차단).
            _node_trust = _verify_node_interpreter_trust(_bin_p_lexical, _js_ep)
            _r["node_interpreter_path"] = str(_node_trust.get("node_interpreter_path", "") or "")
            _r["node_interpreter_sha256"] = str(_node_trust.get("node_interpreter_sha256", "") or "")
            _r["node_interpreter_trusted"] = bool(_node_trust.get("node_interpreter_trusted"))
            if not _r["node_interpreter_trusted"]:
                _r["acceptance_eligible"] = False
                _prev_prov = str(_r.get("provenance_reason", "") or "")
                _node_reason = f"node_interpreter_untrusted:{str(_node_trust.get('node_interpreter_reason', ''))[:60]}"
                _r["provenance_reason"] = (
                    f"{_prev_prov}|{_node_reason}" if _prev_prov else _node_reason
                )
            # REJECT#17 수정 B + REJECT#19: npm provenance 교차 검증 — 조작 양성(tamper) 탐지 전용.
            #   acceptance_eligible은 Authenticode로 결정; 아래는 trust(trusted=False) 판정만 수행.
            try:
                _pkg_root_for_integrity = _js_ep.parent.parent
                # 소스 1: .package-lock.json (조작 양성이면 즉시 차단)
                _lock = _check_npm_lockfile_integrity(_pkg_root_for_integrity)
                if _lock.get("available") and not _lock.get("ok"):
                    _r["trusted"] = False
                    _r["untrusted_reason"] = (
                        f"npm_lockfile_integrity_invalid:{_lock.get('reason', '')}"
                    )
                    return _r
                # 소스 2: package.json _integrity / _resolved (조작 양성이면 즉시 차단)
                _integ = _check_package_json_npm_integrity(_pkg_root_for_integrity)
                if _integ.get("available") and not _integ.get("ok"):
                    _r["trusted"] = False
                    _r["untrusted_reason"] = (
                        f"npm_integrity_non_registry_resolved:{_integ.get('reason', '')}"
                    )
                    return _r
                # 소스 3: npm ls (조작 양성만 차단)
                if not _lock.get("available") and not _integ.get("available"):
                    _npm_ls = _get_npm_ls_integrity(_pkg_root_for_integrity)
                    if _npm_ls.get("available") and not _npm_ls.get("ok"):
                        _r["trusted"] = False
                        _r["untrusted_reason"] = (
                            f"npm_ls_integrity_invalid:{_npm_ls.get('reason', '')}"
                        )
                        return _r
                    # npm ls absent → non-blocking (Authenticode가 acceptance_eligible 결정)
            except Exception as _exc:  # noqa: BLE001
                # provenance 확인 자체 실패는 정상 설치를 깨지 않도록 non-blocking.
                pass
        elif _trusted_by_npm:
            # npm 래퍼 디렉토리에 있으나 JS 진입점을 찾을 수 없음 → fail-closed (AC#1/#4)
            _r["trusted"] = False
            _r["untrusted_reason"] = f"js_entrypoint_not_found_for_npm_wrapper:{_bin_p_lexical}"
            return _r
        else:
            # REJECT#15 문제 B: 시스템 경로 direct native install (Linux 등) → JS 체인 불필요.
            #   codex 실행 파일 자체가 최종 native binary이므로, 위 step 6에서 검증한 codex_binary_path/
            #   sha256이 native 신뢰를 보장한다. 별도 native 체인 필드 부재를 operational trust가
            #   허용하도록 install_type=direct_native로 표시한다(신뢰는 시스템 경로에 한정, fail-closed).
            _r["install_type"] = "direct_native"
            # REJECT#17 수정 C: 시스템 경로 접두사만으로 신뢰하지 않고 위치·소유권을 추가 검증한다.
            #   시스템 경로에 사용자가 직접 쓴(홈/cwd 내부 또는 현재 사용자 소유) 바이너리를 차단한다.
            _own = _verify_direct_native_ownership(_bin_p_lexical)
            if not _own.get("trusted"):
                _r["trusted"] = False
                _r["untrusted_reason"] = f"{_own.get('failure_code')}:{_bin_p_lexical}"
                return _r
        return _r
    except Exception as _exc:  # noqa: BLE001
        _r["untrusted_reason"] = f"path_verification_error:{type(_exc).__name__}:{_exc}"
        return _r


def _check_codex_chatgpt_auth(
    codex_bin: Optional[str] = None,
    node_bin: Optional[str] = None,
    codex_js: Optional[str] = None,
) -> Dict[str, Any]:
    """`codex login status`로 ChatGPT Plus 인증을 강제한다(요구3).

    정확히 "Logged in using ChatGPT" 만 허용한다. 미로그인/상태확인실패/API key/불명은 차단.
    REJECT#9: codex_bin=None(production 모드)이면 binary 경로 신뢰 검증을 먼저 수행한다.

    Args:
        codex_bin: codex 실행 파일 경로(테스트 주입용). None이면 PATH에서 해석.
        node_bin: 신뢰 검증된 node 인터프리터 절대 경로(REJECT#31). codex_js와 함께 제공되면
            login status 확인을 [node_bin, codex_js, "login", "status"]로 직접 실행하여 사용자
            쓰기 가능 npm 래퍼(codex.cmd) 우회를 차단한다. 로그인 상태 위조를 방지한다.
        codex_js: 레지스트리 SHA가 검증된 codex.js 진입점 절대 경로(REJECT#31). node_bin과 함께
            제공될 때만 직접 실행 경로가 활성화된다. None/빈 값이면 기존 codex_bin 경로를 사용.
    Returns:
        {"result": "OK", "auth_source": "chatgpt"} 또는
        {"result": "BLOCKED", "failure_code": str, "message": str}.
    """
    if codex_bin is None:
        # REJECT#9: production 모드에서 PATH에서 찾은 binary 신뢰 검증
        _found = shutil.which("codex") or ""
        if _found:
            _trust = _verify_codex_binary_path_trust(_found)
            if not _trust["trusted"]:
                return {
                    "result": "BLOCKED",
                    "failure_code": "codex_binary_untrusted_path",
                    "message": (
                        f"Codex 실행 파일이 신뢰되지 않은 위치에 있습니다: "
                        f"{_trust['untrusted_reason']}"
                    ),
                    "codex_binary_path": _found,
                    "codex_binary_sha256": "",
                }
            # REJECT#19: acceptance_eligible=False이면 독립 provenance 없음 → 실행 차단(fail-closed).
            #   trusted=True(체인 구조 OK)이더라도 provenance가 없는 binary는 승인 자격 없음.
            if not _trust.get("acceptance_eligible", True):
                return {
                    "result": "BLOCKED",
                    "failure_code": "codex_binary_provenance_absent",
                    "message": (
                        f"Codex 실행 파일의 독립 provenance가 없습니다"
                        f"({_trust.get('provenance_reason', 'provenance_absent_all_sources')}): "
                        "lockfile·package.json·npm ls 세 소스 모두 absent — "
                        "수락 자격 없음(fail-closed)."
                    ),
                    "codex_binary_path": _found,
                    "codex_binary_sha256": _trust.get("sha256", ""),
                }
        _bin = _found or "codex"
    else:
        _bin = str(codex_bin)
        # REJECT#20: 명시적 codex_bin도 신뢰 체인(trusted) 검증은 수행한다. 단, acceptance_eligible은
        #   더 이상 검사하지 않는다. npm 7+ 글로벌 설치에서는 provenance 소스가 모두 부재이므로
        #   acceptance_eligible=False가 항상 발생하여 production flow를 영구 차단하기 때문이다.
        #   (acceptance_eligible 검사는 _cmd_gates_codex_review에서 직접 수행 — 방어 이중 게이트)
        if _bin and _bin != "codex":
            _trust_explicit = _verify_codex_binary_path_trust(_bin)
            if not _trust_explicit["trusted"]:
                return {
                    "result": "BLOCKED",
                    "failure_code": "codex_binary_untrusted_path",
                    "message": (
                        f"Codex 실행 파일(명시)이 신뢰되지 않은 위치에 있습니다: "
                        f"{_trust_explicit['untrusted_reason']}"
                    ),
                    "codex_binary_path": _bin,
                    "codex_binary_sha256": "",
                }
    # REJECT#31 AC#2: node_bin + codex_js가 모두 제공되면 검증된 node로 codex.js를 직접 실행하여
    #   login status를 확인한다. 사용자 쓰기 가능 npm 래퍼(codex.cmd)를 실행 파일로 쓰지 않으므로
    #   악성 래퍼가 "Logged in using ChatGPT"를 위조할 수 없다. 둘 중 하나라도 없으면 기존 경로 유지.
    _auth_node_bin = str(node_bin) if node_bin else ""
    _auth_codex_js = str(codex_js) if codex_js else ""
    if _auth_node_bin and _auth_codex_js:
        _login_cmd = [_auth_node_bin, _auth_codex_js, "login", "status"]
    else:
        _login_cmd = [_bin, "login", "status"]
    # 인증 상태 확인 subprocess에도 OPENAI_API_KEY를 제거한다(API key 인증 경로 차단).
    _env = os.environ.copy()
    _env.pop("OPENAI_API_KEY", None)
    try:
        _res = subprocess.run(
            _login_cmd,
            capture_output=True, text=True, timeout=30,
            encoding="utf-8", errors="replace", env=_env,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError, PermissionError) as _exc:
        return {
            "result": "BLOCKED",
            "failure_code": "codex_auth_check_failed",
            "message": f"codex login status 확인 실패: {type(_exc).__name__}: {_exc}",
        }
    _combined = f"{_res.stdout or ''}\n{_res.stderr or ''}"
    # REJECT#27 Fix C: 부분 문자열 검사 대신 정확한 라인 일치를 사용한다.
    #   "Logged in using ChatGPT" in combined → "Not Logged in using ChatGPT"도 True가 되어 잘못 통과.
    #   공백을 제거한 각 라인이 CODEX_CHATGPT_LOGIN_MARKER와 정확히 일치할 때만 허용한다.
    _auth_ok = (
        _res.returncode == 0
        and any(
            _ln.strip() == CODEX_CHATGPT_LOGIN_MARKER
            for _ln in _combined.splitlines()
        )
    )
    if _auth_ok:
        return {"result": "OK", "auth_source": "chatgpt"}
    return {
        "result": "BLOCKED",
        "failure_code": "codex_not_chatgpt_authenticated",
        "message": (
            "codex login status가 'Logged in using ChatGPT'가 아닙니다 — "
            "ChatGPT Plus 인증만 허용됩니다(API key/미로그인 차단, fail-closed)."
        ),
    }


def _codex_policy_signature(model_policy: Optional[Dict[str, Any]]) -> str:
    """model_policy에서 cache 무효화용 결정적 서명 문자열을 만든다(문제6: 정책 변경→cache miss).

    Args:
        model_policy: _build_codex_model_policy 결과(선택). None이면 빈 서명.
    Returns:
        "risk:model:effort:mode" 형식 문자열(정책 없으면 "").
    """
    if not isinstance(model_policy, dict):
        return ""
    return ":".join(str(model_policy.get(_k, "")) for _k in (
        "risk_level", "selected_model", "selected_reasoning_effort", "mode",
    ))


def _build_codex_prompt_for_review(bundle: Dict[str, Any], pipeline_id: str) -> str:
    """Codex exec stdin에 전달할 리뷰 프롬프트를 조립한다(bundle 요약 + 판정 규칙).

    Args:
        bundle: _build_codex_review_bundle이 만든 review bundle dict.
        pipeline_id: 현재 파이프라인 ID.
    Returns:
        Codex에 stdin으로 넘길 프롬프트 문자열.
    Raises:
        TypeError: bundle이 None/비dict이거나 pipeline_id가 None/비str인 경우.
    """
    if bundle is None or not isinstance(bundle, dict):
        raise TypeError("bundle must be a dict")
    if pipeline_id is None or not isinstance(pipeline_id, str):
        raise TypeError("pipeline_id must be str")
    # IMP-20260712-DAE1 REJECT#4: evidence_complete=False이면 CRITICAL diff hunk가 누락된 것이므로
    #   Codex에게 코드 없이 blind approval을 요구하는 상황이다 → prompt 생성을 차단(fail-closed).
    #   REJECT#29: 예산 증가로 evidence_complete=True 달성 시 이 경로 미진입.
    if not bundle.get("evidence_complete", False):
        _trunc_crit = bundle.get("truncated_critical_hunks", 1)
        _trunc_noncrit = bundle.get("truncated_noncrit_hunks", 0)
        raise ValueError(
            f"evidence_complete=False: diff hunk 누락(truncated_critical={_trunc_crit}, "
            f"truncated_noncrit={_trunc_noncrit}) — Codex 호출 차단(blind approval 방지)"
        )
    _changed = list(bundle.get("changed_files", []) or [])
    lines = [
        f"[Codex Review] pipeline_id={pipeline_id}",
        f"evidence_complete={bundle.get('evidence_complete', False)}",
        f"changed_files_count={bundle.get('changed_files_count', len(_changed))}",
        "",
        "## 변경 파일 목록",
    ]
    lines += [f"  - {f}" for f in _changed[:50]]

    # IMP-20260712-DAE1 REJECT#4: 실제 unified diff hunk를 직렬화한다. Codex가 코드를 직접 읽거나
    #   명령을 실행하지 않고도 변경 내용을 판단할 수 있도록 diff 본문을 그대로 실어 보낸다.
    _hunks = list(bundle.get("diff_hunks", []) or [])
    lines += ["", "## 변경 코드 (unified diff)"]
    for _hunk in _hunks:
        _fn = str(_hunk.get("function", "unknown"))
        _is_crit = bool(_hunk.get("is_critical", False))
        lines.append(f"\n### {'[CRITICAL] ' if _is_crit else ''}함수: {_fn}")
        lines.append(str(_hunk.get("hunk", "")))

    _fas = bundle.get("function_before_after_shas") or {}
    if _fas:
        lines += [
            "",
            "## 함수 변경 SHA (before → after)",
            "# 주의: 실제로 변경된 함수(before != after)만 아래에 표시됩니다.",
            "# 이 목록에 없는 함수는 변경되지 않았습니다.",
        ]
        for _fn_id, _shas in _fas.items():
            _b = str(_shas.get("before", "") or "")
            _a = str(_shas.get("after", "") or "")
            lines.append(f"  {_fn_id}: {_b[:16]}...→{_a[:16]}...")

    # REJECT#6: CRITICAL Python 파일의 file-level SHA attestation을 프롬프트에 포함한다.
    # diff 대신 SHA로 변경 증거가 제공되는 CRITICAL 파일의 내용 변경 여부를 Codex에 전달한다.
    _file_shas = bundle.get("file_sha_attestations") or {}
    if _file_shas:
        lines += [
            "",
            "## CRITICAL Python 파일 SHA 증거 (file-level before → after)",
            "# 이 파일들은 diff 대신 file-level SHA로 변경 증거를 제공합니다.",
            "# [CHANGED] = before_sha != after_sha (파일 내용 변경됨).",
            "# [UNCHANGED] = before_sha == after_sha (파일 내용 동일).",
        ]
        for _fp, _shas in sorted(_file_shas.items()):
            _b = str(_shas.get("before_sha", "") or "")
            _a = str(_shas.get("after_sha", "") or "")
            _chg = bool(_shas.get("changed", False))
            _tag = "[CHANGED]  " if _chg else "[UNCHANGED]"
            lines.append(f"  {_tag} {_fp}: {_b[:16]}...→{_a[:16]}...")

    _tassert = bundle.get("test_assertions") or {}
    if _tassert:
        lines += ["", "## 테스트 검증 근거 (핵심 assert)"]
        for _tf, _assertions in _tassert.items():
            lines.append(f"\n{_tf}:")
            # test_assertions는 리스트(원문) 또는 int(개수, redacted disk bundle)일 수 있다.
            if isinstance(_assertions, list):
                for _a in _assertions[:20]:
                    lines.append(f"  {_a}")
            else:
                lines.append(f"  (assert {_assertions}개)")

    _oracles = bundle.get("oracle_results") or []
    if _oracles:
        lines += ["", "## Oracle 검증 결과"]
        for _oc in _oracles[:10]:
            lines.append(
                f"  {_oc.get('case_id', '')}: "
                f"{_oc.get('case_kind', '')} → {_oc.get('result', '')}"
            )

    # IMP-20260712-DAE1 REJECT#3(요구6): verdict 스키마를 JSON으로 강제한다.
    # IMP-20260712-DAE1 bugfix#3/4: 모델이 파일을 읽거나 명령어를 실행하여 내부 타임아웃이 발생하는
    # 버그 수정. 위에서 제공한 diff 내용만 보고 판단하도록 명령어 실행과 파일 읽기를 금지한다.
    lines += [
        "",
        "## 출력 규칙 (엄격히 준수 필수)",
        "- 쉘 명령어를 실행하지 마세요 (command_execution 사용 금지).",
        "- 파일을 직접 읽지 마세요. 위 diff 내용만으로 판단하세요.",
        "- 리뷰 분석/설명/코드 인용 텍스트를 출력하지 마세요.",
        "- 마지막 출력은 아래 JSON 하나만 출력하세요 (다른 텍스트 없이).",
        '승인: {"verdict": "APPROVE_TO_USER"}',
        '거절: {"verdict": "REJECT", "root_cause": "...", "reproduction": "...", '
        '"required_fix": "...", "acceptance_criteria": ["..."]}',
        "REJECT인데 root_cause/reproduction/required_fix/acceptance_criteria 중 하나라도 "
        "누락되면 무효 처리됩니다.",
    ]
    return "\n".join(lines)


def _check_codex_capability_gate(
    actual_model: str,
    risk_level: str,
    verification_level: str = CODEX_VERIFICATION_UNVERIFIED,
) -> Dict[str, Any]:
    """HIGH/CRITICAL에서 최소 invocation_verified 이상 필요(IMP-20260712-DAE1 REJECT#12 정책).

    REJECT#12 fix: CRITICAL도 invocation_verified 허용. actual_verified 필수 요건 제거.
    gpt-5.6-* CLI는 actual_model/effort를 보고하지 않으므로 actual_verified는 달성 불가.
    unverified(명시 인자 실행 불확실 또는 exit 비정상)만 HIGH/CRITICAL에서 차단한다.

    Args:
        actual_model: 감지된 실제 모델명 (REJECT#12: 미사용으로 전환, 호환성 보존용 유지).
        risk_level: 현재 risk level (대소문자 무관).
        verification_level: _compute_model_verification_level 결과.
    Returns:
        {"result": "OK"} 또는
        {"result": "BLOCKED", "failure_code": "model_verification_unverified"}.
    """
    _risk = str(risk_level or "").upper()
    _vl = str(verification_level or CODEX_VERIFICATION_UNVERIFIED)
    if _risk in {"HIGH", "CRITICAL"} and _vl == CODEX_VERIFICATION_UNVERIFIED:
        return {"result": "BLOCKED", "failure_code": "model_verification_unverified"}
    return {"result": "OK"}


# [Purpose]: IMP-20260712-DAE1 REJECT#4 — Codex가 실제 변경 코드를 볼 수 있도록 semantic evidence
#   (unified diff hunk + 함수 before/after SHA + 테스트 assert + oracle 결과)를 조립한다. 원문(코드)은
#   bundle 파일에 persist하지 않고 Codex prompt(stdin)에만 실어, no_nonce_exposure/TC-J(대문자 8자
#   토큰 금지) 불변식과 충돌하지 않게 한다. bundle 파일에는 이 결과에서 도출한 redacted 메타데이터
#   (함수명/is_critical/chars/hunk_sha256, 함수 SHA, 개수, semantic_evidence_sha256)만 기록한다.
# [Assumptions]: origin/main이 로컬에 fetch되어 있어 `git diff/show origin/main`이 동작한다. 실패는
#   best-effort로 흡수하고 evidence_complete=False로 fail-closed한다.
# [Vulnerability & Risks]: 함수 본문 추출이 실패하면 before/after SHA가 빈 값이 된다. ast 파싱 실패
#   시 라인 기반 fallback을 사용한다. 병리적 대형 diff는 CODEX_REVIEW_BUNDLE_BUDGET_CHARS로 절단한다.
# [Improvement]: 파일::함수 단위 정밀 diff 매칭(현재는 pipeline.py 단일 파일 hunk 파싱)으로 고도화 가능.
def _extract_python_function_bodies(source: str) -> Dict[str, str]:
    """파이썬 소스에서 {함수명: 함수본문소스} 매핑을 O(n) 단일 패스로 추출한다.

    성능: 대형 파일(pipeline.py ~34k줄)에서 ast.parse는 파싱만 4초 이상 소요되므로, 함수 본문
    SHA 계산에는 ast를 쓰지 않고 들여쓰기 기반 라인 스택으로 단일 패스 추출한다(중복 함수명은
    첫 정의를 우선). def 라인부터, 이후 같거나 더 얕은 들여쓰기의 코드가 나오기 직전까지를 본문으로 본다.

    Args:
        source: 파이썬 소스 전체 텍스트.
    Returns:
        {함수명: 본문 소스 문자열}. 입력이 비었으면 빈 dict.
    """
    if source is None or not isinstance(source, str) or not source.strip():
        return {}
    bodies: Dict[str, str] = {}
    lines = source.splitlines()
    _def_re = re.compile(r"^(\s*)(?:async\s+)?def\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(")
    # open_defs: (indent, name, start_idx) 스택. 현재 라인 들여쓰기가 스택 상단 def의
    #   들여쓰기 이하이면 그 def의 본문이 끝난 것으로 보고 [start_idx, i)를 본문으로 확정한다.
    open_defs: List[Tuple[int, str, int]] = []

    def _close(_end_idx: int) -> None:
        _ind, _name, _start = open_defs.pop()
        if _name not in bodies:
            bodies[_name] = "\n".join(lines[_start:_end_idx]).rstrip()

    for _i, _ln in enumerate(lines):
        if not _ln.strip():
            continue  # 빈 줄은 경계 판정에서 무시(본문에는 slice로 포함됨)
        _indent = len(_ln) - len(_ln.lstrip())
        # 데코레이터(@...)는 다음 def의 일부로 취급하여 경계 판정에서 제외한다.
        if _ln.lstrip().startswith("@"):
            continue
        while open_defs and _indent <= open_defs[-1][0]:
            _close(_i)
        _m = _def_re.match(_ln)
        if _m:
            open_defs.append((len(_m.group(1)), _m.group(2), _i))
    while open_defs:
        _close(len(lines))
    return bodies


def _build_codex_semantic_evidence(
    pipeline_id: str,
    changed_files: List[str],
    included_functions: List[str],
) -> Dict[str, Any]:
    """실제 변경 코드를 담은 Codex semantic evidence dict를 조립한다(원문 포함).

    Args:
        pipeline_id: 현재 파이프라인 ID (None 불가).
        changed_files: 변경 파일 경로 목록 (None → 빈 목록).
        included_functions: 변경/추가된 pipeline.py 함수명 목록 (None → 빈 목록).
    Returns:
        {"diff_hunks": [{function, hunk, is_critical, chars}], "function_before_after_shas": {},
         "test_assertions": {}, "oracle_results": [], "evidence_complete": bool,
         "truncated_critical_hunks": int, "bundle_budget_chars": int,
         "semantic_evidence_sha256": str}.
    Raises:
        TypeError: pipeline_id가 None/비str인 경우.
    """
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(f"pipeline_id must be str, got {type(pipeline_id).__name__}")
    _cf: List[str] = [str(f) for f in (changed_files or [])]
    _funcs: List[str] = [str(f) for f in (included_functions or [])]

    sem: Dict[str, Any] = {
        "diff_hunks": [],
        "function_before_after_shas": {},
        "file_sha_attestations": {},       # REJECT#35: CRITICAL Python 파일의 file-level SHA 증거
        "test_assertions": {},
        "oracle_results": [],
        "evidence_complete": False,
        "truncated_critical_hunks": 0,
        "truncated_noncrit_hunks": 0,      # REJECT#35: non-critical 예산 초과 카운트
        "missing_noncrit_files": [],        # REJECT#35: non-critical 누락 파일 목록
        "missing_critical_files": [],       # REJECT#35: CRITICAL 파일 중 diff도 SHA도 없는 파일
        "bundle_budget_chars": 0,
        "semantic_evidence_sha256": "",
        "changed_constants": [],  # REJECT#32: CODEX_CRITICAL_CONSTANTS 소속 변경 상수 목록
    }

    _crit_funcs = set(CODEX_CRITICAL_FUNCTIONS)

    # 1) diff_hunks: git diff origin/main...HEAD --unified=3 -- pipeline.py
    # IMP-20260712-DAE1 REJECT#10: --unified=8→3 (hunk 분리 정밀도 향상, 예산 절약).
    _diff_ok = False
    _all_hunks: List[Dict[str, Any]] = []
    _nonpy_crit_expected: List[str] = []  # 비Python CRITICAL 파일 목록 (cross-validation용)
    try:
        if "pipeline.py" in _cf:
            _dr = subprocess.run(
                ["git", "diff", "origin/main...HEAD", "--unified=3", "--", "pipeline.py"],
                capture_output=True, text=True, timeout=30,
                cwd=str(BASE_DIR), encoding="utf-8", errors="replace",
            )
            if _dr.returncode == 0:
                _diff_ok = True
                _cur_fn = "unknown"
                _cur_lines: List[str] = []

                def _flush(_fn: str, _buf: List[str]) -> None:
                    if not _buf:
                        return
                    _txt = "\n".join(_buf)
                    _all_hunks.append({
                        "function": _fn,
                        "hunk": _txt,
                        # REJECT#28 Fix 2: pipeline.py의 unknown function hunk는 최소 CRITICAL로
                        #   취급한다. hunk 헤더에서 함수명을 추출할 수 없을 때 non-critical로 분류하면
                        #   예산 초과 시 조용히 누락되어 evidence_complete=True가 될 수 있다.
                        "is_critical": _fn in _crit_funcs or _fn == "unknown",
                        "chars": len(_txt),
                    })

                for _ln in _dr.stdout.splitlines():
                    if _ln.startswith("@@"):
                        _flush(_cur_fn, _cur_lines)
                        _cur_lines = [_ln]
                        _ctx_m = re.search(
                            r"@@[^@]*@@\s*(?:async\s+)?def\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(",
                            _ln,
                        )
                        _cur_fn = _ctx_m.group(1) if _ctx_m else "unknown"
                    elif _ln.startswith(("---", "+++", "diff --git", "index ")):
                        continue
                    else:
                        if _cur_lines:
                            _cur_lines.append(_ln)
                _flush(_cur_fn, _cur_lines)

            # REJECT#32 Fix: pipeline.py diff에서 CODEX_CRITICAL_CONSTANTS 소속 상수 변경 감지.
            #   `+CONST_NAME` / `-CONST_NAME` 줄(모듈 상단 상수 정의)을 스캔한다.
            _changed_const_set: set = set()
            _crit_const_names = set(CODEX_CRITICAL_CONSTANTS)
            for _diff_scan_ln in _dr.stdout.splitlines():
                # 추가/삭제 줄만 검사. diff 헤더/메타 줄 제외.
                if not (_diff_scan_ln.startswith("+") or _diff_scan_ln.startswith("-")):
                    continue
                if _diff_scan_ln.startswith(("---", "+++")):
                    continue
                _scan_stripped = _diff_scan_ln[1:].strip()
                for _cc in _crit_const_names:
                    # 상수 이름으로 시작하는 정의 줄: "CODEX_MODEL_POLICIES: Dict = {" 등.
                    if _scan_stripped.startswith(_cc):
                        _changed_const_set.add(_cc)
                        break
            sem["changed_constants"] = sorted(_changed_const_set)
    except Exception:  # noqa: BLE001 — diff 실패는 fail-closed(evidence_complete=False)
        _diff_ok = False

    # IMP-20260712-DAE1 REJECT#16 결함B: 이 시점의 _all_hunks는 section 1의 pipeline.py
    #   function-level hunk만 담고 있다(1b/1c는 아직 실행 전). pipeline.py hunk는 파일 경로가 아니라
    #   함수명(또는 "unknown")을 "function" 키로 갖는다. 이 함수명 집합을 캡처하여, 아래 coverage
    #   판정에서 pipeline.py 유래 hunk(CRITICAL/비CRITICAL 무관)가 selected diff_hunks에 남아 있는지
    #   정확히 확인한다(기존 `any(is_critical)` 전역 검사가 비CRITICAL-only 변경을 놓치던 문제 해결).
    _pipeline_py_hunk_funcs: set = {
        (_h.get("function", "") or "") for _h in _all_hunks
    }

    # 1b) pipeline.py 이외의 CRITICAL 파일 diff 추출 또는 file-level SHA 증거 생성.
    # IMP-20260712-DAE1 REJECT#10: pipeline.py 이외의 CRITICAL 파일도 diff hunk로 포함.
    # REJECT#35: Python CRITICAL 파일(test_codex*.py 등)은 diff 예산 절약을 위해 file-level SHA
    #   attestation으로 처리한다 (AC#3: "diff가 리뷰 입력에 포함되거나 SHA로 결합된 분할 검토").
    #   비Python CRITICAL 파일(.md, .yml 등)은 기존과 같이 전체 diff hunk로 포함.
    #   pipeline.py는 위의 `if _cpf_n == "pipeline.py": continue`에서 이미 제외됨.
    try:
        for _cpf in _cf:
            _cpf_n = _cpf.replace("\\", "/")
            if _cpf_n == "pipeline.py":
                continue  # pipeline.py는 위에서 이미 처리
            if not _is_codex_critical_file(_cpf_n):
                continue
            # REJECT#35: Python CRITICAL 파일은 file-level SHA attestation으로 무결성 증거 수집.
            # REJECT#7: SHA 외에 실제 unified diff도 수집하여 Codex가 decorator/import 변경을 볼 수 있도록.
            #   (SHA만 제공 시 @_CODEX_SKIP 추가 같은 변경이 Codex 입력에서 숨겨지는 문제).
            if _cpf_n.endswith(".py"):
                # SHA attestation (무결성 증거)
                try:
                    _before_sha_r = subprocess.run(
                        ["git", "show", f"origin/main:{_cpf_n}"],
                        capture_output=True, text=True, timeout=30,
                        cwd=str(BASE_DIR), encoding="utf-8", errors="replace",
                    )
                    _before_content = _before_sha_r.stdout if _before_sha_r.returncode == 0 else ""
                    _after_path = BASE_DIR / _cpf_n
                    _after_content = _after_path.read_text(encoding="utf-8", errors="replace") if _after_path.exists() else ""
                    _b_file_sha = hashlib.sha256(_before_content.encode("utf-8")).hexdigest() if _before_content else ""
                    _a_file_sha = hashlib.sha256(_after_content.encode("utf-8")).hexdigest() if _after_content else ""
                    sem["file_sha_attestations"][_cpf_n] = {
                        "before_sha": _b_file_sha,
                        "after_sha": _a_file_sha,
                        "changed": _b_file_sha != _a_file_sha,
                    }
                    if _a_file_sha:
                        # REJECT#11: SHA 수집 성공만으로 _diff_ok=True 하지 않음.
                        # SHA attestation은 무결성 결합용이며 semantic evidence를 대체하지 않는다.
                        # _diff_ok는 실제 diff 청크 수집 후에만 True로 설정.
                        pass
                except Exception:  # noqa: BLE001
                    pass  # SHA 수집 실패는 missing_critical_files에서 감지됨
                # REJECT#7: 실제 unified diff 수집 — Codex가 decorator/import/assert 변경을 볼 수 있어야 함.
                # REJECT#8: 파일당 50K 단일 청크 방식(REJECT#7)은 50K 이후 내용을 silently drop하여
                #   truncated_critical_hunks=0 / evidence_complete=True를 잘못 반환한다.
                #   → 45K 청크로 분할하여 전체 diff를 _all_hunks에 추가.
                #   budget 초과로 청크가 제거되면 budget trimmer가 truncated_critical_hunks를 증가시켜
                #   evidence_complete=False로 차단한다 (fail-closed).
                # REJECT#11: diff 청크가 추가된 경우에만 _diff_ok=True로 설정.
                _before_hunk_count = len(_all_hunks)
                _PY_CRIT_CHUNK_SIZE = 45000  # 청크당 45K (part 헤더 포함 후 50K 이내 안전 마진)
                try:
                    _py_diff_r = subprocess.run(
                        ["git", "diff", "origin/main", "--unified=3", "--", _cpf_n],
                        capture_output=True, text=True, timeout=30,
                        cwd=str(BASE_DIR), encoding="utf-8", errors="replace",
                    )
                    if _py_diff_r.returncode == 0 and _py_diff_r.stdout.strip():
                        _py_diff_text = _py_diff_r.stdout.strip()
                        if len(_py_diff_text) <= _PY_CRIT_CHUNK_SIZE:
                            # 단일 청크: 분할 불필요
                            _all_hunks.append({
                                "function": _cpf_n,
                                "hunk": _py_diff_text,
                                "is_critical": True,
                                "chars": len(_py_diff_text),
                                "hunk_sha256": hashlib.sha256(_py_diff_text.encode("utf-8")).hexdigest(),
                            })
                        else:
                            # 다중 청크: 절단 없이 45K 단위로 분할하여 전체 포함
                            _chunks: List[str] = []
                            _off = 0
                            while _off < len(_py_diff_text):
                                _chunks.append(_py_diff_text[_off:_off + _PY_CRIT_CHUNK_SIZE])
                                _off += _PY_CRIT_CHUNK_SIZE
                            _n_ch = len(_chunks)
                            for _chi, _ck in enumerate(_chunks, 1):
                                _ck_hdr = f"[CRITICAL_PYTHON_DIFF_PART_{_chi}_OF_{_n_ch}]\n{_ck}"
                                _all_hunks.append({
                                    "function": f"{_cpf_n} [PART {_chi}/{_n_ch}]",
                                    "hunk": _ck_hdr,
                                    "is_critical": True,
                                    "chars": len(_ck_hdr),
                                    "hunk_sha256": hashlib.sha256(_ck_hdr.encode("utf-8")).hexdigest(),
                                })
                except Exception:  # noqa: BLE001
                    pass  # diff 수집 실패는 missing_critical_files에서 감지됨
                # REJECT#11: SHA가 아닌 실제 diff 청크 수집 성공 시에만 _diff_ok=True
                if len(_all_hunks) > _before_hunk_count:
                    _diff_ok = True
                continue
            _nonpy_crit_expected.append(_cpf_n)
            _npdr = subprocess.run(
                ["git", "diff", "origin/main...HEAD", "--unified=3", "--", _cpf_n],
                capture_output=True, text=True, timeout=30,
                cwd=str(BASE_DIR), encoding="utf-8", errors="replace",
            )
            if _npdr.returncode == 0 and _npdr.stdout.strip():
                _nptxt = _npdr.stdout.strip()
                _all_hunks.append({
                    "function": _cpf_n,
                    "hunk": _nptxt,
                    "is_critical": True,
                    "chars": len(_nptxt),
                })
                # REJECT#34: 비Python CRITICAL 파일 diff 수집 성공 → evidence_complete 조건 충족.
                #   pipeline.py가 없어도 .claude/agents/*.md 등 CRITICAL 파일만 변경한 PR에서
                #   hunk 수집 성공 시 evidence_complete=True가 되어야 한다.
                _diff_ok = True
    except Exception:  # noqa: BLE001 — 비Python diff 실패는 cross-validation에서 감지
        pass

    # 1c) 비CRITICAL changed file diff 추출 (LOW/MEDIUM risk 파일 포함).
    # REJECT#25 Fix 1: pipeline.py가 없는 LOW 문서·MEDIUM 코드 변경에서도 실제 변경 diff를
    #   포함하고 evidence_complete=True를 보장한다.
    #   비CRITICAL 파일도 diff를 수집하여 diff_hunks에 추가(is_critical=False).
    #   파일 diff 하나라도 성공하면 _diff_ok=True로 갱신하여 evidence_complete 조건을 충족시킨다.
    # IMP-20260712-DAE1 REJECT#15 Fix3: diff 실패·빈 출력도 _diff_failed_noncrit에 기록하여
    #   evidence_complete=False로 처리한다. 조용히 무시하면 changed_files 목록 전체가 diff로
    #   커버됐는지 보장할 수 없으므로 fail-closed로 추적한다.
    _diff_failed_noncrit: List[str] = []
    try:
        for _ncf in _cf:
            _ncf_n = _ncf.replace("\\", "/")
            if _ncf_n == "pipeline.py":
                continue  # pipeline.py는 section 1에서 이미 처리
            if _is_codex_critical_file(_ncf_n):
                continue  # CRITICAL 파일은 section 1b에서 이미 처리
            _ncdr = subprocess.run(
                ["git", "diff", "origin/main...HEAD", "--unified=3", "--", _ncf_n],
                capture_output=True, text=True, timeout=30,
                cwd=str(BASE_DIR), encoding="utf-8", errors="replace",
            )
            if _ncdr.returncode == 0 and _ncdr.stdout.strip():
                _nctxt = _ncdr.stdout.strip()
                _all_hunks.append({
                    "function": _ncf_n,
                    "hunk": _nctxt,
                    "is_critical": False,
                    "chars": len(_nctxt),
                })
                _diff_ok = True  # 비CRITICAL 파일 diff 성공 → _diff_ok=True
            else:
                # diff 실패 또는 빈 출력: 파일이 changed_files에 있는데 diff를 얻지 못한 경우.
                _diff_failed_noncrit.append(_ncf_n)
    except Exception:  # noqa: BLE001 — loop 자체 예외는 무시하되 이미 수집된 실패 목록은 보존
        pass

    # 예산 적용: CRITICAL hunk를 먼저 채우고, 예산 초과 시 truncated_critical_hunks 계수.
    # REJECT#35: non-critical도 예산 초과 시 truncated_noncrit 계수. missing_noncrit_files 기록.
    _budget = CODEX_REVIEW_BUNDLE_BUDGET_CHARS
    _used = 0
    _truncated_crit = 0
    _truncated_noncrit = 0
    _missing_noncrit_files: List[str] = []
    _selected: List[Dict[str, Any]] = []
    _crit_hunks = [h for h in _all_hunks if h.get("is_critical")]
    _noncrit_hunks = [h for h in _all_hunks if not h.get("is_critical")]
    for _h in _crit_hunks:
        _c = int(_h.get("chars", 0))
        if _used + _c <= _budget:
            _selected.append(_h)
            _used += _c
        else:
            _truncated_crit += 1  # CRITICAL hunk가 예산 초과로 잘림 → evidence 불완전
    for _h in _noncrit_hunks:
        _c = int(_h.get("chars", 0))
        if _used + _c <= _budget:
            _selected.append(_h)
            _used += _c
        else:
            # REJECT#35: non-critical 예산 초과도 evidence_complete에 영향을 준다.
            #   조용히 제외하지 않고 누락 수·파일명을 기록한다.
            _truncated_noncrit += 1
            _missing_noncrit_files.append(_h.get("function", "unknown"))
    sem["diff_hunks"] = _selected
    sem["truncated_critical_hunks"] = _truncated_crit
    sem["truncated_noncrit_hunks"] = _truncated_noncrit
    # IMP-20260712-DAE1 REJECT#15 Fix3: diff 실패 파일도 missing_noncrit_files에 포함.
    #   예산 초과로 잘린 파일과 diff 자체에 실패한 파일을 모두 누락으로 처리한다.
    _missing_noncrit_files.extend(_diff_failed_noncrit)
    sem["missing_noncrit_files"] = _missing_noncrit_files
    sem["bundle_budget_chars"] = _used

    # 2) function_before_after_shas: 각 변경 함수의 base/current 본문 SHA (best-effort).
    _fas: Dict[str, Dict[str, str]] = {}
    try:
        _before_bodies: Dict[str, str] = {}
        _after_bodies: Dict[str, str] = {}
        if _funcs and "pipeline.py" in _cf:
            try:
                _br = subprocess.run(
                    ["git", "show", "origin/main:pipeline.py"],
                    capture_output=True, text=True, timeout=30,
                    cwd=str(BASE_DIR), encoding="utf-8", errors="replace",
                )
                if _br.returncode == 0:
                    _before_bodies = _extract_python_function_bodies(_br.stdout)
            except Exception:  # noqa: BLE001
                _before_bodies = {}
            try:
                _cur_src = (BASE_DIR / "pipeline.py").read_text(
                    encoding="utf-8", errors="replace"
                )
                _after_bodies = _extract_python_function_bodies(_cur_src)
            except Exception:  # noqa: BLE001
                _after_bodies = {}
        for _fn in _funcs:
            _bs = _before_bodies.get(_fn, "")
            _as = _after_bodies.get(_fn, "")
            _b_sha = hashlib.sha256(_bs.encode("utf-8")).hexdigest() if _bs else ""
            _a_sha = hashlib.sha256(_as.encode("utf-8")).hexdigest() if _as else ""
            # IMP-20260712-DAE1 REJECT#6: 실제로 변경된 함수(before != after)만 포함한다.
            # IMP-20260712-DAE1 REJECT#10: CRITICAL 함수만 포함(비CRITICAL 제거 — build_parser 등).
            #   비CRITICAL 함수를 SHA 목록에 포함하면 Codex가 diff 없는 이유를 오해한다.
            # REJECT#28 Fix 1: 신규 추가 CRITICAL 함수(before_sha="")와 삭제된 CRITICAL 함수(after_sha="")도
            #   SHA 항목에 포함하여 필수 커버리지 대상으로 기록한다.
            #   기존: _b_sha AND _a_sha 둘 다 필요 → 신규/삭제 함수 제외(fail-open 취약).
            #   수정: _b_sha OR _a_sha 하나만 있어도 CRITICAL이면 포함.
            if _fn in _crit_funcs and (_b_sha or _a_sha) and _b_sha != _a_sha:
                _fas[f"pipeline.py::{_fn}"] = {"before": _b_sha, "after": _a_sha}
    except Exception:  # noqa: BLE001
        _fas = {}
    sem["function_before_after_shas"] = _fas

    # REJECT#30 Fix 2: hunk 단위 CRITICAL 누락 감지 — 기존 함수명 set 방식 대체.
    # 이전 방식(REJECT#10, REJECT#15, REJECT#28 Fix 3a/3b)의 3가지 취약점:
    #   (a) 같은 CRITICAL 함수에 여러 hunk가 있고 일부만 선택 → 함수명이 _covered_ids에 있어
    #       나머지 hunk 누락이 검출되지 않음 (REJECT#30 AC#2).
    #   (b) Fix 3a(신규·삭제 함수 skip) → before/after SHA 한쪽이 빈 경우 hunk 포함 강제 불가
    #       (REJECT#30 AC#3: "신규·삭제 함수도 해당 diff hunk 포함을 강제해야 함").
    #   (c) `_truncated_crit = 0` 초기화로 budget 단계 누락 수(line 9053)가 지워짐.
    # 수정: is_critical=True hunk 총 수 vs _selected 내 수를 직접 비교.
    #   신규·삭제 함수 hunk, 멀티-hunk, unknown-named hunk, 비Python CRITICAL 파일 hunk가
    #   모두 동일한 단일 계산에 포함된다. 별도 루프(_fas loop, _nonpy loop, Fix 3b)가 불필요.
    try:
        _all_crit_count = sum(1 for _h in _all_hunks if _h.get("is_critical"))
        _sel_crit_count = sum(1 for _h in _selected if _h.get("is_critical"))
        _truncated_crit = max(0, _all_crit_count - _sel_crit_count)
        sem["truncated_critical_hunks"] = _truncated_crit
    except Exception:  # noqa: BLE001 — cross-validation 실패 → fail-closed
        _truncated_crit += 1
        sem["truncated_critical_hunks"] = _truncated_crit

    # 3) test_assertions: 변경된 테스트 파일의 test_* 함수별 assert 라인(최대 5개).
    _tassert: Dict[str, List[str]] = {}
    try:
        _test_fn_re = re.compile(r"^\s*def\s+(test_[A-Za-z0-9_]*)\s*\(")
        for _tf in _cf:
            _tfn = _tf.replace("\\", "/")
            if not (_tfn.startswith("tests/") and _tfn.endswith(".py")):
                continue
            _tfp = BASE_DIR / _tfn
            if not _tfp.exists():
                continue
            try:
                _tlines = _tfp.read_text(
                    encoding="utf-8", errors="replace"
                ).splitlines()
            except Exception:  # noqa: BLE001
                continue
            _cur_test = ""
            for _tl in _tlines:
                _tm = _test_fn_re.match(_tl)
                if _tm:
                    _cur_test = _tm.group(1)
                    _tassert.setdefault(_cur_test, [])
                    continue
                if _cur_test and _tl.strip().startswith("assert "):
                    if len(_tassert[_cur_test]) < 5:
                        _tassert[_cur_test].append(_tl.strip())
        # 빈 assert 목록 test는 제거(노이즈 축소).
        _tassert = {_k: _v for _k, _v in _tassert.items() if _v}
    except Exception:  # noqa: BLE001
        _tassert = {}
    sem["test_assertions"] = _tassert

    # 4) oracle_results: oracle case 요약(case_id/case_kind/result). 원문 미포함(소문자 안전).
    _ores: List[Dict[str, str]] = []
    try:
        _odir = BASE_DIR / "tests" / "oracles" / pipeline_id
        if _odir.exists() and _odir.is_dir():
            for _cdir in sorted(p for p in _odir.iterdir() if p.is_dir()):
                _kind = "unknown"
                _meta = _cdir / "case.json"
                if _meta.exists():
                    try:
                        _mj = json.loads(_meta.read_text(encoding="utf-8"))
                        if isinstance(_mj, dict):
                            _kind = str(_mj.get("case_kind", "unknown") or "unknown")
                    except Exception:  # noqa: BLE001
                        _kind = "unknown"
                _ores.append({
                    "case_id": _cdir.name,
                    "case_kind": _kind,
                    "result": "recorded",
                })
    except Exception:  # noqa: BLE001
        _ores = []
    sem["oracle_results"] = _ores

    # 5) evidence_complete: 모든 CRITICAL 변경 파일이 실제 diff hunk에 커버되었고
    #    budget 초과 없을 때 True.
    #    REJECT#11: SHA attestation은 무결성 증거로만 사용하며 evidence_complete 판정에 불충분.
    #    CRITICAL 파일은 반드시 실제 diff hunk가 있어야 evidence_complete=True가 된다.
    #    fail-closed: changed_files가 비었고 CRITICAL 파일도 없으면 False.
    _has_critical_file = any(_is_codex_critical_file(f) for f in _cf)
    # REJECT#11: _hunk_covered_files = 실제 diff hunk가 있는 파일의 base명 집합.
    # pipeline.py는 function-level hunk로 처리되며 함수명이 "function" 키다.
    # 다른 CRITICAL Python 파일은 file 경로가 "function" 키 또는 "[PART N/M]" suffix 형태.
    # "[PART N/M]" suffix를 제거해 base 파일명을 추출한다.
    _hunk_covered_files: set = set()
    for _h in sem["diff_hunks"]:
        _fn_str: str = _h.get("function", "") or ""
        # PART suffix 제거 (예: "tests/e2e/foo.py [PART 2/4]" → "tests/e2e/foo.py")
        _fn_base = _fn_str.split(" [PART ")[0]
        _hunk_covered_files.add(_fn_base)
    # pipeline.py: pipeline.py에서 유래한 hunk(CRITICAL/비CRITICAL 무관)가 selected diff_hunks에
    #   하나라도 남아 있으면 pipeline.py 자체를 커버됨으로 처리한다.
    #   IMP-20260712-DAE1 REJECT#16 결함B: 기존 `any(is_critical)` 조건은 두 가지 결함이 있었다.
    #     (1) pipeline.py의 비CRITICAL 함수(build_parser 등)만 변경된 경우, pipeline.py hunk가
    #         selected에 있어도 is_critical=False라 pipeline.py를 covered로 인정하지 못해
    #         missing_critical_files에 남고 evidence_complete=False로 불필요하게 차단됐다.
    #     (2) 다른 파일의 CRITICAL hunk에도 True가 되는 부정확한 전역 검사였다.
    #   → pipeline.py 유래 hunk(function이 _pipeline_py_hunk_funcs에 속함)를 직접 확인한다.
    #   CRITICAL hunk가 예산 초과로 절단되면 아래 _truncated_crit 검사가 evidence_complete=False를
    #   그대로 강제하므로, 이 완화는 CRITICAL 완전성 검사를 약화하지 않는다.
    if "pipeline.py" in _cf and any(
        (_h.get("function", "") or "") in _pipeline_py_hunk_funcs
        for _h in sem["diff_hunks"]
    ):
        _hunk_covered_files.add("pipeline.py")
    _sha_covered = set(sem["file_sha_attestations"].keys())
    _crit_changed = [
        f.replace("\\", "/") for f in _cf if _is_codex_critical_file(f.replace("\\", "/"))
    ]
    # REJECT#11: CRITICAL 파일은 실제 diff hunk 기준으로 누락 판정
    # (SHA attestation만으로는 missing에서 제외되지 않음)
    sem["missing_critical_files"] = [
        f for f in _crit_changed
        if f not in _hunk_covered_files
    ]
    if not _cf and not _has_critical_file:
        sem["evidence_complete"] = False
    else:
        sem["evidence_complete"] = bool(
            _diff_ok
            and _truncated_crit == 0
            and _truncated_noncrit == 0
            and len(sem["missing_critical_files"]) == 0
            and len(sem["diff_hunks"]) > 0  # REJECT#11: file_sha_attestations만으로는 불충분
            and len(_diff_failed_noncrit) == 0  # REJECT#15: diff 실패 파일 없어야 완전 증거
        )

    # 6) semantic_evidence_sha256: 원문 포함 semantic 섹션의 결정적 integrity digest.
    # REJECT#6: file_sha_attestations와 missing_critical_files를 digest에 포함하여
    #   CRITICAL Python 파일 내용 변경 시 SHA가 바뀌도록 한다.
    try:
        _sec = json.dumps({
            "diff_hunks": sem["diff_hunks"],
            "function_before_after_shas": sem["function_before_after_shas"],
            "file_sha_attestations": sem["file_sha_attestations"],
            "missing_critical_files": sem["missing_critical_files"],
            "test_assertions": sem["test_assertions"],
        }, sort_keys=True, ensure_ascii=False)
        sem["semantic_evidence_sha256"] = hashlib.sha256(
            _sec.encode("utf-8")
        ).hexdigest()
    except Exception:  # noqa: BLE001
        sem["semantic_evidence_sha256"] = ""
    return sem


def _build_codex_review_bundle(state: Dict[str, Any], pipeline_id: str) -> Tuple[str, str]:
    """Codex Review 입력 bundle을 SSoT artifact로 materialize하고 (SHA256, 경로)를 반환한다.

    Args:
        state: 활성 pipeline_state (진단 로그 기록에 사용).
        pipeline_id: 현재 파이프라인 ID. bundle 경로/게이트 결과 경로 계산에 사용.
    Returns:
        (sha256_hex, bundle_path) — write 성공 시 non-empty SHA. 실패 시 ("", "").
    Raises:
        없음 — 모든 예외를 내부에서 흡수하고 실패 시 ("", "")를 반환한다(fail-closed는 호출자 책임).
    """
    if pipeline_id is None:
        # None 입력 방어: bundle을 만들 수 없으므로 fail-closed로 호출자에게 위임.
        return ("", "")
    if not isinstance(pipeline_id, str):
        return ("", "")

    # BUG-20260702-E69E: bundle은 "검토 대상 입력"의 결정적 스냅샷이어야 한다. 동일 대상에 대한
    #   --retry-cli-error가 동일 bundle SHA를 산출하도록 실행 시각(_now) 같은 휘발성 메타데이터는
    #   bundle에 포함하지 않는다(포함하면 재시도마다 SHA가 달라져 거짓 snapshot 변경으로 오판됨).
    bundle: Dict[str, Any] = {
        "pipeline_id": str(pipeline_id or ""),
        "pr_url": "",
        "pr_head_sha": "",
        "packet_sha256": "",
        "verification_json_sha256": "",
        "pr_body_candidate_sha256": "",
        "contract_sha256": "",
        "changed_files": [],
        "critical_file_summary": {},
        "technical_gate_status": "UNKNOWN",
        "oracle_gate_status": "UNKNOWN",
        "github_ci_gate_status": "UNKNOWN",
        # IMP-20260710-DB54 MT-3: minimal review bundle — 대형 diff 원문/oracle 원문을
        #   포함하지 않고 개수/SHA만 담아 Codex CLI에 보내는 payload 크기를 줄인다.
        #   review_bundle_sha256은 자기 참조 placeholder다. bundle의 신뢰 루트 SHA는
        #   _sha256_file(bundle_path)(아래 반환값)이며, _codex_snapshot_identity도 동일 함수로
        #   재계산하므로 이 embedded 필드는 빈 문자열로 고정하여 파일 SHA 결정성을 보존한다
        #   (E69E snapshot 불변식 유지 — 파일을 SHA로 재기록하지 않는다).
        "review_bundle_sha256": "",
        "changed_files_count": 0,
        "oracle_count": 0,
        # IMP-20260710-DB54 rework MT-3: 필수 최소 컨텍스트 필드 (원문 제외, 개수/SHA/식별자만).
        "included_functions": [],       # 이번 PR에서 추가/수정된 pipeline.py 함수명 목록.
        "excluded_files": [],           # bundle에서 의도적으로 제외한 항목 목록.
        "excluded_files_reason": "",    # 제외 사유(PR body 원문/packet 원문/oracle 원문/raw ACCEPT 등).
        "critical_file_shas": {},       # {상대경로: SHA} — 변경된 critical 파일의 현재 SHA.
        "critical_function_shas": {},   # {함수식별자: SHA} — 핵심 함수 식별자/SHA(best-effort).
        "changed_critical_files": [],   # 이번 PR에서 변경된 critical 파일 경로 목록.
        "test_summary": {},             # {테스트파일: [테스트함수...]} — 원문 없이 요약만.
        "oracle_summary": [],           # oracle case 요약(case_id/case_kind/SHA/result) — 원문 제외.
        # IMP-20260712-DAE1 REJECT#4: semantic evidence. 원문 코드는 bundle에 persist하지 않고
        #   (no_nonce_exposure/TC-J 불변식 보존) prompt(stdin)에만 실으며, bundle에는 redacted
        #   메타데이터(함수명/is_critical/chars/hunk_sha256, 함수 SHA, 개수, integrity SHA)만 둔다.
        "diff_hunks": [],                    # redacted: {function, is_critical, chars, hunk_sha256}
        "function_before_after_shas": {},    # {함수식별자: {"before": sha, "after": sha}}
        "test_assertions": {},               # redacted: {test_name: assert_count(int)}
        "oracle_results": [],                # oracle case_kind/result (소문자 안전)
        "evidence_complete": False,          # CRITICAL hunk 모두 포함됐으면 True
        "truncated_critical_hunks": 0,       # 예산 초과로 잘린 CRITICAL hunk 수
        "semantic_evidence_sha256": "",      # semantic 섹션(원문 포함) 결정적 SHA
        "bundle_budget_chars": 0,            # 실제 사용한 diff 예산 문자수
        # IMP-20260712-DAE1 MT-7: Codex Model Router 정책 섹션 (실제 값은 _cmd_gates_codex_review가
        #   risk 분류 후 result에 기록; bundle에는 결정성 placeholder만 둔다).
        "model_policy": {
            "router_version": CODEX_MODEL_ROUTER_VERSION,
            "risk_level": "UNKNOWN",
            "selected_model": "unknown",
            "mode": "unknown",
        },
    }

    try:
        # pr_head_sha (gh CLI, best-effort)
        try:
            bundle["pr_head_sha"] = _get_current_pr_head_sha() or ""
        except Exception:  # noqa: BLE001 — best-effort; 실패는 빈 문자열로 대체
            bundle["pr_head_sha"] = ""

        # pr_url (gh pr view, best-effort)
        try:
            r = subprocess.run(
                _build_gh_cmd_prefix() + ["pr", "view", "--json", "url", "--jq", ".url"],
                capture_output=True, text=True, timeout=15,
                cwd=str(BASE_DIR), encoding="utf-8", errors="replace",
            )
            if r.returncode == 0:
                bundle["pr_url"] = r.stdout.strip()
        except Exception:  # noqa: BLE001
            bundle["pr_url"] = ""

        # packet_sha256: 3자 SHA 불변식 — staging이 있으면 staged SHA를 우선 사용한다.
        # (codex-review가 staged SHA로 기록하므로, bundle도 동일 SHA를 가져야 3자가 일치한다.)
        try:
            _stg_for_pkt = _load_acceptance_staging(pipeline_id)
            _staged_pkt_sha = (
                str(_stg_for_pkt.get("staged_packet_sha256", "") or "")
                if isinstance(_stg_for_pkt, dict) else ""
            )
            if _staged_pkt_sha:
                bundle["packet_sha256"] = _staged_pkt_sha
            else:
                _pkt = _packet_output_path()
                if _pkt.exists():
                    bundle["packet_sha256"] = _sha256_file(_pkt)
        except Exception:  # noqa: BLE001
            bundle["packet_sha256"] = ""

        # verification_json_sha256: FROZEN staged JSON SHA만 사용한다(3자 SHA 불변식).
        # 의도적으로 live human_acceptance_packet.json 파일 SHA로 fallback하지 않는다.
        #   - verification_json은 _codex_live_sha_snapshot의 live 재검증 차원이며(설계상 bundle SHA에
        #     포함되지 않는 차원), 이 값을 bundle에 넣으면 cache_key가 mutable live json에 종속되어
        #     "cache_key 일치 + live SHA 불일치" 안전망(cache_live_sha_mismatch)이 무력화된다.
        #   - staging이 있으면 request-accept가 동결한 staged_json_sha256을 그대로 실어 3자 불변식을
        #     만족하고, staging이 없으면 빈 값으로 두어 cache_key 결정성과 live 재검증 경로를 보존한다.
        try:
            _stg_for_vj = _load_acceptance_staging(pipeline_id)
            _staged_vj_sha = (
                str(_stg_for_vj.get("staged_json_sha256", "") or "")
                if isinstance(_stg_for_vj, dict) else ""
            )
            if _staged_vj_sha:
                bundle["verification_json_sha256"] = _staged_vj_sha
        except Exception:  # noqa: BLE001
            bundle["verification_json_sha256"] = ""

        # contract_sha256
        try:
            _cp = CONTRACTS_DIR / pipeline_id / "task_contract.json"
            if _cp.exists():
                bundle["contract_sha256"] = _sha256_file(_cp)
        except Exception:  # noqa: BLE001
            bundle["contract_sha256"] = ""

        # pr_body_candidate_sha256: staged_packet_content로 PR body 블록을 교체한
        #   최종 body의 canonical SHA. staged_packet_sha256(패킷 파일 SHA)와는 의미가 다르다.
        # IMP-20260703-B985 MT-9: staged frozen SHA를 먼저 읽어 re-fetch 방지.
        # 필드가 없으면 구형 staging 재계산 fallback.
        try:
            _stg = _load_acceptance_staging(pipeline_id)
            if isinstance(_stg, dict):
                _cached_sha = _stg.get("pr_body_candidate_sha256", "")
                if _cached_sha:
                    bundle["pr_body_candidate_sha256"] = _cached_sha
                else:
                    # Fallback: 이전 방식 (re-fetch)
                    _staged_content = _stg.get("staged_packet_content")
                    if _staged_content:
                        _cur_body = _get_pr_body_text()
                        if _cur_body is not None:
                            _final_body = _replace_pr_body_packet_block(
                                _cur_body, _staged_content
                            )
                            bundle["pr_body_candidate_sha256"] = (
                                _canonical_pr_body_sha256(_final_body)
                            )
        except Exception:  # noqa: BLE001
            bundle["pr_body_candidate_sha256"] = ""

        # changed_files (git diff origin/main...HEAD --name-only)
        try:
            dr = subprocess.run(
                ["git", "diff", "origin/main...HEAD", "--name-only"],
                capture_output=True, text=True, timeout=30,
                cwd=str(BASE_DIR), encoding="utf-8", errors="replace",
            )
            if dr.returncode == 0:
                cf = [f.strip() for f in dr.stdout.strip().splitlines() if f.strip()]
                bundle["changed_files"] = cf
                bundle["changed_files_count"] = len(cf)
                bundle["critical_file_summary"] = {
                    f: _is_codex_critical_file(f) for f in cf
                }
                # IMP-20260710-DB54 rework MT-3/MT-4: 변경된 critical 파일 목록 + 현재 SHA.
                _changed_crit = [f for f in cf if _is_codex_critical_file(f)]
                bundle["changed_critical_files"] = _changed_crit
                _crit_shas: Dict[str, str] = {}
                for _cf in _changed_crit:
                    try:
                        _cfp = BASE_DIR / _cf
                        if _cfp.exists():
                            _crit_shas[_cf] = _sha256_file(_cfp)
                    except Exception:  # noqa: BLE001 — 개별 파일 SHA 실패는 건너뜀
                        continue
                bundle["critical_file_shas"] = _crit_shas
        except Exception:  # noqa: BLE001
            bundle["changed_files"] = []
            bundle["changed_files_count"] = 0

        # IMP-20260710-DB54 rework MT-3: included_functions — 이번 PR에서 추가/수정된
        #   pipeline.py 함수명(diff의 추가 라인 중 `def NAME(` 패턴). 원문 diff는 담지 않는다.
        try:
            _incl: List[str] = []
            if "pipeline.py" in bundle.get("changed_files", []):
                _fr = subprocess.run(
                    ["git", "diff", "origin/main...HEAD", "--unified=0", "--", "pipeline.py"],
                    capture_output=True, text=True, timeout=30,
                    cwd=str(BASE_DIR), encoding="utf-8", errors="replace",
                )
                if _fr.returncode == 0:
                    for _ln in _fr.stdout.splitlines():
                        if _ln.startswith("@@"):
                            # @@ 컨텍스트 헤더에서 수정된 기존 함수명 추출
                            _ctx_m = re.search(
                                r"@@[^@]*@@\s*(?:async\s+)?def\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(",
                                _ln
                            )
                            if _ctx_m:
                                _name = _ctx_m.group(1)
                                if _name not in _incl:
                                    _incl.append(_name)
                        elif _ln.startswith("+") and not _ln.startswith("+++"):
                            _m = re.search(r"^\+\s*def\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(", _ln)
                            if _m:
                                _name = _m.group(1)
                                if _name not in _incl:
                                    _incl.append(_name)
            bundle["included_functions"] = _incl
        except Exception:  # noqa: BLE001
            bundle["included_functions"] = []

        # IMP-20260710-DB54 rework MT-3: excluded_files — bundle에서 의도적으로 제외한 항목.
        #   실제 원문(대형 diff/PR body/packet/oracle/raw ACCEPT)을 payload에 넣지 않았음을 명시한다.
        bundle["excluded_files"] = [
            "pr_body_full_text",
            "human_acceptance_packet_full_text",
            "oracle_input_expected_raw",
            "raw_accept_code_and_nonce",
            "large_test_file_full_diff",
        ]
        bundle["excluded_files_reason"] = (
            "비용/보안: PR body 원문·packet 원문·oracle 원문·raw ACCEPT 코드/nonce·"
            "대형 테스트 파일 전체 diff는 Codex payload에서 제외하고 개수/SHA/식별자만 포함한다. "
            "raw ACCEPT 코드/nonce는 어떤 경우에도 bundle에 포함하지 않는다(fail-closed)."
        )

        # IMP-20260712-DAE1 REJECT#4: semantic evidence(실제 변경 코드)를 조립하고, bundle에는
        #   redacted 메타데이터만 persist한다(원문은 prompt/stdin에서만 노출). 이 블록이
        #   critical_function_shas 버그(모든 함수에 pipeline.py 전체 파일 SHA를 동일 적용)를
        #   function_before_after_shas.after(함수 본문 개별 SHA)로 교체하여 해결한다.
        _semantic = _build_codex_semantic_evidence(
            pipeline_id,
            list(bundle.get("changed_files", []) or []),
            list(bundle.get("included_functions", []) or []),
        )
        bundle["function_before_after_shas"] = _semantic["function_before_after_shas"]
        # diff_hunks는 원문(hunk 텍스트) 없이 redacted 메타데이터만 persist한다(nonce-scan 안전).
        bundle["diff_hunks"] = [
            {
                "function": str(_h.get("function", "unknown")),
                "is_critical": bool(_h.get("is_critical", False)),
                "chars": int(_h.get("chars", 0)),
                "hunk_sha256": hashlib.sha256(
                    str(_h.get("hunk", "")).encode("utf-8")
                ).hexdigest(),
            }
            for _h in _semantic.get("diff_hunks", [])
        ]
        # test_assertions는 assert 원문 없이 개수만 persist한다(대문자 토큰 유입 방지).
        bundle["test_assertions"] = {
            str(_tn): len(_al) for _tn, _al in _semantic.get("test_assertions", {}).items()
        }
        bundle["oracle_results"] = _semantic["oracle_results"]
        bundle["evidence_complete"] = bool(_semantic["evidence_complete"])
        bundle["truncated_critical_hunks"] = int(_semantic["truncated_critical_hunks"])
        bundle["truncated_noncrit_hunks"] = int(_semantic.get("truncated_noncrit_hunks", 0))
        bundle["missing_noncrit_files"] = list(_semantic.get("missing_noncrit_files", []))
        bundle["missing_critical_files"] = list(_semantic.get("missing_critical_files", []))
        # REJECT#35: CRITICAL Python 파일의 file-level SHA attestation (before/after SHA)
        bundle["file_sha_attestations"] = dict(_semantic.get("file_sha_attestations", {}))
        bundle["semantic_evidence_sha256"] = str(_semantic["semantic_evidence_sha256"])
        bundle["bundle_budget_chars"] = int(_semantic["bundle_budget_chars"])
        # REJECT#32: changed_constants는 번들 파일에 포함하지 않는다.
        #   CODEX_CRITICAL_CONSTANTS 원문(예: "CRITICAL" 8자)이 직렬화 번들에 들어가면
        #   bundle_contains_nonce preflight 검사가 오탐으로 차단된다(8자 대문자 패턴).
        #   _cmd_gates_codex_review에서 git diff를 직접 재스캔하여 상수 변경을 감지한다.
        # critical_function_shas: function_before_after_shas의 after(함수 본문 개별 SHA)를 사용.
        #   (기존 버그: 모든 함수에 pipeline.py 전체 파일 SHA를 동일 적용 → 함수별 구분 불가.)
        try:
            _cfn_shas: Dict[str, str] = {}
            for _fn_id, _sh in bundle["function_before_after_shas"].items():
                _after = str(_sh.get("after", "") or "")
                if _after:
                    _cfn_shas[_fn_id] = _after
            bundle["critical_function_shas"] = _cfn_shas
        except Exception:  # noqa: BLE001
            bundle["critical_function_shas"] = {}

        # IMP-20260710-DB54 rework MT-3: test_summary — 테스트 파일별 테스트 함수 목록(원문 제외).
        try:
            _tsum: Dict[str, List[str]] = {}
            for _tf in bundle.get("changed_files", []):
                _tfn = _tf.replace("\\", "/")
                if not (_tfn.startswith("tests/") and _tfn.endswith(".py")):
                    continue
                _tfp = BASE_DIR / _tfn
                if not _tfp.exists():
                    continue
                try:
                    _funcs: List[str] = []
                    for _tl in _tfp.read_text(encoding="utf-8", errors="replace").splitlines():
                        _tm = re.match(r"\s*def\s+(test_[A-Za-z0-9_]*)\s*\(", _tl)
                        if _tm:
                            _funcs.append(_tm.group(1))
                    _tsum[_tfn] = _funcs
                except Exception:  # noqa: BLE001
                    continue
            bundle["test_summary"] = _tsum
        except Exception:  # noqa: BLE001
            bundle["test_summary"] = {}

        # IMP-20260710-DB54 rework MT-3: oracle_summary — oracle case 요약(원문 제외).
        try:
            _osum: List[Dict[str, str]] = []
            _odir2 = BASE_DIR / "tests" / "oracles" / pipeline_id
            if _odir2.exists() and _odir2.is_dir():
                for _cdir in sorted(p for p in _odir2.iterdir() if p.is_dir()):
                    _in_p = _cdir / "input.json"
                    _exp_p = _cdir / "expected.json"
                    _entry = {
                        "case_id": _cdir.name,
                        "case_kind": "unknown",
                        "input_sha256": _sha256_file(_in_p) if _in_p.exists() else "",
                        "expected_sha256": _sha256_file(_exp_p) if _exp_p.exists() else "",
                        "result": "recorded",
                    }
                    _osum.append(_entry)
            bundle["oracle_summary"] = _osum
        except Exception:  # noqa: BLE001
            bundle["oracle_summary"] = []

        # IMP-20260710-DB54 MT-3: oracle_count — oracle 원문을 bundle에 넣지 않고 개수만 기록한다.
        #   우선순위: contract oracle_manifest 길이 → tests/oracles/<pid>/ 하위 케이스 디렉토리 수.
        try:
            _oracle_count = 0
            _manifest = state.get("contract", {}) if isinstance(state, dict) else {}
            _om = _manifest.get("oracle_manifest") if isinstance(_manifest, dict) else None
            if isinstance(_om, list):
                _oracle_count = len(_om)
            if _oracle_count == 0:
                _odir = BASE_DIR / "tests" / "oracles" / pipeline_id
                if _odir.exists() and _odir.is_dir():
                    _oracle_count = sum(1 for _p in _odir.iterdir() if _p.is_dir())
            bundle["oracle_count"] = int(_oracle_count)
        except Exception:  # noqa: BLE001
            bundle["oracle_count"] = 0

        # IMP-20260710-DB54 rework MT-3(문제4): gate 상태는 state["external_gates"](SSoT)를
        #   1순위로 읽는다. state에 없을 때만 pipeline_contracts/<pid>/gates/*.json으로 fallback한다.
        #   fallback 시 oracle_result.json은 top-level status가 아니라 summary.verdict가 실제
        #   신뢰 필드이므로(기존 버그: 항상 UNKNOWN), summary.verdict를 먼저 읽는다.
        _eg = state.get("external_gates") if isinstance(state, dict) else None
        _eg = _eg if isinstance(_eg, dict) else {}

        def _resolve_gate_status(_gate_name: str, _fname: str) -> str:
            # 1순위: state external_gates SSoT
            _g = _eg.get(_gate_name)
            if isinstance(_g, dict):
                _s = str(_g.get("status", "") or "")
                if _s:
                    return _s
            # 2순위: gates/*.json 파일 (summary.verdict 우선, 없으면 top-level status)
            _gp = CONTRACTS_DIR / pipeline_id / "gates" / _fname
            if _gp.exists():
                try:
                    _gj = json.loads(_gp.read_text(encoding="utf-8"))
                    if isinstance(_gj, dict):
                        _summary = _gj.get("summary")
                        if isinstance(_summary, dict) and _summary.get("verdict"):
                            return str(_summary.get("verdict"))
                        if _gj.get("status"):
                            return str(_gj.get("status"))
                except Exception:  # noqa: BLE001
                    pass
            return "UNKNOWN"

        bundle["technical_gate_status"] = _resolve_gate_status(
            "technical", "technical_result.json"
        )
        bundle["oracle_gate_status"] = _resolve_gate_status(
            "oracle", "oracle_result.json"
        )
        bundle["github_ci_gate_status"] = _resolve_gate_status(
            "github_ci", "github_ci_result.json"
        )

        # IMP-20260710-DB54 rework: 테스트 전용 block-only seam. 프로덕션 경로를 우회하는 데
        #   쓸 수 없다(필드를 누락/무력화하여 하위 guard가 BLOCKED되게만 만든다). QA 검증용.
        _test_drop = os.environ.get("PIPELINE_CODEX_TEST_DROP_BUNDLE_FIELD")
        if _test_drop and _test_drop in bundle:
            bundle.pop(_test_drop, None)
        if os.environ.get("PIPELINE_CODEX_TEST_EMPTY_CRITICAL_SHAS") == "1":
            bundle["critical_file_shas"] = {}
        if os.environ.get("PIPELINE_CODEX_TEST_EXCLUDE_CRITICAL") == "1":
            _ex = list(bundle.get("excluded_files", []))
            _ex.append("pipeline.py")
            bundle["excluded_files"] = _ex

        # IMP-20260712-DAE1 MT-7: raw ACCEPT 코드/nonce 유출 방지(fail-closed). bundle에 아래
        #   금지 키가 하나라도 있으면 즉시 ("", "")를 반환하여 Codex CLI 호출을 차단한다.
        _forbidden_bundle_keys = {
            "acceptance_code", "nonce", "accept_code", "approval_code", "raw_accept",
        }
        for _fk in _forbidden_bundle_keys:
            if _fk in bundle:
                try:
                    _log_event(
                        state,
                        f"codex_review_bundle_forbidden_key_blocked: {_fk}",
                    )
                except Exception:  # noqa: BLE001
                    pass
                return ("", "")

        # materialize — _codex_snapshot_identity가 읽는 동일 경로에 쓴다(SSoT 불변식).
        #   PIPELINE_STATE_PATH 격리 시 state 파일 옆 .pipeline/에 위치한다(테스트 오염 방지).
        bundle_path = _codex_review_bundle_path(pipeline_id)
        bundle_path.parent.mkdir(parents=True, exist_ok=True)
        raw = json.dumps(
            bundle, ensure_ascii=False, sort_keys=True, indent=2
        ).encode("utf-8")
        bundle_path.write_bytes(raw)
        # _codex_snapshot_identity가 _sha256_file로 재현하므로 동일 함수로 SHA를 계산한다.
        sha = _sha256_file(bundle_path)
        if not sha:
            return ("", "")
        return (sha, str(bundle_path))
    except Exception as exc:  # noqa: BLE001 — write/직렬화 실패만 여기 도달. fail-closed는 호출자.
        try:
            _log_event(state, f"codex_review_bundle_build_failed: {exc}")
        except Exception:  # noqa: BLE001
            pass
        return ("", "")


# [Purpose]: IMP-20260710-DB54 MT-4 — Codex Review 캐시 키를 결정적으로 계산한다. 동일한
#            contract_sha256 + review_bundle_sha256 조합은 동일한 검토 대상이므로 같은 캐시 키를
#            산출하여, 반복 Codex CLI 호출(비용) 없이 이전 verdict를 재사용할 수 있게 한다.
# [Assumptions]: 두 SHA는 서로 다른 차원이므로 ":"로 구분하여 충돌을 방지한다. 16자로 절단해도
#            32bit×2 입력 조합의 충돌 확률은 실무상 무시 가능하다.
# [Vulnerability & Risks]: None/비str 입력은 즉시 TypeError로 차단하여 잘못된 키로 캐시 오염을 막는다.
# [Improvement]: 키에 pipeline_id를 접두로 붙이면 파이프라인 간 캐시 분리를 더 명확히 할 수 있다.
def _codex_cache_key(
    contract_sha256: str,
    review_bundle_sha256: str,
    policy_signature: str = "",
) -> str:
    """contract + bundle + policy 서명으로 결정적 16자 캐시 키를 계산한다.

    IMP-20260712-DAE1 rework(문제6): policy_signature(모델/effort/정책)를 키에 포함하여,
    같은 contract+bundle이라도 모델/effort/정책이 바뀌면 cache miss가 되게 한다.
    기본값 ""은 기존 호출자와의 하위 호환을 보존한다.

    Args:
        contract_sha256: 계약 파일 SHA-256.
        review_bundle_sha256: review bundle 파일 SHA-256.
        policy_signature: 모델 정책 서명(선택, _codex_policy_signature 결과).
    Returns:
        sha256(contract + ":" + bundle + ":" + policy)의 앞 16자 hex 문자열.
    Raises:
        TypeError: 인자가 None이거나 str이 아닌 경우.
    """
    if contract_sha256 is None:
        raise TypeError("contract_sha256 must not be None")
    if not isinstance(contract_sha256, str):
        raise TypeError(
            f"contract_sha256 must be str, got {type(contract_sha256).__name__}"
        )
    if review_bundle_sha256 is None:
        raise TypeError("review_bundle_sha256 must not be None")
    if not isinstance(review_bundle_sha256, str):
        raise TypeError(
            f"review_bundle_sha256 must be str, got {type(review_bundle_sha256).__name__}"
        )
    if policy_signature is None:
        raise TypeError("policy_signature must not be None")
    if not isinstance(policy_signature, str):
        raise TypeError(
            f"policy_signature must be str, got {type(policy_signature).__name__}"
        )
    raw = f"{contract_sha256}:{review_bundle_sha256}:{policy_signature}".encode("utf-8")
    return hashlib.sha256(raw).hexdigest()[:16]


# [Purpose]: IMP-20260710-DB54 MT-4 — Codex Review 캐시 파일(codex_review_cache.json) 경로를
#            반환한다. _codex_review_result_path와 동일한 PIPELINE_STATE_PATH 격리 규칙을 사용하여
#            E2E 테스트가 전역 .pipeline/을 오염시키지 않게 한다.
# [Assumptions]: PIPELINE_STATE_PATH가 설정되면 state 파일 옆 .pipeline/에, 아니면 운영 PIPELINE_CI_DIR에 위치한다.
# [Vulnerability & Risks]: 환경 변수 경로가 조작되면 임의 위치에 캐시가 생기나, 캐시는 SHA 재검증
#            후에만 신뢰되므로(critical file SHA 불일치 시 무효화) 위조 캐시가 판정을 뒤집지 못한다.
# [Improvement]: 캐시 파일에 스키마 버전을 넣어 향후 포맷 변경 시 안전한 마이그레이션을 지원할 수 있다.
def _codex_review_cache_path() -> Path:
    """codex_review_cache.json 경로를 반환 (PIPELINE_STATE_PATH 격리 지원).

    Returns:
        .pipeline/codex_review_cache.json 절대 경로.
    """
    env_state = os.environ.get("PIPELINE_STATE_PATH")
    if env_state:
        return Path(env_state).resolve().parent / ".pipeline" / "codex_review_cache.json"
    return PIPELINE_CI_DIR / "codex_review_cache.json"


# [Purpose]: IMP-20260710-DB54 MT-4 — 동일 검토 대상(contract+bundle SHA)에 대한 이전 Codex verdict를
#            캐시에서 조회한다. cache hit이면 Codex CLI를 호출하지 않아 리뷰 비용을 절감한다.
# [Assumptions]: 캐시 파일은 {cache_key, contract_sha256, review_bundle_sha256, verdict,
#            critical_file_shas} 형식이다. critical_file_shas는 {상대경로: SHA} 매핑이다.
# [Vulnerability & Risks]: 캐시가 오래되어 critical file(pipeline.py 등)이 바뀌면 stale verdict를
#            재사용할 위험이 있다. critical_file_shas의 현재 SHA를 재계산하여 하나라도 다르면
#            무효화(hit=False)한다(safe cache). 파일 없음/파싱 실패도 miss로 처리(fail-safe).
# [Improvement]: 캐시 만료 시각(TTL)을 추가하면 오래된 항목을 자동 폐기할 수 있다.
def _check_codex_cache(
    contract_sha256: str,
    review_bundle_sha256: str,
    state: Dict[str, Any],
    pipeline_id: str,
    current_bundle: Optional[Dict[str, Any]] = None,
    model_policy: Optional[Dict[str, Any]] = None,
    actual_model: Optional[str] = None,
    risk_level: Optional[str] = None,
) -> Dict[str, Any]:
    """contract+bundle SHA 조합으로 캐시된 Codex verdict를 조회한다 (critical file SHA 재검증).

    Args:
        contract_sha256: 현재 계약 SHA-256.
        review_bundle_sha256: 현재 review bundle SHA-256.
        state: 활성 pipeline_state (인터페이스 일관성; 직접 미사용).
        pipeline_id: 현재 파이프라인 ID (인터페이스 일관성; 직접 미사용).
        current_bundle: 이번 리뷰의 현재 bundle dict(선택). 제공 시 excluded_files에 critical
            파일이 있으면 cache 사용을 BLOCKED하고, critical 변경 대비 critical_file_shas 정보
            부재를 cache miss로 처리한다 (IMP-20260710-DB54 rework MT-4 문제5).
    Returns:
        {"hit": bool, "cached_verdict": str|None, "cache_key": str, "reason": str,
         "blocked": bool, "block_reason": str, "live_sha_snapshot": dict,
         "excluded_files": list}.
    Raises:
        TypeError: contract_sha256/review_bundle_sha256가 None/비str이거나 pipeline_id가
            None/비str인 경우.
    """
    if contract_sha256 is None:
        raise TypeError("contract_sha256 must not be None")
    if not isinstance(contract_sha256, str):
        raise TypeError(
            f"contract_sha256 must be str, got {type(contract_sha256).__name__}"
        )
    if review_bundle_sha256 is None:
        raise TypeError("review_bundle_sha256 must not be None")
    if not isinstance(review_bundle_sha256, str):
        raise TypeError(
            f"review_bundle_sha256 must be str, got {type(review_bundle_sha256).__name__}"
        )
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(f"pipeline_id must be str, got {type(pipeline_id).__name__}")

    # IMP-20260712-DAE1 rework(문제6): 모델/effort/정책 변경 시 cache miss가 되도록 정책 서명을
    #   cache key에 포함한다. model_policy가 없으면 빈 서명(하위 호환).
    cache_key = _codex_cache_key(
        contract_sha256, review_bundle_sha256,
        _codex_policy_signature(model_policy),
    )
    miss: dict = {
        "hit": False,
        "cached_verdict": None,
        "cache_key": cache_key,
        "reason": "",
        "blocked": False,
        "block_reason": "",
        "live_sha_snapshot": {},
        "excluded_files": [],
    }

    # IMP-20260712-DAE1 MT-5: model policy 기반 cache 금지. CRITICAL(cache_allowed=False)은 항상
    #   캐시를 신뢰하지 않는다. actual_model=unknown + HIGH/CRITICAL도 캐시 금지(fail-closed).
    if isinstance(model_policy, dict):
        _cache_allowed = model_policy.get("cache_allowed")
        if _cache_allowed is False:
            _miss = dict(miss)
            _miss["reason"] = "CRITICAL risk: 캐시 항상 금지 (cache_allowed=False) — CLI 직접 실행으로 진행"
            return _miss

    # REJECT#11/12 fix: actual_model=unknown 시 blocked=True 반환 및 cache miss 조기 반환을
    #   모두 제거한다. HIGH+unknown은 캐시를 먼저 조회하여 valid entry가 있으면 Fix2 검증을 거쳐
    #   재사용한다. cache miss이면 CLI를 실행하고 _check_codex_model_capability_match로 검증한다.
    #   (CRITICAL은 위 cache_allowed=False 블록에서 이미 miss를 반환하므로 여기에 도달하지 않는다.)

    # IMP-20260710-DB54 rework MT-4(문제5): 현재 bundle의 excluded_files에 critical 파일이 있으면
    #   Codex가 그 파일을 못 본 것이므로 캐시 사용 자체를 금지한다(BLOCKED). 캐시 유무와 무관.
    if isinstance(current_bundle, dict):
        _cur_excl = current_bundle.get("excluded_files")
        if isinstance(_cur_excl, list):
            for _e in _cur_excl:
                try:
                    if _is_codex_critical_file(str(_e)):
                        blocked = dict(miss)
                        blocked["blocked"] = True
                        blocked["block_reason"] = (
                            f"excluded_files에 critical 파일 포함: {_e} — 캐시 사용 금지 (BLOCKED)"
                        )
                        blocked["reason"] = blocked["block_reason"]
                        return blocked
                except TypeError:
                    continue

    cache_path = _codex_review_cache_path()
    if not cache_path.exists():
        miss["reason"] = "캐시 파일 없음 (cache miss)"
        return miss

    try:
        cached = json.loads(cache_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, ValueError):
        miss["reason"] = "캐시 파일 로드/파싱 실패 (fail-safe cache miss)"
        return miss

    if not isinstance(cached, dict):
        miss["reason"] = "캐시 파일이 dict가 아님 (cache miss)"
        return miss

    # 키/SHA 일치 검증 (결정적 대상 동일성).
    if str(cached.get("cache_key", "") or "") != cache_key:
        miss["reason"] = "cache_key 불일치 (cache miss)"
        return miss
    if str(cached.get("contract_sha256", "") or "") != contract_sha256:
        miss["reason"] = "contract_sha256 불일치 (cache miss)"
        return miss
    if str(cached.get("review_bundle_sha256", "") or "") != review_bundle_sha256:
        miss["reason"] = "review_bundle_sha256 불일치 (cache miss)"
        return miss

    # REJECT#18: 캐시에 auth_source가 없거나 chatgpt가 아니면 cache miss (fail-closed).
    #   원 실행이 실제 ChatGPT Plus로 인증하지 않은 결과는 신뢰할 수 없다.
    _cached_auth = str(cached.get("auth_source", "") or "").strip()
    if not _cached_auth or _cached_auth != "chatgpt":
        miss["reason"] = (
            f"캐시 auth_source={_cached_auth!r} — chatgpt가 아니거나 누락 (cache miss, fail-closed)"
        )
        return miss

    # IMP-20260710-DB54 rework MT-4(문제5): 캐시 생성 당시 excluded_files에 critical 파일이
    #   있었다면 그 캐시 verdict는 critical 파일을 보지 못하고 산출된 것이므로 사용 금지(BLOCKED).
    _cached_excl = cached.get("excluded_files")
    if isinstance(_cached_excl, list):
        for _e in _cached_excl:
            try:
                if _is_codex_critical_file(str(_e)):
                    blocked = dict(miss)
                    blocked["blocked"] = True
                    blocked["block_reason"] = (
                        f"캐시 excluded_files에 critical 파일 포함: {_e} — 캐시 사용 금지 (BLOCKED)"
                    )
                    blocked["reason"] = blocked["block_reason"]
                    return blocked
            except TypeError:
                continue

    # IMP-20260710-DB54 rework MT-4(문제5): critical 파일이 변경 범위에 있는데 캐시에 그 SHA
    #   정보(critical_file_shas)가 비어 있으면 검증할 수 없으므로 cache miss(BLOCKED 아님).
    _cached_changed_crit = cached.get("changed_critical_files")
    if isinstance(_cached_changed_crit, list) and _cached_changed_crit:
        _cfs = cached.get("critical_file_shas")
        if not (isinstance(_cfs, dict) and _cfs):
            miss["reason"] = (
                "critical 파일이 변경됐으나 캐시에 critical_file_shas 정보가 없음 (cache miss)"
            )
            return miss

    # critical file SHA 재검증 — 하나라도 현재 SHA와 다르면 캐시 무효화(safe cache).
    critical_file_shas = cached.get("critical_file_shas")
    if isinstance(critical_file_shas, dict):
        for _rel, _cached_sha in critical_file_shas.items():
            try:
                _fp = BASE_DIR / str(_rel)
                _cur_sha = _sha256_file(_fp) if _fp.exists() else ""
            except Exception:  # noqa: BLE001 — SHA 계산 실패는 무효화(fail-safe)
                _cur_sha = ""
            if _cur_sha != str(_cached_sha or ""):
                return {
                    "hit": False,
                    "cached_verdict": None,
                    "cache_key": cache_key,
                    "reason": (
                        f"critical file 변경으로 캐시 무효화: {_rel} "
                        "(cached SHA != current SHA)"
                    ),
                }

    # IMP-20260712-DAE1 REJECT#16: 캐시 hit 전 binary 신뢰 재검증.
    #   원 실행에서 저장한 codex_binary_path + sha256이 현재도 유효한지 확인한다.
    #   비어있거나(저장 안 됨), 파일이 없거나, SHA가 바뀌면 cache miss로 처리(fail-closed).
    _cached_bin_path = str(cached.get("codex_binary_path", "") or "")
    _cached_bin_sha = str(cached.get("codex_binary_sha256", "") or "")
    _cached_js_path = str(cached.get("codex_js_entrypoint_path", "") or "")
    _cached_js_sha = str(cached.get("codex_js_entrypoint_sha256", "") or "")
    # REJECT#LATEST AC#2: native/vendor binary SHA도 캐시 hit 전 재검증한다 (cache 우회 차단).
    _cached_native_path = str(cached.get("codex_native_binary_path", "") or "")
    _cached_native_sha = str(cached.get("codex_native_binary_sha256", "") or "")
    # REJECT#28 AC#3: node 인터프리터 SHA도 캐시 hit 전 재검증한다 (악성 node 교체 탐지).
    _cached_node_path = str(cached.get("codex_node_interpreter_path", "") or "")
    _cached_node_sha = str(cached.get("codex_node_interpreter_sha256", "") or "")
    _cached_node_trusted = bool(cached.get("codex_node_interpreter_trusted"))
    # REJECT#15 문제 B: 설치 유형도 캐시에서 복원하여 operational trust 면제를 승계한다.
    _cached_install_type = str(cached.get("codex_install_type", "") or "")
    if _cached_bin_path:
        try:
            _cur_bin_sha = _sha256_file(Path(_cached_bin_path)) if Path(_cached_bin_path).exists() else ""
        except Exception:  # noqa: BLE001
            _cur_bin_sha = ""
        if not _cur_bin_sha or _cur_bin_sha != _cached_bin_sha:
            miss["reason"] = (
                "codex binary SHA 불일치 또는 파일 부재 — cache miss (fail-closed). "
                f"binary_path={_cached_bin_path!r}"
            )
            return miss
        # JS 진입점도 저장돼 있으면 SHA 재검증
        if _cached_js_path and _cached_js_sha:
            try:
                _cur_js_sha = _sha256_file(Path(_cached_js_path)) if Path(_cached_js_path).exists() else ""
            except Exception:  # noqa: BLE001
                _cur_js_sha = ""
            if not _cur_js_sha or _cur_js_sha != _cached_js_sha:
                miss["reason"] = (
                    "codex JS 진입점 SHA 불일치 또는 파일 부재 — cache miss (fail-closed). "
                    f"js_path={_cached_js_path!r}"
                )
                return miss
        # REJECT#LATEST AC#2: native/vendor binary가 저장돼 있으면 SHA 재검증 (vendor 교체 탐지)
        if _cached_native_path and _cached_native_sha:
            try:
                _cur_native_sha = (
                    _sha256_file(Path(_cached_native_path))
                    if Path(_cached_native_path).exists() else ""
                )
            except Exception:  # noqa: BLE001
                _cur_native_sha = ""
            if not _cur_native_sha or _cur_native_sha != _cached_native_sha:
                miss["reason"] = (
                    "codex native binary SHA 불일치 또는 파일 부재 — cache miss (fail-closed). "
                    f"native_path={_cached_native_path!r}"
                )
                return miss
        # REJECT#28 AC#3: node 인터프리터가 저장돼 있으면 SHA 재검증 (악성 node 교체 탐지).
        if _cached_node_path and _cached_node_sha:
            if not _is_valid_sha256_hex(_cached_node_sha):
                miss["reason"] = (
                    "codex node interpreter SHA 형식 오류 — cache miss (fail-closed). "
                    f"node_path={_cached_node_path!r}"
                )
                return miss
            try:
                _cur_node_sha = (
                    _sha256_file(Path(_cached_node_path))
                    if Path(_cached_node_path).exists() else ""
                )
            except Exception:  # noqa: BLE001
                _cur_node_sha = ""
            if not _cur_node_sha or _cur_node_sha != _cached_node_sha:
                miss["reason"] = (
                    "codex node interpreter SHA 불일치 또는 파일 부재 — cache miss (fail-closed). "
                    f"node_path={_cached_node_path!r}"
                )
                return miss

    _live_snap = cached.get("live_sha_snapshot")
    return {
        "hit": True,
        "cached_verdict": str(cached.get("verdict", "") or "") or None,
        "cache_key": cache_key,
        "reason": "cache hit — Codex CLI 호출 없이 캐시된 verdict 재사용",
        "blocked": False,
        "block_reason": "",
        "live_sha_snapshot": _live_snap if isinstance(_live_snap, dict) else {},
        "excluded_files": _cached_excl if isinstance(_cached_excl, list) else [],
        # IMP-20260712-DAE1 rework#2(요구4): 원 codex_cli 실행이 기록한 actual model/effort를
        #   재사용 경로로 전달한다(request-accept 신뢰 게이트의 selected==actual 검증용).
        "cached_actual_model": str(cached.get("actual_model", "") or "") or None,
        "cached_actual_effort": str(cached.get("actual_effort", "") or "") or None,
        # IMP-20260712-DAE1 REJECT#3(요구4/8): invoked/verification 증거도 재사용 경로로 전달한다.
        "cached_invoked_model": str(cached.get("invoked_model", "") or "") or None,
        "cached_invoked_effort": str(cached.get("invoked_effort", "") or "") or None,
        "cached_verification_level": str(cached.get("model_verification_level", "") or "") or None,
        # REJECT#18: 원 실행의 auth_source를 캐시에서 복원한다 (하드코딩 chatgpt 제거).
        "cached_auth_source": _cached_auth,
        # REJECT#16: binary trust 증거를 hit 결과로 전달 (복원 후 재검증·기록용).
        "cached_codex_binary_path": _cached_bin_path,
        "cached_codex_binary_sha256": _cached_bin_sha,
        "cached_js_entrypoint_path": _cached_js_path,
        "cached_js_entrypoint_sha256": _cached_js_sha,
        # REJECT#LATEST AC#2/#3: native binary 신뢰 증거를 hit 결과로 전달 (복원 후 재검증·기록용).
        "cached_codex_native_binary_path": _cached_native_path,
        "cached_codex_native_binary_sha256": _cached_native_sha,
        # REJECT#28 AC#3: node 인터프리터 신뢰 증거를 hit 결과로 전달 (복원 후 재검증·기록용).
        "cached_codex_node_interpreter_path": _cached_node_path,
        "cached_codex_node_interpreter_sha256": _cached_node_sha,
        "cached_codex_node_interpreter_trusted": _cached_node_trusted,
        # REJECT#15 문제 B: 설치 유형을 hit 결과로 전달 (복원 후 operational trust 면제 승계용).
        "cached_codex_install_type": _cached_install_type,
    }


# [Purpose]: IMP-20260710-DB54 rework MT-4(문제2/6) — cache hit 재사용 전에 재검증할 7개 live SHA를
#            현재 디스크/artifact에서 best-effort로 관측한다. bundle SHA에 포함되지 않는 차원
#            (verification_json/canonical/approval/pending)까지 포함하여, 캐시가 산출된 시점 대비
#            현재 검토 대상이 실제로 동일한지 확인하는 데 쓴다.
# [Assumptions]: 각 필드는 조회 실패 시 빈 문자열로 대체한다(BLOCK 아님). acceptance_request가 없으면
#            canonical/approval/pending은 빈 문자열이 된다(비교에서 자연히 제외됨).
# [Vulnerability & Risks]: 관측 실패를 빈 문자열로 대체하므로, 캐시 시점에도 빈 값이었던 차원은
#            비교에서 제외된다. 이는 "관측 가능한 차원만 검증"하는 fail-safe 방향이라 안전하다.
# [Improvement]: acceptance_request 스키마 변경 시 필드명을 상수 테이블로 추출하면 drift를 막을 수 있다.
def _codex_live_sha_snapshot(state: Dict[str, Any], pipeline_id: str) -> Dict[str, str]:
    """cache 재검증용 7개 live SHA를 현재 상태에서 관측하여 dict로 반환한다.

    Args:
        state: 활성 pipeline_state.
        pipeline_id: 현재 파이프라인 ID.
    Returns:
        {pr_head_sha, packet_sha256, verification_json_sha256, pr_body_candidate_sha256,
         github_canonical_pr_body_sha256, approval_message_sha256, pending_comment_sha256}
        — 모두 str(관측 실패 시 빈 문자열).
    Raises:
        TypeError: pipeline_id가 None/비str인 경우.
    """
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(f"pipeline_id must be str, got {type(pipeline_id).__name__}")

    snap = {
        "pr_head_sha": "",
        "packet_sha256": "",
        "verification_json_sha256": "",
        "pr_body_candidate_sha256": "",
        "github_canonical_pr_body_sha256": "",
        "approval_message_sha256": "",
        "pending_comment_sha256": "",
    }
    try:
        snap["pr_head_sha"] = _get_current_pr_head_sha() or ""
    except Exception:  # noqa: BLE001
        snap["pr_head_sha"] = ""
    try:
        _pkt = _packet_output_path()
        if _pkt.exists():
            snap["packet_sha256"] = _sha256_file(_pkt)
    except Exception:  # noqa: BLE001
        snap["packet_sha256"] = ""
    try:
        _vj = _packet_json_output_path()
        if _vj.exists():
            snap["verification_json_sha256"] = _sha256_file(_vj)
    except Exception:  # noqa: BLE001
        snap["verification_json_sha256"] = ""
    try:
        _ident = _codex_snapshot_identity(pipeline_id)
        snap["pr_body_candidate_sha256"] = str(
            _ident.get("pr_body_candidate_sha256", "") or ""
        )
    except Exception:  # noqa: BLE001
        snap["pr_body_candidate_sha256"] = ""
    try:
        _req = _load_acceptance_request()
        if isinstance(_req, dict) and str(_req.get("pipeline_id", "") or "") == pipeline_id:
            snap["github_canonical_pr_body_sha256"] = str(
                _req.get("github_canonical_pr_body_sha256", "") or ""
            )
            snap["approval_message_sha256"] = str(
                _req.get("approval_message_sha256", "") or ""
            )
            snap["pending_comment_sha256"] = str(
                _req.get("pending_comment_sha256", "") or ""
            )
    except Exception:  # noqa: BLE001
        pass
    return snap


# [Purpose]: IMP-20260710-DB54 rework MT-4(문제2) — 캐시 생성 시 저장한 live SHA snapshot과 현재
#            live SHA snapshot을 비교하여, cache hit 재사용이 안전한지 판정한다. 하나라도 관측된
#            (non-empty) 캐시 값이 현재와 다르면 재검증 실패로 BLOCKED되게 한다.
# [Assumptions]: cached_snapshot은 캐시 파일의 live_sha_snapshot이다. 빈 값(캐시 시점 미관측)은
#            비교에서 제외한다(관측 가능한 차원만 검증하는 fail-safe).
# [Vulnerability & Risks]: 캐시 시점 빈 값이었던 차원은 검증을 건너뛴다. 그러나 이 차원들은 캐시
#            생성 시에도 관측 불가였으므로, 검증 생략이 stale verdict 재사용을 허용하지 않는다.
# [Improvement]: 필드별 가중치를 두어 일부 차원 불일치는 경고, 핵심 차원은 BLOCKED로 세분화 가능.
def _verify_codex_cache_live_shas(
    cached_snapshot: Optional[Dict[str, Any]], state: Dict[str, Any], pipeline_id: str
) -> Dict[str, Any]:
    """캐시에 저장된 live SHA snapshot과 현재 live SHA를 비교한다.

    Args:
        cached_snapshot: 캐시 파일의 live_sha_snapshot(없으면 빈 dict 취급).
        state: 활성 pipeline_state.
        pipeline_id: 현재 파이프라인 ID.
    Returns:
        {"ok": bool, "mismatched": list[str], "current": dict}.
    Raises:
        TypeError: pipeline_id가 None/비str인 경우.
    """
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(f"pipeline_id must be str, got {type(pipeline_id).__name__}")
    cached = cached_snapshot if isinstance(cached_snapshot, dict) else {}
    current = _codex_live_sha_snapshot(state, pipeline_id)
    mismatched: List[str] = []
    for _k, _cv in cached.items():
        _cvs = str(_cv or "")
        if not _cvs:
            continue  # 캐시 시점 미관측 차원은 비교 제외(fail-safe)
        if str(current.get(_k, "") or "") != _cvs:
            mismatched.append(str(_k))
    return {"ok": not mismatched, "mismatched": mismatched, "current": current}


# [Purpose]: IMP-20260710-DB54 rework MT-3(문제3) — bundle이 Codex payload로 유효한 최소 필수
#            필드를 갖췄는지 검사한다. 하나라도 없으면 호출자가 fail-closed BLOCKED 처리한다.
# [Assumptions]: bundle은 _build_codex_review_bundle이 만든 dict(또는 그 파일 로드 결과)다.
# [Vulnerability & Risks]: 필드가 존재하지만 빈 값인 경우(빈 list/dict)는 "존재"로 간주한다.
#            필수 필드의 존재 자체가 계약이며, 내용 채움은 best-effort이기 때문이다.
# [Improvement]: 필드별 타입 검증(list/dict/str)까지 확장하면 더 강한 스키마 계약을 만들 수 있다.
def _codex_bundle_required_fields_missing(bundle: Dict[str, Any]) -> List[str]:
    """bundle에서 누락된 필수 필드 목록을 반환한다(없으면 빈 list).

    Args:
        bundle: 검사할 bundle dict.
    Returns:
        누락된 필수 필드명 목록.
    Raises:
        TypeError: bundle이 None/비dict인 경우.
    """
    if bundle is None:
        raise TypeError("bundle must not be None")
    if not isinstance(bundle, dict):
        raise TypeError(f"bundle must be dict, got {type(bundle).__name__}")
    required = ("included_functions", "excluded_files", "critical_file_shas", "test_summary")
    return [f for f in required if f not in bundle]


# ---------------------------------------------------------------------------
# BUG-20260702-E69E: Codex CLI 실행 오류를 REJECT verdict와 분리한다.
#   Codex가 명시적으로 "REJECT - ..."를 반환한 경우만 REJECTED이며,
#   usage limit / timeout / network / non-zero exit / parse 실패 등 CLI 실행
#   실패는 모두 ERROR로 분류한다. ERROR는 reject rate-limit을 트리거하지 않고,
#   승인 코드 발급을 차단하되 --retry-cli-error로 재시도할 수 있다.
# ---------------------------------------------------------------------------

# [Purpose]: BUG-20260702-E69E MT-6 — Codex Review 이력(.pipeline/codex_review_history.jsonl)
#            경로를 반환한다. PIPELINE_STATE_PATH 격리를 지원하여 E2E 테스트가 전역 이력을
#            오염시키지 않도록 한다.
# [Assumptions]: PIPELINE_STATE_PATH가 설정되면 그 state 파일과 같은 .pipeline 디렉토리에 위치한다.
# [Vulnerability & Risks]: append-only jsonl이므로 파일 손상 시 마지막 줄만 영향받는다.
# [Improvement]: 향후 이력 항목에 reviewer 서명/TTL을 추가해 위변조 검출을 강화할 수 있다.
def _codex_review_history_path() -> Path:
    """codex_review_history.jsonl (Codex Review append-only 이력) 경로를 반환한다.

    Returns:
        .pipeline/codex_review_history.jsonl 절대 경로.
    """
    env_state = os.environ.get("PIPELINE_STATE_PATH")
    if env_state:
        return Path(env_state).resolve().parent / ".pipeline" / "codex_review_history.jsonl"
    return PIPELINE_CI_DIR / "codex_review_history.jsonl"


# [Purpose]: BUG-20260702-E69E MT-1 — Codex CLI 실행 결과(exit_code/stdout/stderr)를 분석하여
#            error_type과 재시도 가능 여부(error_retryable)를 반환한다. CLI 실행 실패를 Codex의
#            REJECT verdict와 명확히 구분하기 위한 단일 분류 지점이다.
# [Assumptions]: 호출자는 subprocess 실행 후 exit_code(int), stdout(str), stderr(str)를 그대로
#            넘긴다. subprocess.TimeoutExpired는 호출자가 exit_code=-1 + stdout/stderr에
#            "timeout" 문자열을 채워 넘기거나, 직접 error_type="timeout"으로 처리한다.
# [Vulnerability & Risks]: 문자열 매칭 기반이므로 Codex CLI 메시지 문구가 바뀌면 nonzero_exit로
#            fallback될 수 있다. 이는 fail-closed(ERROR로 처리) 방향이라 안전하다.
# [Improvement]: Codex CLI가 구조화된 error code를 반환하면 문자열 매칭 대신 code 기반 분류로
#            전환할 수 있다.
def _classify_codex_cli_error(exit_code: int, stdout: str, stderr: str) -> Dict[str, Any]:
    """Codex CLI 실행 결과를 분석하여 error 분류를 반환한다.

    Args:
        exit_code: subprocess 종료 코드 (정수). timeout은 관례상 -1로 넘길 수 있다.
        stdout: CLI 표준 출력 문자열.
        stderr: CLI 표준 에러 문자열.
    Returns:
        {"error_type": str, "error_retryable": bool} 형식의 dict.
        error_type 값: usage_limit | timeout | missing_executable | network |
                       parse_failure | nonzero_exit.
    Raises:
        TypeError: exit_code가 None/비int이거나 stdout/stderr가 None/비str인 경우.
    """
    if exit_code is None:
        raise TypeError("exit_code must not be None")
    # bool은 int의 subclass이므로 명시적으로 배제 (True/False를 exit code로 오용 방지).
    if isinstance(exit_code, bool) or not isinstance(exit_code, int):
        raise TypeError(
            f"exit_code must be int, got {type(exit_code).__name__}"
        )
    if stdout is None:
        raise TypeError("stdout must not be None")
    if not isinstance(stdout, str):
        raise TypeError(f"stdout must be str, got {type(stdout).__name__}")
    if stderr is None:
        raise TypeError("stderr must not be None")
    if not isinstance(stderr, str):
        raise TypeError(f"stderr must be str, got {type(stderr).__name__}")

    out_low = stdout.lower()
    err_low = stderr.lower()
    combined = out_low + "\n" + err_low

    # 1) usage limit — Codex CLI가 사용량 한도에 도달한 경우. 재시도 가능(시간 경과 후).
    if "you've hit your usage limit" in out_low or "usage limit" in combined:
        return {"error_type": "usage_limit", "error_retryable": True}

    # 2) timeout — subprocess.TimeoutExpired 또는 timeout 관련 문자열. 재시도 가능.
    if exit_code == -1 or "timeout" in combined or "timed out" in combined:
        return {"error_type": "timeout", "error_retryable": True}

    # 3) missing_executable — codex CLI 자체가 없음. 재시도해도 동일 실패 → 재시도 불가.
    if (
        "not found" in err_low
        or "command not found" in combined
        or "no such file" in err_low
        or "is not recognized" in err_low  # Windows: '...' is not recognized ...
    ):
        return {"error_type": "missing_executable", "error_retryable": False}

    # 4) network — 네트워크/연결 오류. 재시도 가능.
    if (
        "network" in combined
        or "connection" in combined
        or "connect" in combined and "refused" in combined
        or "econnreset" in combined
        or "dns" in combined
    ):
        return {"error_type": "network", "error_retryable": True}

    # 5) parse_failure — exit 0이지만 stdout이 비었거나 verdict로 파싱 불가. 재시도 가능.
    if exit_code == 0:
        return {"error_type": "parse_failure", "error_retryable": True}

    # 6) nonzero_exit — 위 조건 어디에도 해당하지 않는 non-zero exit. 재시도 가능(원인 불명확).
    return {"error_type": "nonzero_exit", "error_retryable": True}


# [Purpose]: BUG-20260702-E69E REJECT-2 — Codex CLI stdout의 마지막 JSON block을 파싱하여
#            machine-readable verdict를 추출한다. startswith("REJECT") 같은 취약한 prefix 판정을
#            대체하는 신뢰 루트다. {"verdict": "APPROVE_TO_USER"|"REJECT", "reason": ...} 형식만
#            유효 verdict로 인정하고, REJECT는 비어있지 않은 reason을 요구한다(fail-closed).
# [Assumptions]: Codex CLI가 JSON protocol을 지원하면 stdout 끝에 단일 JSON object를 출력한다.
#            JSON이 없거나 형식이 다르면 None을 반환하여 호출자가 legacy fallback으로 진행한다.
# [Vulnerability & Risks]: 알 수 없는 verdict 값이나 reason 없는 REJECT는 None(=파싱 실패)으로
#            처리하여 임의 문자열이 verdict로 승격되는 것을 막는다.
# [Improvement]: schema_version 필드를 강제하여 protocol 버전 협상을 정교화할 수 있다.
def _parse_json_verdict(stdout: str) -> Optional[Dict[str, Any]]:
    """stdout의 마지막 JSON block을 파싱하여 verdict를 추출한다.

    Args:
        stdout: Codex CLI 표준 출력 문자열.
    Returns:
        {"verdict": "APPROVED"|"REJECTED", "reason": str, "source": "json_protocol"}
        또는 None (JSON 없음/파싱 실패/알 수 없는 verdict/reason 없는 REJECT).
    """
    # None/비str 입력 방어 — 명시적 None 반환(예외 대신 fallback 허용).
    if stdout is None:
        return None
    if not isinstance(stdout, str):
        return None
    if not stdout:
        return None

    # 오른쪽에서 마지막 '}'를 찾고, 그에 대응하는 마지막 '{'로 JSON 블록을 추출한다.
    end = stdout.rfind("}")
    if end == -1:
        return None
    start = stdout.rfind("{", 0, end + 1)
    if start == -1:
        return None

    json_str = stdout[start:end + 1]
    try:
        obj = json.loads(json_str)
    except (json.JSONDecodeError, ValueError):
        return None

    if not isinstance(obj, dict):
        return None

    verdict = str(obj.get("verdict", "") or "")
    reason = str(obj.get("reason", "") or "")

    if verdict == "APPROVE_TO_USER":
        return {"verdict": "APPROVED", "reason": reason, "source": "json_protocol"}
    if verdict == "REJECT":
        # IMP-20260712-DAE1 REJECT#3(요구6): REJECT 스키마는 4개 필수 필드를 강제한다.
        #   root_cause, reproduction, required_fix, acceptance_criteria 중 하나라도 누락되면
        #   parse_failure(None 반환)로 처리한다(임의 REJECT 승격 금지, fail-closed).
        _root_cause = str(obj.get("root_cause", "") or "").strip()
        _reproduction = str(obj.get("reproduction", "") or "").strip()
        _required_fix = str(obj.get("required_fix", "") or "").strip()
        _acceptance = obj.get("acceptance_criteria")
        _acceptance_ok = isinstance(_acceptance, list) and len(_acceptance) > 0 and all(
            str(x).strip() for x in _acceptance
        )
        if not (_root_cause and _reproduction and _required_fix and _acceptance_ok):
            return None
        _reason_text = reason or (
            f"root_cause={_root_cause}; reproduction={_reproduction}; "
            f"required_fix={_required_fix}"
        )
        return {
            "verdict": "REJECTED",
            "reason": _reason_text,
            "root_cause": _root_cause,
            "reproduction": _reproduction,
            "required_fix": _required_fix,
            "acceptance_criteria": [str(x).strip() for x in (_acceptance or [])],
            "source": "json_protocol",
        }

    # 알 수 없는 verdict 값 → 파싱 실패로 처리(임의 문자열 승격 방지).
    return None


# [Purpose]: BUG-20260702-E69E MT-2 — Codex CLI 실행 결과 원시값(exit_code/stdout/stderr)을
#            분석하여 표준화된 Codex Review 결과 dict를 반환한다. CLI 실행 실패는 REJECT로
#            fallback하지 않고 ERROR로 분류하며, exit 0인 경우에만 stdout을 verdict로 파싱한다.
# [Assumptions]: Codex CLI는 승인 시 stdout에 JSON verdict 또는 "APPROVE_TO_USER"를, 거절 시
#            JSON verdict 또는 정확한 "REJECT - <사유>" 형식을 출력한다. exit_code는 실제 종료 코드다.
# [Vulnerability & Risks]: exit 0 + 유효하지 않은 stdout은 parse_failure ERROR로 처리(fail-closed).
#            REJECT verdict만 REJECTED로 승격되며, CLI 오류는 절대 REJECTED가 되지 않는다.
#            "REJECT" 단독/"REJECTED"/"REJECT_LIMIT"/"INFO: REJECT" 등은 REJECTED로 승격되지 않는다.
# [Improvement]: JSON protocol이 정착되면 legacy 정규식 fallback을 제거할 수 있다.
def _run_codex_cli_review(exit_code: int, stdout: str, stderr: str) -> Dict[str, Any]:
    """Codex CLI 실행 결과를 표준화된 Codex Review 결과 dict로 변환한다.

    분류 규칙:
      - exit_code != 0 → _classify_codex_cli_error 호출 → status="ERROR".
      - exit_code == 0 이지만 stdout이 APPROVE_TO_USER / REJECT - ... 형식이 아님
        → parse_failure status="ERROR" (fail-closed).
      - exit_code == 0 + stdout에 "REJECT" → status="REJECTED" (verdict="REJECT").
      - exit_code == 0 + stdout에 "APPROVE_TO_USER" → status="APPROVED".
    CLI 실행 오류를 REJECT로 fallback하지 않는다(핵심 결함 수정).

    Args:
        exit_code: subprocess 종료 코드 (정수, timeout은 -1).
        stdout: CLI 표준 출력.
        stderr: CLI 표준 에러.
    Returns:
        dict {status, error_type, error_retryable, codex_cli_exit_code,
              codex_cli_stdout_excerpt, codex_cli_stderr_excerpt, verdict, reject_reason}.
    Raises:
        TypeError: exit_code가 None/비int이거나 stdout/stderr가 None/비str인 경우.
    """
    if exit_code is None:
        raise TypeError("exit_code must not be None")
    if isinstance(exit_code, bool) or not isinstance(exit_code, int):
        raise TypeError(f"exit_code must be int, got {type(exit_code).__name__}")
    if stdout is None:
        raise TypeError("stdout must not be None")
    if not isinstance(stdout, str):
        raise TypeError(f"stdout must be str, got {type(stdout).__name__}")
    if stderr is None:
        raise TypeError("stderr must not be None")
    if not isinstance(stderr, str):
        raise TypeError(f"stderr must be str, got {type(stderr).__name__}")

    base = {
        "status": "ERROR",
        "error_type": None,
        "error_retryable": False,
        "codex_cli_exit_code": exit_code,
        "codex_cli_stdout_excerpt": stdout[:200],
        "codex_cli_stderr_excerpt": stderr[:200],
        "verdict": None,
        "reject_reason": None,
    }

    # non-zero exit → CLI 실행 실패 → ERROR (절대 REJECT로 fallback하지 않음).
    if exit_code != 0:
        classified = _classify_codex_cli_error(exit_code, stdout, stderr)
        base["error_type"] = classified["error_type"]
        base["error_retryable"] = classified["error_retryable"]
        return base

    # exit 0 — stdout을 verdict로 파싱. 빈 stdout은 parse_failure.
    stripped = stdout.strip()
    if not stripped:
        classified = _classify_codex_cli_error(0, stdout, stderr)
        base["error_type"] = classified["error_type"]  # parse_failure
        base["error_retryable"] = classified["error_retryable"]
        return base

    # BUG-20260702-E69E REJECT-2: JSON verdict protocol을 먼저 시도(machine-readable).
    #   startswith("REJECT") 취약 판정을 대체한다. JSON이 유효하면 그 verdict를 신뢰 루트로 사용.
    _json_verdict = _parse_json_verdict(stripped)
    if _json_verdict is not None:
        if _json_verdict["verdict"] == "APPROVED":
            return {
                "status": "APPROVED",
                "error_type": None,
                "error_retryable": False,
                "codex_cli_exit_code": exit_code,
                "codex_cli_stdout_excerpt": stdout[:200],
                "codex_cli_stderr_excerpt": stderr[:200],
                "verdict": "APPROVE_TO_USER",
                "reject_reason": None,
            }
        if _json_verdict["verdict"] == "REJECTED":
            # IMP-20260712-DAE1 REJECT#9: _parse_json_verdict가 검증한 structured 필드를 보존한다.
            return {
                "status": "REJECTED",
                "error_type": None,
                "error_retryable": False,
                "codex_cli_exit_code": exit_code,
                "codex_cli_stdout_excerpt": stdout[:200],
                "codex_cli_stderr_excerpt": stderr[:200],
                "verdict": "REJECT",
                "reject_reason": _json_verdict["reason"],
                "root_cause": _json_verdict.get("root_cause") or None,
                "reproduction": _json_verdict.get("reproduction") or None,
                "required_fix": _json_verdict.get("required_fix") or None,
                "acceptance_criteria": _json_verdict.get("acceptance_criteria") or None,
            }

    # NDJSON fallback: real codex exec outputs verdict in agent_message items.
    # REJECT#19: 전체 NDJSON을 끝까지 수집한 뒤 판정을 결정한다.
    #   복수/상충 판정이 있으면 parse_failure(fail-closed). 단일만 허용.
    if _json_verdict is None:
        _ndjson_verdicts: List[Dict[str, Any]] = []
        for _ndjson_line in stripped.splitlines():
            _ndjson_line = _ndjson_line.strip()
            if not _ndjson_line:
                continue
            try:
                _ndjson_obj = json.loads(_ndjson_line)
            except (json.JSONDecodeError, ValueError):
                continue
            if (
                isinstance(_ndjson_obj, dict)
                and _ndjson_obj.get("type") == "item.completed"
                and isinstance(_ndjson_obj.get("item"), dict)
                and _ndjson_obj["item"].get("type") == "agent_message"
            ):
                _agent_text = str(_ndjson_obj["item"].get("text", "") or "").strip()
                _at_upper = _agent_text.upper()
                if _at_upper == "APPROVE_TO_USER":
                    _ndjson_verdicts.append({"kind": "APPROVE"})
                elif _agent_text.startswith("{"):
                    # IMP-20260712-DAE1 bugfix#5: JSON verdict in agent_message.text
                    # REJECT#20: _parse_json_verdict 실패 시 INVALID 추가 (fail-closed).
                    # JSON-like text가 스키마 검증을 통과하지 못하면 INVALID로 수집해야
                    # 이후 복수 판정 차단 규칙이 올바르게 동작한다.
                    _inner_parsed = _parse_json_verdict(_agent_text)
                    if _inner_parsed is not None:
                        if _inner_parsed["verdict"] == "APPROVED":
                            _ndjson_verdicts.append({"kind": "APPROVE"})
                        elif _inner_parsed["verdict"] == "REJECTED":
                            _ndjson_verdicts.append({
                                "kind": "REJECT",
                                "parsed": _inner_parsed,
                            })
                    else:
                        # JSON처럼 시작하지만 verdict 스키마 검증 실패 → INVALID (fail-closed)
                        _ndjson_verdicts.append({"kind": "INVALID"})
                elif re.match(r"^REJECT\s+-\s+\S", _agent_text, re.IGNORECASE):
                    # IMP-20260712-DAE1 REJECT#9: plaintext REJECT는 구조화 검증 미통과 → INVALID
                    _ndjson_verdicts.append({"kind": "INVALID"})

        # REJECT#19: 복수(2개 이상) 판정 → parse_failure (AC#3)
        if len(_ndjson_verdicts) >= 2:
            base["error_type"] = "parse_failure"
            base["error_retryable"] = False
            return base

        # 단일 판정 처리 (AC#4)
        if len(_ndjson_verdicts) == 1:
            _vd = _ndjson_verdicts[0]
            if _vd["kind"] == "APPROVE":
                return {
                    "status": "APPROVED",
                    "error_type": None,
                    "error_retryable": False,
                    "codex_cli_exit_code": exit_code,
                    "codex_cli_stdout_excerpt": stdout[:200],
                    "codex_cli_stderr_excerpt": stderr[:200],
                    "verdict": "APPROVE_TO_USER",
                    "reject_reason": None,
                }
            if _vd["kind"] == "REJECT":
                # IMP-20260712-DAE1 REJECT#9: structured 필드 보존.
                _p = _vd["parsed"]
                return {
                    "status": "REJECTED",
                    "error_type": None,
                    "error_retryable": False,
                    "codex_cli_exit_code": exit_code,
                    "codex_cli_stdout_excerpt": stdout[:200],
                    "codex_cli_stderr_excerpt": stderr[:200],
                    "verdict": "REJECT",
                    "reject_reason": _p.get("reason") or None,
                    "root_cause": _p.get("root_cause") or None,
                    "reproduction": _p.get("reproduction") or None,
                    "required_fix": _p.get("required_fix") or None,
                    "acceptance_criteria": _p.get("acceptance_criteria") or None,
                }
            # INVALID (plaintext REJECT 등) → parse_failure
            base["error_type"] = "parse_failure"
            base["error_retryable"] = False
            return base
        # 0 verdicts → fall through to legacy parsing below

    up = stripped.upper()
    # IMP-20260712-DAE1 REJECT#9: 기존 legacy "REJECT - <사유>" plaintext REJECT 승격 경로를
    # parse_failure ERROR로 교체한다. REJECT는 반드시 _parse_json_verdict의 4-필드 JSON 스키마
    # 검증(root_cause/reproduction/required_fix/acceptance_criteria)을 통과해야 한다.
    # "REJECT - reason" 단독 평문 출력은 구조화 필드 없이 trust-chain을 우회할 수 있으므로 차단.
    if re.match(r"^REJECT\s+-\s+\S", stripped, re.IGNORECASE):
        base["error_type"] = "parse_failure"
        base["error_retryable"] = False
        return base

    # 명시적 APPROVE_TO_USER (legacy). BUG-20260702-E69E REJECT-2: substring 매칭은
    #   "WARNING: APPROVE_TO_USER may be premature" 같은 진단 문구를 승인으로 오분류하므로
    #   stripped stdout이 정확히 APPROVE_TO_USER일 때만 승격한다(fail-closed). 그 외는 아래
    #   parse_failure ERROR로 흐른다.
    if up == "APPROVE_TO_USER":
        return {
            "status": "APPROVED",
            "error_type": None,
            "error_retryable": False,
            "codex_cli_exit_code": exit_code,
            "codex_cli_stdout_excerpt": stdout[:200],
            "codex_cli_stderr_excerpt": stderr[:200],
            "verdict": "APPROVE_TO_USER",
            "reject_reason": None,
        }

    # exit 0 이지만 유효한 verdict 형식이 아님 → parse_failure ERROR (fail-closed).
    #   "REJECT" 단독/"REJECTED"/"REJECT_LIMIT"/"INFO: REJECT" 등은 모두 여기서 처리된다.
    classified = _classify_codex_cli_error(0, stdout, stderr)
    base["error_type"] = classified["error_type"]  # parse_failure
    base["error_retryable"] = classified["error_retryable"]
    return base


# [Purpose]: BUG-20260702-E69E MT-6 — Codex Review 결과 1건을 append-only 이력 파일에 기록한다.
#            reject/CLI-error 카운트와 rate-limit 기여 여부를 함께 남겨 감사 추적을 가능하게 한다.
# [Assumptions]: entry는 최소 "status" 키를 포함한다. reject_count/cli_error_count는 호출자가
#            누적 계산하여 넘긴다(없으면 0).
# [Vulnerability & Risks]: append 실패(OSError)는 조용히 흡수하지 않고 호출자가 인지하도록 예외를
#            전파한다. 단, 이력 기록 실패가 gate 판정 자체를 바꾸지는 않는다.
# [Improvement]: 이력 회전(rotation)을 추가해 파일이 무한히 커지는 것을 방지할 수 있다.
def _append_codex_history(entry: Dict[str, Any]) -> None:
    """Codex Review 결과 1건을 codex_review_history.jsonl에 append한다.

    저장 필드(누락 시 기본값 채움):
      timestamp, status, error_type, reject_count, cli_error_count,
      counts_toward_reject_rate_limit, acceptance_eligible.

    Args:
        entry: 기록할 결과 dict. 최소 "status" 키 포함.
    Raises:
        TypeError: entry가 None이거나 dict가 아닌 경우.
        OSError: 이력 파일 write 실패 시.
    """
    if entry is None:
        raise TypeError("entry must not be None")
    if not isinstance(entry, dict):
        raise TypeError(f"entry must be dict, got {type(entry).__name__}")

    status = str(entry.get("status", "") or "")
    record = {
        "timestamp": str(entry.get("timestamp", "") or _now()),
        "status": status,
        "error_type": entry.get("error_type"),
        "reject_count": int(entry.get("reject_count", 0) or 0),
        "cli_error_count": int(entry.get("cli_error_count", 0) or 0),
        # reject rate-limit에 기여하는 것은 REJECTED 상태뿐이다.
        "counts_toward_reject_rate_limit": bool(
            entry.get("counts_toward_reject_rate_limit", status == "REJECTED")
        ),
        "acceptance_eligible": bool(
            entry.get("acceptance_eligible", status == "APPROVED")
        ),
    }
    # BUG-20260702-E69E REJECT-1: attempt 단위 추적 필드를 있으면 보존한다(감사 추적).
    if entry.get("attempt_id"):
        record["attempt_id"] = str(entry.get("attempt_id"))
    if entry.get("invalidation_reason"):
        record["invalidation_reason"] = str(entry.get("invalidation_reason"))
    if entry.get("invalidated_from_attempt_id"):
        record["invalidated_from_attempt_id"] = str(entry.get("invalidated_from_attempt_id"))
    if entry.get("changed_fields"):
        # snapshot 변경으로 무효화된 경우, 어떤 SHA 차원이 바뀌었는지 이력에 남긴다.
        _cf = entry.get("changed_fields")
        record["changed_fields"] = list(_cf) if isinstance(_cf, (list, tuple)) else [str(_cf)]
    if entry.get("snapshot_identity") and isinstance(entry.get("snapshot_identity"), dict):
        record["snapshot_identity"] = dict(entry.get("snapshot_identity"))  # type: ignore[arg-type]
    hist_path = _codex_review_history_path()
    hist_path.parent.mkdir(parents=True, exist_ok=True)
    with open(hist_path, "a", encoding="utf-8") as fh:
        fh.write(json.dumps(record, ensure_ascii=False) + "\n")


# [Purpose]: BUG-20260702-E69E MT-4 — Codex Review reject rate-limit을 판정한다. reject_count에만
#            기반하며, cli_error_count(CLI 실행 실패)는 rate-limit 트리거에서 완전히 제외한다.
# [Assumptions]: reject_count는 누적 REJECTED 횟수, cli_error_count는 누적 ERROR 횟수다.
#            retry_cli_error=True는 --retry-cli-error 플래그(ERROR 상태 우회)를 의미한다.
# [Vulnerability & Risks]: reject_count가 음수로 넘어오면 방어적으로 0 취급(잘못된 상태로 인한
#            무한 우회 방지). retry_cli_error는 reject rate-limit을 우회하지 못한다(REJECT는 실제
#            거절이므로 CLI-error 재시도로 우회 불가).
# [Improvement]: reject 시각을 함께 받아 시간 창(window) 기반 rate-limit으로 정교화할 수 있다.
def _check_codex_rate_limit(
    reject_count: int,
    cli_error_count: int = 0,
    retry_cli_error: bool = False,
    reject_threshold: int = 2,
) -> Dict[str, Any]:
    """Codex Review reject rate-limit 여부를 판정한다 (reject_count 기반).

    규칙:
      - reject_count >= reject_threshold(기본 2) → RATE_LIMITED.
      - cli_error_count는 rate-limit 트리거에서 완전히 제외된다.
      - retry_cli_error 플래그는 reject rate-limit을 우회하지 못한다(REJECT는 실제 거절).

    Args:
        reject_count: 누적 REJECTED 횟수.
        cli_error_count: 누적 ERROR 횟수 (rate-limit 판정에 미사용, 진단용).
        retry_cli_error: --retry-cli-error 플래그 여부.
        reject_threshold: rate-limit 임계값 (기본 2).
    Returns:
        {"status": "OK"|"RATE_LIMITED", "reject_count": int, "cli_error_count": int,
         "reason": str}.
    Raises:
        TypeError: reject_count/cli_error_count/reject_threshold가 None/비int이거나
            retry_cli_error가 비bool인 경우.
        ValueError: reject_threshold가 1 미만인 경우.
    """
    if reject_count is None:
        raise TypeError("reject_count must not be None")
    if isinstance(reject_count, bool) or not isinstance(reject_count, int):
        raise TypeError(f"reject_count must be int, got {type(reject_count).__name__}")
    if cli_error_count is None:
        raise TypeError("cli_error_count must not be None")
    if isinstance(cli_error_count, bool) or not isinstance(cli_error_count, int):
        raise TypeError(
            f"cli_error_count must be int, got {type(cli_error_count).__name__}"
        )
    if not isinstance(retry_cli_error, bool):
        raise TypeError(
            f"retry_cli_error must be bool, got {type(retry_cli_error).__name__}"
        )
    if reject_threshold is None:
        raise TypeError("reject_threshold must not be None")
    if isinstance(reject_threshold, bool) or not isinstance(reject_threshold, int):
        raise TypeError(
            f"reject_threshold must be int, got {type(reject_threshold).__name__}"
        )
    # reject_threshold는 rate-limit 하한 — 1 미만은 무의미(모든 reject 즉시 차단은 별도 정책).
    if reject_threshold < 1:
        raise ValueError(
            f"reject_threshold must be >= 1, got {reject_threshold}"
        )

    # 방어적 정규화: 음수 카운트는 0으로 취급 (잘못된 상태로 인한 무한 우회 방지).
    # negative counts are not meaningful; clamp to 0 to fail-safe.
    eff_reject = reject_count if reject_count > 0 else 0
    eff_cli_error = cli_error_count if cli_error_count > 0 else 0

    if eff_reject >= reject_threshold:
        return {
            "status": "RATE_LIMITED",
            "reject_count": eff_reject,
            "cli_error_count": eff_cli_error,
            "reason": (
                f"reject_count={eff_reject} >= threshold={reject_threshold} — "
                "Codex REJECT가 반복되어 rate-limit이 적용됩니다. "
                "--force-review로만 우회할 수 있습니다."
            ),
        }

    return {
        "status": "OK",
        "reject_count": eff_reject,
        "cli_error_count": eff_cli_error,
        "reason": "reject rate-limit 미적용",
    }


def _check_codex_review_gate(
    pipeline_id: str, state: Dict[str, Any]
) -> Dict[str, Any]:
    """gates accept --result ACCEPT 전 Codex Review Loop 승인 여부를 검증 (fail-closed).

    .pipeline/codex_review_loop_state.json을 로드하여 다음을 검사한다:
      - 파일 없음/파싱 오류 → codex_review_not_approved BLOCKED (fail-closed)
      - status != APPROVED → codex_review_not_approved BLOCKED
      - APPROVED이지만 5개 필수 필드(pipeline_id, pr_head_sha, packet_sha256,
        pr_body_sha256, accept_code) 중 하나라도 없거나 빔 → codex_review_stale BLOCKED
      - APPROVED이지만 pipeline_id가 현재 파이프라인과 다름 → codex_review_stale BLOCKED
      - APPROVED이지만 gh CLI로 head SHA를 못 얻음 → codex_review_stale BLOCKED (fail-closed)
      - APPROVED이지만 pr_head_sha가 현재 PR head SHA와 다름 → codex_review_stale BLOCKED
      - acceptance_request.json이 없거나 packet_sha256/pr_body_sha256이 빔
        → codex_review_stale BLOCKED (fail-closed)
      - APPROVED이지만 packet_sha256/pr_body_sha256이 acceptance_request.json과 다름
        → codex_review_stale BLOCKED
      - 모두 존재하고 일치 → PASS

    2차 REJECT 재작업(IMP-20260626-4121): "값이 있으면 비교, 없으면 SKIP" 구조를
    제거하고 모든 비교를 fail-closed로 강화한다. APPROVED 파일만 있고 필드가
    누락된 경우 우회를 차단한다.

    기존 provenance/replay/nonce 검증을 대체하지 않으며, 그 이전 선검사로만 동작한다.

    Args:
        pipeline_id: 현재 활성 파이프라인 ID.
        state: pipeline_state dict (현재 미사용이나 인터페이스 일관성 위해 수신).
    Returns:
        {"status": "PASS"} 또는
        {"status": "BLOCKED", "failure_code": str, "message": str}.
    Raises:
        TypeError: pipeline_id가 None이거나 str가 아닌 경우.
    """
    if pipeline_id is None:
        raise TypeError("pipeline_id must not be None")
    if not isinstance(pipeline_id, str):
        raise TypeError(
            f"pipeline_id must be str, got {type(pipeline_id).__name__}"
        )

    loop_path = _codex_review_loop_state_path()
    if not loop_path.exists():
        return {
            "status": "BLOCKED",
            "failure_code": "codex_review_not_approved",
            "message": (
                "Codex 검토가 아직 APPROVE되지 않았습니다. "
                "gates request-accept를 먼저 실행하세요."
            ),
        }

    try:
        with open(loop_path, encoding="utf-8") as fh:
            loop_state = json.load(fh)
        if not isinstance(loop_state, dict):
            raise ValueError("codex_review_loop_state.json is not an object")
    except (OSError, json.JSONDecodeError, ValueError):
        # fail-closed: 로드/파싱 실패는 미승인으로 간주
        return {
            "status": "BLOCKED",
            "failure_code": "codex_review_not_approved",
            "message": (
                "codex_review_loop_state.json 로드/파싱에 실패했습니다 (fail-closed). "
                "gates request-accept를 다시 실행하세요."
            ),
        }

    if str(loop_state.get("status", "")) != "APPROVED":
        return {
            "status": "BLOCKED",
            "failure_code": "codex_review_not_approved",
            "message": (
                "Codex 검토가 아직 APPROVE되지 않았습니다. "
                "gates request-accept를 먼저 실행하세요."
            ),
        }

    # APPROVED — fail-closed 필수 필드 존재 검증 (2차 REJECT 재작업).
    # "값이 있으면 비교, 없으면 SKIP" 구조의 우회를 차단한다. 아래 5개 필드가
    # 하나라도 비어 있으면 비교 자체를 SKIP하지 않고 즉시 codex_review_stale BLOCKED.
    required_fields = [
        "pipeline_id",
        "pr_head_sha",
        "packet_sha256",
        "pr_body_sha256",
        "accept_code",
    ]
    for field in required_fields:
        if not str(loop_state.get(field, "") or "").strip():
            return {
                "status": "BLOCKED",
                "failure_code": "codex_review_stale",
                "message": (
                    f"Codex APPROVED 상태에 필수 필드 '{field}'가 없거나 "
                    "비어 있습니다. gates request-accept를 다시 실행하세요."
                ),
            }

    # pipeline_id 일치 검증 (다른 파이프라인의 승인 상태 재사용 차단).
    # 빈 값 체크는 위 required_fields 루프에서 이미 완료.
    if str(loop_state["pipeline_id"]) != pipeline_id:
        return {
            "status": "BLOCKED",
            "failure_code": "codex_review_stale",
            "message": (
                "Codex APPROVED 상태의 pipeline_id가 현재 파이프라인과 다릅니다. "
                "이전 파이프라인의 승인 상태가 남아 있습니다. "
                "현재 파이프라인에서 gates request-accept를 다시 실행하세요."
            ),
        }

    # head SHA 일치 검증 — gh CLI 실패 시 SKIP이 아니라 fail-closed BLOCKED.
    current_head_sha = _get_current_pr_head_sha()
    if not current_head_sha:
        return {
            "status": "BLOCKED",
            "failure_code": "codex_review_stale",
            "message": (
                "PR head SHA를 확인할 수 없습니다 (gh CLI 없음/실패). "
                "fail-closed — gates request-accept를 다시 실행하세요."
            ),
        }
    if str(loop_state["pr_head_sha"]).lower() != str(current_head_sha).lower():
        return {
            "status": "BLOCKED",
            "failure_code": "codex_review_stale",
            "message": (
                "Codex APPROVED 상태의 pr_head_sha가 현재 PR head SHA와 다릅니다. "
                "PR에 새 커밋이 push되었습니다. gates request-accept를 다시 실행하세요."
            ),
        }

    # packet_sha256 / pr_body_sha256 일치 검증 — acceptance_request.json 기준.
    # acceptance_request.json이 없거나 필드가 비면 fail-closed BLOCKED.
    _req = _load_acceptance_request()
    if _req is None:
        return {
            "status": "BLOCKED",
            "failure_code": "codex_review_stale",
            "message": (
                "acceptance_request.json이 없습니다. "
                "gates request-accept를 먼저 실행하세요."
            ),
        }

    req_packet_sha = str(_req.get("packet_sha256", "") or "")
    if not req_packet_sha:
        return {
            "status": "BLOCKED",
            "failure_code": "codex_review_stale",
            "message": (
                "acceptance_request.json에 packet_sha256이 없거나 비어 있습니다. "
                "fail-closed — gates request-accept를 다시 실행하세요."
            ),
        }
    if req_packet_sha != str(loop_state["packet_sha256"]):
        return {
            "status": "BLOCKED",
            "failure_code": "codex_review_stale",
            "message": (
                "Codex APPROVED 상태의 packet_sha256이 현재 acceptance_request.json과 "
                "다릅니다. packet이 갱신되었습니다. gates request-accept를 다시 실행하세요."
            ),
        }

    req_body_sha = str(_req.get("pr_body_sha256", "") or "")
    if not req_body_sha:
        return {
            "status": "BLOCKED",
            "failure_code": "codex_review_stale",
            "message": (
                "acceptance_request.json에 pr_body_sha256이 없거나 비어 있습니다. "
                "fail-closed — gates request-accept를 다시 실행하세요."
            ),
        }
    if req_body_sha != str(loop_state["pr_body_sha256"]):
        return {
            "status": "BLOCKED",
            "failure_code": "codex_review_stale",
            "message": (
                "Codex APPROVED 상태의 pr_body_sha256이 현재 acceptance_request.json과 "
                "다릅니다. PR 본문이 갱신되었습니다. gates request-accept를 다시 실행하세요."
            ),
        }

    return {"status": "PASS"}


def _check_acceptance_readiness(
    state: Dict[str, Any],
) -> Dict[str, Any]:
    """gates accept --result ACCEPT 실행 전 PR 품질 및 acceptance packet readiness hard gate.

    반환값:
        {
            "status": "PASS" | "BLOCKED",
            "failure_code": str,      # BLOCKED 시 원인 코드
            "failure_category": str,
            "blocked_reason": Optional[str],
            "missing_sections": List[str],  # pr_body_incomplete 시 누락 섹션
            "return_phase": str,      # BLOCKED 시 재작업 담당 phase
            "allow_accept": bool,
        }

    IMP-20260519-E979 REJECT 재작업:
    - Blocker 1: gh CLI 없음 / gh pr view 실패 / PR 없음 / JSON 파싱 실패는 더 이상
      PASS로 통과시키지 않고 BLOCKED를 반환한다(allow_accept=False).
    - Blocker 2: human acceptance packet readiness는 GitHub PR 댓글을 기본으로 검증한다.
      로컬 파일 검사는 PIPELINE_TEST_ACCEPTANCE_PACKET_PATH 환경변수가 설정된
      테스트 환경에서만 사용하는 fallback이다.
    """
    pass_result: Dict[str, Any] = {
        "status": "PASS",
        "failure_code": "",
        "failure_category": "",
        "blocked_reason": None,
        "missing_sections": [],
        "return_phase": "build",
        "allow_accept": True,
    }

    # --- Blocker 1: gh CLI로 PR 메타데이터 조회 — 실패 시 BLOCKED ---
    try:
        pr_result = subprocess.run(
            ["gh", "pr", "view", "--json", "isDraft,title,body,number,url"],
            capture_output=True, text=True, encoding="utf-8", check=False,
        )
    except (FileNotFoundError, OSError):
        # gh CLI 미설치 — 더 이상 PASS로 통과시키지 않음
        return _acceptance_blocked(
            "gh_cli_not_available",
            (
                "GitHub CLI(gh)가 설치되어 있지 않아 PR 상태를 검증할 수 없습니다. "
                "gh CLI를 설치하고 인증한 뒤 gates accept를 다시 실행하세요."
            ),
        )

    if pr_result.returncode != 0:
        stderr_text = (pr_result.stderr or "").strip()
        # PR 없음(404 / no pull requests found) → pr_not_found
        lowered = stderr_text.lower()
        if "no pull requests found" in lowered or "404" in lowered or "not found" in lowered:
            return _acceptance_blocked(
                "pr_not_found",
                (
                    "현재 브랜치에 연결된 GitHub PR을 찾을 수 없습니다. "
                    "PR을 생성한 뒤 gates accept를 다시 실행하세요. "
                    + stderr_text[:200]
                ),
            )
        # 그 외 gh pr view 실패 → pr_view_failed
        return _acceptance_blocked(
            "pr_view_failed",
            (
                "gh pr view 명령이 실패했습니다"
                f"(exit code {pr_result.returncode}). "
                + stderr_text[:200]
                + " gh 인증과 네트워크 상태를 확인한 뒤 다시 실행하세요."
            ),
        )

    raw_stdout = (pr_result.stdout or "").strip()
    if not raw_stdout:
        # 출력이 비어 있음 → PR을 찾지 못한 것으로 간주
        return _acceptance_blocked(
            "pr_not_found",
            (
                "gh pr view 출력이 비어 있어 PR을 확인할 수 없습니다. "
                "현재 브랜치에 연결된 PR이 있는지 확인한 뒤 다시 실행하세요."
            ),
        )

    try:
        pr_data = json.loads(raw_stdout)
    except (json.JSONDecodeError, ValueError):
        # JSON 파싱 실패 → pr_metadata_parse_error
        return _acceptance_blocked(
            "pr_metadata_parse_error",
            (
                "gh pr view 가 반환한 PR 메타데이터(JSON)를 해석하지 못했습니다. "
                "잠시 후 gates accept를 다시 실행하세요."
            ),
        )

    if not isinstance(pr_data, dict):
        return _acceptance_blocked(
            "pr_metadata_parse_error",
            (
                "gh pr view 가 반환한 PR 메타데이터 형식이 올바르지 않습니다. "
                "잠시 후 gates accept를 다시 실행하세요."
            ),
        )

    # --- 1. Draft PR 차단 ---
    if pr_data.get("isDraft", False):
        return _acceptance_blocked(
            "pr_is_draft",
            (
                "PR이 Draft 상태입니다. "
                "Draft를 해제한 뒤 gates accept를 다시 실행하세요."
            ),
        )

    pr_body: str = (pr_data.get("body") or "").lstrip("﻿")
    pr_url: str = pr_data.get("url") or ""

    # --- 2 & 3. 필수 섹션 + 임시 문구 검사 — IMP-20260611-A716 MT-3: _validate_pr_body_readiness 위임 ---
    body_result = _validate_pr_body_readiness(pr_body)
    if not body_result.get("allow_accept", True):
        return body_result

    # --- 4. Blocker 2: human acceptance packet readiness 확인 ---
    # 기본: GitHub PR 댓글 검증. fallback: 로컬 파일(테스트 환경 전용).
    env_override = os.environ.get("PIPELINE_TEST_ACCEPTANCE_PACKET_PATH", "").strip()
    if env_override:
        # 테스트 환경 fallback — 로컬 파일로 검증
        packet_result = _check_acceptance_packet_via_local_file(state)
    else:
        # 운영 기본 경로 — GitHub PR 댓글로 검증
        packet_result = _check_acceptance_packet_via_github(pr_url)
    if not packet_result.get("allow_accept", True):
        return packet_result

    # --- 5. IMP-20260703-B985 MT-24: packet summary 정합성 검사 (oracle_summary/CI count) ---
    # oracle gate PASS인데 packet의 oracle_summary가 FAIL이거나, PR body 상단 요약과 final packet의
    # CI run ID/test count가 충돌하면 BLOCKED. 정보 부족(파일/필드 없음)은 PASS로 흘려보낸다.
    summary_result = _check_packet_summary_consistency(state, pr_body)
    if not summary_result.get("allow_accept", True):
        return summary_result

    return pass_result


# [Purpose]: IMP-20260703-B985 MT-24 (REJECT #19) — readiness validator 강화. oracle gate가 PASS인데
#            packet에 표시된 oracle_summary가 FAIL이거나, PR body 상단 요약과 final packet의 CI run
#            ID/test count가 충돌하면 BLOCKED로 차단한다(gate 표시-실제 불일치 상태로 승인 방지).
# [Assumptions]: human_acceptance_packet.md 및 state["external_gates"]가 SSoT. gh CLI 부재나 packet
#            파일 부재 등 정보 부족은 PASS로 흘려보낸다(정보 부족을 차단 사유로 삼지 않음).
# [Vulnerability & Risks]: 정규식 파싱은 packet 형식 변경에 취약하다. 필드/파일 부재는 PASS로 처리하므로
#            형식이 크게 바뀌면 검사가 무력화될 수 있다(의도적 non-fatal 설계).
# [Improvement]: packet JSON(verification_json)의 구조화 필드만으로 비교하면 정규식 취약성을 줄일 수 있다.
def _check_packet_summary_consistency(
    state: Dict[str, Any], pr_body: Optional[str]
) -> Dict[str, Any]:
    """packet summary 정합성(oracle_summary/CI count) 검사 (불일치 시 BLOCKED dict 반환).

    Args:
        state: 활성 pipeline_state dict (None/비dict 금지).
        pr_body: 현재 PR 본문 텍스트 (None 허용 — 해당 검사 skip).
    Returns:
        _acceptance_blocked(...) 또는 PASS dict (allow_accept=True).
    Raises:
        TypeError: state가 None이거나 dict가 아닌 경우.
    """
    if state is None:
        raise TypeError("state must not be None")
    if not isinstance(state, dict):
        raise TypeError(f"state must be dict, got {type(state).__name__}")

    pass_result: Dict[str, Any] = {
        "status": "PASS",
        "failure_code": "",
        "failure_category": "",
        "blocked_reason": None,
        "missing_sections": [],
        "return_phase": "build",
        "allow_accept": True,
    }

    # 검사 A: oracle gate PASS인데 packet oracle_summary가 FAIL.
    _gates = state.get("external_gates") or {}
    _oracle_gate = str((_gates.get("oracle") or {}).get("status", "") or "").upper()
    if _oracle_gate == "PASS":
        _pkt_text = ""
        try:
            _pkt_p = _packet_output_path()
            if _pkt_p.exists():
                _pkt_text = _pkt_p.read_text(encoding="utf-8", errors="replace")
        except OSError:
            _pkt_text = ""
        if _pkt_text:
            _m_oracle = re.search(r"oracle_summary:\s*([A-Za-z_]+)", _pkt_text)
            if _m_oracle and _m_oracle.group(1).upper() == "FAIL":
                return _acceptance_blocked(
                    "oracle_summary_mismatch",
                    (
                        "Oracle gate는 PASS이지만 acceptance packet의 oracle_summary가 FAIL로 "
                        "표시되어 있습니다. packet을 최신 상태로 재생성한 뒤 다시 실행하세요 "
                        "(python pipeline.py gates request-accept)."
                    ),
                )

    # 검사 B: PR body 상단 요약과 final packet의 CI run ID/test count 충돌.
    if pr_body:
        _packet_block = ""
        _body_top = pr_body
        _mb = re.search(
            r"<!-- PIPELINE_FINAL_PACKET_START -->(.*?)<!-- PIPELINE_FINAL_PACKET_END -->",
            pr_body, re.DOTALL,
        )
        if _mb:
            _packet_block = _mb.group(1)
            _body_top = pr_body[: _mb.start()]

        if _packet_block:
            def _find_run_id(text: str) -> str:
                m = re.search(
                    r"(?:ci_run_id|CI run ID|run[_ ]?id)[^\d]{0,6}(\d{6,})",
                    text, re.IGNORECASE,
                )
                return m.group(1) if m else ""

            _top_run = _find_run_id(_body_top)
            _pkt_run = _find_run_id(_packet_block)
            if _top_run and _pkt_run and _top_run != _pkt_run:
                return _acceptance_blocked(
                    "ci_count_mismatch",
                    (
                        "PR 본문 상단 요약의 CI run ID와 final packet의 CI run ID가 다릅니다 "
                        f"(상단: {_top_run}, packet: {_pkt_run}). "
                        "PR 본문과 packet을 동일 값으로 갱신한 뒤 다시 실행하세요."
                    ),
                )

            def _find_test_count(text: str) -> str:
                m = re.search(
                    r"(\d+)\s*(?:개|tests?)\s*(?:통과|passed|PASS)",
                    text, re.IGNORECASE,
                )
                return m.group(1) if m else ""

            _top_tc = _find_test_count(_body_top)
            _pkt_tc = _find_test_count(_packet_block)
            if _top_tc and _pkt_tc and _top_tc != _pkt_tc:
                return _acceptance_blocked(
                    "ci_count_mismatch",
                    (
                        "PR 본문 상단 요약의 테스트 통과 수와 final packet의 테스트 통과 수가 "
                        f"다릅니다 (상단: {_top_tc}, packet: {_pkt_tc}). "
                        "PR 본문과 packet을 동일 값으로 갱신한 뒤 다시 실행하세요."
                    ),
                )

    return pass_result


_FORBIDDEN_ACCEPTANCE_EVIDENCE_PREFIXES = (
    ".pipeline/phase_evidence/",
    ".pipeline/agent_receipts/",
    "pipeline_contracts/",
)
_FORBIDDEN_ACCEPTANCE_EVIDENCE_EXACT = {
    "pipeline_state.json",
}


def _is_internal_pipeline_path(item: str) -> bool:
    """acceptance evidence로 사용할 수 없는 내부 파이프라인 경로인지 검사합니다."""
    normalized = item.replace("\\", "/").strip()
    for prefix in _FORBIDDEN_ACCEPTANCE_EVIDENCE_PREFIXES:
        if normalized.startswith(prefix) or normalized == prefix.rstrip("/"):
            return True
    if normalized in _FORBIDDEN_ACCEPTANCE_EVIDENCE_EXACT:
        return True
    return False


def _validate_user_acceptance_evidence(raw: Any) -> Dict[str, Any]:
    items = _split_evidence_items(raw)
    if not items:
        _die(
            "[USER ACCEPTANCE BLOCKED] ACCEPT에는 실제 확인 증거가 필요합니다. "
            "실제 결과 파일/폴더 경로, 스크린샷 경로, PR 링크, GitHub Actions 첨부파일 링크 중 하나를 넣으세요."
        )

    placeholders = [item for item in items if item.upper() in PLACEHOLDER_EVIDENCE_VALUES]
    if placeholders:
        _die(
            "[USER ACCEPTANCE BLOCKED] ACCEPT에는 placeholder 증거를 쓸 수 없습니다: "
            + ", ".join(placeholders)
            + ". 실제 결과 경로나 검토 링크를 넣으세요."
        )

    # MT-2: 내부 파이프라인 경로 거부
    internal = [item for item in items if not _is_evidence_url(item) and _is_internal_pipeline_path(item)]
    if internal:
        _die(
            "[PIPELINE ERROR] acceptance evidence는 pipeline_outputs/ 또는 GitHub URL이어야 합니다. "
            "내부 phase evidence 경로는 허용되지 않습니다: "
            + ", ".join(internal)
        )

    files: List[Dict[str, Any]] = []
    urls: List[str] = []
    missing: List[str] = []
    for item in items:
        if _is_evidence_url(item):
            urls.append(item)
            continue
        path = _resolve_artifact_path(item)
        if path is None:
            missing.append(item)
            continue
        if path.is_file():
            files.append(_path_sha_payload(path))
        else:
            files.append({
                "path": _display_path(path),
                "kind": "directory",
                "exists": True,
            })

    if missing:
        _die(
            "[USER ACCEPTANCE BLOCKED] 증거 경로/링크를 확인할 수 없습니다: "
            + ", ".join(missing)
        )
    if not files and not urls:
        _die(
            "[USER ACCEPTANCE BLOCKED] ACCEPT에는 실제 결과 파일/폴더 경로 또는 검토 링크가 최소 1개 필요합니다."
        )
    return {"files": files, "urls": urls, "raw_items": items}


def _resolve_artifact_path(raw: str) -> Optional[Path]:
    if re.match(r"^[a-zA-Z][a-zA-Z0-9+.-]*://", raw):
        return None
    path = Path(raw)
    if not path.is_absolute():
        path = BASE_DIR / path
    try:
        resolved = path.resolve()
    except OSError:
        return None
    if not resolved.exists():
        return None
    return resolved


def _ensure_output_registry(state: Dict[str, Any]) -> Dict[str, Any]:
    outputs = state.get("outputs")
    if not isinstance(outputs, dict):
        outputs = {"items": []}
    if not isinstance(outputs.get("items"), list):
        outputs["items"] = []
    state["outputs"] = outputs
    return outputs


def _pipeline_output_dir(pid: str) -> Path:
    return OUTPUTS_ROOT / pid


def _copy_to_pipeline_outputs(pid: str, source: Path, label: str = "") -> Path:
    out_dir = _pipeline_output_dir(pid)
    safe_label = re.sub(r"[^A-Za-z0-9_.-]+", "-", label.strip()).strip("-")
    dest_name = source.name if not safe_label else f"{safe_label}-{source.name}"
    dest = out_dir / dest_name
    dest.parent.mkdir(parents=True, exist_ok=True)
    if source.resolve() != dest.resolve():
        shutil.copy2(source, dest)
    return dest


def _register_output_item(
    state: Dict[str, Any],
    *,
    kind: str,
    path: str,
    label: str,
    copy_to_outputs: bool = True,
    notes: str = "",
) -> Dict[str, Any]:
    pid = str(state.get("pipeline_id") or "")
    if not pid:
        _die("[OUTPUT REGISTRY] active pipeline_id is required")
    resolved = _resolve_artifact_path(path)
    if not resolved or not resolved.is_file():
        _die(f"[OUTPUT REGISTRY] output file not found: {path}")
    public_path = resolved
    if copy_to_outputs:
        public_path = _copy_to_pipeline_outputs(pid, resolved, label)
    item = {
        "kind": kind,
        "label": label or kind,
        "source_path": _display_path(resolved),
        "public_path": _display_path(public_path),
        "sha256": _sha256_file(public_path),
        "size_bytes": public_path.stat().st_size,
        "notes": notes,
        "registered_at": _now(),
    }
    outputs = _ensure_output_registry(state)
    existing = [
        old for old in outputs["items"]
        if not (isinstance(old, dict) and old.get("public_path") == item["public_path"])
    ]
    existing.append(item)
    outputs["items"] = existing
    manifest_path = _contract_paths(pid)["outputs_manifest"]
    manifest = {
        "schema_version": 1,
        "pipeline_id": pid,
        "generated_at": _now(),
        "items": outputs["items"],
    }
    _write_json(manifest_path, manifest)
    return item


def _deployment_artifacts(
    state: Dict[str, Any],
    evidence: Optional[str],
) -> Tuple[List[Path], List[str], List[str]]:
    """배포 대상 산출물 경로 목록과 차단된 산출물 이름 목록을 반환한다.

    IMP-20260528-3898 MT-3: _is_internal_artifact() SSoT를 사용하여 내부 산출물을
    배포 대상에서 자동 제외한다.
    IMP-20260529-D8BA MT-1: SECRET_PATTERNS / SECRET_FILENAME_PATTERNS SSoT를
    사용하여 민감 정보가 포함된/민감 정보 파일명을 배포 대상에서 자동 제외한다.

    차단된 파일 이름 목록은 deployment_manifest.json의 blocked_internal_artifacts /
    blocked_secret_artifacts 필드에 각각 기록된다.

    Returns:
        (allowed_paths, blocked_internal, blocked_secret) 3-tuple.
        allowed_paths: 배포할 파일 Path 목록 (내부/민감 산출물 제외)
        blocked_internal: 차단된 내부 산출물 파일 이름 목록
        blocked_secret: 차단된 민감 정보 산출물 파일 이름 목록
    """
    candidates: List[str] = []
    candidates.extend(_split_evidence_paths(evidence))
    outputs = _ensure_output_registry(state)
    for item in outputs.get("items", []):
        if isinstance(item, dict):
            candidates.extend(_split_evidence_paths(item.get("public_path")))
    phases = state.get("phases", {})
    if isinstance(phases, dict):
        for phase_name in ("build",):
            phase = phases.get(phase_name, {})
            if isinstance(phase, dict):
                candidates.extend(_split_evidence_paths(phase.get("evidence")))

    result: List[Path] = []
    blocked: List[str] = []
    blocked_secret: List[str] = []
    seen: set = set()
    for raw in candidates:
        # 내부 산출물은 배포에서 제외 (SSoT: WORKSPACE_INTERNAL_PATTERNS)
        normalized = raw.replace("\\", "/").strip() if raw else ""
        basename = normalized.split("/")[-1] if "/" in normalized else normalized
        if _is_internal_artifact(raw):
            if basename and basename not in blocked:
                blocked.append(basename)
            continue
        # IMP-20260529-D8BA MT-1: secret 파일명 패턴 검사 (.env/*.key/*.pem 등)
        if _is_secret_filename(raw):
            if basename and basename not in blocked_secret:
                blocked_secret.append(basename)
            continue
        # IMP-20260529-D8BA MT-1: 파일 내용에서 secret 검사
        candidate_path = _resolve_artifact_path(raw)
        if candidate_path and candidate_path.is_file():
            try:
                content = candidate_path.read_text(encoding="utf-8", errors="replace")
                if _scan_text_for_secrets(content):
                    if basename and basename not in blocked_secret:
                        blocked_secret.append(basename)
                    continue
            except Exception:
                pass  # 읽기 실패는 secret 검사 통과로 간주(다른 경로에서 차단됨)
        if not candidate_path:
            continue
        key = str(candidate_path).lower()
        if key in seen:
            continue
        seen.add(key)
        result.append(candidate_path)
    return result, blocked, blocked_secret


def _copy_deployment_artifact(src: Path, deploy_dir: Path) -> Dict[str, Any]:
    try:
        rel = src.resolve().relative_to(BASE_DIR)
    except ValueError:
        rel = Path(src.name)
    dest = deploy_dir / rel
    if src.is_dir():
        shutil.copytree(src, dest, dirs_exist_ok=True)
        kind = "directory"
        sha256 = None
    else:
        dest.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(src, dest)
        kind = "file"
        sha256 = _sha256_file(dest)
    return {
        "kind": kind,
        "source": _display_path(src),
        "destination": str(dest),
        "sha256": sha256,
    }


def _deploy_accepted_outputs(
    state: Dict[str, Any],
    evidence: Optional[str],
    notes: Optional[str],
    evidence_validation: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    pid = str(state.get("pipeline_id") or "UNKNOWN")
    deploy_root = _deployment_root()
    deploy_dir = deploy_root / pid
    # IMP-20260528-3898 MT-3 / IMP-20260529-D8BA MT-1: 내부/민감 산출물 필터 — 3-tuple
    artifacts, blocked_internal, blocked_secret = _deployment_artifacts(state, evidence)
    # IMP-20260612-CE06 MT-1: 배포 직전 _is_deployable_evidence SSoT로 최종 방어.
    # _deployment_artifacts가 이미 내부 산출물을 제외하지만, 동일 SSoT 헬퍼로
    # 한 번 더 검증하여 내부 산출물이 배포 경로로 새는 것을 차단한다.
    _deployable_artifacts: List[Path] = []
    for _art in artifacts:
        if _is_deployable_evidence(str(_art)):
            _deployable_artifacts.append(_art)
        else:
            _name = _art.name
            if _name and _name not in blocked_internal:
                blocked_internal.append(_name)
    artifacts = _deployable_artifacts
    external_urls = list((evidence_validation or {}).get("urls") or [])
    if not artifacts and not external_urls:
        _die(
            "[ACCEPTANCE DEPLOY BLOCKED] 배포할 결과물을 찾지 못했습니다. "
            "--evidence에 실제 파일/폴더 경로 또는 GitHub 첨부파일/PR 링크를 넣으세요."
        )
    deploy_dir.mkdir(parents=True, exist_ok=True)
    copied = [_copy_deployment_artifact(path, deploy_dir) for path in artifacts]
    manifest = {
        "schema_version": 1,
        "pipeline_id": pid,
        "deployed_at": _now(),
        "deploy_root": str(deploy_root),
        "deploy_dir": str(deploy_dir),
        "evidence": evidence,
        "validated_evidence": evidence_validation or {},
        "notes": notes or "",
        "artifacts": copied,
        "external_urls": external_urls,
        # IMP-20260528-3898 MT-3: 차단된 내부 산출물 목록 기록
        "blocked_internal_artifacts": blocked_internal,
        # IMP-20260529-D8BA MT-1: 차단된 민감 정보 산출물 목록 기록
        "blocked_secret_artifacts": blocked_secret,
    }
    manifest_path = deploy_dir / "deployment_manifest.json"
    _write_json(manifest_path, manifest)
    manifest["manifest_path"] = str(manifest_path)
    return manifest


def _enable_phase_attestations(state: Dict[str, Any]) -> None:
    state["phase_attestations"] = _ensure_phase_attestations(state)
    state["phase_attestations"]["enabled"] = True


def _expected_agent_id(phase: str) -> str:
    if phase not in PHASE_AGENT_IDS:
        _die(f"agent receipts are not supported for phase: {phase}", exit_code=2)
    return PHASE_AGENT_IDS[phase]


def _agent_token_hash(token: str) -> str:
    return hashlib.sha256(token.encode("utf-8")).hexdigest()


def _new_agent_run_id(phase: str) -> str:
    return f"{phase}-{secrets.token_hex(8)}"


def _receipt_path_for_run(pid: str, phase: str, run_id: str) -> Path:
    safe_run = re.sub(r"[^A-Za-z0-9_.-]+", "_", run_id)
    return AGENT_RECEIPT_DIR / pid / phase / f"{safe_run}.json"


def _path_sha_payload(path: Path) -> Dict[str, Any]:
    return {
        "path": _display_path(path),
        "sha256": _sha256_file(path),
        "size_bytes": path.stat().st_size,
    }


def _agent_run_start(state: Dict[str, Any], phase: str, agent_id: Optional[str]) -> Tuple[Dict[str, Any], str]:
    if phase not in AGENT_RUN_PHASES:
        _die(f"agent start supports phases: {', '.join(AGENT_RUN_PHASES)}", exit_code=2)
    expected = _expected_agent_id(phase)
    actual_agent = agent_id or expected
    if actual_agent != expected:
        _die(f"[AGENT RECEIPT GATE] {phase} must be executed by {expected}, got {actual_agent!r}")

    # PM Planner 재시도 제한: 동일 파이프라인에서 pm_planner phase가 PM_PLANNER_MAX_RETRIES회
    # 이상 시작되면 failure_packet을 기록하고 종료.
    if phase == "pm_planner":
        existing_runs = state.get("agent_runs", {})
        planner_run_count = sum(
            1 for r in existing_runs.values()
            if isinstance(r, dict) and r.get("phase") == "pm_planner"
        )
        if planner_run_count >= PM_PLANNER_MAX_RETRIES:
            pid = str(state.get("pipeline_id") or "UNKNOWN")
            failure_data = {
                "schema_version": 1,
                "pipeline_id": pid,
                "gate": "PM_PLANNER_RETRY_LIMIT",
                "recorded_at": _now(),
                "retry_count": planner_run_count,
                "max_retries": PM_PLANNER_MAX_RETRIES,
                "message": (
                    f"[PM PLANNER RETRY LIMIT] pm-planner-agent가 {planner_run_count}회 이상 실행되었습니다. "
                    f"최대 허용 횟수({PM_PLANNER_MAX_RETRIES})를 초과했습니다. "
                    "근본 원인을 분석하고 새 파이프라인을 시작하거나 관리자에게 문의하세요."
                ),
            }
            failure_path = BASE_DIR / "failure_packet.json"
            try:
                failure_path.write_text(json.dumps(failure_data, ensure_ascii=False, indent=2), encoding="utf-8")
            except OSError:
                pass
            _die(str(failure_data["message"]))

    gate_phase = "pm" if phase in {"pm_planner", "pipeline_manager"} else phase
    ok, reason = check_gate(state, gate_phase)
    if not ok:
        _die(f"[GATE BLOCKED] {reason}")
    pid = str(state.get("pipeline_id") or "")
    run_id = _new_agent_run_id(phase)
    token = f"tok_{secrets.token_urlsafe(32)}"
    run = {
        "schema_version": 1,
        "run_id": run_id,
        "pipeline_id": pid,
        "phase": phase,
        "agent_id": actual_agent,
        "status": "RUNNING",
        "started_at": _now(),
        "completed_at": None,
        "token_hash": _agent_token_hash(token),
        "output_file": None,
        "output_sha256": None,
        "evidence_files": [],
        "receipt_path": None,
        "receipt_sha256": None,
        "used_by_phase": None,
        "used_at": None,
        "commit_sha": _git_rev_parse("HEAD"),
    }
    state.setdefault("agent_runs", {})[run_id] = run
    _log_event(state, f"agent run started phase={phase} agent={actual_agent} run_id={run_id}")
    return run, token


def _agent_run_finish(
    state: Dict[str, Any],
    *,
    run_id: str,
    token: str,
    output_file: str,
    evidence: Optional[str],
    notes: Optional[str],
) -> Dict[str, Any]:
    runs = state.setdefault("agent_runs", {})
    run = runs.get(run_id)
    if not isinstance(run, dict):
        _die(f"[AGENT RECEIPT GATE] unknown run_id: {run_id}")
    if run.get("status") != "RUNNING":
        _die(f"[AGENT RECEIPT GATE] run {run_id} is not RUNNING")
    if not token or _agent_token_hash(token) != run.get("token_hash"):
        _die("[AGENT RECEIPT GATE] invalid agent run token")

    output_path = Path(output_file)
    if not output_path.is_absolute():
        output_path = BASE_DIR / output_path
    if not output_path.exists() or not output_path.is_file():
        _die(f"[AGENT RECEIPT GATE] output file not found: {output_file}")

    evidence_files: List[Dict[str, Any]] = []
    for raw in _split_evidence_paths(evidence):
        path = _resolve_artifact_path(raw)
        if path and path.is_file():
            evidence_files.append(_path_sha_payload(path))

    run["status"] = "COMPLETED"
    run["completed_at"] = _now()
    run["output_file"] = _display_path(output_path)
    run["output_sha256"] = _sha256_file(output_path)
    run["evidence_files"] = evidence_files
    run["notes"] = notes or ""
    receipt = {
        "schema_version": 1,
        "receipt_type": "agent-run-receipt-v1",
        "pipeline_id": run.get("pipeline_id"),
        "phase": run.get("phase"),
        "agent_id": run.get("agent_id"),
        "run_id": run_id,
        "status": run.get("status"),
        "started_at": run.get("started_at"),
        "completed_at": run.get("completed_at"),
        "output_file": run.get("output_file"),
        "output_sha256": run.get("output_sha256"),
        "evidence_files": evidence_files,
        "commit_sha": run.get("commit_sha"),
    }
    receipt_path = _receipt_path_for_run(str(run.get("pipeline_id")), str(run.get("phase")), run_id)
    _write_json(receipt_path, receipt)
    run["receipt_path"] = _display_path(receipt_path)
    run["receipt_sha256"] = _sha256_file(receipt_path)
    _log_event(state, f"agent run completed phase={run.get('phase')} agent={run.get('agent_id')} run_id={run_id}")
    return run


def _validate_agent_run_receipt(
    state: Dict[str, Any],
    run_phase: str,
    run_id: Optional[str],
    report_file: Optional[str],
    *,
    consume_phase: str,
) -> Optional[Dict[str, Any]]:
    if not _phase_attestations_enabled(state):
        return None
    if not run_id:
        _die(
            f"[AGENT RECEIPT GATE] {consume_phase} requires a completed {run_phase} receipt. "
            f"Start with `python pipeline.py agent start --phase {run_phase}`, pass the token to {_expected_agent_id(run_phase)}, "
            "then finish the run before recording the phase."
        )
    run = state.setdefault("agent_runs", {}).get(run_id)
    if not isinstance(run, dict):
        _die(f"[AGENT RECEIPT GATE] unknown run_id: {run_id}")
    if run.get("pipeline_id") != state.get("pipeline_id"):
        _die("[AGENT RECEIPT GATE] run pipeline_id mismatch")
    # Legacy PM compat: "pm_planner" run_phase accepts run.phase="pm" (older state schema)
    _legacy_pm_phases = {"pm"} if run_phase == "pm_planner" else set()
    if run.get("phase") != run_phase and run.get("phase") not in _legacy_pm_phases:
        _die(f"[AGENT RECEIPT GATE] run phase mismatch: expected {run_phase}, got {run.get('phase')}")
    # Resolve expected agent: for legacy pm receipt (phase="pm") use pm-agent, else normal lookup
    actual_run_phase = run.get("phase", run_phase)
    expected_agent = _expected_agent_id(actual_run_phase)
    if run.get("agent_id") != expected_agent:
        _die(f"[AGENT RECEIPT GATE] {run_phase} requires {expected_agent}, got {run.get('agent_id')}")
    if run.get("status") != "COMPLETED":
        _die(f"[AGENT RECEIPT GATE] run {run_id} must be COMPLETED")
    used = run.get("used_by_phase")
    if used and used != consume_phase:
        _die(f"[AGENT RECEIPT GATE] run {run_id} was already used by {used}")
    if not run.get("receipt_path") or not run.get("receipt_sha256"):
        _die(f"[AGENT RECEIPT GATE] run {run_id} is missing receipt file")
    receipt_path = _resolve_artifact_path(str(run.get("receipt_path")))
    if not receipt_path or not receipt_path.is_file():
        _die(f"[AGENT RECEIPT GATE] receipt file missing for run {run_id}")
    if _sha256_file(receipt_path) != run.get("receipt_sha256"):
        _die(f"[AGENT RECEIPT GATE] receipt hash mismatch for run {run_id}")
    if report_file:
        report_path = Path(report_file)
        if not report_path.is_absolute():
            report_path = BASE_DIR / report_path
        output_path = _resolve_artifact_path(str(run.get("output_file") or ""))
        if not output_path or report_path.resolve() != output_path.resolve():
            _die("[AGENT RECEIPT GATE] --report-file must match the completed agent run output_file")
        if _sha256_file(report_path.resolve()) != run.get("output_sha256"):
            _die("[AGENT RECEIPT GATE] report hash mismatch against agent run output")
    run["used_by_phase"] = consume_phase
    run["used_at"] = _now()
    return run


def _validate_agent_run_for_phase(
    state: Dict[str, Any],
    phase: str,
    run_id: Optional[str],
    report_file: Optional[str],
) -> Optional[Dict[str, Any]]:
    run_phase = PHASE_RECEIPT_RUN_PHASES.get(phase, phase)
    return _validate_agent_run_receipt(
        state,
        run_phase,
        run_id,
        report_file,
        consume_phase=phase,
    )


def _safe_phase_artifact_name(path: Path) -> str:
    name = path.name or "evidence"
    return re.sub(r"[^A-Za-z0-9_.-]+", "_", name)


def _git_check_ignored(path: Path) -> bool:
    try:
        rel = path.resolve().relative_to(BASE_DIR)
    except ValueError:
        return True
    try:
        proc = subprocess.run(
            ["git", "check-ignore", "-v", str(rel)],
            cwd=str(BASE_DIR),
            check=False,
            capture_output=True,
            text=True,
            encoding="utf-8",
            errors="replace",
        )
        if proc.returncode != 0:
            return False
        last_match = ""
        for line in proc.stdout.splitlines():
            if line.strip():
                last_match = line
        if not last_match:
            return False
        pattern_part = last_match.split("\t", 1)[0]
        parts = pattern_part.split(":", 2)
        pattern = parts[2] if len(parts) == 3 else pattern_part
        return not pattern.startswith("!")
    except OSError:
        return False


def _workspace_check_for_file(path: Path) -> Dict[str, Any]:
    return {
        "path": _normalize_rel_path(str(path)),
        "sha256": _sha256_file(path),
        "size_bytes": path.stat().st_size,
    }


def _copy_phase_evidence_file(pid: str, phase: str, label: str, raw_path: Optional[str]) -> Optional[Dict[str, Any]]:
    if not raw_path:
        return None
    path = Path(str(raw_path))
    if not path.is_absolute():
        path = BASE_DIR / path
    if not path.exists() or not path.is_file():
        return None
    dest_dir = PHASE_ATTESTATION_EVIDENCE_DIR / pid / phase
    dest_dir.mkdir(parents=True, exist_ok=True)
    dest_name = f"{label}_{_safe_phase_artifact_name(path)}"
    dest = dest_dir / dest_name
    shutil.copy2(path, dest)
    ignored_by_git = _git_check_ignored(dest)
    return {
        "label": label,
        "source": _display_path(path),
        "path": _normalize_rel_path(str(dest)),
        "sha256": _sha256_file(dest),
        "size_bytes": dest.stat().st_size,
        "requires_force_add": ignored_by_git,
    }


def _phase_status_is_closed(phase: str, status: str) -> bool:
    if phase in ("pm", "dev", "build"):
        return status == "DONE"
    if phase == "qa":
        return status == "PASS"
    return False


def _prepare_phase_attestation_request(state: Dict[str, Any], phase: str) -> Dict[str, Any]:
    if phase not in PHASE_ATTESTATION_PHASES:
        _die(f"phase attestation only supports: {', '.join(PHASE_ATTESTATION_PHASES)}", exit_code=2)
    if not _phase_attestations_enabled(state):
        _die(
            "phase attestations must be enabled for every pipeline. Use "
            "`python pipeline.py contract init` or `python pipeline.py gates init` "
            "to migrate this state."
        )
    pid = str(state.get("pipeline_id") or "")
    phase_info = state.get("phases", {}).get(phase, {})
    if not isinstance(phase_info, dict):
        _die(f"missing phase state for {phase}")
    phase_status = str(phase_info.get("status") or "PENDING")
    if not _phase_status_is_closed(phase, phase_status):
        _die(f"{phase} phase must be completed before preparing phase CI attestation; current status={phase_status}")

    copied: List[Dict[str, Any]] = []
    workspace_checks: List[Dict[str, Any]] = []
    local_only: List[Dict[str, Any]] = []
    agent_run: Optional[Dict[str, Any]] = None

    run_id = phase_info.get("agent_run_id")
    if not run_id:
        _die(f"[AGENT RECEIPT GATE] {phase} phase cannot prepare CI attestation without agent_run_id")
    run = state.setdefault("agent_runs", {}).get(str(run_id))
    if not isinstance(run, dict):
        _die(f"[AGENT RECEIPT GATE] agent run not found for {phase}: {run_id}")
    _validate_agent_run_for_phase(state, phase, str(run_id), phase_info.get("report_file"))
    receipt_path = _resolve_artifact_path(str(run.get("receipt_path") or ""))
    if not receipt_path:
        _die(f"[AGENT RECEIPT GATE] receipt file missing for {phase}: {run_id}")
    agent_run = {
        "run_id": run.get("run_id"),
        "phase": run.get("phase"),
        "agent_id": run.get("agent_id"),
        "status": run.get("status"),
        "output_file": run.get("output_file"),
        "output_sha256": run.get("output_sha256"),
        "receipt_path": run.get("receipt_path"),
        "receipt_sha256": run.get("receipt_sha256"),
        "used_by_phase": run.get("used_by_phase"),
    }
    receipt_copy = _copy_phase_evidence_file(pid, phase, "agent_receipt", str(receipt_path))
    if not receipt_copy:
        _die(f"[AGENT RECEIPT GATE] could not copy receipt evidence for {phase}: {run_id}")
    agent_run["receipt_source_path"] = agent_run["receipt_path"]
    agent_run["receipt_path"] = receipt_copy["path"]
    agent_run["receipt_sha256"] = receipt_copy["sha256"]
    copied.append(receipt_copy)

    manager_run: Optional[Dict[str, Any]] = None
    if phase == "pm":
        manager_run_id = phase_info.get("manager_run_id")
        # Legacy PM compat: if no manager_run_id, skip manager CI check (old single-receipt flow)
        if manager_run_id:
            manager = state.setdefault("agent_runs", {}).get(str(manager_run_id))
            if not isinstance(manager, dict):
                _die(f"[PM MANAGER GATE] manager run not found for pm: {manager_run_id}")
            _validate_agent_run_receipt(
                state,
                "pipeline_manager",
                str(manager_run_id),
                phase_info.get("manager_report_file"),
                consume_phase="pm_manager",
            )
            manager_receipt_path = _resolve_artifact_path(str(manager.get("receipt_path") or ""))
            if not manager_receipt_path:
                _die(f"[PM MANAGER GATE] manager receipt file missing for pm: {manager_run_id}")
            manager_run = {
                "run_id": manager.get("run_id"),
                "phase": manager.get("phase"),
                "agent_id": manager.get("agent_id"),
                "status": manager.get("status"),
                "output_file": manager.get("output_file"),
                "output_sha256": manager.get("output_sha256"),
                "receipt_path": manager.get("receipt_path"),
                "receipt_sha256": manager.get("receipt_sha256"),
                "used_by_phase": manager.get("used_by_phase"),
            }
            manager_receipt_copy = _copy_phase_evidence_file(pid, phase, "manager_receipt", str(manager_receipt_path))
            if not manager_receipt_copy:
                _die(f"[PM MANAGER GATE] could not copy manager receipt evidence for pm: {manager_run_id}")
            manager_run["receipt_source_path"] = manager_run["receipt_path"]
            manager_run["receipt_path"] = manager_receipt_copy["path"]
            manager_run["receipt_sha256"] = manager_receipt_copy["sha256"]
            copied.append(manager_receipt_copy)

    report = _copy_phase_evidence_file(pid, phase, "report", phase_info.get("report_file"))
    if report:
        copied.append(report)
    if phase == "pm":
        manager_report = _copy_phase_evidence_file(pid, phase, "manager_report", phase_info.get("manager_report_file"))
        if manager_report:
            copied.append(manager_report)
    if phase == "dev":
        atomic_scope = state.get("atomic_scope", {})
        if isinstance(atomic_scope, dict):
            scope = _copy_phase_evidence_file(pid, phase, "scope_manifest", atomic_scope.get("manifest_file"))
            if scope:
                copied.append(scope)

    for raw in _split_evidence_paths(phase_info.get("evidence")):
        path = _resolve_artifact_path(raw)
        if not path or not path.is_file():
            continue
        if _git_check_ignored(path):
            local_only.append({
                "path": _display_path(path),
                "sha256": _sha256_file(path),
                "reason": "ignored_or_outside_git_checkout",
            })
            continue
        workspace_checks.append(_workspace_check_for_file(path))

    request = {
        "schema_version": 1,
        "request_type": "pipeline-phase-attestation-request-v1",
        "generated_at": _now(),
        "pipeline_id": pid,
        "phase": phase,
        "phase_status": phase_status,
        "commit_hint": _git_rev_parse("HEAD"),
        "state": {
            "current_phase": state.get("current_phase"),
            "phase_completed_at": phase_info.get("completed_at"),
            "report_file": phase_info.get("report_file"),
            "evidence": phase_info.get("evidence"),
        },
        "agent_run": agent_run,
        "manager_run": manager_run,
        "copied_evidence": copied,
        "workspace_file_checks": workspace_checks,
        "local_only_files": local_only,
    }
    _write_json(PHASE_ATTESTATION_REQUEST, request)
    return request


def _state_contract_enabled(state: Dict[str, Any]) -> bool:
    info = state.get("contract_v2")
    return isinstance(info, dict) and bool(info.get("enabled"))


def _state_contract_frozen(state: Dict[str, Any]) -> bool:
    info = state.get("contract_v2")
    return isinstance(info, dict) and bool(info.get("frozen"))


def _resolve_pipeline_context(args: argparse.Namespace) -> Tuple[str, str, str, Optional[Dict[str, Any]]]:
    state = _load()
    pid = getattr(args, "pipeline_id", None) or (state or {}).get("pipeline_id")
    if not pid:
        _die("--pipeline-id is required when no active pipeline exists", exit_code=2)
    desc = getattr(args, "desc", None) or (state or {}).get("description") or ""
    ptype = getattr(args, "type", None) or (state or {}).get("type") or "FEAT"
    return str(pid), str(desc), str(ptype), state


# ── Gate validation ──────────────────────────────────────────────────────────

def check_gate(state: Dict[str, Any], phase: str) -> Tuple[bool, str]:
    """phase에 진입할 수 있는지 검증합니다.

    BUG-20260507-C2E2 MT-2: current_phase 불변식 추가.
    요청 phase가 state의 current_phase와 일치하지 않으면 BLOCKED 반환.

    Returns:
        (ok, reason) -ok=True면 진입 가능, False면 reason에 차단 사유.
    """
    if phase not in GATE_RULES:
        return False, f"알 수 없는 phase: {phase}"

    terminal = state.get("terminal_state")
    if terminal in ("COMPLETE", "FAILED", "TERMINATED"):
        return False, f"파이프라인이 이미 종료되었습니다 (terminal_state={terminal}). 새 파이프라인을 시작하세요: python pipeline.py new"
    if state.get("blocked"):
        return False, f"파이프라인 차단 중: {state.get('blocked_reason', '알 수 없음')}"

    # BUG-20260508-78D2 MT-1: current_phase 불변식 강화 — PM 면제 제거 + None 방어
    # state["current_phase"]는 단축형("pm", "dev", "qa", ...) 으로 저장됨.
    # current_phase 누락(None) 시 즉시 BLOCKED — 손상된 상태 파일 방어.
    # _new_state()는 항상 current_phase="pm"으로 초기화하므로 신규 파이프라인에는 영향 없음.
    _label_map = {
        "pm": "Phase 1 - PM (Planning)",
        "dev": "Phase 2 - Dev (Implementation)",
        "qa": "Phase 4 - QA (Verification)",
        "sec": "Phase 5 - Security (Audit)",
        "build": "Phase 6 - Build (Packaging)",
        "harness": "Phase 7 - External Gates (Acceptance)",
        "architect": "Phase 8 - Architect (RCA)",
    }
    current_phase_raw = state.get("current_phase")
    if current_phase_raw is None:
        return (
            False,
            "current_phase 필드 누락 — 상태 파일이 손상되었거나 파이프라인이 초기화되지 않았습니다. "
            "python pipeline.py status 확인."
        )
    # current_phase가 단축형인 경우 그대로 비교. 레이블 형식이면 역매핑.
    _label_to_short = {v: k for k, v in _label_map.items()}
    current_phase_short = _label_to_short.get(current_phase_raw, current_phase_raw)
    if current_phase_short != phase:
        return (
            False,
            f"current_phase 불일치 — 현재={current_phase_raw!r} (={current_phase_short}), 요청={phase}. "
            f"순서대로 진행하세요: python pipeline.py status"
        )

    if phase == "dev" and _state_contract_enabled(state) and not _state_contract_frozen(state):
        return (
            False,
            "contract_v2 is enabled but not frozen. Run `python pipeline.py contract ready` "
            "and `python pipeline.py contract freeze` before Dev.",
        )

    phase_attestation_blocker = _phase_attestation_blocker_for_phase(state, phase)
    if phase_attestation_blocker:
        return False, phase_attestation_blocker

    for required_phase, required_status in GATE_RULES[phase]:
        actual = state["phases"][required_phase]["status"]
        if isinstance(required_status, list):
            if actual not in required_status:
                options = " 또는 ".join(required_status)
                return (
                    False,
                    f"{PHASE_LABELS[required_phase]} 상태가 [{options}] 이어야 합니다. "
                    f"현재: [{actual}]",
                )
        else:
            if actual != required_status:
                return (
                    False,
                    f"{PHASE_LABELS[required_phase]} 상태가 [{required_status}] 이어야 합니다. "
                    f"현재: [{actual}]",
                )
    return True, ""


# ── Agent Office Dashboard auto-start helpers ────────────────────────────────

DASHBOARD_HOST = "127.0.0.1"
DASHBOARD_PORT = 8765
DASHBOARD_URL = f"http://{DASHBOARD_HOST}:{DASHBOARD_PORT}/"
DASHBOARD_HEALTH = f"{DASHBOARD_URL}api/health"
DASHBOARD_PROJECT_ROOT = Path(__file__).resolve().parent
DASHBOARD_LOG = DASHBOARD_PROJECT_ROOT / "logs" / "dashboard.log"


def _dashboard_is_alive(timeout: float = 0.6) -> bool:
    """대시보드 서버가 응답하는지 확인. 호출 실패 시 False."""
    try:
        with urllib.request.urlopen(DASHBOARD_HEALTH, timeout=timeout) as resp:
            return 200 <= resp.status < 300
    except Exception:
        return False


def _dashboard_port_in_use() -> bool:
    """포트가 점유 상태이면 True (다른 프로세스가 listen 중)."""
    sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    try:
        sock.settimeout(0.4)
        return sock.connect_ex((DASHBOARD_HOST, DASHBOARD_PORT)) == 0
    except OSError:
        return False
    finally:
        try:
            sock.close()
        except OSError:
            pass


def _start_dashboard_background() -> Optional[int]:
    """대시보드 서버를 백그라운드로 기동. 이미 실행 중이면 None 반환.

    반환값: subprocess PID 또는 None.
    """
    if _dashboard_is_alive():
        return None
    if _dashboard_port_in_use():
        # 다른 프로세스가 점유 중 — 우리가 띄운 것이 아닐 가능성. 건드리지 않음.
        return None

    server_module = DASHBOARD_PROJECT_ROOT / "webapp" / "server.py"
    if not server_module.exists():
        return None

    try:
        DASHBOARD_LOG.parent.mkdir(exist_ok=True)
    except OSError:
        pass

    cmd = [
        sys.executable, "-m", "uvicorn",
        "webapp.server:app",
        "--host", DASHBOARD_HOST,
        "--port", str(DASHBOARD_PORT),
        "--log-level", "warning",
    ]

    # Windows: DETACHED_PROCESS + CREATE_NEW_PROCESS_GROUP, no console window.
    creationflags = 0
    startupinfo = None
    if os.name == "nt":
        DETACHED_PROCESS = 0x00000008
        CREATE_NEW_PROCESS_GROUP = 0x00000200
        CREATE_NO_WINDOW = 0x08000000
        creationflags = DETACHED_PROCESS | CREATE_NEW_PROCESS_GROUP | CREATE_NO_WINDOW
        startupinfo = subprocess.STARTUPINFO()
        startupinfo.dwFlags |= subprocess.STARTF_USESHOWWINDOW

    try:
        log_handle = open(DASHBOARD_LOG, "ab", buffering=0)
    except OSError:
        log_handle = subprocess.DEVNULL  # type: ignore[assignment]

    try:
        proc = subprocess.Popen(
            cmd,
            cwd=str(DASHBOARD_PROJECT_ROOT),
            stdout=log_handle,
            stderr=log_handle,
            stdin=subprocess.DEVNULL,
            creationflags=creationflags,
            startupinfo=startupinfo,
            close_fds=(os.name != "nt"),
        )
        return proc.pid
    except (OSError, FileNotFoundError) as exc:
        print(DIM(f"  대시보드 자동 시작 실패: {exc}"))
        return None
    except Exception as exc:  # pragma: no cover - defensive
        print(DIM(f"  대시보드 자동 시작 예외: {exc}"))
        return None


def _ensure_dashboard_running(open_browser: bool = True) -> None:
    """대시보드 서버가 살아있도록 보장하고, 필요 시 브라우저를 연다."""
    already_alive = _dashboard_is_alive()
    pid = None
    if not already_alive:
        pid = _start_dashboard_background()
        # 서버 부팅 대기 (최대 ~3초)
        if pid is not None:
            import time
            for _ in range(15):
                time.sleep(0.2)
                if _dashboard_is_alive():
                    break

    if _dashboard_is_alive():
        if pid is not None:
            print(DIM(f"  에이전트 오피스 대시보드 시작됨 (PID {pid}) → {DASHBOARD_URL}"))
        else:
            print(DIM(f"  에이전트 오피스 대시보드 이미 실행 중 → {DASHBOARD_URL}"))
        # 브라우저 자동 오픈 제거 (IMP-20260505-C0FC) — open_browser 파라미터는 시그니처 호환을 위해 유지하되 동작은 no-op.
    else:
        print(DIM("  대시보드 자동 시작 보류 — 수동으로 'VS Code 태스크: 에이전트 대시보드 시작' 실행 가능"))


# ── Commands ─────────────────────────────────────────────────────────────────

def cmd_new(args: argparse.Namespace) -> None:
    """새 파이프라인 시작."""
    # IMP-20260621-8A27: active state는 runtime store에 있을 수 있으므로
    # STATE_FILE.exists() 대신 _load()로 기존 파이프라인을 해석한다.
    existing = _load()
    # IMP-20260623-7EAA MT-3: 이전 파이프라인 workspace readiness가 BLOCKED이면
    # 새 파이프라인 시작을 차단한다 (누락된 protected evidence 복구 강제).
    if existing:
        prev_cleanup = existing.get("post_complete_cleanup")
        if isinstance(prev_cleanup, dict) and prev_cleanup.get("status") == "BLOCKED":
            # IMP-20260623-7EAA TC-5: stdout으로 출력하여 oracle command_check stdout_contains 검증 가능하게
            print(
                "\n[PIPELINE ERROR] 이전 파이프라인 workspace readiness가 BLOCKED입니다. "
                "workspace cleanup BLOCKED"
            )
            print("복구: python pipeline.py hygiene final-cleanup --apply")
            sys.exit(1)
    if existing:
        pid = existing.get("pipeline_id", "?")
        # Archive existing
        HISTORY_DIR.mkdir(exist_ok=True)
        archive = HISTORY_DIR / f"{pid}_{existing.get('updated_at', 'old').replace(':', '-')}.json"
        archive.write_text(
            json.dumps(existing, ensure_ascii=False, indent=2), encoding="utf-8"
        )
        print(DIM(f"이전 파이프라인 [{pid}] → {archive.name} 보관"))

    pipeline_type = args.type.upper()
    pipeline_id   = _generate_id(pipeline_type)
    state = _new_state(pipeline_id, pipeline_type, args.desc)
    _log_event(state, f"파이프라인 생성: {pipeline_id}")
    _save(state)

    # IMP-20260621-8A27: active-run pointer를 생성하여 후속 명령이 runtime
    # store(.pipeline/runs/<id>/state.json)를 찾을 수 있게 한다.
    # PIPELINE_STATE_PATH가 설정된 경우(테스트 격리 등)에는 pointer를 만들지
    # 않는다 — env override가 항상 최우선이므로 pointer가 불필요하고, 격리된
    # 테스트가 실제 .pipeline/active_run.json을 오염시키지 않도록 한다.
    if not os.environ.get("PIPELINE_STATE_PATH"):
        pointer_path = _active_run_pointer_path()
        pointer_path.parent.mkdir(parents=True, exist_ok=True)
        pointer_payload = {
            "pipeline_id": pipeline_id,
            "created_at": _now(),
            "state_path": str(_state_path_for_pipeline_id(pipeline_id)),
        }
        _tmp_ptr: Optional[Path] = None
        try:
            with tempfile.NamedTemporaryFile(
                mode="w", encoding="utf-8", dir=pointer_path.parent,
                delete=False, suffix=".tmp"
            ) as _ptr:
                json.dump(pointer_payload, _ptr, ensure_ascii=False, indent=2)
                _tmp_ptr = Path(_ptr.name)
            os.replace(str(_tmp_ptr), str(pointer_path))
        except Exception:
            if _tmp_ptr is not None and _tmp_ptr.exists():
                _tmp_ptr.unlink(missing_ok=True)
            raise

    print()
    print(BOLD(GREEN("  파이프라인 생성 완료")))
    print(f"  ID:   {CYAN(pipeline_id)}")
    print(f"  유형: {pipeline_type}")
    print(f"  설명: {args.desc}")
    print()
    print(BOLD(YELLOW("  세션 언어 규칙")))
    print("  사용자에게 보이는 진행 설명, 도구 설명, PR 안내, 승인/거절 질문은 모두 쉬운 한국어로 작성하세요.")
    print("  예: 'Check latest status' 대신 '최신 상태 확인'. 코드 식별자와 명령어는 그대로 두되 한국어 설명을 붙이세요.")
    print()

    # Auto-start the Agent Office Dashboard so the user can see live activity.
    skip_dashboard = bool(getattr(args, "no_dashboard", False)) or os.environ.get(
        "PIPELINE_NO_DASHBOARD"
    )
    if not skip_dashboard:
        try:
            _ensure_dashboard_running(open_browser=False)
        except Exception as exc:  # pragma: no cover - defensive, never block pipeline
            print(DIM(f"  대시보드 부트 예외 무시: {exc}"))

    print(f"  다음 단계: {YELLOW('python pipeline.py agent start --phase pm_planner')}")
    print(f"  PM 인수 기록: {YELLOW('python pipeline.py agent start --phase pipeline_manager')}")
    print(f"  PM 완료 기록: {YELLOW('python pipeline.py done --phase pm --report-file step_plan.xml --decomp --clarification --roadmap --planner-run-id <planner_run_id> --manager-run-id <manager_run_id> --manager-report manager_handoff.xml')}")
    print()


def _check_pm_clarification_gate(state: Dict[str, Any]) -> Tuple[bool, str]:
    """PM Clarification Gate — clarification_needed or empty acceptance_criteria blocks Dev entry.

    IMP-20260523-D80A: PM이 모호한 요구사항을 Dev로 넘기지 못하게 막는 hard gate.

    Args:
        state: 현재 파이프라인 state dict.

    Returns:
        Tuple[bool, str]: (ok, reason_message).
        - 레거시 파이프라인(pm_clarification_gate 필드 없음): PASS (하위 호환)
        - clarification_needed=true: FAIL
        - acceptance_criteria 비어 있음: FAIL
        - 둘 다 통과: PASS
    """
    cg = state.get("pm_clarification_gate")
    if cg is None:
        return (True, "")  # Legacy pipeline: no field -> PASS (사용자 답변 B)
    if cg.get("clarification_needed"):
        return (False, "PM clarification이 미해소 상태입니다. done --phase pm --clarification-needed false로 해소 후 진행하세요.")
    if not cg.get("acceptance_criteria"):
        return (False, "acceptance_criteria가 비어 있습니다. done --phase pm --clarification-criteria로 기준을 제공하세요.")
    return (True, "")


def cmd_check(args: argparse.Namespace) -> None:
    """gate 검증 -exit 0: 통과, exit 1: 차단."""
    state = _load_branch_state(args)
    phase = args.phase.lower()

    # Phase 6 -> 7 does not ask the user anymore. Phase 7 is deterministic
    # automation; the only user decision is the final gates accept ACCEPT/REJECT.
    # IMP-20260612-8104 MT-1: Codex Review Gate 제거 — trust chain은
    # Technical/Oracle/GitHub CI/User Acceptance 4개 외부 게이트로 정리됨.

    # PM Clarification Gate (IMP-20260523-D80A) — Dev 진입 전 항상 동작
    if phase == "dev":
        cg_ok, cg_reason = _check_pm_clarification_gate(state)
        if not cg_ok:
            _record_failure_packet(
                state, "technical", {},
                command=[sys.executable, "pipeline.py", "done", "--phase", "pm",
                         "--clarification-needed", "false", "--clarification-criteria", "..."],
                note=cg_reason,
                status="BLOCKED",
                phase="dev",
                failure_code="pm_clarification_gate_blocked",
                failure_category="missing_evidence",
                summary_ko=f"Dev 진입 차단 — PM Clarification Gate: {cg_reason}",
                expected="clarification_needed=false AND acceptance_criteria 비어있지 않음",
                actual=cg_reason,
                exit_code=1,
                owner="PM",
                return_phase="pm",
                required_actions=["python pipeline.py done --phase pm --clarification-needed false --clarification-criteria '...'"],
                retry_allowed=True,
            )
            _save(state)
            print()
            print(RED("[PM CLARIFICATION GATE BLOCKED] Dev 진입 차단"))
            print(RED(f"  사유: {cg_reason}"))
            print()
            sys.exit(1)

    # IMP-20260527-075A MT-3: attempt budget gate — dev/qa/build 진입 직전 budget 차단 검사.
    # phase별 한도 초과 또는 동일 failure_code 반복 시 exit 1 + 한국어 메시지 + failure_packet.
    if phase in ("dev", "qa", "build"):
        # build phase는 budget 추적 대상이 아니므로 dev/qa만 검사 (build는 gate 카테고리)
        budget_phase = phase if phase in ("dev", "qa") else None
        if budget_phase is not None:
            _ensure_attempt_budget_keys(state)
            bg_check = _check_attempt_budget(state, budget_phase)
            if bg_check["blocked"]:
                msg = _korean_budget_message(
                    budget_phase,
                    bg_check["attempts_used"],
                    bg_check["max_attempts"],
                    bg_check["failure_code"],
                    bg_check.get("repeat_failure_code"),
                )
                _record_failure_packet(
                    state, "technical", {},
                    command=[sys.executable, "pipeline.py", "budget", "reset",
                             "--phase", budget_phase, "--reason", "재시도 한도 초과 후 사용자 확인 재시작"],
                    note=msg,
                    status="BLOCKED",
                    phase=budget_phase,
                    failure_code=str(bg_check["failure_code"]),
                    failure_category="missing_evidence",
                    summary_ko=msg,
                    expected=f"{budget_phase} phase 재시도 한도 내",
                    actual=msg,
                    exit_code=1,
                    owner="Pipeline Manager",
                    return_phase="architect",
                    required_actions=[
                        "prompt-architect-agent로 이관하여 RCA 수행",
                        f"사용자 확인 후 `python pipeline.py budget reset --phase {budget_phase} --reason ...`로 재시작",
                    ],
                    retry_allowed=False,
                )
                _save(state)
                print()
                print(RED(f"[GATE BLOCKED] {budget_phase} phase 재시도 한도 초과"))
                print(RED(f"  {msg}"))
                print()
                sys.exit(1)

    ok, reason = check_gate(state, phase)

    if ok:
        # IMP-20260522-29C1 fix-forward v3: phase 진입 시점(check PASS)에 started_at 기록.
        # done/qa 완료 시점이 아닌 check PASS 순간에 기록해야 elapsed가 정확해진다.
        _chk_phase = state.get("phases", {}).get(phase)
        if isinstance(_chk_phase, dict) and not _chk_phase.get("started_at"):
            _chk_phase["started_at"] = _now()
            _save(state)
        print(GREEN(f"\n[GATE OK] {PHASE_LABELS.get(phase, phase)} 진입 가능\n"))
        sys.exit(0)
    else:
        # MT-2 (IMP-20260519-EC9F): check gate 차단 시 failure_packet 생성
        # 선행 phase가 완료되지 않아 진입이 차단된 경우
        _record_failure_packet(
            state,
            f"check_{phase}",
            {},
            failure_code=f"gate_blocked_{phase}",
            failure_category="missing_evidence",
            summary_ko=f"{PHASE_LABELS.get(phase, phase)} 진입 차단 — {reason}",
            expected=f"Phase {phase} 진입을 위한 선행 단계 완료",
            actual=reason,
            owner="Pipeline Manager",
            return_phase=_gate_return_phase_for_check(phase),
            required_actions=[
                "python pipeline.py status 로 미완료 phase 확인",
                f"미완료 선행 phase를 완료한 후 다시 python pipeline.py check --phase {phase} 실행",
            ],
            retry_allowed=True,
        )
        _save(state)
        print()
        print(RED(f"[GATE BLOCKED] {PHASE_LABELS.get(phase, phase)} 진입 차단"))
        print(RED(f"  사유: {reason}"))
        print()
        print("  해결 방법:")
        for req_phase, req_status in GATE_RULES.get(phase, []):
            actual = state["phases"][req_phase]["status"]
            if isinstance(req_status, list):
                ok_now = actual in req_status
            else:
                ok_now = actual == req_status
            icon = GREEN("✓") if ok_now else RED("✗")
            expected = "/".join(req_status) if isinstance(req_status, list) else req_status
            print(f"    {icon} {PHASE_LABELS[req_phase]} → [{expected}] (현재: {actual})")
        print()
        sys.exit(1)


def _gate_return_phase_for_check(phase: str) -> str:
    """check --phase [phase] 차단 시 복구해야 할 return_phase를 반환.

    IMP-20260519-EC9F MT-2: cmd_check 실패 packet의 return_phase를 일관되게 결정.
    """
    mapping: Dict[str, str] = {
        "dev": "pm",
        "qa": "dev",
        "sec": "dev",
        "build": "qa",
        "architect": "harness",
    }
    return mapping.get(phase, "pm")


def cmd_done(args: argparse.Namespace) -> None:
    """pm 또는 dev phase 완료 처리."""
    branch: Optional[str] = getattr(args, "branch", None)
    state = _load_branch_state(args, "state 파일이 없습니다. tournament-start 먼저 실행하세요.")
    phase = args.phase.lower()

    if phase not in ("pm", "dev"):
        _die("'done' 명령은 pm/dev 전용입니다. qa/sec/build/harness는 전용 명령 사용.")

    ok, reason = check_gate(state, phase)
    if not ok:
        _die(f"[GATE BLOCKED] {reason}")

    # ── MT-1: PM Analysis Gate (IMP-20260506-A064) ───────────────────────────
    # PM이 step_plan 발행 전 3가지 분석 단계를 완료했는지 기록합니다.
    # --decomp: decomposition_audit 출력 완료 (micro-task 분해)
    # --clarification: Mandatory Clarification Triggers 판정 완료
    # --roadmap: User Roadmap Presentation Gate 처리 완료 (면제 조건 적용 시에도 기록)
    # --judgment-confirmed: AMBIGUOUS decomposition_audit 발행 시 judgment_calls_resolved
    #   블록이 step_plan에 포함되었음을 선언. AMBIGUOUS 외 상황에서는 플래그 불필요.
    if phase == "pm":
        decomp_done: bool = bool(getattr(args, "decomp", False))
        clarification_done: bool = bool(getattr(args, "clarification", False))
        roadmap_done: bool = bool(getattr(args, "roadmap", False))
        judgment_confirmed: bool = bool(getattr(args, "judgment_confirmed", False))
        pm_gate_flags: Dict[str, bool] = {
            "decomp": decomp_done,
            "clarification": clarification_done,
            "roadmap": roadmap_done,
            "judgment_confirmed": judgment_confirmed,
        }
        # ── Hard gates: decomp, clarification 필수 ────────────────────────────
        if not decomp_done:
            _die(
                "[PM GATE] --decomp 플래그 필수 — PM이 <decomposition_audit> 블록을 출력한 후 "
                "이 플래그를 포함하여 done --phase pm을 호출하세요."
            )
        if not clarification_done:
            _die(
                "[PM GATE] --clarification 플래그 필수 — PM이 Mandatory Clarification Triggers 판정을 "
                "완료한 후 이 플래그를 포함하여 done --phase pm을 호출하세요."
            )
        if not roadmap_done:
            _die(
                "[PM ROADMAP GATE] --roadmap 플래그 필수 — PM이 dev-agent spawn 전에 사용자에게 "
                "로드맵을 보고하고 '진행' 승인을 받은 뒤 기록해야 합니다."
            )
        # judgment_confirmed: AMBIGUOUS audit일 때 아래 atomic plan gate에서 hard 검증
        state.setdefault("pm_analysis_gate", {})
        state["pm_analysis_gate"].update(pm_gate_flags)
        flags_summary = ", ".join(f"{k}={'Y' if v else 'N'}" for k, v in pm_gate_flags.items())
        print(GREEN(f"  [PM ANALYSIS GATE] {flags_summary}"))
        # PM Clarification Gate 저장 (IMP-20260523-D80A)
        _cn = bool(getattr(args, "clarification_needed", False))
        _assumptions = str(getattr(args, "clarification_assumptions", "없음") or "없음")
        _criteria_source = str(getattr(args, "clarification_criteria_source", "user") or "user")
        _criteria_raw = getattr(args, "clarification_criteria", None)
        _criteria_list: list = []
        if _criteria_raw:
            _criteria_list = [c.strip() for c in str(_criteria_raw).split(",") if c.strip()]
        state["pm_clarification_gate"] = {
            "clarification_needed": _cn,
            "assumptions": _assumptions,
            "acceptance_criteria_source": _criteria_source,
            "acceptance_criteria": _criteria_list,
            "recorded_at": _now(),
        }
        print(GREEN(f"  [PM CLARIFICATION GATE] clarification_needed={_cn}, criteria={len(_criteria_list)}개"))
        # IMP-20260602-1ABE MT-2: structured AC를 state 상위 키로 저장 + requirements_tracking 플래그
        # _validate_pm_step_plan_file가 atomic_plan에 structured_acceptance_criteria를 채워둔다 (MT-1).
        # 여기서는 그 값을 state 상위로 복사하고 requirements_tracking을 활성화한다.
        # legacy 호환: structured AC가 있고 pm_clarification_gate.acceptance_criteria가 비어있으면
        # structured AC의 requirement 문자열로 자동 백필 (기존 코드 깨지지 않도록).
        _atomic_plan = state.get("atomic_plan") or {}
        _structured_ac_from_plan = _atomic_plan.get("structured_acceptance_criteria") or []
        if _structured_ac_from_plan:
            state["requirements_tracking"] = {
                "enabled": True,
                "schema_version": 1,
                "recorded_at": _now(),
            }
            state["structured_acceptance_criteria"] = _structured_ac_from_plan
            # legacy 자동 백필: pm_clarification_gate.acceptance_criteria가 비어있을 때만
            if not state["pm_clarification_gate"].get("acceptance_criteria"):
                state["pm_clarification_gate"]["acceptance_criteria"] = [
                    str(ac.get("requirement", "")).strip()
                    for ac in _structured_ac_from_plan
                    if ac.get("requirement")
                ]
            print(GREEN(
                f"  [REQUIREMENTS TRACKING] enabled=true structured_ac={len(_structured_ac_from_plan)}개"
            ))
        # AMBIGUOUS 감지: --decomp 선언했으나 --judgment-confirmed 미선언 시 경고
        if decomp_done and not judgment_confirmed:
            print(YELLOW(
                "  [JUDGMENT WARN] decomp 선언됨 — decomposition_audit이 AMBIGUOUS인 경우 "
                "--judgment-confirmed 플래그를 추가하여 judgment_calls_resolved 포함을 선언하세요. "
                "(AMBIGUOUS가 아니면 무시)"
            ))

    # PM atomic plan gate: the --decomp flag is never accepted as mere metadata.
    # Every PM completion must provide parseable planning XML so Round 1 cannot
    # silently skip decomposition or impersonate Dev/QA output.
    report_file: Optional[str] = getattr(args, "report_file", None)
    agent_run: Optional[Dict[str, Any]] = None
    if phase == "pm":
        if not report_file:
            _die(
                "[ATOMIC PLAN GATE] PM done requires "
                "`python pipeline.py done --phase pm --report-file step_plan.xml --planner-run-id <planner_run_id> "
                "--manager-run-id <manager_run_id> --manager-report manager_handoff.xml --decomp --clarification ...`"
            )
        # Legacy compat: old pipelines pass --agent-run-id for pm. New pipelines use
        # --planner-run-id + --manager-run-id. Accept both; reject only if neither provided
        # when phase_attestations are enabled (which requires receipts).
        legacy_agent_run_id = getattr(args, "agent_run_id", None)
        planner_run_id = getattr(args, "planner_run_id", None)
        manager_run_id = getattr(args, "manager_run_id", None)
        manager_report = getattr(args, "manager_report", None)

        _is_legacy_pm = bool(legacy_agent_run_id and not planner_run_id and not manager_run_id)

        if _is_legacy_pm:
            # Legacy PM path: single --agent-run-id pointing at a "pm" phase receipt
            planner_run = _validate_agent_run_receipt(
                state,
                "pm_planner",  # logical phase; legacy receipt has phase="pm"
                legacy_agent_run_id,
                report_file,
                consume_phase="pm",
            )
            manager_run = None
        else:
            planner_run = _validate_agent_run_receipt(
                state,
                "pm_planner",
                planner_run_id,
                report_file,
                consume_phase="pm",
            )
            manager_run = _validate_agent_run_receipt(
                state,
                "pipeline_manager",
                manager_run_id,
                manager_report,
                consume_phase="pm_manager",
            )
        state["atomic_plan"] = _validate_pm_step_plan_file(report_file, state)
        state["execution_profile"] = state["atomic_plan"].get("execution_profile") or _new_execution_profile("STANDARD")
        if not _is_legacy_pm:
            state["pm_manager_handoff"] = _validate_manager_handoff_file(
                manager_report,
                state,
                step_plan_file=report_file,
                planner_run_id=str(planner_run_id),
            )
        if state["atomic_plan"]["audit_result"] == "AMBIGUOUS" and not judgment_confirmed:
            _die(
                "[ATOMIC PLAN GATE] AMBIGUOUS decomposition requires --judgment-confirmed "
                "and <judgment_calls_resolved> in the PM report."
            )
        print(GREEN(
            f"  [ATOMIC PLAN GATE] micro_tasks={state['atomic_plan']['micro_task_count']} "
            f"audit={state['atomic_plan']['audit_result']}"
        ))
        module_gates = _init_module_gates_from_atomic_plan(state)
        print(GREEN(
            f"  [MODULE GATE] initialized {len(module_gates.get('sequence', []))} incremental modules"
        ))
        profile = _execution_profile(state)
        print(GREEN(
            f"  [EXECUTION PROFILE] {profile.get('mode')} "
            f"product_code_write_allowed={profile.get('product_code_write_allowed')}"
        ))
        agent_run = planner_run
        if manager_run is not None:
            state["phases"]["pm"]["manager_run_id"] = manager_run["run_id"]
            state["phases"]["pm"]["manager_agent_id"] = manager_run["agent_id"]
            state["phases"]["pm"]["manager_report_file"] = manager_report

    evidence = args.files if hasattr(args, "files") and args.files else None

    if phase == "dev":
        scope_declared: bool = bool(getattr(args, "scope_declared", False))
        if not scope_declared:
            _die(
                "[SCOPE GATE] Dev DONE requires --scope-declared. "
                "dev-agent must provide <scope_declaration> before Phase 2 can close."
            )
        module_blockers = _module_gate_blockers(state)
        if module_blockers:
            _die(
                "[MODULE GATE] Dev DONE requires every micro_task to pass module QA "
                "and integration first: " + "; ".join(module_blockers)
            )
        _validate_module_checkpoints(state)
        print(GREEN("  [SCOPE GATE] scope_declaration confirmed"))
        state["dev_handover"] = _validate_dev_handover_file(report_file, state)
        state.setdefault("dev_gate_flags", {})
        state["dev_gate_flags"]["scope_declared"] = True
        scope_manifest: Optional[str] = getattr(args, "scope_manifest", None)
        if not scope_manifest:
            _die(
                "[ATOMIC SCOPE GATE] Dev DONE requires "
                "`--scope-manifest scope_manifest.json` in every pipeline."
            )
        state["atomic_scope"] = _validate_dev_scope_manifest(scope_manifest, state, args.files)
        print(GREEN(
            f"  [ATOMIC SCOPE GATE] micro_tasks={len(state['atomic_scope']['micro_task_ids'])} "
            f"files={len(state['atomic_scope']['files'])}"
        ))

    # dev phase: --files에 나열된 경로가 실제로 존재하는지 검증
    if phase == "dev" and evidence:
        missing = [t.strip() for t in evidence.split(",") if t.strip() and not Path(t.strip()).exists()]
        if missing:
            print(RED("\n[FILE NOT FOUND] DONE 기록 거부 — 존재하지 않는 파일:"))
            for p in missing: print(RED(f"  - {p}"))
            print(RED("dev-agent가 실제로 파일을 작성한 후 다시 실행하세요.\n"))
            sys.exit(1)

    if phase != "pm":
        agent_run = _validate_agent_run_for_phase(
            state,
            phase,
            getattr(args, "agent_run_id", None),
            report_file,
        )

    # IMP-20260522-29C1 MT-2 (fix-forward): phase started_at fallback.
    # pm phase는 pipeline_started_at을 시작 시점으로 사용한다.
    # 그 외 phase는 check --phase 시점에 started_at이 기록되어야 한다.
    # done 시점에 fallback으로 _now()를 기록하면 elapsed가 ≈0이 되므로 제거한다.
    if not state["phases"]["pm"].get("started_at") and phase == "pm":
        state["phases"]["pm"]["started_at"] = (
            state.get("pipeline_started_at") or state.get("created_at")
        )
    state["phases"][phase]["status"]       = "DONE"
    state["phases"][phase]["completed_at"] = _now()
    state["phases"][phase]["evidence"]     = evidence
    state["phases"][phase]["report_file"]  = report_file
    if agent_run:
        state["phases"][phase]["agent_run_id"] = agent_run["run_id"]
        state["phases"][phase]["agent_id"] = agent_run["agent_id"]
    state["current_phase"] = PHASE_ORDER[PHASE_ORDER.index(phase) + 1]
    _log_event(state, f"{phase} DONE | evidence: {evidence}")
    # IMP-20260527-075A MT-3: dev DONE PASS 시 dev attempt budget 초기화 (성공 = 새 사이클)
    if phase == "dev":
        _ensure_attempt_budget_keys(state)
        _record_attempt_budget(state, "dev", "PASS")
    if phase == "dev":
        if _openai_advisory_required():
            review_files = _advisory_review_files_from_args(state, evidence)
            advisory_result = _auto_run_openai_advisory(state, kind="gpt-code", files=review_files)
            status = advisory_result.get("status")
            if status == "COMPLETED":
                print(GREEN(f"  [GPT ADVISORY] gpt-code completed via {OPENAI_ADVISORY_MODEL}"))
            elif status == "SKIPPED":
                print(YELLOW(f"  [GPT ADVISORY] gpt-code skipped: {advisory_result.get('reason')}"))
            else:
                print(RED(f"  [GPT ADVISORY] gpt-code error: {advisory_result.get('reason')}"))
        else:
            print(DIM("  [GPT ADVISORY] auto-run disabled by default (set ENABLE_GPT_ADVISORY_REQUIRED=1 to enable)"))
    _record_snapshot(state, phase, branch)
    _save_state_for(state, branch)

    next_phase = state["current_phase"]
    branch_tag = f" [Branch {branch}]" if branch else ""
    print(GREEN(f"\n[{phase.upper()} DONE]{branch_tag} {PHASE_LABELS[phase]} 완료"))
    if evidence:
        for f in evidence.split(","):
            print(f"  파일: {f.strip()}")
    print(f"\n  다음 단계: {YELLOW(f'python pipeline.py check --phase {next_phase}')}")
    print()


def cmd_qa(args: argparse.Namespace) -> None:
    """QA 결과 기록."""
    branch: Optional[str] = getattr(args, "branch", None)
    state = _load_branch_state(args)
    ok, reason = check_gate(state, "qa")
    if not ok:
        _die(f"[GATE BLOCKED] {reason}")

    result = args.result.upper()
    if result not in ("PASS", "FAIL"):
        _die("--result 는 PASS 또는 FAIL 이어야 합니다.")

    # ── MT-2: QA numeric_score 기록 강제 (IMP-20260506-A064) ────────────────
    # --numeric-score: QA가 산출한 수치 점수(0~QA_MAX_SCORE 정수).
    # PASS/FAIL 공통 hard gate: --numeric-score 필수
    # PASS 시: QA_PASS_THRESHOLD점(QA_MAX_SCORE의 80%) 이상 추가 요건.
    # FAIL 시: 점수 하한 없음. 이 값은 QA 하한선과 Circuit Breaker 추적용이며
    # Phase 7 COMPLETE 판정이나 external gate를 대체하지 않는다.
    numeric_score_raw: Optional[str] = getattr(args, "numeric_score", None)
    numeric_score: Optional[int] = None
    if numeric_score_raw is None:
        _die(
            "\n[QA NUMERIC GATE] --numeric-score 필수 (PASS/FAIL 공통).\n"
            f"  qa-agent는 <numeric_score> 블록을 출력하고 0~{QA_MAX_SCORE} 점수를 반드시 제출해야 합니다.\n"
            "  예: python pipeline.py qa --result FAIL --numeric-score 60 --failure-sig \"PD:abc123\"\n"
        )
    if numeric_score_raw is not None:
        try:
            numeric_score = int(numeric_score_raw)
        except (ValueError, TypeError):
            _die(f"--numeric-score 는 0~{QA_MAX_SCORE} 정수여야 합니다.")
        if not (0 <= numeric_score <= QA_MAX_SCORE):
            _die(f"--numeric-score 범위 오류: 0~{QA_MAX_SCORE} 이어야 합니다.")
        if result == "PASS" and numeric_score < QA_PASS_THRESHOLD:
            print(RED(
                f"\n[QA NUMERIC GATE] PASS 기록 거부 — numeric_score={numeric_score} < {QA_PASS_THRESHOLD} ({int(QA_PASS_RATIO * 100)}% of {QA_MAX_SCORE})"
            ))
            print(RED("  QA numeric_verdict가 FAIL이면 --result FAIL로 기록하세요. 최종 COMPLETE는 external gates가 결정합니다.\n"))
            sys.exit(1)

    # ── MT-3: Circuit Breaker failure_signature 추적 (IMP-20260506-A064) ─────
    # --failure-sig: QA FAIL 시 <failure_signature>[category]:[hash]</failure_signature> 값.
    # 동일 failure_signature가 연속 2회 감지되면 RECURRING 경고 출력 (PM이 Circuit Breaker 발동 판단).
    failure_sig: Optional[str] = getattr(args, "failure_sig", None)
    if result == "FAIL":
        if not failure_sig:
            _die(
                "[QA GATE] --failure-sig 필수 — QA FAIL 시 <failure_signature> 값을 포함하여 "
                "pipeline.py qa --result FAIL --numeric-score N --failure-sig '[category]:[hash]'를 호출하세요. "
                "Circuit Breaker 패턴 추적에 필수입니다."
            )
        sig_match = re.fullmatch(r"([A-Z][A-Z0-9_-]{1,15}):([0-9a-fA-F]{8})", failure_sig)
        if not sig_match:
            _die(
                "[QA GATE] --failure-sig는 '[CATEGORY]:[HASH8]' 형식이어야 합니다. "
                "HASH8은 정확히 8자리 16진수입니다. 슬러그 signature는 동일 오류를 "
                "다른 오류처럼 쪼개 Circuit Breaker를 약화시키므로 허용하지 않습니다."
            )
        failure_sig = f"{sig_match.group(1)}:{sig_match.group(2).lower()}"
        # qa_fail_history 초기화 (없을 시 신규 생성)
        state.setdefault("qa_fail_history", [])
        fail_history: List[Dict[str, Any]] = state["qa_fail_history"]
        round_n = len(fail_history) + 1

        repeat_indicator = "FIRST"
        if failure_sig and fail_history:
            # 직전 라운드의 failure_signature와 비교
            prev_entry = fail_history[-1]
            prev_sig = prev_entry.get("failure_signature")
            if prev_sig and prev_sig == failure_sig:
                repeat_indicator = "RECURRING"

        history_entry: Dict[str, Any] = {
            "round": round_n,
            "verdict": "FAIL",
            "failure_signature": failure_sig or "N/A",
            "repeat_indicator": repeat_indicator,
            "recorded_at": _now(),
        }
        fail_history.append(history_entry)
        state["qa_fail_history"] = fail_history

        if repeat_indicator == "RECURRING":
            print(RED(
                f"\n[CIRCUIT BREAKER] QA FAIL 동일 시그니처 2회 연속 감지 — "
                f"failure_signature='{failure_sig}'\n"
                f"  PM은 dev-agent 3회 재spawn 대신 Phase 8 (prompt-architect-agent)로 즉시 이관하세요.\n"
                f"  참조: CLAUDE.md v3.0 Circuit Breaker Protocol\n"
            ))
        elif failure_sig:
            print(YELLOW(
                f"  [CIRCUIT BREAKER] Round {round_n} FAIL 기록 — "
                f"signature='{failure_sig}' ({repeat_indicator})"
            ))
    elif result == "PASS":
        # PASS 시 qa_fail_history 초기화 (새 사이클 시작)
        if state.get("qa_fail_history"):
            state["qa_fail_history"] = []

    # IMP-20260527-075A MT-3: attempt budget 누적/초기화 (qa phase)
    _ensure_attempt_budget_keys(state)
    if result == "FAIL":
        _record_attempt_budget(state, "qa", "FAIL", failure_code=failure_sig)
    else:
        _record_attempt_budget(state, "qa", "PASS")

    # ── QA Report Hallucination Gate ──────────────────────────────────────────
    report_file: Optional[str] = getattr(args, "report_file", None)
    qa_report_validation = _validate_qa_report_file(
        report_file,
        result=result,
        numeric_score=int(numeric_score),
    )
    state["qa_report_validation"] = qa_report_validation

    agent_run = _validate_agent_run_for_phase(
        state,
        "qa",
        getattr(args, "agent_run_id", None),
        report_file,
    )

    # IMP-20260522-29C1 MT-2 (fix-forward): qa phase started_at.
    # check --phase qa 시점에 started_at이 기록되어야 한다.
    # qa 결과 기록 시점에 fallback으로 _now()를 쓰면 elapsed ≈ 0이 되므로 제거한다.
    state["phases"]["qa"]["status"]       = result
    state["phases"]["qa"]["completed_at"] = _now()
    state["phases"]["qa"]["evidence"]     = getattr(args, "agent_id", None)
    state["phases"]["qa"]["agent_id"]     = getattr(args, "agent_id", None)
    state["phases"]["qa"]["report_file"]  = report_file
    if agent_run:
        state["phases"]["qa"]["agent_run_id"] = agent_run["run_id"]
        state["phases"]["qa"]["agent_id"] = agent_run["agent_id"]
    # MT-2: numeric_score를 phase 메타데이터에 저장
    if numeric_score is not None:
        state["phases"]["qa"]["numeric_score"] = numeric_score

    if result == "PASS":
        state["current_phase"] = "sec"
        msg = GREEN("[QA PASS] 다음: Phase 5 -Security 또는 Phase 6 -Build")
        next_cmd = "python pipeline.py check --phase sec  # 네트워크/DB 포함 시\n  python pipeline.py sec --skip      # 해당 없을 시"
    else:
        state["current_phase"] = "dev"
        state["phases"]["dev"]["status"] = "PENDING"
        msg = RED("[QA FAIL] Phase 2 -Dev 재작업 필요")
        next_cmd = "python pipeline.py done --phase dev --files \"수정된파일들\" --report-file dev_handover.xml --scope-declared --scope-manifest scope_manifest.json --agent-run-id <dev_run_id>"
        # MT-2 (IMP-20260519-EC9F): QA FAIL 시 failure_packet 생성
        _sig = str(failure_sig or "")
        _record_failure_packet(
            state,
            "qa",
            {},
            failure_code=f"qa_fail_{_sig.split(':')[0].lower() if _sig else 'unknown'}",
            failure_category="test_failed",
            summary_ko=f"QA FAIL — failure_signature={_sig or 'N/A'}, score={numeric_score}/{QA_MAX_SCORE}",
            expected=f"QA numeric_score >= {QA_PASS_THRESHOLD}/{QA_MAX_SCORE} 모든 카테고리 PASS",
            actual=f"numeric_score={numeric_score}, failure_signature={_sig or 'N/A'}",
            owner="Dev",
            return_phase="dev",
            required_actions=[
                "qa_report.xml 의 critical_issues 항목을 수정하세요",
                "python pipeline.py done --phase dev --files \"수정된파일들\" --report-file dev_handover.xml --scope-declared --scope-manifest scope_manifest.json --agent-run-id <dev_run_id>",
            ],
            retry_allowed=True,
        )

    _log_event(state, f"qa {result}" + (f" numeric={numeric_score}" if numeric_score is not None else ""))
    _record_snapshot(state, "qa", branch)
    _save_state_for(state, branch)
    branch_tag = f" [Branch {branch}]" if branch else ""
    print(f"\n{msg}{branch_tag}")
    if numeric_score is not None:
        score_color = GREEN if (result == "PASS") else RED
        print(score_color(f"  numeric_score={numeric_score}/{QA_MAX_SCORE}"))
    print(f"\n  다음: {YELLOW(next_cmd)}\n")


def cmd_sec(args: argparse.Namespace) -> None:
    """Security 결과 기록."""
    branch: Optional[str] = getattr(args, "branch", None)
    state = _load_branch_state(args)
    ok, reason = check_gate(state, "sec")
    if not ok:
        _die(f"[GATE BLOCKED] {reason}")

    if getattr(args, "skip", False):
        status   = "SKIP"
        risk     = "N/A"
        msg      = YELLOW("[SEC SKIP] 네트워크/DB 없음 -보안 감사 생략")
    else:
        result = args.result.upper()
        risk   = getattr(args, "risk", "UNKNOWN").upper()
        if result not in ("PASS", "BLOCK", "FAIL"):
            _die("--result 는 PASS, BLOCK 또는 FAIL 이어야 합니다.")
        if result == "BLOCK":
            state["blocked"]        = True
            state["blocked_reason"] = f"SEC BLOCK -risk: {risk}"
            _log_event(state, f"sec BLOCK risk={risk}")
            # MT-2 (IMP-20260519-EC9F): SEC BLOCK 시 failure_packet 생성
            _record_failure_packet(
                state,
                "sec",
                {},
                failure_code="sec_block_critical",
                failure_category="security_failed",
                summary_ko=f"보안 감사 BLOCK — risk_level={risk}, Critical 취약점 발견",
                expected="security_agent 감사 결과 SAFE (risk_level=LOW)",
                actual=f"risk_level={risk}, BLOCK 판정",
                owner="Dev",
                return_phase="dev",
                required_actions=[
                    "security_audit 리포트의 CRITICAL finding remediation_code를 적용하세요",
                    "python pipeline.py done --phase dev 이후 sec 재감사 실행",
                ],
                retry_allowed=True,
            )
            _save_state_for(state, branch)
            _die(f"[SEC BLOCK] risk_level={risk} -dev-agent 수정 후 재감사 필요.", exit_code=2)
        if result == "FAIL":
            state["phases"]["sec"]["status"]       = "FAIL"
            state["phases"]["sec"]["completed_at"] = _now()
            state["phases"]["sec"]["evidence"]     = risk
            state["current_phase"] = "dev"
            state["phases"]["dev"]["status"] = "PENDING"
            _log_event(state, f"sec FAIL risk={risk}")
            # MT-2 (IMP-20260519-EC9F): SEC FAIL 시 failure_packet 생성
            _record_failure_packet(
                state,
                "sec",
                {},
                failure_code="sec_fail_high",
                failure_category="security_failed",
                summary_ko=f"보안 감사 FAIL — risk_level={risk}, HIGH 이상 취약점 발견",
                expected="security_agent 감사 결과 SAFE 또는 LOW risk",
                actual=f"risk_level={risk}, FAIL 판정 (Tier2 이상)",
                owner="Dev",
                return_phase="dev",
                required_actions=[
                    "security_audit 리포트의 HIGH/MEDIUM finding을 수정하세요",
                    "python pipeline.py done --phase dev 이후 python pipeline.py sec 재실행",
                ],
                retry_allowed=True,
            )
            _save_state_for(state, branch)
            print(YELLOW(f"\n[SEC FAIL] risk_level={risk} — Tier2 이상 발견"))
            print("\n  다음: " + YELLOW('python pipeline.py done --phase dev --files "수정된파일들" --report-file dev_handover.xml --scope-declared --scope-manifest scope_manifest.json --agent-run-id <dev_run_id>') + "\n")
            return
        status = "PASS"
        msg    = GREEN(f"[SEC PASS] risk_level={risk}")

    state["phases"]["sec"]["status"]       = status
    state["phases"]["sec"]["completed_at"] = _now()
    state["phases"]["sec"]["evidence"]     = risk
    state["current_phase"] = "build"
    _log_event(state, f"sec {status} risk={risk}")
    _record_snapshot(state, "sec", branch)
    _save_state_for(state, branch)

    print(f"\n{msg}")
    print(f"\n  다음: {YELLOW('python pipeline.py check --phase build')}\n")


def cmd_build(args: argparse.Namespace) -> None:
    """Build 결과 기록."""
    branch: Optional[str] = getattr(args, "branch", None)
    state = _load_branch_state(args)

    # --build-deferred: 패키징 파일 변경이 감지되었으나 최종 ACCEPT 직전까지 빌드를 유보.
    # build_deferred=true를 pipeline_state.json에 기록하고 즉시 종료.
    # 실제 EXE 빌드 기록은 ACCEPT 직전 별도 명령으로 수행한다.
    build_deferred_flag: bool = bool(getattr(args, "build_deferred", False))
    if build_deferred_flag:
        state["build_deferred"] = True
        _log_event(state, "build_deferred=true recorded (EXE build deferred to pre-ACCEPT step)")
        _save(state)
        print(GREEN("[BUILD DEFERRED] build_deferred=true 기록됨. 최종 ACCEPT 전에 EXE 빌드를 완료하세요."))
        return

    ok, reason = check_gate(state, "build")
    if not ok:
        _record_failure_packet(
            state,
            "build_gate",
            {},
            failure_code="build_gate_blocked",
            failure_category="missing_evidence",
            summary_ko=f"Build 진입 차단 — {reason}",
            expected="QA PASS, SEC SKIP/PASS 완료",
            actual=reason,
            owner="Pipeline Manager",
            return_phase="qa",
            required_actions=[
                "python pipeline.py status 로 미완료 phase 확인",
                "QA PASS 및 SEC SKIP/PASS 완료 후 재시도",
            ],
            retry_allowed=True,
        )
        _save(state)
        _die(f"[GATE BLOCKED] {reason}")

    exe = getattr(args, "exe", None)

    # ── MT-4: BUILD 6-Section Report 파일 존재 검증 (IMP-20260506-A064) ──────
    # EXE 빌드인 경우 dist/build_report.xml 파일이 존재해야 DONE 기록 허용.
    # N/A 빌드(Streamlit/MD-only/메타-태스크)는 검증 생략.
    # --report-file 로 커스텀 경로 지정 가능 (기본: dist/build_report.xml).
    is_na_build = (exe is None) or (str(exe).strip().upper() == "N/A")
    build_report_file: Optional[str] = getattr(args, "report_file", None)
    skip_reason: Optional[str] = getattr(args, "skip_reason", None)
    if not is_na_build:
        # EXE 파일 실제 존재 검증
        exe_path = Path(str(exe))
        if not exe_path.exists():
            _record_failure_packet(
                state,
                "build_exe_missing",
                {},
                failure_code="build_exe_missing",
                failure_category="missing_artifact",
                summary_ko=f"Build 실패 — EXE 파일 없음: {exe}",
                expected=f"EXE 파일 존재: {exe}",
                actual="파일 없음",
                owner="Build",
                return_phase="build",
                required_actions=[
                    "PyInstaller를 실행하여 EXE를 생성하세요: pyinstaller --onefile main.py",
                    f"EXE 생성 확인 후 재실행: python pipeline.py build --exe {exe}",
                ],
                retry_allowed=True,
            )
            _save(state)
            _die(
                f"\n[BUILD EXE GATE] EXE 파일 없음: {exe}\n"
                "  PyInstaller dist/ 폴더에 EXE가 생성된 후 이 명령을 실행하세요.\n"
            )
        # dist/build_report.xml 기본 경로 또는 --report-file 지정 경로
        if build_report_file is None:
            build_report_file = str(BASE_DIR / "dist" / "build_report.xml")
        build_report_path = Path(build_report_file)
        if not build_report_path.exists():
            _record_failure_packet(
                state,
                "build_report_missing",
                {},
                failure_code="build_report_xml_missing",
                failure_category="missing_artifact",
                summary_ko=f"Build 실패 — build_report.xml 없음: {build_report_file}",
                expected=f"build_report.xml 존재: {build_report_file}",
                actual="파일 없음",
                owner="Build",
                return_phase="build",
                required_actions=[
                    "build-agent.md '## Output Format' 섹션의 6-Section Report 형식으로 build_report.xml을 작성하세요.",
                    f"{build_report_file} 파일 생성 후 재실행",
                ],
                retry_allowed=True,
            )
            _save(state)
            print(RED(
                f"\n[BUILD REPORT GATE] build_report.xml 파일 없음: {build_report_file}"
            ))
            print(RED(
                "  build-agent는 dist/build_report.xml 파일을 저장한 후 이 명령을 실행해야 합니다."
            ))
            print(RED(
                "  (build-agent.md '## Output Format' 섹션 참조 — 6-Section Report 파일 저장 의무)\n"
            ))
            sys.exit(1)
        # 6-Section XML 블록 검증 — BUG-20260507-C2E2: _verify_build_report_xml (ET only, no regex fallback)
        # XML comment bypass 차단: comment 내 가짜 섹션 태그는 무효 처리됨
        build_report_text = ""
        bp = Path(build_report_file)
        for enc in ("utf-8", "cp949", "latin-1"):
            try:
                build_report_text = bp.read_text(encoding=enc)
                break
            except (UnicodeDecodeError, OSError):
                continue
        if not build_report_text:
            _record_failure_packet(
                state,
                "build_report_read_error",
                {},
                failure_code="build_report_xml_read_error",
                failure_category="invalid_artifact",
                summary_ko=f"Build 실패 — build_report.xml 읽기 오류: {build_report_file}",
                expected="UTF-8/CP949/Latin-1 인코딩으로 읽기 성공",
                actual="모든 인코딩으로 읽기 실패",
                owner="Build",
                return_phase="build",
                required_actions=[
                    "build_report.xml 파일이 비어있지 않은지 확인하세요.",
                    "UTF-8로 재저장 후 재실행하세요.",
                ],
                retry_allowed=True,
            )
            _save(state)
            print(RED(f"\n[BUILD REPORT GATE] build_report.xml 읽기 실패: {build_report_file}\n"))
            sys.exit(1)
        xml_ok, xml_msg = _verify_build_report_xml(build_report_text)
        if not xml_ok:
            _record_failure_packet(
                state,
                "build_report_xml_invalid",
                {},
                failure_code="build_report_xml_invalid_structure",
                failure_category="invalid_artifact",
                summary_ko=f"Build 실패 — build_report.xml 6-Section 검증 실패: {xml_msg}",
                expected="6개 섹션(section_1~section_6) + <status>BUILD SUCCESS</status>",
                actual=xml_msg,
                owner="Build",
                return_phase="build",
                required_actions=[
                    "build_report.xml에 6개 섹션 XML 태그를 추가하세요 (build-agent.md '## Output Format' 참조).",
                    "XML comment(<!-- -->)로 감싼 섹션은 유효하지 않으므로 실제 태그로 교체하세요.",
                ],
                retry_allowed=True,
            )
            _save(state)
            print(RED(f"\n[BUILD 6-SECTION GATE] XML 검증 실패: {xml_msg}"))
            print(RED("  build_report.xml에 6개 섹션과 <status>BUILD SUCCESS</status>가 실제 XML 태그로 포함되어야 합니다."))
            print(RED("  XML comment(<!-- -->)로 감싼 섹션은 유효하지 않습니다.\n"))
            sys.exit(1)
        print(GREEN("  [BUILD REPORT GATE] 6-Section Report 검증 통과 (XML comment bypass 차단 완료)"))
        # IMP-20260623-7EAA Round 2 (F1): build_report.xml을 pipeline-owned artifact로
        # cleanup_only 등록 → COMPLETE 후 _run_post_complete_cleanup이 자동 삭제 대상으로 인식.
        try:
            _register_workspace_artifact(
                state,
                str(build_report_file),
                _CLEANUP_POLICY_CLEANUP_ONLY,
                "build phase report — cleanup_only",
            )
        except (TypeError, ValueError, OSError):
            # 등록 실패가 build 기록을 막지 않는다 (best-effort).
            pass
    else:
        # MT-2 (IMP-20260507-49F7): whitelist 방식으로 교체.
        # 조건: len >= 5 AND reason.lower() in whitelist (AND 논리, OR 아님).
        # 허용 목록 외 값 또는 축약어("skip" 등)는 모두 차단.
        SKIP_REASON_WHITELIST = {
            "md-only", "meta-task", "streamlit", "power-automate", "no-code", "docs-only"
        }
        reason = (skip_reason or "").strip()
        if len(reason) < 5 or reason.lower() not in SKIP_REASON_WHITELIST:
            _record_failure_packet(
                state,
                "build_na_skip_reason_invalid",
                {},
                failure_code="build_na_invalid_skip_reason",
                failure_category="invalid_argument",
                summary_ko=(
                    f"Build N/A 거부 — skip-reason이 whitelist에 없거나 길이 < 5: '{reason}'"
                ),
                expected=f"허용 목록 중 하나: {sorted(SKIP_REASON_WHITELIST)}",
                actual=f"제공된 skip-reason: '{reason}'",
                owner="Build",
                return_phase="build",
                required_actions=[
                    f"--skip-reason을 허용 목록 중 하나로 변경하세요: {sorted(SKIP_REASON_WHITELIST)}",
                    "예: --skip-reason \"meta-task\" 또는 --skip-reason \"streamlit\"",
                ],
                retry_allowed=True,
            )
            _save(state)
            _die(
                "\n[BUILD N/A GATE] --exe \"N/A\" 기록 거부 — --skip-reason이 whitelist에 없거나 길이 < 5.\n"
                f"  허용 목록(대소문자 무관): {sorted(SKIP_REASON_WHITELIST)}\n"
                "  예: --skip-reason \"meta-task\", --skip-reason \"streamlit\""
            )
        skip_reason = reason
        print(YELLOW("  [BUILD REPORT GATE] N/A 빌드 — build_report.xml 검증 생략, 최종 ACCEPT 보고서에 사유 기록"))

    agent_run = _validate_agent_run_for_phase(
        state,
        "build",
        getattr(args, "agent_run_id", None),
        build_report_file,
    )

    state["phases"]["build"]["status"]       = "DONE"
    state["phases"]["build"]["completed_at"] = _now()
    state["phases"]["build"]["evidence"]     = exe
    state["phases"]["build"]["report_file"]  = build_report_file if not is_na_build else None
    state["phases"]["build"]["skip_reason"]  = skip_reason if is_na_build else None
    if agent_run:
        state["phases"]["build"]["agent_run_id"] = agent_run["run_id"]
        state["phases"]["build"]["agent_id"] = agent_run["agent_id"]
    state["current_phase"] = "harness"
    _log_event(state, f"build DONE exe={exe}" + (f" skip_reason={skip_reason}" if is_na_build else ""))
    _record_snapshot(state, "build", branch)
    _save_state_for(state, branch)

    print(GREEN(f"\n[BUILD DONE] EXE: {exe or '경로 미지정'}"))
    print()
    print(BOLD(YELLOW("  ★ Phase 7 External Gates 실행 의무 -생략 불가")))
    print("  다음 절차:")
    print("    1. Build evidence commit/push 후 GitHub Actions phase attestation 확인:")
    print(f"       {YELLOW('python pipeline.py gates phase-ci --phase build --repo hojiyong2-commits/Pipeline')}")
    print("    2. test-harness-agent는 진단만 수행하고, 아래 external gates를 기록:")
    print(f"       {YELLOW('python pipeline.py gates technical')}")
    print(f"       {YELLOW('python pipeline.py gates oracle')}")
    print(f"       {YELLOW('python pipeline.py gates github-ci --repo hojiyong2-commits/Pipeline')}")
    print(f"       {YELLOW('python pipeline.py gates request-accept --evidence [결과물-경로]')}  ← 1단계: 사용자에게 코드 표시")
    print(f"       {YELLOW('python pipeline.py gates accept --result ACCEPT --evidence [경로] --acceptance-code ACCEPT-<pid>-<nonce>')}  ← 2단계: 사용자 코드 입력 후")
    print()


